insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('spanish', 'p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', '{"learn": {"enabled": true, "items": [{"title": "The five vowel sounds — short, pure, always the same", "html": "<p>Spanish has <strong>five</strong> vowel sounds and they <strong>never change</strong> — unlike English. Each is short and crisp. Tap 🔊 to hear them.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"a\">a</span> — like ‘cat’</td><td><span data-say=\"alto\">alto</span>, <span data-say=\"antes\">antes</span></td></tr>\n              <tr><td><span data-say=\"e\">e</span> — like ‘pet’</td><td><span data-say=\"español\">español</span>, <span data-say=\"medio\">medio</span></td></tr>\n              <tr><td><span data-say=\"i\">i</span> — like ‘see’</td><td><span data-say=\"idea\">idea</span>, <span data-say=\"iglesia\">iglesia</span></td></tr>\n              <tr><td><span data-say=\"o\">o</span> — like ‘hot’</td><td><span data-say=\"dos\">dos</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n              <tr><td><span data-say=\"u\">u</span> — like ‘boot’</td><td><span data-say=\"universidad\">universidad</span>, <span data-say=\"instituto\">instituto</span></td></tr>\n            </table>\n            <p>Never let a vowel ‘glide’ the way English does — keep it pure and even.</p>", "check": {"question": "How many vowel sounds does Spanish have, and do they change?", "options": ["Five, and they stay the same", "Twelve different ones, like in English", "Five, but they glide", "Three main ones only"], "answer": 0, "explain": "Five pure vowels (a, e, i, o, u) that never change — the foundation of clear Spanish."}}, {"title": "The alphabet and the extra letter ñ", "html": "<p>The Spanish alphabet is the same as English plus one extra letter: <strong>ñ</strong> (‘eñe’). Some useful letter names: <span data-say=\"be\">be</span> (b), <span data-say=\"ce\">ce</span> (c), <span data-say=\"jota\">jota</span> (j), <span data-say=\"hache\">hache</span> (h), <span data-say=\"uve\">uve</span> (v), <span data-say=\"i griega\">i griega</span> (y).</p>\n            <ul>\n              <li><strong>ñ</strong> = the ‘ny’ sound in ‘onion’: <span data-say=\"mañana\">mañana</span>, <span data-say=\"cumpleaños\">cumpleaños</span>.</li>\n              <li>Spelling aloud matters for the exam — practise spelling your name and town.</li>\n            </ul>", "check": {"question": "Which letter is unique to the Spanish alphabet?", "options": ["ñ", "k", "w", "q"], "answer": 0, "explain": "ñ (eñe) is the extra letter; it makes the ‘ny’ sound as in mañana."}}, {"title": "Stress and the written accent (á é í ó ú)", "html": "<p>Two simple rules tell you which syllable is stressed:</p>\n            <ul>\n              <li>Words ending in a <strong>vowel, n or s</strong> → stress the <strong>second-to-last</strong> syllable: <span data-say=\"hablo\">hablo</span>, <span data-say=\"joven\">joven</span>.</li>\n              <li>Words ending in any <strong>other consonant</strong> → stress the <strong>last</strong> syllable: <span data-say=\"hablar\">hablar</span>, <span data-say=\"ciudad\">ciudad</span>.</li>\n              <li>A <strong>written accent</strong> overrides both and shows the stress: <span data-say=\"región\">región</span>, <span data-say=\"sonreír\">sonreír</span>.</li>\n            </ul>\n            <p>Accents can change meaning: <span data-say=\"sí\">sí</span> (yes) vs <em>si</em> (if); <span data-say=\"él\">él</span> (he) vs <em>el</em> (the). The upside-down <strong>¿ ¡</strong> open questions and exclamations.</p>", "check": {"question": "‘hablar’ ends in ‑r. Which syllable is stressed?", "options": ["the last one (ha-blar)", "none of them — it needs a written accent", "the first one (ha-blar)", "the middle one"], "answer": 0, "explain": "Ending in a consonant other than n/s → stress the final syllable: ha-BLAR."}}, {"title": "The letter C: two sounds (+ Z and QU)", "html": "<p>The letter <strong>c</strong> makes two different sounds depending on the next letter:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ca, co, cu</strong> → hard /k/</td><td><span data-say=\"casa\">casa</span>, <span data-say=\"coche\">coche</span>, <span data-say=\"escuchar\">escuchar</span></td></tr>\n              <tr><td><strong>ce, ci</strong> → soft ‘th’ (Spain)</td><td><span data-say=\"cerca\">cerca</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n            </table>\n            <ul>\n              <li><strong>z</strong> makes the same soft sound as ce/ci: <span data-say=\"zona\">zona</span>, <span data-say=\"manzana\">manzana</span>.</li>\n              <li>To get a hard /k/ before e or i, Spanish uses <strong>que, qui</strong> (the u is silent): <span data-say=\"porque\">porque</span>, <span data-say=\"quince\">quince</span>.</li>\n            </ul>", "check": {"question": "How is the ‘c’ in ‘cinco’ pronounced?", "options": ["soft (like ‘th’ / ‘s’)", "just like an English ‘ch’ sound", "hard, like ‘k’", "silent"], "answer": 0, "explain": "c before e or i is soft; before a/o/u it is hard /k/. So cinco = ‘thin-ko’."}}, {"title": "The letter G, and GUE / GUI", "html": "<p>Like c, the letter <strong>g</strong> makes two sounds:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ga, go, gu</strong> → hard /g/</td><td><span data-say=\"gato\">gato</span>, <span data-say=\"largo\">largo</span>, <span data-say=\"preguntar\">preguntar</span></td></tr>\n              <tr><td><strong>ge, gi</strong> → throaty /x/ (like ‘loch’)</td><td><span data-say=\"gente\">gente</span>, <span data-say=\"gimnasio\">gimnasio</span></td></tr>\n            </table>\n            <ul>\n              <li>To keep a hard /g/ before e or i, add a silent <strong>u</strong>: <span data-say=\"hamburguesa\">hamburguesa</span>, <span data-say=\"guitarra\">guitarra</span>.</li>\n            </ul>", "check": {"question": "How is the ‘g’ in ‘gente’ pronounced?", "options": ["throaty, like the ‘ch’ in ‘loch’", "like an English ‘j’ as in the word ‘jam’ exactly", "hard, like ‘g’ in ‘go’", "silent"], "answer": 0, "explain": "g before e or i is the throaty /x/ sound; before a/o/u it is a hard /g/."}}, {"title": "Why sounds matter in the exam", "html": "<p>Sound-Symbol Correspondences (SSCs) are tested directly:</p>\n            <ul>\n              <li><strong>Paper 2 (Speaking): Read-aloud</strong> — you read a short text out loud and are marked on accurate sounds.</li>\n              <li><strong>Paper 1 (Listening): Dictation</strong> — you write down what you hear, so you must link sound → spelling.</li>\n            </ul>\n            <p>Master a few rules (soft c, throaty g, silent h, rolled r) and both tasks become far easier. <span class=\"tier-h\">H</span> Higher texts are longer, but the same rules apply.</p>", "check": {"question": "Which TWO papers test your sound knowledge most directly?", "options": ["Speaking (read-aloud) and Listening (dictation)", "The Reading paper and the Writing paper only, nothing else", "Writing and Speaking essays", "None — sounds aren''t assessed"], "answer": 0, "explain": "Read-aloud (Paper 2) and dictation (Paper 1) both reward accurate sound-symbol links."}}]}, "terms": {"enabled": true, "pairs": [{"term": "a, e, i, o, u", "definition": "five short, pure vowels"}, {"term": "ñ (eñe)", "definition": "the ‘ny’ sound — mañana"}, {"term": "ca, co, cu", "definition": "hard /k/ — casa, coche"}, {"term": "ce, ci", "definition": "soft ‘th’/‘s’ — cerca, cinco"}, {"term": "z", "definition": "soft sound — zona, manzana"}, {"term": "que, qui", "definition": "hard /k/, silent u — porque, quince"}, {"term": "ga, go, gu", "definition": "hard /g/ — gato, largo"}, {"term": "ge, gi", "definition": "throaty /x/ — gente, gimnasio"}, {"term": "gue, gui", "definition": "hard /g/, silent u — guitarra"}, {"term": "silent h", "definition": "not pronounced — hospital, hoy"}, {"term": "written accent (é)", "definition": "marks the stressed syllable"}, {"term": "¿ ? · ¡ !", "definition": "open a question / exclamation"}, {"term": "stress rule 1", "definition": "vowel/n/s → 2nd-to-last syllable"}, {"term": "stress rule 2", "definition": "other consonant → last syllable"}, {"term": "sí vs si", "definition": "yes vs if — accent changes meaning"}, {"term": "el alfabeto", "definition": "same as English + ñ"}, {"term": "jota (j)", "definition": "throaty sound — ojo, naranja"}, {"term": "uve (v)", "definition": "soft ‘b’ sound — verde, verdad"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"cinco\" data-listen></span><br>Listen. How is the ‘c’ sound here?", "options": ["soft, like ‘th’ / ‘s’", "hard, like ‘k’ in ‘cat’", "silent, not pronounced", "rolled like a Spanish ‘r’"], "answer": 0, "explain": "‘cinco’ — c before i is soft. (Before a/o/u it would be hard.)"}, {"question": "<span data-say=\"gato\" data-listen></span><br>Listen. The ‘g’ sound is…", "options": ["hard, like ‘g’ in ‘go’", "throaty, like the ‘ch’ in ‘loch’", "silent", "soft like an English ‘j’"], "answer": 0, "explain": "‘gato’ — g before a is hard. (Before e/i it is the throaty sound.)"}, {"question": "<span data-say=\"mañana\" data-listen></span><br>Listen. Which spelling did you hear?", "options": ["mañana", "manana", "manyana", "maniana"], "answer": 0, "explain": "The ‘ny’ sound is written ñ: mañana."}, {"question": "The five Spanish vowels are best described as…", "options": ["short and always the same", "long and changing, like English", "silent most of the time", "only used in stressed syllables"], "answer": 0, "explain": "Spanish vowels are pure, short and consistent."}, {"question": "‘hablar’ ends in ‑r. Where is the stress?", "options": ["the final syllable", "the first syllable", "spread evenly across it", "shown by a written accent"], "answer": 0, "explain": "Ending in a consonant (not n/s) → stress the last syllable: ha-BLAR."}, {"question": "To write a hard /k/ sound before ‘e’, Spanish uses…", "options": ["qu (as in porque)", "just the letter c (as in cerca)", "the letter k in every case", "z (as in zona)"], "answer": 0, "explain": "que/qui give a hard /k/ (silent u); ‘c’ before e/i is soft."}, {"question": "Which word has the throaty /x/ ‘g’ sound?", "options": ["gimnasio", "gato", "largo", "guitarra"], "answer": 0, "explain": "g before i (gimnasio) is throaty; the others are hard /g/."}, {"question": "<span data-say=\"zona\" data-listen></span><br>Listen. The ‘z’ sound matches which letters?", "options": ["ce / ci (soft)", "ca / co (hard)", "qu (hard k)", "ñ (ny)"], "answer": 0, "explain": "z makes the same soft sound as ce/ci."}, {"question": "Why does ‘guitarra’ have a ‘u’ after the g?", "options": ["to keep the g hard before ‘i’", "because every single g must be followed by a u", "to make the g throaty", "to add an extra syllable"], "answer": 0, "explain": "gue/gui keep a hard /g/ before e/i; the u is silent."}, {"question": "A written accent (as in ‘región’) tells you…", "options": ["which syllable is stressed", "that you should whisper the whole word", "the word is plural", "to roll the r"], "answer": 0, "explain": "The accent marks the stressed syllable (and can change meaning)."}]}, "fib": {"enabled": true, "questions": [{"text": "The word for ‘five’ is [cinco]. <span data-say=\"cinco\" data-listen>cinco</span>"}, {"text": "The ‘ny’ sound word for ‘tomorrow’ is ma[ñan]a. <span data-say=\"mañana\" data-listen>mañana</span>"}, {"text": "To keep a hard g before i, we write gu[it]arra. <span data-say=\"guitarra\" data-listen>guitarra</span>"}, {"text": "c before e or i sounds [soft]. (hard or soft?)"}, {"text": "Words ending in a vowel, n or s stress the [second]-to-last syllable. (which one?)"}, {"text": "The extra Spanish letter is [ñ]. (its symbol)"}, {"text": "g before e or i is [throaty]. (hard or throaty?)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Spanish vowels change their sound depending on the word, like English.", "answer": false, "explain": "Spanish vowels are pure and always the same."}, {"statement": "‘ñ’ is a separate letter of the Spanish alphabet.", "answer": true, "explain": "ñ (eñe) is a distinct letter; it makes the ‘ny’ sound."}, {"statement": "c before e or i is pronounced soft (like ‘th’/‘s’).", "answer": true, "explain": "ce/ci are soft; ca/co/cu are hard /k/."}, {"statement": "The letter h is usually silent in Spanish.", "answer": true, "explain": "h is silent: hospital, hoy."}, {"statement": "‘que’ and ‘qui’ give a soft ‘s’ sound.", "answer": false, "explain": "They give a hard /k/ (the u is silent)."}, {"statement": "A written accent shows which syllable is stressed.", "answer": true, "explain": "It marks stress and can change meaning (sí vs si)."}, {"statement": "g before a, o or u is hard, as in ‘gato’.", "answer": true, "explain": "ga/go/gu are hard; ge/gi are throaty."}, {"statement": "Words ending in ‑r stress the second-to-last syllable.", "answer": false, "explain": "Ending in a consonant (not n/s) → stress the LAST syllable (ha-BLAR)."}]}, "misc": {"enabled": true, "items": [{"myth": "Pronouncing ‘v’ (verde) like an English ‘v’.", "truth": "Spanish v sounds almost like a soft ‘b’: verde.", "check": {"question": "How is Spanish ‘v’ (verde) pronounced?", "options": ["almost like a soft ‘b’", "exactly like an English ‘v’", "like an English ‘f’", "it is always silent"], "answer": 0, "explain": "v and b sound almost identical in Spanish — a soft ‘b’."}}, {"myth": "Saying the ‘h’ in ‘hospital’.", "truth": "The h is silent: ‘ospital’.", "check": {"question": "How do you pronounce the h in ‘hospital’?", "options": ["you don''t — it is silent", "as a strong English ‘h’ sound", "as a throaty sound", "as a ‘j’"], "answer": 0, "explain": "h is silent in Spanish (hospital, hoy)."}}, {"myth": "Reading ‘gente’ with a hard English ‘g’.", "truth": "g before e/i is throaty: ‘hente’.", "check": {"question": "The g in ‘gente’ should sound…", "options": ["throaty, like ‘loch’", "like an English ‘j’ in ‘jam’", "hard, like ‘go’", "silent"], "answer": 0, "explain": "g before e/i is the throaty /x/, not a hard g."}}, {"myth": "Reading ‘ce’ in ‘cerca’ as a hard ‘k’.", "truth": "c before e/i is soft: ‘therka’.", "check": {"question": "The c in ‘cerca’ is…", "options": ["soft (‘th’/‘s’)", "hard, like ‘k’", "silent", "a throaty sound"], "answer": 0, "explain": "c before e/i is soft; only ca/co/cu are hard."}}, {"myth": "Letting vowels glide, e.g. ‘no’ → ‘nou’.", "truth": "Keep vowels pure and short: ‘no’.", "check": {"question": "How should you say a Spanish vowel like the ‘o’ in ‘no’?", "options": ["short and pure, no glide", "long, gliding towards an ‘ou’ sound", "silent unless stressed", "rolled"], "answer": 0, "explain": "Spanish vowels never glide — keep them crisp."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 2 — Read-aloud (speaking)", "html": "Before you read, scan for the traps: soft c/z, throaty ge/gi, silent h, and the vowels. Read slowly and evenly — accurate sounds beat speed. Rolling the rr and keeping vowels pure make the biggest difference.", "check": {"question": "What matters most in the read-aloud task?", "options": ["accurate sounds, read steadily", "reading it as fast as you possibly can", "a loud English accent", "skipping the hard words"], "answer": 0, "explain": "You''re marked on accurate pronunciation, not speed."}}, {"title": "Paper 1 — Dictation (listening)", "html": "Link sound to spelling: a soft ‘th’ could be c (ce/ci) or z; a throaty sound is ge/gi or j; a silent h still gets written. Say the word in your head and picture the letters.", "check": {"question": "You hear a throaty sound before an ‘e’. It is most likely spelt…", "options": ["ge or j", "gue or gui", "ca", "qu"], "answer": 0, "explain": "The throaty /x/ before e is ge (or j); gue would be a hard g."}}, {"title": "Paper 4 — Accents in writing", "html": "In written Spanish, missing or wrong accents can cost accuracy marks and even change meaning (sí/si, él/el). When you learn a word, learn its accent as part of the spelling.", "check": {"question": "Why do written accents matter in Paper 4?", "options": ["they affect accuracy and can change meaning", "they only ever matter when you are speaking aloud", "they are optional decoration", "they show the plural"], "answer": 0, "explain": "Accents carry meaning and accuracy marks (sí = yes vs si = if)."}}]}, "exam": {"enabled": true, "questions": [{"question": "<strong>Read-aloud practice.</strong> Read this text out loud, then tick the sounds you produced correctly.<br><br><em>«Hola. Me llamo Guille. Vivo en una ciudad grande y voy al gimnasio los jueves. La gente aquí es muy simpática.»</em><br><br>Hear a model first: 🔊 <span data-say=\"Hola. Me llamo Guille. Vivo en una ciudad grande y voy al gimnasio los jueves. La gente aquí es muy simpática.\">model</span>", "marks": 5, "hint": "Watch: gui (hard g), ciudad (soft c), gimnasio & gente (throaty g), jueves (throaty j), the silent h in Hola, and pure vowels.", "markScheme": "<div class=\"marks-section\"><h5>Self-mark — 5 pronunciation points</h5><ul>\n                <li>Silent <strong>h</strong> in ‘Hola’ (not an English h).</li>\n                <li><strong>gui</strong> in ‘Guille’ = hard g (silent u).</li>\n                <li>Soft <strong>c</strong> in ‘ciudad’ (‘th’/‘s’, not ‘k’).</li>\n                <li>Throaty <strong>g/j</strong> in ‘gimnasio’, ‘gente’, ‘jueves’.</li>\n                <li>Pure, even <strong>vowels</strong> throughout.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Tick each feature you produced correctly. In the real NEA an examiner rewards clear, comprehensible pronunciation.</li>\n            </ul></div>"}, {"question": "<strong>Dictation.</strong> Listen and write the four words you hear, then check them.<br>🔊 <span data-say=\"cinco\" data-listen>word 1</span> &nbsp; 🔊 <span data-say=\"gente\" data-listen>word 2</span> &nbsp; 🔊 <span data-say=\"guitarra\" data-listen>word 3</span> &nbsp; 🔊 <span data-say=\"mañana\" data-listen>word 4</span>", "marks": 4, "hint": "Think about the sound rules: soft c, throaty g vs hard gui, the ‘ny’ = ñ.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks</h5><ul>\n                <li>1 = <strong>cinco</strong> (soft c) · 2 = <strong>gente</strong> (throaty g) · 3 = <strong>guitarra</strong> (hard gui) · 4 = <strong>mañana</strong> (ñ).</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>1 mark per correctly-spelt word. Minor accent slips are condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'p-2-tricky-letters-ll-ch-j-h-r-v', 'P.2 Tricky Letters: ll, ch, ñ, j, h, r, v', '{"learn": {"enabled": true, "items": [{"title": "ll — one letter, one sound: the ‘y’ in ‘yes’", "html": "<p>The double letter <strong>ll</strong> is never two separate ‘l’ sounds — in most of the Spanish-speaking world it is pronounced like the English <strong>‘y’</strong> in ‘yes’.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"llamar\">llamar</span> — to call</td><td>sounds like ‘ya-MAR’</td></tr>\n              <tr><td><span data-say=\"calle\">calle</span> — street</td><td>sounds like ‘CA-ye’</td></tr>\n              <tr><td><span data-say=\"amarillo\">amarillo</span> — yellow</td><td>sounds like ‘a-ma-RI-yo’</td></tr>\n              <tr><td><span data-say=\"silla\">silla</span> — chair</td><td>sounds like ‘SI-ya’</td></tr>\n            </table>\n            <p>English speakers often say a hard ‘l’ sound (as in the word ‘llama’ mispronounced in English) — resist that instinct.</p>", "check": {"question": "How is the ‘ll’ in ‘calle’ pronounced?", "options": ["like the ‘y’ in ‘yes’", "as two separate English ‘l’ sounds run together", "silent — it isn''t pronounced at all", "like the throaty ‘ch’ in ‘loch’"], "answer": 0, "explain": "ll = ‘y’ sound: calle sounds like ‘CA-ye’, not ‘CAL-le’."}}, {"title": "ch — always the familiar English ‘ch’", "html": "<p><strong>ch</strong> is one of the easier tricky letters: it always sounds like the English ‘ch’ in ‘chip’ — and it never softens the way it can in French.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"leche\">leche</span> — milk</td><td>‘LE-che’, as in ‘chip’</td></tr>\n              <tr><td><span data-say=\"ocho\">ocho</span> — eight</td><td>‘O-cho’, as in ‘chip’</td></tr>\n              <tr><td><span data-say=\"noche\">noche</span> — night</td><td>‘NO-che’</td></tr>\n              <tr><td><span data-say=\"mucho\">mucho</span> — a lot</td><td>‘MU-cho’</td></tr>\n            </table>\n            <p>Because it is so close to the English sound, the real risk is skipping it or swapping it for a soft ‘sh’ — keep it crisp.</p>", "check": {"question": "How should you pronounce the ‘ch’ in ‘leche’?", "options": ["like the English ‘ch’ in ‘chip’", "silent — it isn''t pronounced at all", "like a soft French ‘sh’ sound", "like a hard English ‘k’ sound"], "answer": 0, "explain": "ch is always the familiar English ‘ch’ sound — leche = ‘LE-che’."}}, {"title": "ñ — a ‘ny’ glide, not a plain n", "html": "<p><strong>ñ</strong> (‘eñe’) is a separate letter from ‘n’ and always adds a ‘y’ glide, like the ‘ny’ in ‘canyon’.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mañana\">mañana</span> — tomorrow</td><td>‘ma-NYA-na’</td></tr>\n              <tr><td><span data-say=\"cumpleaños\">cumpleaños</span> — birthday</td><td>‘cum-ple-A-nyos’</td></tr>\n              <tr><td><span data-say=\"pequeño\">pequeño</span> — small</td><td>‘pe-QUE-nyo’</td></tr>\n              <tr><td><span data-say=\"año\">año</span> — year</td><td>‘A-nyo’</td></tr>\n            </table>\n            <p>Dropping the tilde and saying a plain ‘n’ is a very common English-speaker error — the glide is essential, not optional decoration.</p>", "check": {"question": "What does the tilde on ‘ñ’ change about the sound?", "options": ["it adds a ‘y’ glide, giving ‘ny’", "it makes the letter completely silent, with no sound", "it turns the n into an ‘m’ sound", "nothing — ñ and n sound identical"], "answer": 0, "explain": "ñ = ‘ny’, as in cumpleaños (‘cum-ple-A-nyos’) — never a plain n."}}, {"title": "j and h — similar on the page, opposite in sound", "html": "<p>These two letters trip learners up because they sit close together conceptually, yet do opposite things.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>j</strong> → throaty /x/</td><td><span data-say=\"ojo\">ojo</span>, <span data-say=\"naranja\">naranja</span>, <span data-say=\"trabajar\">trabajar</span></td></tr>\n              <tr><td><strong>h</strong> → always silent</td><td><span data-say=\"hospital\">hospital</span>, <span data-say=\"hoy\">hoy</span>, <span data-say=\"ahora\">ahora</span></td></tr>\n            </table>\n            <p><strong>j</strong> is pronounced from the back of the throat, like the Scottish ‘loch’ — never like an English ‘j’ (as in ‘jam’). <strong>h</strong> is never pronounced at all, even at the start of a word.</p>", "check": {"question": "Which statement correctly contrasts j and h?", "options": ["j is a throaty sound; h is always silent", "j is silent; h is a throaty sound instead", "both letters are completely silent in Spanish", "both letters sound like an English ‘j’ in ‘jam’"], "answer": 0, "explain": "j = throaty /x/ (ojo); h = never pronounced (hospital = ‘os-pi-TAL’)."}}, {"title": "r vs rr — a quick tap or a strong roll?", "html": "<p>Spanish has two different r-sounds, and mixing them up can change the meaning of a word entirely.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>single <strong>r</strong> between vowels → one quick tap</td><td><span data-say=\"pero\">pero</span> (but), <span data-say=\"hablar\">hablar</span> (to speak)</td></tr>\n              <tr><td><strong>rr</strong>, or <strong>r</strong> at the start of a word → strongly rolled</td><td><span data-say=\"cerrar\">cerrar</span> (to close), <span data-say=\"sonreír\">sonreír</span> (to smile), <span data-say=\"perro\">perro</span> (dog)</td></tr>\n            </table>\n            <p>The signature exam trap is the minimal pair <span data-say=\"pero\">pero</span> (‘but’) vs <span data-say=\"perro\">perro</span> (‘dog’) — say the wrong one and the sentence stops making sense. <span class=\"tier-h\">H</span> Higher-tier read-aloud texts pack several of these r-sounds into one sentence, so practise the switch.</p>", "check": {"question": "What is the difference between ‘pero’ and ‘perro’?", "options": ["a single tap vs a strongly rolled r, and the meaning changes completely", "nothing at all — the two words are pronounced in exactly the same identical way", "‘pero’ has a silent r and ‘perro’ does not", "only the stress moves to a different syllable"], "answer": 0, "explain": "pero (single tap, ‘but’) vs perro (rolled rr, ‘dog’) — a classic minimal pair."}}, {"title": "v and b — the same soft ‘b’ sound", "html": "<p>In Spanish, <strong>v</strong> and <strong>b</strong> are pronounced almost identically — a soft ‘b’, made without fully closing the lips. Spanish speakers do not distinguish them the way English does.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"verde\">verde</span> — green</td><td>soft ‘b’, not an English ‘v’</td></tr>\n              <tr><td><span data-say=\"verdad\">verdad</span> — truth</td><td>soft ‘b’, not an English ‘v’</td></tr>\n              <tr><td><span data-say=\"vivir\">vivir</span> — to live</td><td>soft ‘b’ at the start too</td></tr>\n              <tr><td><span data-say=\"beber\">beber</span> — to drink</td><td>compare: also a soft ‘b’</td></tr>\n            </table>\n            <p>The letter''s own name — <span data-say=\"uve\">uve</span> — is a useful reminder: it borrows the ‘b’ sound, not an English ‘v’.</p>", "check": {"question": "How does Spanish ‘v’ (as in ‘verde’) sound?", "options": ["almost exactly like a soft ‘b’ sound", "exactly like an English ‘v’, as in ‘van’", "like an English ‘f’ sound instead", "it is completely silent"], "answer": 0, "explain": "Spanish v and b share the same soft ‘b’-like sound — verde is not an English ‘v’."}}]}, "terms": {"enabled": true, "pairs": [{"term": "ll (llamar)", "definition": "sounds like ‘y’ — ‘ya-MAR’"}, {"term": "ll (calle)", "definition": "sounds like ‘y’ — ‘CA-ye’"}, {"term": "ch (leche)", "definition": "English ‘ch’ — ‘LE-che’"}, {"term": "ch (ocho)", "definition": "English ‘ch’ — ‘O-cho’"}, {"term": "ñ (mañana)", "definition": "‘ny’ glide — ‘ma-NYA-na’"}, {"term": "ñ (cumpleaños)", "definition": "‘ny’ glide — ‘cum-ple-A-nyos’"}, {"term": "j (ojo)", "definition": "throaty /x/ — like Scottish ‘loch’"}, {"term": "j (naranja)", "definition": "throaty /x/ sound"}, {"term": "silent h (hospital)", "definition": "not pronounced — ‘os-pi-TAL’"}, {"term": "silent h (hoy)", "definition": "not pronounced at all"}, {"term": "single r (pero)", "definition": "one quick tap between vowels"}, {"term": "single r (hablar)", "definition": "one quick tap between vowels"}, {"term": "rr (cerrar)", "definition": "strongly rolled"}, {"term": "rr (perro)", "definition": "strongly rolled — ‘dog’"}, {"term": "word-initial r (sonreír)", "definition": "rolled, like rr"}, {"term": "v (verde)", "definition": "soft ‘b’ sound, not English v"}, {"term": "b (beber)", "definition": "same soft ‘b’ sound as v"}, {"term": "pero vs perro", "definition": "‘but’ vs ‘dog’ — single tap vs rolled rr"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"llamar\" data-listen></span><br>Listen. The ‘ll’ sound you hear is closest to the English…", "options": ["‘y’ in ‘yes’", "‘l’ sound, doubled up and held for longer", "‘j’ in the English word ‘jam’", "‘w’ in ‘wet’"], "answer": 0, "explain": "ll = ‘y’ sound: llamar sounds like ‘ya-MAR’."}, {"question": "<span data-say=\"leche\" data-listen></span><br>Listen. How is the ‘ch’ in this word pronounced?", "options": ["silent — it isn''t pronounced at all", "like the English ‘ch’ in ‘chip’", "like a soft French ‘sh’ sound", "like a hard English ‘k’ sound"], "answer": 1, "explain": "ch is always the familiar English ‘ch’ — leche = ‘LE-che’."}, {"question": "<span data-say=\"cumpleaños\" data-listen></span><br>Listen. Which spelling matches what you hear?", "options": ["cumpleanos", "cumplenos", "cumpleaños", "cumpleagnos"], "answer": 2, "explain": "The ‘ny’ glide is written with a tilde: cumpleaños."}, {"question": "Which pair of words BOTH contain the throaty j sound?", "options": ["ojo and naranja", "hoy and hospital", "calle and llamar", "leche and ocho"], "answer": 0, "explain": "ojo and naranja both use the throaty /x/ j sound."}, {"question": "<span data-say=\"perro\" data-listen></span><br>Listen. Is this r single-tap or rolled?", "options": ["silent, not pronounced at all", "pronounced like an English r, as in ‘red’", "a single quick tap of the tongue", "strongly rolled — this is the rr sound"], "answer": 3, "explain": "perro is spelt with rr, so the r is strongly rolled."}, {"question": "<span data-say=\"pero\" data-listen></span><br>Listen. Is this r single-tap or rolled?", "options": ["a single quick tap of the tongue", "strongly rolled, like the rr in perro", "silent — the r isn''t pronounced here", "pronounced with an English r sound"], "answer": 0, "explain": "A single r between vowels (pero) is just one quick tap."}, {"question": "Why do ‘pero’ (but) and ‘perro’ (dog) mean completely different things?", "options": ["they are actually pronounced exactly the same way", "one of them uses a silent h at the start that completely changes its meaning", "a single-tap r versus a strongly rolled rr changes the word", "the stress moves from the first to the second syllable"], "answer": 2, "explain": "The single r / rolled rr distinction is what separates pero from perro."}, {"question": "<span data-say=\"verde\" data-listen></span><br>Listen. The consonant sound you hear is closest to an English…", "options": ["‘f’ sound", "soft ‘b’ sound", "‘v’ sound, exactly as in English", "silent sound — nothing is pronounced"], "answer": 1, "explain": "Spanish v and b share the same soft ‘b’-like sound."}, {"question": "Which two words BOTH contain a silent letter?", "options": ["llamar and calle", "naranja and ojo", "verde and verdad", "hospital and hoy"], "answer": 3, "explain": "hospital and hoy both start with a silent h."}, {"question": "<span data-say=\"calle\" data-listen></span><br>Listen. Which spelling matches what you hear?", "options": ["carre", "calle", "cae", "calye"], "answer": 1, "explain": "The ‘y’ sound here is written ll: calle."}]}, "fib": {"enabled": true, "questions": [{"text": "The word for ‘street’ is [calle]. <span data-say=\"calle\" data-listen>calle</span>"}, {"text": "The word for ‘birthday’, with its ‘ny’ sound, is cumplea[ños]. <span data-say=\"cumpleaños\" data-listen>cumpleaños</span>"}, {"text": "ll sounds like the English letter [y]. (which one?)"}, {"text": "j is pronounced from the back of the throat, like the Scottish word ‘[loch]’."}, {"text": "A single r between vowels, as in ‘pero’, is a quick [tap]. (tap or roll?)"}, {"text": "‘perro’ has a strongly [rolled] r. (tap or roll?)"}, {"text": "The word for ‘green’ is [verde]. <span data-say=\"verde\" data-listen>verde</span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "In most Spanish accents, ‘ll’ sounds like the English ‘y’.", "answer": true, "explain": "ll = ‘y’ sound: llamar, calle."}, {"statement": "The letter h is usually pronounced strongly in Spanish, just like in English.", "answer": false, "explain": "h is always silent: hospital, hoy."}, {"statement": "‘ch’ always sounds like the English ‘ch’ in ‘chip’.", "answer": true, "explain": "ch never softens — leche, ocho."}, {"statement": "A single r between vowels (as in ‘pero’) is rolled just as strongly as the rr in ‘perro’.", "answer": false, "explain": "Single r = one quick tap; rr = a strong roll."}, {"statement": "ñ adds a ‘y’ glide, making ‘mañana’ sound like ‘ma-NYA-na’.", "answer": true, "explain": "ñ = ‘ny’, never a plain n."}, {"statement": "Spanish ‘v’ is pronounced exactly like an English ‘v’.", "answer": false, "explain": "Spanish v sounds like a soft ‘b’, not an English v."}, {"statement": "‘j’ is pronounced from the back of the throat, similar to the Scottish ‘loch’.", "answer": true, "explain": "j = throaty /x/: ojo, naranja."}, {"statement": "‘pero’ and ‘perro’ are pronounced identically.", "answer": false, "explain": "pero (single tap) vs perro (rolled rr) — a minimal pair with different meanings."}]}, "misc": {"enabled": true, "items": [{"myth": "Pronouncing ‘ll’ (as in llamar) as two separate English ‘l’ sounds.", "truth": "‘ll’ is a single ‘y’ sound: llamar sounds like ‘ya-MAR’.", "check": {"question": "How should ‘ll’ in ‘llamar’ sound?", "options": ["like the English ‘y’ in ‘yes’", "like two separate English ‘l’ sounds run together", "like the throaty j sound instead", "silent, with no sound at all"], "answer": 0, "explain": "ll is a single ‘y’ sound, never two ‘l’ sounds."}}, {"myth": "Pronouncing the h in ‘hospital’ as a strong English h.", "truth": "h is always silent: ‘hospital’ sounds like ‘os-pi-TAL’.", "check": {"question": "How is the h in ‘hospital’ pronounced?", "options": ["it isn''t — the h is always silent", "as a strong English h sound, exactly like the start of ‘hospital’ in English", "as a throaty j sound instead", "as a soft ‘ch’ sound"], "answer": 0, "explain": "h is never pronounced in Spanish."}}, {"myth": "Rolling the r in ‘pero’ as strongly as in ‘perro’.", "truth": "A single r between vowels (pero) is just one quick tap.", "check": {"question": "How strongly should the r in ‘pero’ be rolled?", "options": ["barely at all — it is a single quick tap", "exactly as strongly as the rr in ‘perro’", "not pronounced at all", "rolled even more strongly than rr"], "answer": 0, "explain": "Single r between vowels = one quick tap, not a roll."}}, {"myth": "Pronouncing Spanish v (as in verde) like an English v.", "truth": "Spanish v sounds almost like a soft b: verde.", "check": {"question": "How is Spanish ‘v’ (verde) pronounced?", "options": ["almost like a soft ‘b’ sound", "exactly like an English ‘v’, as in ‘van’", "like an English ‘f’ sound instead", "it is always silent"], "answer": 0, "explain": "v and b sound almost identical in Spanish — a soft ‘b’."}}, {"myth": "Saying ‘mañana’ with a plain n instead of the ñ glide.", "truth": "ñ always adds a ‘y’ glide: ‘ma-NYA-na’.", "check": {"question": "What happens if you drop the tilde and say a plain n in ‘mañana’?", "options": ["you lose the essential ‘y’ glide the ñ adds", "nothing at all changes — n and ñ are pronounced exactly the same way", "the whole word becomes silent", "the stress moves to a different syllable"], "answer": 0, "explain": "ñ is a distinct letter with its own ‘ny’ sound."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 2 — Read-aloud (speaking)", "html": "Scan the text first for tricky-letter traps: ll (y sound), ch, ñ (ny), j (throaty), silent h, single r vs rolled rr, and v/b (soft b). Read steadily — accurate sounds are worth more than speed.", "check": {"question": "What should you do before reading a Paper 2 text aloud?", "options": ["scan it for tricky-letter traps like ll, ñ, j and rr", "read it as fast as possible without stopping to think", "skip over any word you find difficult to say", "translate every single word into English first"], "answer": 0, "explain": "Spotting the traps in advance stops you defaulting to English sounds mid-sentence."}}, {"title": "Paper 1 — Dictation (listening)", "html": "Listen for the minimal pairs: a single tap is r (pero), a strong roll is rr (perro) — this one difference changes the word''s meaning. A ‘y’ sound is almost always ll; a ‘ny’ glide is always ñ.", "check": {"question": "In dictation, a strongly rolled r sound should usually be written as…", "options": ["rr, or r at the very start of a word", "a single r written between two vowels only, never at the start", "ñ, with a tilde added", "silent — don''t write it at all"], "answer": 0, "explain": "A rolled r is written rr (or word-initial r); a single tap is a lone r."}}, {"title": "Paper 4 — Spelling tricky letters accurately", "html": "Confusing ll/y, ñ/n, v/b, or single r/rr in writing changes meaning (pero/perro) or reads as a spelling error. Learn each tricky letter as part of the word''s spelling, not as an afterthought.", "check": {"question": "Why does it matter if you write ‘pero’ instead of ‘perro’ in an exam answer?", "options": ["it is a completely different word with a different meaning", "examiners never distinguish between the two different spellings at all", "it only affects your pronunciation mark, not writing", "both spellings are always accepted as identical"], "answer": 0, "explain": "pero (‘but’) and perro (‘dog’) are different words — the spelling carries meaning."}}]}, "exam": {"enabled": true, "questions": [{"question": "<strong>Read-aloud practice.</strong> Read this text out loud, then tick the sounds you produced correctly.<br><br><em>«Mi amigo Guillermo tiene un perro que se llama Chico. Vivimos en una calle cerca del hospital, y mañana vamos a la playa. Mi hermano prefiere el chocolate, pero yo prefiero la naranja y llevo una camiseta verde.»</em><br><br>Hear a model first: 🔊 <span data-say=\"Mi amigo Guillermo tiene un perro que se llama Chico. Vivimos en una calle cerca del hospital, y mañana vamos a la playa. Mi hermano prefiere el chocolate, pero yo prefiero la naranja y llevo una camiseta verde.\">model</span>", "marks": 7, "hint": "Watch: Guillermo/llama/calle/llevo (ll = y), Chico/chocolate (ch), hospital (silent h), mañana (ñ), naranja (throaty j), perro vs pero (rolled rr vs single tap), verde (soft b, not v).", "markScheme": "<div class=\"marks-section\"><h5>Self-mark — 7 pronunciation points</h5><ul>\n                <li><strong>ll</strong> = ‘y’ sound in Guillermo, llama, calle, llevo.</li>\n                <li><strong>ch</strong> in Chico and chocolate sounds like English ‘ch’.</li>\n                <li>Silent <strong>h</strong> in ‘hospital’.</li>\n                <li><strong>ñ</strong> glide in ‘mañana’.</li>\n                <li>Throaty <strong>j</strong> in ‘naranja’.</li>\n                <li><strong>rr</strong> in ‘perro’ rolled strongly; <strong>r</strong> in ‘pero’ a single tap.</li>\n                <li><strong>v</strong> in ‘verde’ pronounced as a soft ‘b’.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Tick each feature you produced correctly. In the real NEA an examiner rewards clear, comprehensible pronunciation.</li>\n            </ul></div>"}, {"question": "<strong>Dictation.</strong> Listen and write the five words you hear, then check them.<br>🔊 <span data-say=\"llamar\" data-listen>word 1</span> &nbsp; 🔊 <span data-say=\"mañana\" data-listen>word 2</span> &nbsp; 🔊 <span data-say=\"hospital\" data-listen>word 3</span> &nbsp; 🔊 <span data-say=\"perro\" data-listen>word 4</span> &nbsp; 🔊 <span data-say=\"verde\" data-listen>word 5</span>", "marks": 5, "hint": "Think about the sound rules: ll = y, ñ = ny, silent h, rolled rr, v = soft b.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks</h5><ul>\n                <li>1 = <strong>llamar</strong> (ll) · 2 = <strong>mañana</strong> (ñ) · 3 = <strong>hospital</strong> (silent h) · 4 = <strong>perro</strong> (rr) · 5 = <strong>verde</strong> (v).</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>1 mark per correctly-spelt word. Minor accent slips are condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-1-nouns-articles-and-gender', 'G.1 Nouns, Articles and Gender', '{"learn": {"enabled": true, "items": [{"title": "What is grammatical gender?", "html": "<p>Every Spanish noun (naming word) is either <strong>masculine</strong> or <strong>feminine</strong> — this is its <em>gender</em>. Gender decides which word for \"the\" or \"a\" you use in front of it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el chico\">el chico</span></td><td>the boy (masc.)</td><td><span data-say=\"la chica\">la chica</span></td><td>the girl (fem.)</td></tr>\n              <tr><td><span data-say=\"el libro\">el libro</span></td><td>the book (masc.)</td><td><span data-say=\"la mesa\">la mesa</span></td><td>the table (fem.)</td></tr>\n            </table>\n            <p>Gender is not about meaning — <span data-say=\"la mesa\">la mesa</span> (table) is grammatically feminine even though a table has no gender in real life. You simply have to learn <strong>el</strong> or <strong>la</strong> with every new noun as you meet it.</p>", "check": {"question": "What does ''gender'' mean for a Spanish noun?", "options": ["it is masculine or feminine, shown by el or la before it", "it is singular or plural, shown by adding an -s or -es ending", "it is a person, a place or a thing in the sentence", "it carries a written accent on the final vowel"], "answer": 0, "explain": "Gender = masculine or feminine; it decides el/la, un/una and adjective endings, not number or word type."}}, {"title": "How do I know if a noun is masculine or feminine?", "html": "<p>The general rule: nouns ending in <strong>-o</strong> are usually masculine, and nouns ending in <strong>-a</strong> are usually feminine.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el coche\">el coche</span></td><td>the car</td><td><span data-say=\"la casa\">la casa</span></td><td>the house</td></tr>\n              <tr><td><span data-say=\"el gato\">el gato</span></td><td>the cat</td><td><span data-say=\"la ventana\">la ventana</span></td><td>the window</td></tr>\n            </table>\n            <p>But watch these common <strong>exceptions</strong> — words ending in -a that are actually masculine (many come from Greek):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el día\">el día</span></td><td>the day</td><td><span data-say=\"el mapa\">el mapa</span></td><td>the map</td></tr>\n              <tr><td><span data-say=\"el problema\">el problema</span></td><td>the problem</td><td><span data-say=\"el clima\">el clima</span></td><td>the climate</td></tr>\n            </table>\n            <p>And one very common word ending in -o that is feminine instead: <span data-say=\"la mano\">la mano</span> (the hand).</p>\n            <p>Example: <span data-say=\"El problema es que la mano me duele.\">El problema es que la mano me duele.</span> — The problem is that my hand hurts.</p>", "check": {"question": "Which of these words is masculine, even though it ends in -a?", "options": ["el problema", "la habitación", "la ventana", "la mesa"], "answer": 0, "explain": "el problema, el día, el mapa and el clima end in -a but are masculine — common exceptions to learn by heart."}}, {"title": "Nouns ending in -ción, -sión or -dad", "html": "<p>Another reliable rule: nouns ending in <strong>-ción</strong>, <strong>-sión</strong> or <strong>-dad</strong> are always feminine — this rule has no exceptions.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la nación\">la nación</span></td><td>the nation</td><td><span data-say=\"la información\">la información</span></td><td>the information</td></tr>\n              <tr><td><span data-say=\"la televisión\">la televisión</span></td><td>the television</td><td><span data-say=\"la ciudad\">la ciudad</span></td><td>the city</td></tr>\n            </table>\n            <p>This is one of the most useful rules in GCSE Spanish because it always works — memorise it and you can always get the article right for these endings.</p>\n            <p>Example: <span data-say=\"La ciudad tiene mucha información sobre la nación.\">La ciudad tiene mucha información sobre la nación.</span></p>", "check": {"question": "What gender are nouns ending in -ción, -sión or -dad?", "options": ["always feminine, with no exceptions to learn", "always masculine, unless the word is very short", "masculine in the singular but feminine in the plural", "it depends on the very first letter of the word"], "answer": 0, "explain": "-ción/-sión/-dad nouns are always feminine — one of the few gender rules with no exceptions."}}, {"title": "Definite articles: el, la, los, las", "html": "<p>\"The\" changes depending on gender AND number (singular/plural):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>masc. singular</td><td><span data-say=\"el libro\">el libro</span></td><td>masc. plural</td><td><span data-say=\"los libros\">los libros</span></td></tr>\n              <tr><td>fem. singular</td><td><span data-say=\"la mesa\">la mesa</span></td><td>fem. plural</td><td><span data-say=\"las mesas\">las mesas</span></td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> One tricky rule: a feminine singular noun that starts with a stressed <strong>a-</strong> sound takes <strong>el</strong> instead of <strong>la</strong>, just to avoid two a-sounds clashing — but it stays feminine, so the plural is still <strong>las</strong>: <span data-say=\"el agua\">el agua</span> (fem.) → <span data-say=\"las aguas\">las aguas</span>.</p>", "check": {"question": "What is the plural of ''la ciudad''?", "options": ["las ciudades", "los ciudades", "las ciudad", "el ciudades"], "answer": 0, "explain": "la → las for feminine plural, and ciudad adds -es because it ends in a consonant → las ciudades."}}, {"title": "Indefinite articles: un, una, unos, unas", "html": "<p>\"A / an\" is <strong>un</strong> (masc.) or <strong>una</strong> (fem.). The plural forms <strong>unos / unas</strong> mean \"some\":</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"un libro\">un libro</span></td><td>a book</td><td><span data-say=\"unos libros\">unos libros</span></td><td>some books</td></tr>\n              <tr><td><span data-say=\"una mesa\">una mesa</span></td><td>a table</td><td><span data-say=\"unas mesas\">unas mesas</span></td><td>some tables</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Tengo un problema y unas preguntas.\">Tengo un problema y unas preguntas.</span> — I have a problem and some questions.</p>", "check": {"question": "How do you say ''some cities'' in Spanish?", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"], "answer": 0, "explain": "ciudad is feminine → unas; the plural adds -es because it ends in a consonant → unas ciudades."}}, {"title": "Forming plurals + the contractions del and al", "html": "<p>Plural rules for nouns:</p>\n            <ul>\n              <li>ends in a vowel → add <strong>-s</strong>: <span data-say=\"el coche\">el coche</span> → <span data-say=\"los coches\">los coches</span></li>\n              <li>ends in a consonant → add <strong>-es</strong>: <span data-say=\"el profesor\">el profesor</span> → <span data-say=\"los profesores\">los profesores</span></li>\n              <li>ends in <strong>-z</strong> → change to <strong>-c</strong> and add <strong>-es</strong>: <span data-say=\"el lápiz\">el lápiz</span> → <span data-say=\"los lápices\">los lápices</span>; <span data-say=\"la luz\">la luz</span> → <span data-say=\"las luces\">las luces</span></li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> Two contractions are compulsory in Spanish: <strong>de + el = del</strong>, and <strong>a + el = al</strong> (Spanish never writes <em>de el</em> or <em>a el</em>).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"del colegio\">del colegio</span></td><td>of / from the school</td><td><span data-say=\"al gimnasio\">al gimnasio</span></td><td>to the gym</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy al gimnasio después del colegio.\">Voy al gimnasio después del colegio.</span> — I go to the gym after school.</p>", "check": {"question": "Which sentence uses the contractions correctly?", "options": ["Voy al gimnasio después del colegio.", "Voy a el gimnasio después de el colegio.", "Voy al gimnasio después de el colegio.", "Voy a el gimnasio después del colegio."], "answer": 0, "explain": "a+el must always contract to al, and de+el must always contract to del — both together, every time."}}]}, "terms": {"enabled": true, "pairs": [{"term": "el chico / la chica", "definition": "the boy / the girl"}, {"term": "el libro / la mesa", "definition": "the book / the table"}, {"term": "el problema", "definition": "the problem (masc. exception)"}, {"term": "el día", "definition": "the day (masc. exception)"}, {"term": "el mapa", "definition": "the map (masc. exception)"}, {"term": "el clima", "definition": "the climate (masc. exception)"}, {"term": "la mano", "definition": "the hand (fem. exception)"}, {"term": "la nación", "definition": "the nation (-ción = feminine)"}, {"term": "la información", "definition": "the information"}, {"term": "la ciudad", "definition": "the city (-dad = feminine)"}, {"term": "un / una", "definition": "a, an (masc. / fem.)"}, {"term": "unos / unas", "definition": "some (masc. / fem. plural)"}, {"term": "los lápices", "definition": "the pencils (z → c plural)"}, {"term": "las luces", "definition": "the lights (z → c plural)"}, {"term": "los profesores", "definition": "the teachers (consonant + es)"}, {"term": "del (H)", "definition": "de + el = of / from the"}, {"term": "al (H)", "definition": "a + el = to the"}, {"term": "el agua (H)", "definition": "the water (fem. noun, el for the sound)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"la ciudad\" data-listen></span><br>Listen. What is being said?", "options": ["the city", "the nation", "the day", "the problem"], "answer": 0, "explain": "‘la ciudad’ = the city. The traps are all other gender-rule nouns from this topic."}, {"question": "<span data-say=\"el mapa\" data-listen></span><br>Listen. Which word did you hear?", "options": ["el mapa", "la mapa", "el mano", "la mano"], "answer": 0, "explain": "mapa is a masculine exception → el mapa. The traps swap the gender or swap in a different exception word (mano)."}, {"question": "<span data-say=\"el problema\" data-listen></span><br>Listen and choose the correct English meaning.", "options": ["the problem", "the climate", "the day", "the map"], "answer": 0, "explain": "‘el problema’ = the problem. All four options are genuine masculine -a exceptions, so you must listen carefully."}, {"question": "Choose the correct article: ___ problema es difícil.", "options": ["El", "La", "Los", "Las"], "answer": 0, "explain": "problema is a masculine exception ending in -a → El problema. La/Los/Las are all wrong gender or number."}, {"question": "Choose the correct plural of ''el lápiz''.", "options": ["los lápices", "los lápizes", "las lápices", "los lápiz"], "answer": 0, "explain": "z changes to c before -es: el lápiz → los lápices. Trap B keeps the z; C changes the gender; D forgets the plural ending."}, {"question": "How do you say ''a house'' in Spanish?", "options": ["una casa", "un casa", "unos casa", "unas casas"], "answer": 0, "explain": "casa is feminine singular → una casa. B uses the masculine article; C and D wrongly make it plural."}, {"question": "Which is the correct way to say ''to the gym''?", "options": ["al gimnasio", "a el gimnasio", "del gimnasio", "a la gimnasio"], "answer": 0, "explain": "a + el must contract to al. B leaves it uncontracted; C confuses al with del (of/from); D mixes a with the wrong gender article."}, {"question": "Which of these nouns is feminine?", "options": ["la nación", "el día", "el mapa", "el problema"], "answer": 0, "explain": "nación ends in -ción, so it is always feminine. The other three are classic masculine exceptions ending in -a."}, {"question": "Choose the correct plural: ''una ciudad'' → ___", "options": ["unas ciudades", "unos ciudades", "unas ciudad", "un ciudades"], "answer": 0, "explain": "ciudad is feminine → unas; the consonant ending adds -es → unas ciudades."}, {"question": "Which phrase correctly means ''the boy''s book'' (el libro ___ chico)?", "options": ["del", "de el", "de la", "al"], "answer": 0, "explain": "de + el must contract to del. B leaves it uncontracted; C uses the wrong gender; D confuses del with al (to the)."}]}, "fib": {"enabled": true, "questions": [{"text": "[El] problema es muy grande. <span data-say=\"El problema es muy grande.\" data-listen>El problema es muy grande.</span>"}, {"text": "Voy [al] colegio a las ocho. <span data-say=\"Voy al colegio a las ocho.\" data-listen>Voy al colegio a las ocho.</span>"}, {"text": "Tengo [unas] preguntas sobre la tarea. <span data-say=\"Tengo unas preguntas sobre la tarea.\" data-listen>Tengo unas preguntas sobre la tarea.</span>"}, {"text": "Necesito dos [lápices] nuevos para el examen. <span data-say=\"Necesito dos lápices nuevos para el examen.\" data-listen>Necesito dos lápices nuevos para el examen.</span>"}, {"text": "[La] ciudad tiene mucha información. <span data-say=\"La ciudad tiene mucha información.\" data-listen>La ciudad tiene mucha información.</span>"}, {"text": "Salgo [del] gimnasio después de las clases. <span data-say=\"Salgo del gimnasio después de las clases.\" data-listen>Salgo del gimnasio después de las clases.</span>"}, {"text": "Escucha y escribe la palabra que falta: Me duele la [mano]. <span data-say=\"la mano\" data-listen></span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "All nouns ending in -o are masculine, with no exceptions.", "answer": false, "explain": "la mano is a common exception — it ends in -o but is feminine."}, {"statement": "''el problema'' is masculine even though it ends in -a.", "answer": true, "explain": "el problema, el día, el mapa and el clima are exceptions ending in -a."}, {"statement": "Nouns ending in -ción, -sión or -dad are always feminine.", "answer": true, "explain": "This rule has no exceptions — la nación, la televisión, la ciudad."}, {"statement": "The plural of ''el lápiz'' is ''los lápizes''.", "answer": false, "explain": "z changes to c before -es: the correct plural is los lápices."}, {"statement": "''un'' and ''una'' both mean ''the''.", "answer": false, "explain": "un/una mean ''a/an''; el/la mean ''the''."}, {"statement": "''a + el'' must contract to ''al''.", "answer": true, "explain": "Spanish never writes ''a el'' — it always contracts to al."}, {"statement": "''de la casa'' should contract to ''dela casa''.", "answer": false, "explain": "Only de+el (→del) and a+el (→al) contract; de+la never changes."}, {"statement": "''unas ciudades'' means ''some cities''.", "answer": true, "explain": "unas = some (fem. plural); ciudades = cities."}]}, "misc": {"enabled": true, "items": [{"myth": "la problema", "truth": "el problema", "check": {"question": "Why is ''el problema'' correct, not ''la problema''?", "options": ["''problema'' is a masculine exception ending in -a", "''problema'' is only ever used in the plural form", "''la'' is used before every noun that starts with p", "''problema'' takes no article at all in Spanish"], "answer": 0, "explain": "problema, día, mapa and clima are masculine despite ending in -a."}}, {"myth": "el mano", "truth": "la mano", "check": {"question": "Why is ''la mano'' correct, not ''el mano''?", "options": ["''mano'' is a feminine exception ending in -o", "''mano'' is a masculine noun in every context", "''mano'' takes no article at all in Spanish", "''la'' is used only with plural nouns like manos"], "answer": 0, "explain": "la mano is one of the few -o nouns that is actually feminine."}}, {"myth": "de el chico", "truth": "del chico", "check": {"question": "Why must you write ''del chico'', not ''de el chico''?", "options": ["de + el always contracts to del", "de and el can never appear in the same sentence", "''del'' is only ever used with feminine nouns", "''chico'' automatically changes de into del"], "answer": 0, "explain": "de+el must contract to del — Spanish never writes de el."}}, {"myth": "lápizes", "truth": "lápices", "check": {"question": "Why is the plural ''lápices'', not ''lápizes''?", "options": ["z changes to c before adding the plural ending -es", "lápiz never has a plural form in Spanish at all", "you simply add -s after any consonant ending", "the written accent always moves onto the final syllable"], "answer": 0, "explain": "Nouns ending in -z change z→c before -es: lápiz→lápices, luz→luces."}}, {"myth": "el ciudad", "truth": "la ciudad", "check": {"question": "Why is ''la ciudad'' correct, not ''el ciudad''?", "options": ["nouns ending in -dad are always feminine", "''ciudad'' is a masculine exception like día or mapa", "''el'' is used before any word with more than two syllables", "ciudad has no fixed gender and either article works"], "answer": 0, "explain": "-dad nouns are always feminine — la ciudad, la verdad, la libertad."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening: gender clues", "html": "Even when you don''t catch every word, el/la/un/una/los/las tell you the gender and number before the noun arrives. Listen for ''del'' and ''al'' too — they signal ''from/of the'' and ''to the'', and both only ever attach to a masculine noun.", "check": {"question": "You hear ''del colegio''. What must the noun ''colegio'' be?", "options": ["masculine, because del can only exist as de + el", "feminine, because del always marks a feminine noun", "plural, because del is a special plural marker", "in the future tense, because del signals ''will''"], "answer": 0, "explain": "del only exists because de+el contract — colegio must be masculine."}}, {"title": "Paper 3 — Reading: spotting exceptions", "html": "Examiners love testing el día, el mapa, el problema, el clima and la mano because they break the -o/-a rule. If a text uses ''el'' before what looks like a feminine-shaped noun, check it isn''t one of these classic exceptions before you answer.", "check": {"question": "In a reading text you see ''el mapa''. What should you remember?", "options": ["mapa is a genuine masculine exception, not an error", "this must be a printing mistake somewhere in the exam paper", "mapa is always used in the plural in Spanish", "el is being used here instead of los by mistake"], "answer": 0, "explain": "el mapa is a genuine masculine exception, not an error."}}, {"title": "Paper 4 — Writing: agreement checks", "html": "Before you submit written work, re-read every noun phrase and check three things: the article''s gender matches the noun, the article''s number matches the noun, and de+el / a+el have been contracted to del/al. These small slips cost easy marks.", "check": {"question": "Which phrase is fully correct?", "options": ["Voy al gimnasio después del colegio", "Voy a el gimnasio después de el colegio", "Voy al gimnasio después de el colegio", "Voy a el gimnasio después del colegio"], "answer": 0, "explain": "Both contractions must be applied together: al and del."}}]}, "exam": {"enabled": true, "questions": [{"question": "For each noun, write the correct definite article (<strong>el</strong> or <strong>la</strong>) and its plural form. (5 marks — one mark per noun)<br>(1) problema &nbsp; (2) ciudad &nbsp; (3) mano &nbsp; (4) lápiz &nbsp; (5) mapa", "marks": 5, "hint": "Remember: -ma words are masculine exceptions; -dad words are feminine; mano is a feminine exception ending in -o; -z becomes -ces in the plural.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks</h5><ul>\n                <li><strong>(1)</strong> el problema → los problemas <em>(1)</em></li>\n                <li><strong>(2)</strong> la ciudad → las ciudades <em>(1)</em></li>\n                <li><strong>(3)</strong> la mano → las manos <em>(1)</em></li>\n                <li><strong>(4)</strong> el lápiz → los lápices <em>(1)</em></li>\n                <li><strong>(5)</strong> el mapa → los mapas <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Award the mark only if BOTH the article and the plural form are correct.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) The problem is big. <br>(b) I go to the gym after school. <br>(c) I have some questions.", "marks": 4, "hint": "''problem'' is a masculine exception; ''to the gym'' = al gimnasio; ''after school'' = después del colegio; ''some'' before a feminine plural = unas.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> El problema es grande. <em>(1)</em></li>\n                <li><strong>(b)</strong> Voy al gimnasio <em>(1)</em> después del colegio <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Tengo unas preguntas. <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. Both ''al'' and ''del'' must be contracted, not written as ''a el'' / ''de el''.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-2-adjectives-and-agreement', 'G.2 Adjectives and Agreement', '{"learn": {"enabled": true, "items": [{"title": "How do adjectives agree with the noun?", "html": "<p>In Spanish, adjectives must <strong>agree</strong> with the noun they describe — in both <strong>gender</strong> (masculine/feminine) and <strong>number</strong> (singular/plural). Most adjectives end in <strong>-o</strong> for masculine and change to <strong>-a</strong> for feminine; add <strong>-s</strong> for the plural.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"alto\">alto</span></td><td>tall (m. sing.)</td><td><span data-say=\"alta\">alta</span></td><td>tall (f. sing.)</td></tr>\n              <tr><td><span data-say=\"altos\">altos</span></td><td>tall (m. pl.)</td><td><span data-say=\"altas\">altas</span></td><td>tall (f. pl.)</td></tr>\n              <tr><td><span data-say=\"pequeño\">pequeño</span></td><td>small (m.)</td><td><span data-say=\"pequeña\">pequeña</span></td><td>small (f.)</td></tr>\n            </table>\n            <p>Model sentences: <span data-say=\"Mi hermano es alto.\">Mi hermano es alto.</span> (My brother is tall.) — <span data-say=\"Mi hermana es alta.\">Mi hermana es alta.</span> (My sister is tall.) — <span data-say=\"Mis hermanos son altos.\">Mis hermanos son altos.</span> (My brothers are tall.)</p>", "check": {"question": "Why does ‘alto’ change to ‘alta’ in ‘Mi hermana es alta’?", "options": ["it must agree with the feminine noun ‘hermana’", "all adjectives ending in -o are irregular", "‘hermana’ is a plural noun, not singular", "the verb ‘ser’ forces every adjective to end in -a"], "answer": 0, "explain": "Adjectives agree with the gender of the noun they describe — hermana is feminine, so alto → alta."}}, {"title": "Adjectives ending in -e or a consonant", "html": "<p>Some adjectives do <strong>not</strong> change for gender — only for number. This includes adjectives ending in <strong>-e</strong> (add -s for the plural) and most ending in a <strong>consonant</strong> (add -es for the plural).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"grande\">grande</span></td><td>big (m./f.)</td><td><span data-say=\"grandes\">grandes</span></td><td>big (pl.)</td></tr>\n              <tr><td><span data-say=\"inteligente\">inteligente</span></td><td>intelligent (m./f.)</td><td><span data-say=\"inteligentes\">inteligentes</span></td><td>intelligent (pl.)</td></tr>\n              <tr><td><span data-say=\"fácil\">fácil</span></td><td>easy (m./f.)</td><td><span data-say=\"fáciles\">fáciles</span></td><td>easy (pl., accent drops)</td></tr>\n              <tr><td><span data-say=\"azul\">azul</span></td><td>blue (m./f.)</td><td><span data-say=\"azules\">azules</span></td><td>blue (pl.)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Es una casa grande.\">Es una casa grande.</span> (It is a big house.) — <span data-say=\"Son unos libros fáciles.\">Son unos libros fáciles.</span> (They are some easy books.)</p>", "check": {"question": "Why does ‘grande’ stay the same in both ‘un chico grande’ AND ‘una chica grande’?", "options": ["adjectives ending in -e do not change for gender", "grande must always be placed directly before the noun", "grande only describes masculine nouns", "grande behaves like a verb, not an adjective"], "answer": 0, "explain": "Adjectives ending in -e (grande, inteligente) have one form for masculine and feminine — only the plural changes."}}, {"title": "Adjectives of nationality", "html": "<p>Nationality adjectives ending in a <strong>consonant</strong> add <strong>-a</strong> for the feminine (unlike other consonant adjectives). Nationality adjectives already ending in <strong>-o</strong> or <strong>-e</strong> just follow the normal rules.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"español\">español</span></td><td>Spanish (m.)</td><td><span data-say=\"española\">española</span></td><td>Spanish (f.)</td></tr>\n              <tr><td><span data-say=\"francés\">francés</span></td><td>French (m.)</td><td><span data-say=\"francesa\">francesa</span></td><td>French (f., accent drops)</td></tr>\n              <tr><td><span data-say=\"inglés\">inglés</span></td><td>English (m.)</td><td><span data-say=\"inglesa\">inglesa</span></td><td>English (f.)</td></tr>\n              <tr><td><span data-say=\"canadiense\">canadiense</span></td><td>Canadian (-e, invariable)</td><td><span data-say=\"belga\">belga</span></td><td>Belgian (invariable)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Tengo una amiga española.\">Tengo una amiga española.</span> (I have a Spanish friend.) Plural: <span data-say=\"franceses\">franceses</span> / <span data-say=\"francesas\">francesas</span>.</p>", "check": {"question": "How do you say ‘a French friend’ (female)?", "options": ["una amiga francesa", "un amigo francés", "una amiga francés", "unas amigas francesas"], "answer": 0, "explain": "francés adds -a for the feminine: francesa. ‘amiga’ is feminine so the adjective must agree — francés with no -a is left masculine."}}, {"title": "Where does the adjective go?", "html": "<p>Unlike English, most Spanish adjectives go <strong>AFTER</strong> the noun: <span data-say=\"una casa grande\">una casa grande</span> (a big house) — NOT “una grande casa”. <span data-say=\"un coche rojo\">un coche rojo</span> (a red car). <span data-say=\"unos libros interesantes\">unos libros interesantes</span> (some interesting books).</p>\n            <p>A few common adjectives can go <strong>before</strong> the noun and sometimes shorten: <span data-say=\"bueno\">bueno</span> → <span data-say=\"buen\">buen</span> (before a masculine singular noun): <span data-say=\"un buen amigo\">un buen amigo</span>. Likewise <span data-say=\"malo\">malo</span> → <span data-say=\"mal\">mal</span>: <span data-say=\"un mal día\">un mal día</span>. <span class=\"tier-h\">H</span> <span data-say=\"grande\">grande</span> shortens to <span data-say=\"gran\">gran</span> before either gender and changes meaning: <span data-say=\"un gran hombre\">un gran hombre</span> (a great man) vs <span data-say=\"un hombre grande\">un hombre grande</span> (a big man).</p>", "check": {"question": "Where does a normal Spanish adjective usually go?", "options": ["after the noun it describes", "before the noun, like in English", "at the very end of the sentence", "immediately after the verb ‘ser’"], "answer": 0, "explain": "Most Spanish adjectives follow the noun: una casa grande, not una grande casa."}}, {"title": "Comparatives and superlatives", "html": "<p>Comparatives: <span data-say=\"más que\">más + adjective + que</span> (more … than), <span data-say=\"menos que\">menos + adjective + que</span> (less … than), <span data-say=\"tan como\">tan + adjective + como</span> (as … as).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"Soy más alto que mi hermano.\">Soy más alto que mi hermano.</span></td><td>I am taller than my brother.</td></tr>\n              <tr><td><span data-say=\"Es menos interesante que la otra película.\">Es menos interesante que la otra película.</span></td><td>It is less interesting than the other film.</td></tr>\n              <tr><td><span data-say=\"Ella es tan inteligente como su hermana.\">Ella es tan inteligente como su hermana.</span></td><td>She is as intelligent as her sister.</td></tr>\n            </table>\n            <p>Superlative: el/la (los/las) + más + adjective — <span data-say=\"Es el chico más alto de la clase.\">Es el chico más alto de la clase.</span> (He is the tallest boy in the class.)</p>", "check": {"question": "How do you say ‘as easy as’ in Spanish?", "options": ["tan fácil como", "más fácil que", "menos fácil que", "el más fácil de"], "answer": 0, "explain": "tan + adjective + como = as … as. más…que = more…than; menos…que = less…than."}}, {"title": "Higher: irregular comparatives, possessives, demonstratives", "html": "<p><span class=\"tier-h\">H</span> Four common adjectives have an <strong>irregular comparative</strong> — never say “más bueno” or “más malo”:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"bueno, mejor\">bueno → mejor</span></td><td>good → better</td></tr>\n              <tr><td><span data-say=\"malo, peor\">malo → peor</span></td><td>bad → worse</td></tr>\n              <tr><td><span data-say=\"viejo, mayor\">viejo → mayor</span></td><td>old → older</td></tr>\n              <tr><td><span data-say=\"joven, menor\">joven → menor</span></td><td>young → younger</td></tr>\n            </table>\n            <p><strong>Possessive adjectives</strong> agree in number (nuestro/-a agrees in gender too): <span data-say=\"mi casa\">mi casa</span> / <span data-say=\"mis casas\">mis casas</span> (my), <span data-say=\"tu libro\">tu libro</span> / <span data-say=\"tus libros\">tus libros</span> (your), <span data-say=\"su coche\">su coche</span> / <span data-say=\"sus coches\">sus coches</span> (his/her/their), <span data-say=\"nuestra familia\">nuestra familia</span> / <span data-say=\"nuestro perro\">nuestro perro</span> (our).</p>\n            <p><strong>Demonstratives</strong>: <span data-say=\"este libro\">este libro</span> / <span data-say=\"esta casa\">esta casa</span> / <span data-say=\"estos zapatos\">estos zapatos</span> / <span data-say=\"estas chicas\">estas chicas</span> (this/these, close by); <span data-say=\"ese chico\">ese chico</span> / <span data-say=\"esa chica\">esa chica</span> (that, further away).</p>", "check": {"question": "Why is ‘más mejor’ always wrong?", "options": ["mejor is already a comparative — you never add más in front", "mejor must always be placed immediately before the noun it describes", "mejor only exists in the plural form", "más can only combine with -e ending adjectives"], "answer": 0, "explain": "mejor, peor, mayor and menor are already comparative forms — combining them with más creates a double comparative, which is wrong."}}]}, "terms": {"enabled": true, "pairs": [{"term": "alto / alta / altos / altas", "definition": "tall (agrees in gender + number)"}, {"term": "grande", "definition": "big (-e ending, no gender change)"}, {"term": "inteligente", "definition": "intelligent (no gender change)"}, {"term": "fácil / fáciles", "definition": "easy (sing. / pl.)"}, {"term": "azul / azules", "definition": "blue (sing. / pl.)"}, {"term": "español / española", "definition": "Spanish (m. / f.)"}, {"term": "francés / francesa", "definition": "French (m. / f.)"}, {"term": "una casa grande", "definition": "a big house (adjective after noun)"}, {"term": "un gran hombre (H)", "definition": "a great man (gran before noun)"}, {"term": "más … que", "definition": "more … than"}, {"term": "menos … que", "definition": "less … than"}, {"term": "tan … como", "definition": "as … as"}, {"term": "el/la más …", "definition": "the most … (superlative)"}, {"term": "mejor / peor (H)", "definition": "better / worse"}, {"term": "mayor / menor (H)", "definition": "older / younger"}, {"term": "mi / tu / su", "definition": "my / your / his-her (agree in number)"}, {"term": "nuestro / nuestra", "definition": "our (agrees in gender + number)"}, {"term": "este/esta/estos/estas · ese/esa (H)", "definition": "this/these (near) · that (further)"}]}, "mcq": {"enabled": true, "questions": [{"question": "Which sentence correctly describes ‘the tall girls’?", "options": ["las chicas altas", "los chicas altas", "las chicas alta", "la chica alta"], "answer": 0, "explain": "las chicas altas — article, noun and adjective all agree feminine plural. B mismatches the article; C drops the plural -s; D is singular."}, {"question": "<span data-say=\"una camisa azul\" data-listen></span><br>Listen. What do you hear?", "options": ["a blue shirt", "some blue shirts", "a blue dress", "the blue shirts"], "answer": 0, "explain": "‘una camisa azul’ = a blue shirt (singular). B and D wrongly make it plural; C swaps the noun for ‘dress’."}, {"question": "Choose the correctly agreeing phrase: ‘unos coches ___’ (red)", "options": ["rojos", "rojo", "roja", "rojas"], "answer": 0, "explain": "‘unos coches’ is masculine plural, so the adjective must be rojos. rojo is singular, roja/rojas are feminine."}, {"question": "How do you say ‘a Spanish friend’ (female)?", "options": ["una amiga española", "un amigo español", "una amiga español", "unas amigas españolas"], "answer": 0, "explain": "amiga is feminine singular → española. B changes the noun to masculine; C fails to agree; D wrongly makes it plural."}, {"question": "Which sentence has the adjective in the correct position?", "options": ["una casa grande", "una grande casa", "grande una casa", "casa una grande"], "answer": 0, "explain": "Spanish adjectives normally follow the noun: una casa grande. The other options put grande before the noun or scramble the word order."}, {"question": "How do you say ‘taller than’?", "options": ["más alto que", "más alto de", "tan alto como", "menos alto que"], "answer": 0, "explain": "más…que = more…than (taller than). ‘de’ is wrong after más in a comparison; tan…como = as…as; menos…que = less…than."}, {"question": "How do you say ‘the most interesting book’?", "options": ["el libro más interesante", "el más interesante libro", "el libro interesante más", "un libro más interesante"], "answer": 0, "explain": "The superlative keeps the adjective after the noun: el libro más interesante. D uses ‘un’, not the definite article needed for a superlative."}, {"question": "How do you say ‘my older brother’?", "options": ["mi hermano mayor", "mi hermano más viejo", "mi hermano más grande", "mi más mayor hermano"], "answer": 0, "explain": "mayor is the irregular comparative of viejo. B avoids the irregular form; C confuses ‘big’ with ‘old’; D wrongly doubles the comparative."}, {"question": "How do you say ‘our house’ (la casa is feminine)?", "options": ["nuestra casa", "nuestro casa", "nuestras casa", "nuestros casa"], "answer": 0, "explain": "nuestro/-a agrees in gender AND number: casa is feminine singular → nuestra casa. The others fail to agree."}, {"question": "<span data-say=\"Quiero estos zapatos.\" data-listen></span><br>Listen. What does he want?", "options": ["these shoes", "that shoe", "those shoes over there", "this shoe"], "answer": 0, "explain": "‘estos zapatos’ = these shoes (close by, plural). B and D wrongly make it singular; C confuses ‘estos’ (this/these) with ‘aquellos’ (those over there)."}]}, "fib": {"enabled": true, "questions": [{"text": "Mi hermana es muy [alta]. (tall, feminine)"}, {"text": "Los libros son muy [interesantes]. (interesting, plural)"}, {"text": "Tengo un perro [negro]. (black, masculine)"}, {"text": "Es una camisa [azul]. <span data-say=\"Es una camisa azul.\" data-listen>Es una camisa azul.</span>"}, {"text": "Mi hermano [mayor] es más alto que yo. (older)"}, {"text": "Quiero comprar [estos] zapatos negros. (these, masculine plural)"}, {"text": "En [nuestra] casa vivimos con mis abuelos. (our, feminine singular)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Adjectives change their ending depending on the gender and number of the noun they describe.", "answer": true, "explain": "alto/alta/altos/altas — Spanish adjectives agree with the noun."}, {"statement": "‘grande’ changes to ‘granda’ for a feminine noun.", "answer": false, "explain": "grande does not change for gender at all — una casa grande, un chico grande."}, {"statement": "Adjectives of nationality ending in a consonant, like ‘español’, add -a for the feminine.", "answer": true, "explain": "español → española, francés → francesa."}, {"statement": "In Spanish, adjectives are almost always placed BEFORE the noun.", "answer": false, "explain": "Most Spanish adjectives go AFTER the noun: una casa grande, not una grande casa."}, {"statement": "‘más alto que’ means ‘taller than’.", "answer": true, "explain": "más + adjective + que = more…than / -er than."}, {"statement": "The comparative of ‘bueno’ (good) is ‘más bueno’.", "answer": false, "explain": "bueno has an irregular comparative: mejor, not más bueno."}, {"statement": "‘mi’, ‘tu’ and ‘su’ have the same form for masculine and feminine singular nouns.", "answer": true, "explain": "mi casa / mi libro — mi, tu and su only change for number (mis, tus, sus), not gender."}, {"statement": "‘este’ is used for something close to the speaker, ‘ese’ for something further away.", "answer": true, "explain": "este/esta = this (near me); ese/esa = that (near you / a bit further away)."}]}, "misc": {"enabled": true, "items": [{"myth": "una casa alto", "truth": "una casa alta", "check": {"question": "Why is ‘una casa alto’ wrong?", "options": ["‘casa’ is feminine, so the adjective must be ‘alta’", "adjectives never change to agree with nouns", "‘alto’ must always be placed immediately before the noun ‘casa’", "‘casa’ is a masculine noun in Spanish"], "answer": 0, "explain": "casa is feminine, so alto must become alta to agree."}}, {"myth": "los chicas altos", "truth": "las chicas altas", "check": {"question": "What is wrong with ‘los chicas altos’?", "options": ["the article AND the adjective must both be feminine plural", "‘chicas’ should be spelt ‘chicos’ instead", "‘altos’ needs a written accent on its final letter to agree", "nothing — this sentence is already correct"], "answer": 0, "explain": "chicas is feminine plural, so both the article (las) and the adjective (altas) must agree with it."}}, {"myth": "más mejor", "truth": "mejor", "check": {"question": "Why can’t you say ‘más mejor’ for ‘better’?", "options": ["mejor is already the comparative — adding más creates a double comparative", "mejor is actually classified as an adverb, not an adjective, so más cannot apply to it", "más can only be used with colours", "mejor must always follow the noun it describes"], "answer": 0, "explain": "mejor already means ‘better’; putting más in front (‘more better’) is a double comparative and is always wrong."}}, {"myth": "una grande casa", "truth": "una casa grande", "check": {"question": "Why is ‘una grande casa’ wrong for ‘a big house’?", "options": ["most descriptive adjectives go AFTER the noun in Spanish", "grande must always be shortened to gran", "‘casa’ always needs to be placed at the very start of the sentence", "grande should change to grandes here"], "answer": 0, "explain": "In this everyday sense (size), grande follows the noun: una casa grande. Gran before the noun changes the meaning to ‘great’."}}, {"myth": "mi amigas", "truth": "mis amigas", "check": {"question": "What is missing from ‘mi amigas’?", "options": ["the plural -s on the possessive: ‘mis’", "an accent on the final letter of ‘amigas’", "the article ‘las’ before ‘amigas’", "a comma after ‘mi’"], "answer": 0, "explain": "Possessive adjectives agree in number with the noun — ‘amigas’ is plural, so it must be mis amigas."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for agreement", "html": "Listen closely to adjective endings: -o/-a tells you the gender of what is being described, -s/-es tells you if it is plural. ‘Tengo dos hermanas altas’ tells you there is more than one sister before you even hear ‘dos’.", "check": {"question": "You hear ‘…mis primas simpáticas…’. What does the -as ending on ‘simpáticas’ tell you?", "options": ["more than one female cousin is being described", "only one male cousin is being described", "the sentence is set in the past", "nothing — adjective endings carry no information"], "answer": 0, "explain": "The -as ending agrees with feminine plural ‘primas’ — more than one female cousin."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Nationality adjectives are a common trap: ‘francés’ changes to ‘francesa’ for a woman and drops its accent. Also watch adjective position — ‘un gran hombre’ (a great man) is not the same as ‘un hombre grande’ (a big man).", "check": {"question": "‘Mi profesora es una gran mujer’ means…", "options": ["My teacher is a great woman", "My teacher is a very tall woman", "My teacher is an old woman", "My teacher is a large woman"], "answer": 0, "explain": "gran before the noun means ‘great’ (character), not physical size — that would be grande after the noun."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "For the top band, combine a comparative or superlative with a possessive and a demonstrative: ‘Este es mi mejor amigo; es más simpático que los otros.’ Higher students should also try mayor/menor and gran for range.", "check": {"question": "Which answer shows the widest range of grammar for top marks?", "options": ["Este es mi mejor amigo; es más simpático que los otros", "Tengo un amigo muy simpático. Es alto y también es inteligente", "Mi amigo es bueno", "Tengo amigos simpáticos"], "answer": 0, "explain": "It links a demonstrative, a possessive, an irregular comparative (mejor) and a full comparative structure — range plus accuracy, not just extra short sentences."}}]}, "exam": {"enabled": true, "questions": [{"question": "Make each adjective agree with the noun and write out the full phrase.<br>(a) unas casas (grande)<br>(b) el chico (español)<br>(c) la profesora (español)<br>(d) los libros (fácil)<br>(e) mis hermanos (mayor)", "marks": 5, "hint": "Check whether the noun is masculine/feminine and singular/plural, then check whether the adjective is an -o/-a type, an -e type, a nationality, or an irregular comparative.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: grammar)</h5><ul>\n                <li><strong>(a)</strong> unas casas grandes <em>(1)</em> — -e ending, plural +s only.</li>\n                <li><strong>(b)</strong> el chico español <em>(1)</em> — masculine singular, no change.</li>\n                <li><strong>(c)</strong> la profesora española <em>(1)</em> — nationality consonant ending +a for feminine.</li>\n                <li><strong>(d)</strong> los libros fáciles <em>(1)</em> — consonant ending, plural +es, accent drops.</li>\n                <li><strong>(e)</strong> mis hermanos mayores <em>(1)</em> — irregular comparative, plural +es, possessive agrees in number.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per fully correct phrase; accept minor accent slips if the agreement itself is correct.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My sister is taller than me.<br>(b) This is the best book.<br>(c) Our house is very big.", "marks": 4, "hint": "‘taller than’ = más alto/alta que. ‘the best’ = el/la mejor (irregular, no más). ‘our’ must agree with ‘casa’ (feminine).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi hermana es más alta que yo. <em>(1)</em></li>\n                <li><strong>(b)</strong> Este es el mejor libro. <em>(2)</em> — 1 for este/es, 1 for el mejor libro (no ‘más bueno’).</li>\n                <li><strong>(c)</strong> Nuestra casa es muy grande. <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘más alta’ must agree with the feminine subject (hermana).</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-3-present-tense-and-key-irregulars', 'G.3 Present Tense and Key Irregulars', '{"learn": {"enabled": true, "items": [{"title": "How do regular -ar, -er, -ir verbs work?", "html": "<p>The present tense describes what happens now or generally. Remove the -ar/-er/-ir ending and add the pattern endings. Model verb <span data-say=\"hablar\">hablar</span> (to speak):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablo\">hablo</span></td><td>I speak</td><td><span data-say=\"hablamos\">hablamos</span></td><td>we speak</td></tr>\n              <tr><td><span data-say=\"hablas\">hablas</span></td><td>you speak</td><td><span data-say=\"habláis\">habláis</span></td><td>you all speak</td></tr>\n              <tr><td><span data-say=\"habla\">habla</span></td><td>he/she speaks</td><td><span data-say=\"hablan\">hablan</span></td><td>they speak</td></tr>\n            </table>\n            <p>-er verbs like <span data-say=\"comer\">comer</span> (to eat): <span data-say=\"como, comes, come, comemos, coméis, comen\">como, comes, come, comemos, coméis, comen</span>. -ir verbs like <span data-say=\"vivir\">vivir</span> (to live): <span data-say=\"vivo, vives, vive, vivimos, vivís, viven\">vivo, vives, vive, vivimos, vivís, viven</span>.</p>\n            <p>Model sentence: <span data-say=\"Vivo en Madrid y hablo dos idiomas.\">Vivo en Madrid y hablo dos idiomas.</span> — <em>I live in Madrid and I speak two languages.</em></p>", "check": {"question": "What is the ‘yo’ (I) ending for a regular -ir verb like ‘vivir’?", "options": ["-o (vivo)", "-as (vivas)", "-amos (vivamos)", "-en (viven)"], "answer": 0, "explain": "Regular -ar, -er and -ir verbs all take -o for ‘yo’: vivo, como, hablo."}}, {"title": "ser vs estar — two verbs for ‘to be’", "html": "<p>Spanish has two verbs for ‘to be’ and examiners test the difference constantly.</p>\n            <p><strong>ser</strong> — permanent/identity: <span data-say=\"soy, eres, es, somos, sois, son\">soy, eres, es, somos, sois, son</span>. Use for personality, nationality, jobs, time: <span data-say=\"Soy alta y soy española.\">Soy alta y soy española.</span> (I am tall and I am Spanish.)</p>\n            <p><strong>estar</strong> — temporary state/location: <span data-say=\"estoy, estás, está, estamos, estáis, están\">estoy, estás, está, estamos, estáis, están</span>. Use for feelings, mood, position: <span data-say=\"Estoy cansado porque estoy en el gimnasio.\">Estoy cansado porque estoy en el gimnasio.</span> (I am tired because I am at the gym.)</p>\n            <p>Compare: <span data-say=\"Es aburrido.\">Es aburrido.</span> (He is a boring person) vs <span data-say=\"Está aburrido.\">Está aburrido.</span> (He is bored right now).</p>", "check": {"question": "Which verb do you use to say WHERE something is located?", "options": ["estar (está en Madrid)", "ser (es en Madrid)", "tener (tiene en Madrid)", "hacer (hace en Madrid)"], "answer": 0, "explain": "Location always uses estar: está en Madrid. ‘ser en’ is a very common wrong-verb error."}}, {"title": "tener, ir, hacer — three essential irregulars", "html": "<p>These three verbs appear in almost every exam answer.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tener\">tener</span></td><td>to have</td><td><span data-say=\"tengo, tienes, tiene, tenemos, tenéis, tienen\">tengo, tienes, tiene…</span></td></tr>\n              <tr><td><span data-say=\"ir\">ir</span></td><td>to go</td><td><span data-say=\"voy, vas, va, vamos, vais, van\">voy, vas, va…</span></td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td>to do/make</td><td><span data-say=\"hago, haces, hace, hacemos, hacéis, hacen\">hago, haces, hace…</span></td></tr>\n            </table>\n            <p>Remember <span data-say=\"tener que + infinitivo\">tener que + infinitive</span> (to have to) and <span data-say=\"ir a + infinitivo\">ir a + infinitive</span> (going to, near future): <span data-say=\"Tengo quince años y voy a hacer mis deberes.\">Tengo quince años y voy a hacer mis deberes.</span> — <em>I am fifteen and I am going to do my homework.</em></p>\n            <p>Other everyday verbs share this irregular ‘-go’ yo-form too: <span data-say=\"traer\">traer</span> (to bring) → <span data-say=\"traigo\">traigo</span>. Example: <span data-say=\"Traigo mi cuaderno a clase todos los días.\">Traigo mi cuaderno a clase todos los días.</span> — <em>I bring my notebook to class every day.</em></p>", "check": {"question": "How do you say ‘I have to study’?", "options": ["Tengo que estudiar", "Tengo estudiar", "Voy que estudiar", "Tengo que estudiando"], "answer": 0, "explain": "tener que + infinitive = to have to study. B is missing ‘que’; C uses the wrong verb; D wrongly uses the gerund instead of the infinitive."}}, {"title": "Radical-changing (stem-changing) verbs", "html": "<p>Some verbs change their stem vowel in ALL forms EXCEPT <strong>nosotros</strong> and <strong>vosotros</strong>. The endings stay regular.</p>\n            <ul>\n              <li><strong>e → ie</strong>: <span data-say=\"querer\">querer</span> (to want) → <span data-say=\"quiero, quieres, quiere, queremos, queréis, quieren\">quiero, quieres, quiere…</span>; <span data-say=\"preferir\">preferir</span> → <span data-say=\"prefiero\">prefiero</span></li>\n              <li><strong>o → ue</strong>: <span data-say=\"poder\">poder</span> (to be able to) → <span data-say=\"puedo, puedes, puede, podemos, podéis, pueden\">puedo, puedes, puede…</span>; <span data-say=\"dormir\">dormir</span> → <span data-say=\"duermo\">duermo</span></li>\n              <li><strong>e → i</strong>: <span data-say=\"pedir\">pedir</span> (to ask for) → <span data-say=\"pido, pides, pide, pedimos, pedís, piden\">pido, pides, pide…</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Example: <span data-say=\"No puedo salir porque quiero dormir.\">No puedo salir porque quiero dormir.</span> — <em>I can’t go out because I want to sleep.</em></p>", "check": {"question": "Why is ‘puedo’ correct and ‘podo’ wrong for ‘I can’?", "options": ["poder is a stem-changer: o → ue in ‘yo’", "podo is simply an alternative spelling of puedo", "podo is used only in the plural form", "puedo is only used with ‘nosotros’"], "answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}}, {"title": "Reflexive verbs in the present", "html": "<p>Reflexive verbs describe an action you do to yourself and need a pronoun (<strong>me, te, se, nos, os, se</strong>) before the verb.</p>\n            <p><span data-say=\"levantarse\">levantarse</span> (to get up): <span data-say=\"me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan\">me levanto, te levantas, se levanta, nos levantamos, os levantáis, se levantan</span>.</p>\n            <p>Other common ones: <span data-say=\"ducharse\">ducharse</span> (to shower), <span data-say=\"vestirse\">vestirse</span> (to get dressed) <span class=\"tier-h\">H</span>, <span data-say=\"acostarse\">acostarse</span> (to go to bed).</p>\n            <p>Example: <span data-say=\"Me levanto a las siete y me ducho enseguida.\">Me levanto a las siete y me ducho enseguida.</span> — <em>I get up at seven and I shower straight away.</em></p>", "check": {"question": "What is missing from ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "the accent on the final letter of the verb", "the linking word ‘que’ placed before the verb", "the article ‘el’"], "answer": 0, "explain": "levantarse is reflexive: you must include me/te/se — ‘me levanto’."}}, {"title": "gustar-type verbs", "html": "<p><span class=\"tier-h\">H</span> Verbs like <strong>gustar</strong> (to like) work backwards — the thing liked is the subject, so the verb agrees with IT, not with the person.</p>\n            <ul>\n              <li>ONE thing liked → <span data-say=\"me gusta\">me gusta</span>: <span data-say=\"Me gusta el fútbol.\">Me gusta el fútbol.</span> (I like football.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me gustan\">me gustan</span>: <span data-say=\"Me gustan los deportes.\">Me gustan los deportes.</span> (I like sports.)</li>\n            </ul>\n            <p>Other verbs behaving the same way: <span data-say=\"interesar\">interesar</span> (to interest), <span data-say=\"encantar\">encantar</span> (to love — Me encanta…), <span data-say=\"doler\">doler</span> (to hurt) <span class=\"tier-h\">H</span>.</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"bastar\">bastar</span> works the same way: <span data-say=\"Basta con estudiar un poco cada día.\">Basta con estudiar un poco cada día.</span> — <em>It’s enough to study a little each day.</em> On its own, <span data-say=\"¡Basta!\">¡Basta!</span> means <em>Enough!/That’s enough!</em></p>", "check": {"question": "Why is it ‘Me gustan las matemáticas’ and not ‘Me gusta las matemáticas’?", "options": ["‘las matemáticas’ is plural, so the verb is plural", "gustar is always plural in Spanish regardless of the subject", "‘matemáticas’ is a masculine noun", "it describes a future plan"], "answer": 0, "explain": "gustar agrees with the thing liked; ‘las matemáticas’ is plural → gustan (gustar is not always plural)."}}, {"title": "Telling someone what to do: commands with key irregulars", "html": "<p><span class=\"tier-h\">H</span> Two irregular command patterns build on verbs you already know. <strong>Informal (tú) commands</strong> tell a friend what to do, and several are irregular: <span data-say=\"haz\">haz</span> (do/make! — hacer), <span data-say=\"pon\">pon</span> (put! — poner), <span data-say=\"ven\">ven</span> (come! — venir).</p>\n            <p>Example: <span data-say=\"¡Haz tus deberes y ven aquí!\">¡Haz tus deberes y ven aquí!</span> — <em>Do your homework and come here!</em></p>\n            <p><strong>Formal commands and wishes</strong> use the present subjunctive, built from the irregular ‘yo’ form: <span data-say=\"sea, seas, sea, seamos, seáis, sean\">sea, seas, sea…</span> (ser), <span data-say=\"haga, hagas, haga, hagamos, hagáis, hagan\">haga, hagas, haga…</span> (hacer), <span data-say=\"vaya, vayas, vaya, vayamos, vayáis, vayan\">vaya, vayas, vaya…</span> (ir), <span data-say=\"venga, vengas, venga, vengamos, vengáis, vengan\">venga, vengas, venga…</span> (venir).</p>\n            <p>Example: <span data-say=\"Espero que seas feliz y que vayas a la fiesta.\">Espero que seas feliz y que vayas a la fiesta.</span> — <em>I hope you are happy and that you go to the party.</em> Formal: <span data-say=\"¡Venga conmigo, señora!\">¡Venga conmigo, señora!</span> — <em>Come with me, madam!</em></p>", "check": {"question": "Which sentence correctly tells a friend (tú) to ‘come here’?", "options": ["Ven aquí", "Vienes aquí por favor", "Vengas aquí ahora", "Viene aquí conmigo"], "answer": 0, "explain": "The informal tú command of venir is irregular: ven. ‘Vienes’ is just a present-tense statement, not a command; ‘vengas’ and ‘viene’ use the wrong form."}}, {"title": "Present perfect: haber + irregular participles", "html": "<p><span class=\"tier-h\">H</span> The present perfect (‘I have —ed’) uses the PRESENT tense of <span data-say=\"haber\">haber</span> (he, has, ha, hemos, habéis, han) plus a past participle. Several common verbs have an irregular participle to learn by heart.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"he dicho\">he dicho</span></td><td>I have said (decir)</td><td><span data-say=\"he puesto\">he puesto</span></td><td>I have put (poner)</td></tr>\n              <tr><td><span data-say=\"he vuelto\">he vuelto</span></td><td>I have returned (volver)</td><td><span data-say=\"he cubierto\">he cubierto</span></td><td>I have covered (cubrir)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"He dicho la verdad y he vuelto a casa.\">He dicho la verdad y he vuelto a casa.</span> — <em>I have told the truth and I have returned home.</em></p>", "check": {"question": "What is the correct present perfect of ‘decir’ (I have said)?", "options": ["He dicho", "He decido", "He deciendo", "Ha dicho ella"], "answer": 0, "explain": "decir has an irregular participle: dicho, not a regularised ‘decido’/‘deciendo’. ‘Ha dicho ella’ also changes the subject to she."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hablo, comes, vive", "definition": "I speak, you eat, he/she lives (-ar/-er/-ir)"}, {"term": "soy / eres / es", "definition": "I am / you are / he-she is (ser, identity)"}, {"term": "estoy / estás / está", "definition": "I am / you are / he-she is (estar, temporary)"}, {"term": "tengo, tienes, tiene", "definition": "I have, you have, he/she has"}, {"term": "voy, vas, va", "definition": "I go, you go, he/she goes"}, {"term": "hago, haces, hace", "definition": "I do/make, you do, he/she does"}, {"term": "tener que + infinitivo", "definition": "to have to…"}, {"term": "ir a + infinitivo", "definition": "to be going to… (near future)"}, {"term": "quiero, prefiero (e→ie)", "definition": "I want, I prefer"}, {"term": "puedo, duermo (o→ue)", "definition": "I can, I sleep"}, {"term": "pido (e→i)", "definition": "I ask for"}, {"term": "me levanto", "definition": "I get up (reflexive)"}, {"term": "me ducho", "definition": "I shower (reflexive)"}, {"term": "me acuesto", "definition": "I go to bed (reflexive)"}, {"term": "me gusta…", "definition": "I like… (one thing)"}, {"term": "me gustan…", "definition": "I like… (more than one thing)"}, {"term": "me interesa / me encanta (H)", "definition": "…interests me / I love… (gustar-type)"}, {"term": "me duele / me duelen (H)", "definition": "…hurts / …hurt (gustar-type)"}, {"term": "seas (tú — ser)", "definition": "(that) you be / may you be"}, {"term": "haga (yo/él/ella — hacer)", "definition": "(that) I/he/she do, make; formal command"}, {"term": "vaya (yo/él/ella — ir)", "definition": "(that) I/he/she go"}, {"term": "vayas (tú — ir)", "definition": "(that) you go"}, {"term": "venga (yo/él/ella — venir)", "definition": "(that) I/he/she come; formal command ‘come!’"}, {"term": "vengas (tú — venir)", "definition": "(that) you come"}, {"term": "¡Haz! / ¡Pon! / ¡Ven!", "definition": "Do/make! / Put! / Come! (irregular tú commands)"}, {"term": "he dicho / he puesto (H)", "definition": "I have said / I have put"}, {"term": "he vuelto / he cubierto (H)", "definition": "I have returned / I have covered"}, {"term": "traigo (yo — traer)", "definition": "I bring"}, {"term": "¡Basta! (H)", "definition": "Enough!/That’s enough! (bastar)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen brothers", "I am nearly fifteen years old", "My friend is fifteen years old"], "answer": 0, "explain": "‘tengo quince años’ = I am fifteen (tener + años, not ‘to be’). The traps add a false subject or age detail."}, {"question": "<span data-say=\"Me levanto a las siete.\" data-listen></span><br>Listen. What time?", "options": ["seven o’clock", "seven thirty exactly", "quarter past seven", "seventeen o’clock"], "answer": 0, "explain": "‘a las siete’ = at seven. Every distractor is longer and invents a time detail that was not said."}, {"question": "<span data-say=\"No puedo salir porque tengo que estudiar.\" data-listen></span><br>Listen. Why can’t they go out?", "options": ["because they have to study", "because they don’t want to study at all", "because they are already studying now", "because their parents will not allow it"], "answer": 0, "explain": "‘tengo que estudiar’ = I have to study. Every distractor is longer and changes the reason given."}, {"question": "How do you say ‘I like sports’ (plural)?", "options": ["Me gustan los deportes", "Me gusta los deportes", "Me gusto los deportes", "Yo gusto mucho los deportes"], "answer": 0, "explain": "gustar agrees with the plural subject ‘los deportes’ → gustan. B fails to agree; C/D conjugate gustar as if it were a normal verb."}, {"question": "Careful — which sentence means ‘I am bored’ (right now)?", "options": ["Estoy aburrido", "Soy aburrido", "Tengo aburrido", "Hago aburrido"], "answer": 0, "explain": "A temporary feeling takes estar: estoy aburrido. ‘Soy aburrido’ would mean ‘I am a boring person’ — a classic trap."}, {"question": "How do you say ‘I can’t sleep’?", "options": ["No puedo dormir", "No podo dormir", "No puedes dormir", "No puede dormir mucho"], "answer": 0, "explain": "poder is a stem-changer: puedo. ‘podo’ ignores the o→ue change; C/D use the wrong person."}, {"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me ducho antes de desayunar", "Ducho antes de desayunar cada mañana", "Yo ducho muy temprano siempre", "Se ducho antes de desayunar"], "answer": 0, "explain": "ducharse is reflexive: (yo) me ducho. Dropping ‘me’ or using the wrong pronoun is wrong."}, {"question": "Complete: ‘Voy a ___ mis deberes esta tarde.’", "options": ["hacer", "hago", "haciendo", "hecho"], "answer": 0, "explain": "‘ir a’ takes an infinitive → hacer. The others are conjugated / non-finite forms."}, {"question": "‘Prefiero el fútbol al baloncesto’ — which stem-change is this?", "options": ["e → ie (preferir → prefiero)", "o → ue (preferir → prefuero)", "e → i (preferir → prifiero)", "no change at all"], "answer": 0, "explain": "preferir is an e→ie stem-changer: prefiero, prefieres, prefiere…"}, {"question": "‘¿Dónde está el gimnasio?’ uses ‘está’ because…", "options": ["it asks about location, which always takes estar", "location questions always use ‘ser’ instead of estar", "‘gimnasio’ is a feminine noun", "it is describing a permanent personality trait"], "answer": 0, "explain": "Location questions always use estar: ¿dónde está…?"}, {"question": "Complete: ‘Ojalá que ___ buen tiempo mañana.’ (I hope the weather is good)", "options": ["haga", "hace", "hacer", "hiciera"], "answer": 0, "explain": "‘ojalá que’ triggers the present subjunctive: haga. ‘hace’ is a plain statement; ‘hacer’ is the infinitive; ‘hiciera’ is the imperfect subjunctive (past), not present."}, {"question": "Which sentence correctly tells a friend to ‘put the book on the table’?", "options": ["Pon el libro en la mesa", "Pones el libro en la mesa", "Ponga el libro en la mesa", "Poned el libro en la mesa"], "answer": 0, "explain": "The tú command of poner is irregular: pon. ‘Pones’ is a statement; ‘ponga’ is the usted command; ‘poned’ is the vosotros command."}, {"question": "<span data-say=\"He dicho la verdad.\" data-listen></span><br>Listen. What have they done?", "options": ["told the truth", "asked a question yesterday", "written a long letter", "forgotten the answer completely"], "answer": 0, "explain": "‘he dicho la verdad’ = I have told the truth (present perfect + irregular participle dicho). The distractors invent different actions and tenses."}, {"question": "Which sentence means ‘I bring my notebook to class’?", "options": ["Traigo mi cuaderno a clase", "Traes mi cuaderno a clase", "Traje mi cuaderno a clase todos los días", "Traer mi cuaderno a clase"], "answer": 0, "explain": "traigo is the irregular ‘yo’ present of traer (I bring). ‘traes’ = you bring; ‘traje’ = preterite (past); ‘traer’ alone is the infinitive, not a conjugated verb."}, {"question": "Complete: ‘No ___ tonto, José.’ (Don’t be silly)", "options": ["seas", "eres", "estás", "eras"], "answer": 0, "explain": "Negative tú commands use the present subjunctive: no seas. ‘Eres/estás’ are indicative statements; ‘eras’ is imperfect (past)."}, {"question": "Complete: ‘Quiero que ___ a la fiesta conmigo.’ (I want you to go to the party with me)", "options": ["vayas", "vas", "ir", "fuiste"], "answer": 0, "explain": "‘querer que’ triggers the present subjunctive: vayas. ‘vas’ is indicative; ‘ir’ is the infinitive; ‘fuiste’ is the preterite (past)."}]}, "fib": {"enabled": true, "questions": [{"text": "Me [levanto] a las siete. <span data-say=\"Me levanto a las siete.\" data-listen>Me levanto a las siete.</span>"}, {"text": "No [puedo] salir porque tengo que estudiar. <span data-say=\"No puedo salir porque tengo que estudiar.\" data-listen>No puedo salir porque tengo que estudiar.</span>"}, {"text": "Voy a hacer mis [deberes]. <span data-say=\"Voy a hacer mis deberes esta tarde.\" data-listen>Voy a hacer mis deberes esta tarde.</span>"}, {"text": "[Estoy] cansado porque no duermo bien. (temporary state — estar)"}, {"text": "Me [gusta] el fútbol. (I like — singular subject)"}, {"text": "[Tengo] quince años. (age — with tener)"}, {"text": "Mi hermano [duerme] mucho por las noches. (o→ue stem-change: dormir)"}, {"text": "¡[Haz] tus deberes ahora mismo! (tú command — hacer)"}, {"text": "[Traigo] mi cuaderno a clase todos los días. <span data-say=\"Traigo mi cuaderno a clase todos los días.\" data-listen>Traigo mi cuaderno a clase todos los días.</span>"}, {"text": "Espero que [seas] feliz. (that you be — ser, present subjunctive)"}, {"text": "[He] dicho la verdad. (present perfect — ‘yo’ form of haber)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘gustar’ works backwards — the verb agrees with the thing liked, not the person.", "answer": true, "explain": "Me gusta el fútbol / me gustan los deportes — the verb matches the thing liked."}, {"statement": "‘Soy aburrido’ and ‘Estoy aburrido’ mean exactly the same thing.", "answer": false, "explain": "Soy aburrido = I am a boring person (ser, permanent). Estoy aburrido = I am bored right now (estar, temporary)."}, {"statement": "‘tener que’ is followed by an infinitive.", "answer": true, "explain": "tengo que estudiar / trabajar / dormir — always an infinitive."}, {"statement": "‘poder’ changes e → ie in the present tense.", "answer": false, "explain": "poder changes o → ue: puedo, puedes, puede, podemos, podéis, pueden."}, {"statement": "For location (where something is) you use ‘estar’, not ‘ser’.", "answer": true, "explain": "está en Madrid, not es en Madrid."}, {"statement": "‘nosotros’ and ‘vosotros’ keep the regular stem in radical-changing verbs.", "answer": true, "explain": "queremos, podemos, pedimos — the nosotros/vosotros forms do NOT change the stem."}, {"statement": "‘ducharse’ is a reflexive verb, so ‘I shower’ is ‘me ducho’.", "answer": true, "explain": "Reflexive: me ducho, te duchas, se ducha."}, {"statement": "‘voy a’ + infinitive describes something you did in the past.", "answer": false, "explain": "ir a + infinitive = near future (going to…), not the past."}, {"statement": "The informal (tú) command of ‘venir’ is ‘ven’.", "answer": true, "explain": "venir has an irregular tú command: ven (not ‘vienes’)."}, {"statement": "‘Espero que seas feliz’ uses the present subjunctive because it follows ‘espero que’.", "answer": true, "explain": "Verbs of hope/wish + que trigger the subjunctive: seas."}, {"statement": "‘He dicho’ means ‘I will say’.", "answer": false, "explain": "‘he dicho’ is the present perfect (I have said), not the future (diré)."}, {"statement": "‘Traigo’ is the present-tense ‘yo’ form of ‘traer’ (to bring).", "answer": true, "explain": "traer has an irregular yo-form: traigo (like tengo, hago)."}, {"statement": "‘¡Basta!’ on its own means ‘Enough!/That’s enough!’", "answer": true, "explain": "bastar works like gustar — used impersonally. ¡Basta! is the fixed phrase for ‘Enough!’"}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta los deportes.", "truth": "Me gustan los deportes.", "check": {"question": "Why is ‘Me gusta los deportes’ wrong?", "options": ["‘los deportes’ is plural, so it must be ‘gustan’", "you must always put the verb ‘estar’ in front of it too", "‘deportes’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"], "answer": 0, "explain": "gustar agrees with the thing liked; plural subject → gustan."}}, {"myth": "Soy aburrido. (= I am bored right now)", "truth": "Estoy aburrido. (= I am bored right now)", "check": {"question": "Which verb correctly says ‘I am bored right now’?", "options": ["Estoy aburrido — a temporary feeling uses estar", "Soy aburrido — feelings always use ser instead of estar", "Tengo aburrido — feelings use tener", "Hago aburrido — feelings use hacer"], "answer": 0, "explain": "Temporary feelings and moods take estar, not ser. ‘Soy aburrido’ describes a permanent personality trait instead."}}, {"myth": "Yo podo dormir mucho.", "truth": "Yo puedo dormir mucho.", "check": {"question": "Why is ‘podo’ wrong here?", "options": ["poder is a stem-changer: o → ue in ‘yo’ → puedo", "podo is simply an alternative spelling of puedo", "podo is only used in the plural form", "puedo is only used with ‘nosotros’"], "answer": 0, "explain": "poder changes o→ue outside nosotros/vosotros: puedo, puedes, puede, podemos, podéis, pueden."}}, {"myth": "Levanto a las siete.", "truth": "Me levanto a las siete.", "check": {"question": "What is missing in ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "an accent on the final letter of the verb form", "the linking word ‘a’", "the article ‘el’"], "answer": 0, "explain": "levantarse is reflexive: you need me/te/se — ‘me levanto’."}}, {"myth": "Tengo que estudiar mañana obligatoriamente sin ninguna excusa posible.", "truth": "Tengo que estudiar mañana.", "check": {"question": "What is the actual problem with the ‘wrong’ sentence here?", "options": ["nothing grammatically — it is just unnecessarily long for the exam context", "‘tengo que’ is here followed by a fully conjugated verb instead of an infinitive", "‘estudiar’ should be ‘estudio’", "‘mañana’ should come before ‘tengo’"], "answer": 0, "explain": "The grammar (tengo que + infinitive) is correct; padding a sentence with unnecessary words does not add marks in a translation or writing task."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Present-tense verb endings are easy to mishear. Listen for whether it is ‘gusta’ (one thing) or ‘gustan’ (more than one), and whether a stem-changer is used: ‘puedo’ not ‘podo’, ‘quiero’ not ‘quero’.", "check": {"question": "You hear ‘…gustan…’. What does that tell you?", "options": ["more than one thing is liked", "only one single thing is liked", "nothing is liked at all", "it is a future plan"], "answer": 0, "explain": "The -n ending of ‘gustan’ signals a plural subject (los deportes, las matemáticas…)."}}, {"title": "Paper 3 — Reading and translation into English", "html": "Watch ser vs estar: ‘es aburrido’ (he is boring) is very different from ‘está aburrido’ (he is bored). Keep ‘tengo quince años’ natural: ‘I am fifteen’, not ‘I have fifteen years’.", "check": {"question": "‘Está en el gimnasio y tiene que entrenar’ =", "options": ["He/she is at the gym and has to train", "He/she is a gym-like person and wants to train", "He/she was at the gym yesterday and trained", "He/she likes the gym but never trains"], "answer": 0, "explain": "estar en = to be (located) in; tener que = to have to."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a routine, a preference and a plan: ‘Me levanto a las siete, prefiero el fútbol y voy a hacer mis deberes.’ At Higher, add gustar-type and a stem-changer to show range: ‘me interesan…’, ‘pido…’.", "check": {"question": "Which answer reaches the top band?", "options": ["Me levanto a las siete, prefiero el fútbol y voy a hacer mis deberes", "Me levanto y me levanto y me levanto todos los días sin parar nunca jamás", "Estoy bien", "Tengo deberes"], "answer": 0, "explain": "It links a routine action, a stem-changing preference and a near-future plan — range and accuracy, not just repeating one verb."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What does Carlos do straight after getting up? (1)<br>(b) Why does he go to school by bus? (1)<br>(c) Why does he have to study a lot? (1)<br>(d) Why can’t he go out much at weekends? (1)", "marks": 4, "hint": "Find the routine action after ‘y’, the reason after ‘porque’ (twice), and the weekend reason after ‘pero’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> he showers (straight away) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> (because) school is quite far from his house <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) sciences are difficult <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (because) he has to help at home <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I get up at seven. <br>(b) I have to study a lot. <br>(c) I like sports, but I prefer football.", "marks": 5, "hint": "‘I get up’ = reflexive (Me levanto…). ‘I have to’ = tener que + infinitive. ‘I like… I prefer…’ = Me gusta(n)… / prefiero…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me levanto a las siete. <em>(1)</em></li>\n                <li><strong>(b)</strong> Tengo que estudiar mucho. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gustan los deportes <em>(1)</em>, pero <em>(1)</em> prefiero el fútbol <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me gustan los deportes’ must use the plural ‘gustan’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-4-talking-about-the-past', 'G.4 Talking About the Past', '{"learn": {"enabled": true, "items": [{"title": "How do I form the preterite of regular -AR verbs?", "html": "<p>The preterite (<span data-say=\"el pretérito\">el pretérito</span>) describes a <strong>completed action in the past</strong> — something that happened and finished at a specific point in time.</p>\n            <p>Regular <strong>-AR</strong> verbs like <span data-say=\"hablar\">hablar</span> (to speak) follow this pattern:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablé\">hablé</span></td><td>nosotros/as</td><td>hablamos</td></tr>\n              <tr><td>tú</td><td>hablaste</td><td>vosotros/as</td><td>hablasteis</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"habló\">habló</span></td><td>ellos/ellas/ustedes</td><td>hablaron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Ayer hablé con mi profesora por teléfono.\">Ayer hablé con mi profesora por teléfono.</span> — <em>Yesterday I spoke to my teacher on the phone.</em> Note the accent on <strong>hablé</strong> and <strong>habló</strong> — without it, the meaning changes!</p>", "check": {"question": "What is the ''yo'' (I) form of ''hablar'' in the preterite?", "options": ["hablé", "hablaba", "hablo", "he hablado"], "answer": 0, "explain": "The ''yo'' preterite ending for -AR verbs is -é (with an accent): hablé. ''hablaba'' is imperfect, ''hablo'' is present, ''he hablado'' is perfect."}}, {"title": "How do I form the preterite of regular -ER/-IR verbs?", "html": "<p><strong>-ER</strong> and <strong>-IR</strong> verbs share the SAME preterite endings. Compare <span data-say=\"comer\">comer</span> (to eat) and <span data-say=\"vivir\">vivir</span> (to live):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"comí\">comí</span></td><td><span data-say=\"viví\">viví</span></td></tr>\n              <tr><td>tú</td><td>comiste</td><td>viviste</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"comió\">comió</span></td><td><span data-say=\"vivió\">vivió</span></td></tr>\n              <tr><td>nosotros/as</td><td>comimos</td><td>vivimos</td></tr>\n              <tr><td>ellos/ellas/ustedes</td><td>comieron</td><td>vivieron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Anoche comimos pasta en el restaurante.\">Anoche comimos pasta en el restaurante.</span> — <em>Last night we ate pasta at the restaurant.</em></p>", "check": {"question": "Which ending do -ER and -IR verbs share for ''él/ella'' in the preterite?", "options": ["-ió (comió, vivió)", "-aba, used for every single verb", "-ía, with no exceptions at all", "-ando, added to the stem"], "answer": 0, "explain": "-ER/-IR verbs share preterite endings: comió, vivió both end in -ió. -aba/-ía are imperfect endings; -ando builds the gerund."}}, {"title": "What are the key irregular preterites?", "html": "<p>Some very common verbs are IRREGULAR in the preterite — they use different stems and take NO written accent.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"ser\">ser</span> / <span data-say=\"ir\">ir</span></td><td><span data-say=\"fui\">fui</span>, fuiste, <span data-say=\"fue\">fue</span>, fuimos, fuisteis, fueron</td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td><span data-say=\"hice\">hice</span>, hiciste, hizo, hicimos</td></tr>\n              <tr><td><span data-say=\"tener\">tener</span></td><td><span data-say=\"tuve\">tuve</span>, tuviste, tuvo, tuvimos</td></tr>\n              <tr><td><span data-say=\"estar\">estar</span></td><td><span data-say=\"estuve\">estuve</span>, estuviste, estuvo, estuvimos</td></tr>\n            </table>\n            <p><strong>ser and ir share IDENTICAL forms</strong> in the preterite — only context tells you which one is meant: <span data-say=\"Fui al cine.\">Fui al cine.</span> (I went) vs <span data-say=\"Fue muy interesante.\">Fue muy interesante.</span> (It was).</p>\n            <p>More irregular preterite stems worth learning: <span data-say=\"decir\">decir</span> → <span data-say=\"dije\">dije</span>, dijiste, dijo, dijimos, dijisteis, dijeron; <span data-say=\"poder\">poder</span> → <span data-say=\"pude\">pude</span>, pudiste, pudo, pudimos; <span data-say=\"saber\">saber</span> → <span data-say=\"supe\">supe</span>, supiste, supo, supimos; <span data-say=\"querer\">querer</span> → <span data-say=\"quise\">quise</span>, quisiste, quiso, quisimos; <span data-say=\"venir\">venir</span> → <span data-say=\"vine\">vine</span>, viniste, vino, vinimos; <span data-say=\"traer\">traer</span> → <span data-say=\"traje\">traje</span>, trajiste, trajo, trajimos, trajisteis, trajeron.</p>\n            <p>Watch the spelling: verbs with a <strong>-j-</strong> stem (decir, traer, and similar verbs) DROP the <strong>i</strong> in the ellos/ellas ending — <span data-say=\"dijeron\">dijeron</span> and <span data-say=\"trajeron\">trajeron</span>, never \"dijieron\"/\"trajieron\".</p>", "check": {"question": "''fui'' can mean ''I went'' OR ''I was'', because…", "options": ["ser and ir share identical preterite forms", "the word changes its spelling with meaning", "''fui'' only ever means ''I was'' in context", "''fui'' is a completely regular -IR verb"], "answer": 0, "explain": "ser (to be) and ir (to go) have exactly the same irregular preterite forms — fui, fuiste, fue… Context tells you which verb is meant."}}, {"title": "How do I form the imperfect tense?", "html": "<p>The imperfect (<span data-say=\"el imperfecto\">el imperfecto</span>) describes what you <strong>used to do</strong>, <strong>was doing</strong>, or how things <strong>were</strong> — no fixed end point.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablaba\">hablaba</span></td><td><span data-say=\"comía\">comía</span></td><td><span data-say=\"vivía\">vivía</span></td></tr>\n              <tr><td>tú</td><td>hablabas</td><td>comías</td><td>vivías</td></tr>\n              <tr><td>él/ella</td><td>hablaba</td><td>comía</td><td>vivía</td></tr>\n              <tr><td>nosotros/as</td><td><span data-say=\"hablábamos\">hablábamos</span></td><td>comíamos</td><td>vivíamos</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando era niño, jugaba al fútbol todos los días.\">Cuando era niño, jugaba al fútbol todos los días.</span> — <em>When I was a child, I used to play football every day.</em></p>", "check": {"question": "What does the imperfect tense express?", "options": ["a habitual or ongoing past action (''used to'')", "a single action completed at one exact moment", "an action that is going to happen soon", "an instruction telling someone what to do"], "answer": 0, "explain": "The imperfect describes habits, ongoing states or descriptions in the past — ''used to'' / ''was -ing''. A single finished action needs the preterite instead."}}, {"title": "Preterite or imperfect — which do I choose?", "html": "<p>Ask: is it a SINGLE completed event, or a HABIT / DESCRIPTION / ongoing background action?</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>PRETERITE</strong> — one-off, finished</td><td><span data-say=\"ayer\">ayer</span>, <span data-say=\"el año pasado\">el año pasado</span>, <span data-say=\"el fin de semana pasado\">el fin de semana pasado</span>, <span data-say=\"anoche\">anoche</span></td></tr>\n              <tr><td><strong>IMPERFECT</strong> — habit, description, ongoing</td><td><span data-say=\"normalmente\">normalmente</span>, <span data-say=\"todos los días\">todos los días</span>, <span data-say=\"de pequeño\">de pequeño</span>, <span data-say=\"mientras\">mientras</span></td></tr>\n            </table>\n            <p>The two often combine: <span data-say=\"Mientras yo cocinaba, mi hermano llegó a casa.\">Mientras yo cocinaba, mi hermano llegó a casa.</span> — <em>While I was cooking (ongoing, imperfect), my brother arrived (interrupting event, preterite).</em></p>\n            <p>Irregular imperfects: <span data-say=\"ser\">ser</span> → <span data-say=\"era\">era</span>; <span data-say=\"ir\">ir</span> → <span data-say=\"iba\">iba</span>; <span data-say=\"ver\">ver</span> → <span data-say=\"veía\">veía</span>.</p>", "check": {"question": "In ''Mientras cocinaba, mi hermano llegó'', why is ''llegó'' in the preterite?", "options": ["it is the single event that interrupted the ongoing action", "every verb that comes after the word ''mientras'' must always be preterite too", "''llegó'' describes a repeated daily habit", "the whole sentence is describing the future"], "answer": 0, "explain": "''cocinaba'' (imperfect) sets the ongoing background; ''llegó'' (preterite) is the single completed event that broke in."}}, {"title": "Higher: the perfect tense", "html": "<p><span class=\"tier-h\">H</span> The perfect tense (<span data-say=\"el pretérito perfecto\">el pretérito perfecto</span>) links the past to NOW — recent past or experience, with no definite time marker like ''ayer''.</p>\n            <p>Form: <strong>haber</strong> + past participle.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>he</td><td><span data-say=\"he hablado\">he hablado</span></td><td>hemos</td><td>hemos comido</td></tr>\n              <tr><td>has</td><td>has vivido</td><td>habéis</td><td>habéis hecho</td></tr>\n              <tr><td>ha</td><td><span data-say=\"ha comido\">ha comido</span></td><td>han</td><td>han ido</td></tr>\n            </table>\n            <p>Irregular participles: <span data-say=\"hecho\">hecho</span> (hacer), visto (ver), escrito (escribir).</p>\n            <p>Example: <span data-say=\"Nunca he comido paella.\">Nunca he comido paella.</span> — <em>I have never eaten paella.</em></p>", "check": {"question": "How is the perfect tense formed?", "options": ["haber (he/has/ha…) + past participle", "the preterite stem plus the ending -aba", "estar + a gerund ending in -ando/-iendo", "the plain infinitive with no changes"], "answer": 0, "explain": "Perfect = present of haber + past participle: he comido, ha hecho. estar+gerund is the continuous; -aba builds the imperfect."}}, {"title": "What about the ''tú'' and other imperfect forms of tricky verbs?", "html": "<p>So far you''ve mostly seen <strong>yo/él</strong> imperfect forms. Listening and speaking tasks often need <strong>tú</strong> too — asking or telling someone what THEY used to do.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"ser\">ser</span></td><td><span data-say=\"era\">era</span> (yo/él)</td><td><span data-say=\"eras\">eras</span> (tú)</td></tr>\n              <tr><td><span data-say=\"ir\">ir</span></td><td><span data-say=\"iba\">iba</span> (yo/él)</td><td><span data-say=\"ibas\">ibas</span> (tú)</td></tr>\n              <tr><td><span data-say=\"ver\">ver</span></td><td><span data-say=\"veía\">veía</span> (yo/él)</td><td><span data-say=\"veías\">veías</span> (tú)</td></tr>\n              <tr><td><span data-say=\"tener\">tener</span></td><td><span data-say=\"tenía\">tenía</span> (yo/él)</td><td><span data-say=\"tenías\">tenías</span> (tú)</td></tr>\n              <tr><td><span data-say=\"estar\">estar</span></td><td>estaba (yo/él)</td><td><span data-say=\"estabas\">estabas</span> (tú)</td></tr>\n            </table>\n            <p><strong>tener</strong> and <strong>estar</strong> are regular in the imperfect — they just add -ía/-ías or -aba/-abas to the stem, unlike ser/ir/ver which change their stem. Example: <span data-say=\"Cuando eras pequeño, ¿tenías miedo de la oscuridad?\">Cuando eras pequeño, ¿tenías miedo de la oscuridad?</span> — <em>When you were little, were you afraid of the dark?</em></p>\n            <p>Another: <span data-say=\"Yo estaba en casa, pero tú estabas en el colegio.\">Yo estaba en casa, pero tú estabas en el colegio.</span> — <em>I was at home, but you were at school.</em></p>", "check": {"question": "What is the ''tú'' imperfect form of ''tener''?", "options": ["tenías", "tuviste", "tenía", "tienes"], "answer": 0, "explain": "tener is regular in the imperfect: tenía (yo/él), tenías (tú). ''tuviste'' is the preterite tú form; ''tienes'' is present."}}, {"title": "How does ''dar'' behave in the preterite?", "html": "<p><span data-say=\"dar\">dar</span> looks like a regular -AR verb, but in the preterite it borrows the -ER/-IR endings — and with NO written accents at all.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td>di</td><td>nosotros/as</td><td><span data-say=\"dimos\">dimos</span></td></tr>\n              <tr><td>tú</td><td><span data-say=\"diste\">diste</span></td><td>vosotros/as</td><td><span data-say=\"disteis\">disteis</span></td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"dio\">dio</span></td><td>ellos/ellas/ustedes</td><td><span data-say=\"dieron\">dieron</span></td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi madre me dio un regalo y mis amigos me dieron una tarjeta.\">Mi madre me dio un regalo y mis amigos me dieron una tarjeta.</span> — <em>My mum gave me a present and my friends gave me a card.</em></p>", "check": {"question": "Which preterite ending pattern does ''dar'' follow?", "options": ["the -ER/-IR endings, but with no written accents", "the regular -AR endings, with accents on yo and él", "the same imperfect endings as hablar (-aba)", "no ending at all — dar stays the same in the past"], "answer": 0, "explain": "dar is -AR but takes -ER/-IR preterite endings without accents: di, diste, dio, dimos, disteis, dieron."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hablé", "definition": "I spoke"}, {"term": "hablaste", "definition": "you spoke"}, {"term": "habló", "definition": "he/she spoke"}, {"term": "comí", "definition": "I ate"}, {"term": "comió", "definition": "he/she ate"}, {"term": "viví", "definition": "I lived"}, {"term": "fui (ir)", "definition": "I went"}, {"term": "fui (ser)", "definition": "I was"}, {"term": "hice", "definition": "I did / made"}, {"term": "tuve", "definition": "I had"}, {"term": "estuve", "definition": "I was (place/state)"}, {"term": "hablaba", "definition": "I used to speak"}, {"term": "comía", "definition": "I used to eat / was eating"}, {"term": "vivía", "definition": "I used to live"}, {"term": "era", "definition": "I was (description)"}, {"term": "iba", "definition": "I used to go"}, {"term": "veía", "definition": "I used to see / watch"}, {"term": "he comido (H)", "definition": "I have eaten"}, {"term": "eras", "definition": "you were (tú, description)"}, {"term": "tenía", "definition": "I/he/she had (imperfect)"}, {"term": "tenías", "definition": "you had / used to have"}, {"term": "estabas", "definition": "you were (tú, place/state)"}, {"term": "ibas", "definition": "you used to go"}, {"term": "veías", "definition": "you used to see / watch"}, {"term": "dije (decir)", "definition": "I said"}, {"term": "pude (poder)", "definition": "I could / managed to"}, {"term": "supe (saber)", "definition": "I found out / knew"}, {"term": "quise (querer)", "definition": "I wanted / tried to"}, {"term": "vine (venir)", "definition": "I came"}, {"term": "traje (traer)", "definition": "I brought"}, {"term": "dio (dar)", "definition": "he/she gave"}, {"term": "diste (dar)", "definition": "you gave"}, {"term": "dieron (dar)", "definition": "they gave"}, {"term": "dimos (dar)", "definition": "we gave"}, {"term": "disteis (dar)", "definition": "you all gave"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Ayer fui al cine.\" data-listen></span><br>Listen. What happened?", "options": ["I went to the cinema yesterday", "I go to the cinema every single day", "I used to go to the cinema often", "I am going to the cinema later today"], "answer": 0, "explain": "''Ayer fui al cine'' = I went to the cinema yesterday (preterite, one-off past event). The distractors swap it for a habit, present routine or future plan."}, {"question": "<span data-say=\"Cuando era niño, jugaba en el parque todos los días.\" data-listen></span><br>Listen. What is being described?", "options": ["a childhood habit that happened repeatedly", "a single visit made to the park last Tuesday", "a plan to play at the park next weekend", "an instruction telling a child to go and play"], "answer": 0, "explain": "''jugaba… todos los días'' is the imperfect describing a repeated childhood habit. The others turn it into a single event, a future plan or a command."}, {"question": "Complete: \"Ayer, yo ___ (comer) una hamburguesa enorme.\"", "options": ["comí", "comía", "como", "he comido"], "answer": 0, "explain": "''Ayer'' signals a single completed action → preterite: comí. ''comía'' is imperfect, ''como'' present, ''he comido'' perfect (no definite time marker needed there)."}, {"question": "Complete: \"Cuando era pequeña, ___ (vivir) en Madrid.\"", "options": ["vivía", "viví", "vivo", "he vivido"], "answer": 0, "explain": "''Cuando era pequeña'' sets up a description of a past state → imperfect: vivía. ''viví'' is preterite (single event), ''vivo'' present, ''he vivido'' perfect."}, {"question": "Which form means ''I went'' (from ''ir'')?", "options": ["fui", "fue", "iba", "voy"], "answer": 0, "explain": "''fui'' (yo) = I went / I was. ''fue'' is él/ella, ''iba'' is the imperfect (I used to go), ''voy'' is present."}, {"question": "Which sentence correctly says ''I did my homework yesterday''?", "options": ["Hice los deberes ayer", "Hacía los deberes ayer siempre", "Hago los deberes cada día", "He hecho los deberes ayer"], "answer": 0, "explain": "''ayer'' plus a one-off completed action = preterite: Hice los deberes ayer. ''Hacía…siempre'' is imperfect, ''Hago…cada día'' is present, ''He hecho'' is perfect."}, {"question": "Complete: \"De pequeño, normalmente mi madre se ___ (levantarse) a las seis.\"", "options": ["levantaba", "levantó", "levanta", "ha levantado"], "answer": 0, "explain": "''normalmente'' plus a repeated childhood habit = imperfect: se levantaba. ''levantó'' is a single occasion, ''levanta'' present, ''ha levantado'' perfect."}, {"question": "Higher: which sentence correctly uses the perfect tense for ''I have never eaten paella''?", "options": ["Nunca he comido paella", "Nunca comí paella el sábado", "Nunca como paella los domingos", "Nunca comía paella de pequeño"], "answer": 0, "explain": "The perfect (haber + participle) links past experience to now with no definite time marker: Nunca he comido paella. The others add a preterite, present or imperfect time frame."}, {"question": "Complete: \"Mientras yo ___ (cocinar), mi hermano llegó a casa.\"", "options": ["cocinaba", "cociné", "cocino", "he cocinado"], "answer": 0, "explain": "''mientras'' introduces the ongoing background action → imperfect: cocinaba, interrupted by the preterite ''llegó''."}, {"question": "<span data-say=\"El año pasado, viajé a España con mi familia.\" data-listen></span><br>Listen. What is being said?", "options": ["Last year, I travelled to Spain with my family", "Every year, I travel to Spain with my family", "I used to travel to Spain with my family", "Next year, I will travel to Spain with my family"], "answer": 0, "explain": "''El año pasado, viajé'' = Last year, I travelled (preterite, a single trip). The others swap the time frame to present, habitual or future."}, {"question": "Complete: \"Cuando yo era pequeño, ___ (tener) un perro llamado Rex.\"", "options": ["tenía", "tuve", "tengo", "he tenido"], "answer": 0, "explain": "''Cuando era pequeño'' sets up a description of a past state → imperfect: tenía. ''tuve'' is preterite (a single moment of having/receiving), ''tengo'' present, ''he tenido'' perfect."}, {"question": "Complete: \"Cuando ___ (estar) en Madrid, tú visitabas el museo del Prado a menudo.\"", "options": ["estabas", "estuviste", "estás", "has estado"], "answer": 0, "explain": "estar is regular in the imperfect: estaba (yo/él), estabas (tú) — an ongoing state. ''estuviste'' is the preterite tú form (a finished moment), ''estás'' present, ''has estado'' perfect."}, {"question": "<span data-say=\"Mi madre me dio un regalo y mis amigos me dieron una tarjeta.\" data-listen></span><br>Listen. What happened?", "options": ["My mum gave me a present and my friends gave me a card", "My mum gives me a present every single birthday each year", "My mum will give me a present next Tuesday for my birthday", "My mum used to give me a present every single year"], "answer": 0, "explain": "''dio'' and ''dieron'' are the él/ella and ellos preterite forms of dar (no accents). The others swap it into present, future or habitual imperfect."}, {"question": "Complete: \"Ayer, yo no ___ (poder) terminar los deberes a tiempo.\"", "options": ["pude", "podía", "puedo", "he podido"], "answer": 0, "explain": "''Ayer'' + a single completed action → preterite: pude (I managed to / succeeded in). ''podía'' is imperfect (was able to, ongoing), ''puedo'' present, ''he podido'' perfect."}, {"question": "Which sentence means \"I found out the truth yesterday\"?", "options": ["Ayer supe la verdad", "Ayer sabía la verdad", "Ayer sé la verdad", "Ayer he sabido la verdad"], "answer": 0, "explain": "supe (preterite of saber) = ''found out'' at a specific moment. ''sabía'' (imperfect) = ''knew'' as an ongoing state; ''sé'' present; ''he sabido'' perfect."}]}, "fib": {"enabled": true, "questions": [{"text": "Ayer, yo [hablé] (hablar) con mi profesora sobre el examen. <span data-say=\"Ayer, yo hablé con mi profesora sobre el examen.\" data-listen>Ayer, yo hablé con mi profesora sobre el examen.</span>"}, {"text": "El año pasado, nosotros [fuimos] (ir) de vacaciones a Francia. <span data-say=\"El año pasado, nosotros fuimos de vacaciones a Francia.\" data-listen>El año pasado, nosotros fuimos de vacaciones a Francia.</span>"}, {"text": "De pequeño, yo [vivía] (vivir) en Sevilla con mis abuelos. (imperfect — describes a past state)"}, {"text": "Normalmente, mi madre se [levantaba] (levantarse) a las seis. (imperfect — a repeated habit)"}, {"text": "Mientras yo cocinaba, mi hermano [llegó] (llegar) a casa. (the interrupting single event — preterite)"}, {"text": "Escucha y completa: Ayer [estuve] en el parque toda la tarde. <span data-say=\"Ayer estuve en el parque toda la tarde.\" data-listen></span>"}, {"text": "Higher: Nunca [he comido] (comer) paella antes. (perfect tense — haber + participle)"}, {"text": "Cuando eras pequeño, ¿tú [tenías] (tener) miedo de la oscuridad? (imperfect — tú form)"}, {"text": "Escucha y completa: Mis amigos me [dieron] una sorpresa para mi cumpleaños. <span data-say=\"Mis amigos me dieron una sorpresa para mi cumpleaños.\" data-listen></span>"}, {"text": "Anoche, yo [vine] (venir) tarde a casa después de la fiesta."}, {"text": "Ayer, le [dije] (decir) toda la verdad a mi mejor amiga."}, {"text": "Para el picnic, yo [traje] (traer) mi propia comida y bebida."}]}, "tf": {"enabled": true, "questions": [{"statement": "The preterite describes a completed action in the past.", "answer": true, "explain": "hablé, comí, fui — all describe an action that finished at a specific point in time."}, {"statement": "''fui'' can only ever mean ''I was'', never ''I went''.", "answer": false, "explain": "ser and ir share identical preterite forms — ''fui'' can mean ''I went'' (ir) or ''I was'' (ser); context decides."}, {"statement": "-ER and -IR verbs share the same preterite endings.", "answer": true, "explain": "comí/comió and viví/vivió use identical endings once you strip the stem."}, {"statement": "The imperfect is used for a single, completed one-off event.", "answer": false, "explain": "The imperfect describes habits, ongoing states or descriptions; a single finished event needs the preterite."}, {"statement": "''era'', ''iba'' and ''veía'' are the only three irregular imperfect verbs.", "answer": true, "explain": "ser (era), ir (iba) and ver (veía) are the sole imperfect irregulars — every other verb is regular."}, {"statement": "''ayer'' is a time marker usually paired with the preterite.", "answer": true, "explain": "ayer, el año pasado, anoche all point to a finished one-off action → preterite."}, {"statement": "''normalmente'' usually signals the imperfect tense.", "answer": true, "explain": "normalmente, todos los días, de pequeño all point to a habit → imperfect."}, {"statement": "The perfect tense is formed with estar plus a gerund.", "answer": false, "explain": "The perfect is haber + past participle (he comido); estar + gerund (-ando/-iendo) builds the continuous instead."}, {"statement": "''tenía'' can mean both ''I had'' and ''he/she had'' in the imperfect.", "answer": true, "explain": "yo and él/ella share identical -ER/-IR imperfect endings: tenía serves both — only context (or a subject pronoun) tells you which."}, {"statement": "''dar'' takes accented endings in the preterite, just like ''hablar'' does.", "answer": false, "explain": "dar borrows the -ER/-IR preterite endings with NO written accents: di, diste, dio, dimos, disteis, dieron."}]}, "misc": {"enabled": true, "items": [{"myth": "Ayer jugaba al fútbol con mis amigos.", "truth": "Ayer jugué al fútbol con mis amigos.", "check": {"question": "Why is ''Ayer jugaba…'' wrong here?", "options": ["''ayer'' signals a single finished event, so it needs the preterite", "''jugaba'' is spelt correctly but carries an accent mark it should not have", "''jugar'' cannot be used with ''ayer'' at all", "the sentence should be in the future tense instead"], "answer": 0, "explain": "''ayer'' = a one-off, completed action → preterite (jugué), not the imperfect (jugaba), which suits habits."}}, {"myth": "Cuando era niño, jugué en el parque todos los días.", "truth": "Cuando era niño, jugaba en el parque todos los días.", "check": {"question": "Why is ''jugué…todos los días'' wrong here?", "options": ["''todos los días'' describes a repeated habit, needing the imperfect", "''todos los días'' can only ever be used together with the present tense, never the past", "''todos los días'' can only pair with the perfect tense", "the sentence needs a reflexive pronoun instead"], "answer": 0, "explain": "''todos los días'' signals a repeated childhood habit → imperfect (jugaba), not the preterite (jugué), which suits one-off events."}}, {"myth": "Yo hací los deberes ayer.", "truth": "Yo hice los deberes ayer.", "check": {"question": "What is wrong with ''hací''?", "options": ["hacer''s irregular preterite stem is ''hic-'', giving ''hice''", "the ending ''-í'' used here is actually the completely correct and standard ending for hacer", "''hací'' is the correct imperfect form of hacer", "the accent mark has simply been left off ''hací''"], "answer": 0, "explain": "hacer is irregular in the preterite: hice, hiciste, hizo… There is no form ''hací'' — the stem changes to hic-."}}, {"myth": "Nunca comí paella.", "truth": "Nunca he comido paella.", "check": {"question": "Why does ''I have never eaten paella'' need the perfect, not the preterite?", "options": ["there is no definite past time marker, so the perfect links it to now", "''nunca'' can only ever be correctly followed by the imperfect tense in Spanish grammar", "''comí'' is actually spelt incorrectly in that sentence", "the preterite cannot be used with any negative word"], "answer": 0, "explain": "With no time marker like ''ayer'', an experience ''up to now'' takes the perfect: Nunca he comido paella."}}, {"myth": "Mientras cociné, mi hermano llegaba a casa.", "truth": "Mientras cocinaba, mi hermano llegó a casa.", "check": {"question": "Which verb should be the ongoing background action, and which the interrupting event?", "options": ["cocinaba is the ongoing background; llegó is the single interrupting event", "cociné is the ongoing background action here, while llegaba is meant to be the interrupting event", "both verbs must be in the preterite in this sentence", "both verbs must be in the imperfect in this sentence"], "answer": 0, "explain": "The wrong version swaps the tenses round: the ongoing action (cooking) needs the imperfect, and the single event that interrupts it (arriving) needs the preterite."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for tense endings", "html": "Preterite and imperfect verbs often differ by a single sound. Listen for the stressed final vowel: -é/-ó (preterite: hablé, habló) vs -aba/-ía (imperfect: hablaba, comía). That one sound changes whether it was a finished event or a habit.", "check": {"question": "You hear the ending ''-aba'' on a verb. What does that most likely signal?", "options": ["an imperfect form describing a habit or description", "a preterite form that is describing one single finished action in the past", "a command telling someone to do something", "the perfect tense describing an experience"], "answer": 0, "explain": "-aba is the -AR imperfect ending (hablaba, jugaba) — habits, descriptions, ongoing past actions."}}, {"title": "Paper 3 — Reading: spot the accent", "html": "A missing or misread accent changes the tense entirely: ''hablo'' (I speak, present) vs ''habló'' (he/she spoke, preterite); ''hable'' (subjunctive) vs ''hablé'' (I spoke, preterite). Always check who is doing the action before you translate.", "check": {"question": "What is the key difference between ''hablo'' and ''habló'' in a reading text?", "options": ["''hablo'' is present tense (I), ''habló'' is preterite (he/she)", "they are simply two different but interchangeable spellings of the exact same word", "''habló'' is always the correct spelling to use", "there is no real difference in meaning between them"], "answer": 0, "explain": "The accent moves the stress and changes both tense and subject: hablo = I speak (now); habló = he/she spoke (finished)."}}, {"title": "Paper 4 — Writing: mix your past tenses", "html": "Top-band answers combine tenses naturally: a preterite for a single trip, an imperfect for a childhood habit, and (Higher) a perfect for an experience with no date. Example: ''El año pasado fui a España. Cuando era niño, iba todos los veranos. Nunca he visitado Barcelona.''", "check": {"question": "Which answer shows the widest and most accurate range of past tenses?", "options": ["El año pasado fui a España; de niño iba cada verano; nunca he visitado Barcelona", "Fui a España, fui a Francia, fui a Italia y también fui a Portugal el año pasado otra vez", "Voy a España todos los años porque me gusta mucho viajar", "España es un país muy bonito con playas y montañas"], "answer": 0, "explain": "It combines preterite (fui), imperfect (iba) and perfect (he visitado) accurately — range, not just length or repetition."}}]}, "exam": {"enabled": true, "questions": [{"question": "Complete each sentence with the correct form of the verb in brackets (preterite or imperfect).<br>(a) Ayer, yo ___ (ir) al cine con mi hermano. (1)<br>(b) De pequeño, mi abuelo ___ (vivir) en un pueblo pequeño. (1)<br>(c) El año pasado, nosotros ___ (hacer) un viaje a Italia. (1)<br>(d) Mientras mi madre ___ (cocinar), yo puse la mesa. (1)<br>(e) Normalmente, los sábados yo ___ (levantarse) tarde. (1)", "marks": 5, "hint": "Look for the time clue in each sentence: ''ayer''/''el año pasado'' = a single finished event (preterite); ''de pequeño''/''mientras''/''normalmente'' = a habit or ongoing background action (imperfect).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO2 Grammar)</h5><ul>\n                <li><strong>(a)</strong> fui <em>(1)</em> — ''ayer'' = single event → preterite.</li>\n                <li><strong>(b)</strong> vivía <em>(1)</em> — ''de pequeño'' = past description → imperfect.</li>\n                <li><strong>(c)</strong> hicimos <em>(1)</em> — ''el año pasado'' = single event → preterite.</li>\n                <li><strong>(d)</strong> cocinaba <em>(1)</em> — ongoing background action interrupted by ''puse'' → imperfect.</li>\n                <li><strong>(e)</strong> me levantaba <em>(1)</em> — ''normalmente'' = repeated habit → imperfect.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>One mark per correctly-conjugated verb; accept minor accent slips if the tense is clearly right.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) Last year I travelled to Mexico. <br>(b) When I was young, I used to go to the beach every summer. <br>(c) I have never visited Peru.", "marks": 6, "hint": "''Last year'' + a single trip = preterite (viajé). ''Used to go every summer'' = a repeated habit = imperfect (iba). ''I have never visited'' with no exact date = the perfect (he visitado).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> El año pasado <em>(1)</em> viajé a México <em>(1)</em>.</li>\n                <li><strong>(b)</strong> Cuando era joven/niño, iba a la playa <em>(1)</em> todos los veranos <em>(1)</em>.</li>\n                <li><strong>(c)</strong> Nunca <em>(1)</em> he visitado Perú <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. The tense choice (preterite/imperfect/perfect) must be correct for the mark.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about near-future plans? (ir a + infinitivo)", "html": "<p>The easiest way to talk about the future is <strong>ir a + infinitivo</strong> — literally “to go to do something”. Conjugate <span data-say=\"ir\">ir</span> and add an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"voy a\">voy a</span></td><td>I am going to</td><td><span data-say=\"vamos a\">vamos a</span></td><td>we are going to</td></tr>\n              <tr><td><span data-say=\"vas a\">vas a</span></td><td>you are going to</td><td><span data-say=\"vais a\">vais a</span></td><td>you all are going to</td></tr>\n              <tr><td><span data-say=\"va a\">va a</span></td><td>he/she is going to</td><td><span data-say=\"van a\">van a</span></td><td>they are going to</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy a estudiar en la universidad.\">Voy a estudiar en la universidad.</span> — <em>I am going to study at university.</em> Never drop the little word <strong>a</strong> — <span data-say=\"voy estudiar\">voy estudiar</span> is missing it and is wrong.</p>", "check": {"question": "What is wrong with ‘Voy estudiar mañana’?", "options": ["It is missing ‘a’ between voy and the infinitive", "It should not use the verb ‘ir’ at all here", "The infinitive ‘estudiar’ should be conjugated instead", "‘mañana’ must come before ‘voy’, not after it"], "answer": 0, "explain": "ir a + infinitive always needs ‘a’ linking the conjugated ir and the infinitive: voy a estudiar."}}, {"title": "How do I form the simple future for regular verbs?", "html": "<p>For regular verbs, add these endings to the <strong>whole infinitive</strong> — don’t remove -ar/-er/-ir first: <strong>-é, -ás, -á, -emos, -éis, -án</strong>. The same endings work for -ar, -er and -ir verbs.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaré\">hablaré</span></td><td>I will speak</td><td><span data-say=\"hablaremos\">hablaremos</span></td><td>we will speak</td></tr>\n              <tr><td><span data-say=\"comerás\">comerás</span></td><td>you will eat</td><td><span data-say=\"comeréis\">comeréis</span></td><td>you all will eat</td></tr>\n              <tr><td><span data-say=\"vivirá\">vivirá</span></td><td>he/she will live</td><td><span data-say=\"vivirán\">vivirán</span></td><td>they will live</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El año que viene, viviré en Madrid y estudiaré español.\">El año que viene, viviré en Madrid y estudiaré español.</span> — <em>Next year, I will live in Madrid and study Spanish.</em> Every future ending except <strong>-emos</strong> carries a written accent.</p>", "check": {"question": "Complete: ‘Mañana, tú ___ con el director.’ (you will speak)", "options": ["hablarás", "hablaras", "hablas", "hablarías"], "answer": 0, "explain": "hablarás is the future tú form — note the accented á. hablaras drops the accent, hablas is present tense, and hablarías is the CONDITIONAL, not future."}}, {"title": "Which verbs have an irregular stem in the future?", "html": "<p>A group of common verbs use a shortened or changed stem before the <strong>same endings</strong> (-é, -ás, -á, -emos, -éis, -án). Learn these:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"tendré\">tendré</span></td><td>I will have (tener)</td><td><span data-say=\"haré\">haré</span></td><td>I will do/make (hacer)</td></tr>\n              <tr><td><span data-say=\"podré\">podré</span></td><td>I will be able to (poder)</td><td><span data-say=\"saldré\">saldré</span></td><td>I will leave (salir)</td></tr>\n              <tr><td><span data-say=\"vendré\">vendré</span></td><td>I will come (venir)</td><td><span data-say=\"diré\">diré</span></td><td>I will say (decir)</td></tr>\n              <tr><td><span data-say=\"querré\">querré</span></td><td>I will want (querer)</td><td><span data-say=\"pondré\">pondré</span></td><td>I will put (poner)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El sábado, tendré que estudiar pero después saldré con mis amigos.\">El sábado, tendré que estudiar pero después saldré con mis amigos.</span> — <em>On Saturday I will have to study but afterwards I will go out with my friends.</em> Never write “tenerá” — the stem changes to <strong>tendr-</strong> before any future ending.</p>\n            <p>The same pattern applies to <span data-say=\"saber\">saber</span>: <span data-say=\"sabré\">sabré</span> (I will know) uses the stem <strong>sabr-</strong>. Example: <span data-say=\"No sabré la nota hasta el lunes.\">No sabré la nota hasta el lunes.</span> — <em>I won’t know the mark until Monday.</em></p>", "check": {"question": "Complete: ‘El sábado, ella ___ que estudiar.’ (she will have to)", "options": ["tendrá", "tenerá", "tiene", "tendría"], "answer": 0, "explain": "tener has the irregular future stem tendr-. ‘tenerá’ wrongly keeps the full infinitive stem, ‘tiene’ is present tense, and ‘tendría’ is the conditional, not future."}}, {"title": "How do I form the conditional? (would…)", "html": "<p>The conditional uses the <strong>same stem</strong> as the future (regular = whole infinitive; irregular = the same shortened stem), plus a different set of endings: <strong>-ía, -ías, -ía, -íamos, -íais, -ían</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hablaría\">hablaría</span></td><td>I would speak</td><td><span data-say=\"viviríamos\">viviríamos</span></td><td>we would live</td></tr>\n              <tr><td><span data-say=\"tendría\">tendría</span></td><td>I would have</td><td><span data-say=\"haría\">haría</span></td><td>I would do/make</td></tr>\n              <tr><td><span data-say=\"podría\">podría</span></td><td>I would be able to</td><td><span data-say=\"saldrías\">saldrías</span></td><td>you would leave</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Con más dinero, viajaría por el mundo y compraría una casa grande.\">Con más dinero, viajaría por el mundo y compraría una casa grande.</span> — <em>With more money, I would travel the world and buy a big house.</em> Every conditional ending carries a written accent.</p>\n            <p>These same irregular stems carry over into the conditional too: <span data-say=\"diría\">diría</span> (would say, decir), <span data-say=\"querría\">querría</span> (would want, querer), <span data-say=\"pondría\">pondría</span> (would put, poner), <span data-say=\"saldría\">saldría</span> (would leave, salir), <span data-say=\"vendría\">vendría</span> (would come, venir) and <span data-say=\"sabría\">sabría</span> (would know, saber). Example: <span data-say=\"Yo diría que sí, pero no sabría explicar por qué.\">Yo diría que sí, pero no sabría explicar por qué.</span> — <em>I would say yes, but I wouldn’t know how to explain why.</em></p>", "check": {"question": "Complete: ‘Con más tiempo, (yo) ___ más deporte.’ (I would do)", "options": ["haría", "haré", "hago", "harían"], "answer": 0, "explain": "haría is the conditional (would). haré is future (will), hago is present, and harían is conditional but for ‘ellos’ (they), not ‘yo’."}}, {"title": "How do I politely say what I would like? (me gustaría)", "html": "<p><span data-say=\"me gustaría\">me gustaría</span> (I would like) is one of the most useful exam phrases. It is the conditional of <strong>gustar</strong>, so it behaves just like <em>me gusta</em> and is followed by an infinitive.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me gustaría\">me gustaría</span></td><td>I would like</td><td><span data-say=\"te gustaría\">te gustaría</span></td><td>you would like</td></tr>\n              <tr><td><span data-say=\"le gustaría\">le gustaría</span></td><td>he/she would like</td><td><span data-say=\"nos gustaría\">nos gustaría</span></td><td>we would like</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Me gustaría estudiar en el extranjero después del instituto.\">Me gustaría estudiar en el extranjero después del instituto.</span> — <em>I would like to study abroad after school.</em> Like <em>me gusta</em>, it does not agree with what follows — it stays as ‘gustaría’, never ‘gustarían’, when followed by an infinitive.</p>", "check": {"question": "What must follow ‘me gustaría’ in a sentence like ‘me gustaría estudiar’?", "options": ["an infinitive, exactly like after me gusta", "a verb conjugated to agree with ‘yo’, like hago", "the word ‘que’ followed by a new subject", "a plural noun with no verb at all"], "answer": 0, "explain": "me gustaría + infinitive = I would like to do something, exactly like me gusta + infinitive (me gusta estudiar)."}}, {"title": "Higher: the perfect, pluperfect and an intro to the subjunctive", "html": "<p><span class=\"tier-h\">H</span> The <strong>perfect tense</strong> (have/has done) = present of <em>haber</em> + past participle: <span data-say=\"he estudiado\">he estudiado</span> (I have studied), <span data-say=\"ha comido\">ha comido</span> (he/she has eaten).</p>\n            <p>The <strong>pluperfect</strong> (had done) = imperfect of <em>haber</em> + past participle: <span data-say=\"había terminado\">había terminado</span> (I had finished) — used for something that had ALREADY happened before another past event.</p>\n            <p><span class=\"tier-h\">H</span> After certain trigger phrases like <span data-say=\"es importante que\">es importante que</span> (it’s important that) or a future-time <span data-say=\"cuando\">cuando</span> (when), Spanish switches to the <strong>present subjunctive</strong>: <span data-say=\"Es importante que estudies mucho.\">Es importante que estudies mucho.</span> (It’s important that you study a lot.) / <span data-say=\"Cuando llegue a casa, cenaré.\">Cuando llegue a casa, cenaré.</span> (When I get home, I will have dinner.)</p>\n            <p><span class=\"tier-h\">H</span> The <strong>conditional perfect</strong> (would have done) = conditional of <em>haber</em> + past participle: <span data-say=\"habría terminado\">habría terminado</span> (I would have finished) — used for what would have happened under a different past condition: <span data-say=\"Si hubiera estudiado más, habría aprobado el examen.\">Si hubiera estudiado más, habría aprobado el examen.</span> (If I had studied more, I would have passed the exam.)</p>", "check": {"question": "Which sentence correctly uses the present subjunctive after a trigger phrase?", "options": ["Es importante que estudies mucho", "Es importante que estudias mucho", "Es importante estudiar que mucho", "Estudiarás mucho, es importante"], "answer": 0, "explain": "‘es importante que’ + a change of subject triggers the subjunctive (estudies), not the ordinary present indicative (estudias)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "ir a + infinitivo", "definition": "near future: going to…"}, {"term": "voy a / vas a / va a", "definition": "I am / you are / he-she is going to"}, {"term": "hablaré", "definition": "I will speak"}, {"term": "comerás", "definition": "you will eat"}, {"term": "vivirá", "definition": "he/she will live"}, {"term": "tendré (tener)", "definition": "I will have"}, {"term": "haré (hacer)", "definition": "I will do / make"}, {"term": "podré (poder)", "definition": "I will be able to"}, {"term": "saldré (salir)", "definition": "I will leave / go out"}, {"term": "vendré (venir)", "definition": "I will come"}, {"term": "diré (decir)", "definition": "I will say"}, {"term": "hablaría", "definition": "I would speak"}, {"term": "tendría", "definition": "I would have"}, {"term": "me gustaría + infinitivo", "definition": "I would like to…"}, {"term": "he estudiado (H)", "definition": "I have studied"}, {"term": "había terminado (H)", "definition": "I had finished"}, {"term": "es importante que… (H)", "definition": "it’s important that… (+ subjunctive)"}, {"term": "cuando… (future time, H)", "definition": "when… (+ subjunctive)"}, {"term": "sabré (saber)", "definition": "I will know"}, {"term": "sabría (saber)", "definition": "I would know"}, {"term": "habría (haber, H)", "definition": "there would be / would have (+ participle)"}, {"term": "diría (decir)", "definition": "I/he-she would say"}, {"term": "querría (querer)", "definition": "I would want"}, {"term": "pondría (poner)", "definition": "I would put / me pondría = I would become"}, {"term": "saldría (salir)", "definition": "I would leave / go out"}, {"term": "vendría (venir)", "definition": "I would come"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Voy a estudiar esta noche.\" data-listen></span><br>Listen. What is the plan?", "options": ["To study tonight", "To study tomorrow morning instead", "To not study at all tonight", "I already studied last night"], "answer": 0, "explain": "‘voy a estudiar esta noche’ = I’m going to study tonight. The traps change the time, add a negative, or switch to the past."}, {"question": "<span data-say=\"Tendré que trabajar el sábado.\" data-listen></span><br>Listen. What is being said?", "options": ["I will have to work on Saturday", "I would have to work on Saturday", "I had to work last Saturday", "I don’t have to work on Saturday"], "answer": 0, "explain": "‘tendré que’ = I will have to (future). Trap B swaps it for the conditional (tendría), C for the past, D adds a negative."}, {"question": "Which is the correct future form of ‘vivir’ for ‘nosotros’?", "options": ["viviremos", "viviréis", "viviríamos", "vivimos"], "answer": 0, "explain": "The nosotros future ending is -emos → viviremos. viviréis is vosotros, viviríamos is conditional, vivimos is present."}, {"question": "Complete: ‘Si gano la lotería, ___ una casa nueva.’ (I would buy)", "options": ["compraría", "compraré", "compro", "comprarían"], "answer": 0, "explain": "compraría = I would buy (conditional). compraré is future, compro is present, comprarían is conditional but for ‘ellos’."}, {"question": "What does ‘me gustaría viajar a Japón’ mean?", "options": ["I would like to travel to Japan", "I am going to travel to Japan", "I travelled to Japan last year", "I like travelling, and Japan is nice"], "answer": 0, "explain": "me gustaría + infinitive = I would like to. B uses ir a, C is past tense, D breaks the phrase apart."}, {"question": "Which sentence correctly uses the irregular future stem for ‘hacer’?", "options": ["Mañana haré la tarea.", "Mañana haceré la tarea.", "Mañana hacía la tarea siempre.", "Mañana haría la tarea seguramente."], "answer": 0, "explain": "hacer → har- + é = haré. ‘haceré’ keeps the full infinitive wrongly, ‘hacía’ is imperfect, ‘haría’ is conditional."}, {"question": "<span data-say=\"Cuando tenga dieciocho años, aprenderé a conducir.\" data-listen></span><br>Listen. What will happen at 18?", "options": ["They will learn to drive", "They will buy a car", "They have already learned to drive", "They will not be allowed to drive"], "answer": 0, "explain": "‘aprenderé a conducir’ = I will learn to drive. The traps swap the action, the tense, or add a negative."}, {"question": "Complete: ‘Ellos ___ venir a la fiesta el viernes.’ (they will be able to)", "options": ["podrán", "poderán", "pueden", "podrían"], "answer": 0, "explain": "poder → podr- + án = podrán. ‘poderán’ wrongly keeps the infinitive stem, ‘pueden’ is present, ‘podrían’ is conditional."}, {"question": "Which sentence correctly uses the present subjunctive?", "options": ["Es importante que hagas los deberes.", "Es importante que haces los deberes.", "Es importante hacer que los deberes.", "Es importante harás los deberes pronto."], "answer": 0, "explain": "‘es importante que’ + new subject needs the subjunctive: hagas. B keeps the ordinary present, C and D are ungrammatical word orders."}, {"question": "What is the difference between ‘tendré’ and ‘tendría’?", "options": ["tendré = will have, tendría = would have", "tendré = would have, tendría = will have", "they mean exactly the same thing", "tendré is present tense, tendría is past tense"], "answer": 0, "explain": "The -é ending marks the future (will), the -ía ending marks the conditional (would) — same stem, different meaning."}, {"question": "Complete: ‘Yo ___ el resultado el viernes.’ (I will know)", "options": ["sabré", "sabría", "sé", "supe"], "answer": 0, "explain": "sabré is the future of saber (I will know) — sabría is the conditional (would know), sé is present, supe is preterite."}, {"question": "<span data-say=\"Sin tráfico, habría más tiempo para todo.\" data-listen></span><br>Listen. What does the sentence mean?", "options": ["There would be more time for everything", "There will certainly be more time for everything", "There was more time for everything", "There is more time for everything"], "answer": 0, "explain": "habría = there would be (impersonal conditional of haber, same family as hay/había/habrá). Trap B adds a false emphasis, C is imperfect (was), D is present (is)."}, {"question": "Complete: ‘Yo ___ que sí, pero no estoy segura.’ (I would say)", "options": ["diría", "diré", "decía", "dijo"], "answer": 0, "explain": "diría = would say (conditional of decir). diré is future, decía is imperfect (was saying), dijo is preterite (he/she said) for a different subject."}]}, "fib": {"enabled": true, "questions": [{"text": "Yo [voy] a estudiar esta noche. <span data-say=\"Yo voy a estudiar esta noche.\" data-listen>Yo voy a estudiar esta noche.</span>"}, {"text": "Mañana, ella [tendrá] que trabajar. <span data-say=\"Mañana, ella tendrá que trabajar.\" data-listen>Mañana, ella tendrá que trabajar.</span>"}, {"text": "El año que viene, (yo) [viviré] en Madrid. (I will live — vivir)"}, {"text": "Con más dinero, (nosotros) [compraríamos] una casa grande. (we would buy — comprar)"}, {"text": "Me [gustaría] viajar a Japón algún día. (I would like)"}, {"text": "[haré] los deberes antes de salir. (I will do — hacer, yo)"}, {"text": "Es importante que (tú) [estudies] mucho para el examen. (present subjunctive of estudiar)"}, {"text": "Yo [querría] un café, por favor. (I would like/want — querer, polite)"}, {"text": "Con un buen trabajo, (yo) me [pondría] muy contento. (I would become — ponerse)"}]}, "tf": {"enabled": true, "questions": [{"statement": "The near future (ir a + infinitive) is formed with a conjugated form of ‘ir’, then ‘a’, then an infinitive.", "answer": true, "explain": "voy a estudiar, vas a comer, va a salir — always ir + a + infinitive."}, {"statement": "The simple future removes -ar/-er/-ir before adding the endings, like the imperfect tense.", "answer": false, "explain": "Future endings attach to the WHOLE infinitive (hablar+é); it is the stem for irregular verbs that changes, not a rule about all verbs."}, {"statement": "‘tendré’, ‘haré’, ‘podré’ and ‘saldré’ all have irregular stems in the future.", "answer": true, "explain": "tener→tendr-, hacer→har-, poder→podr-, salir→saldr- — all irregular future stems."}, {"statement": "The conditional uses a completely different stem from the future for irregular verbs.", "answer": false, "explain": "The conditional reuses the SAME stem as the future (e.g. tendr-); only the endings change."}, {"statement": "‘me gustaría’ is followed by an infinitive, just like ‘me gusta’.", "answer": true, "explain": "me gustaría estudiar / me gustaría viajar — same pattern as me gusta + infinitive."}, {"statement": "Every future and conditional ending carries a written accent, except the ‘nosotros’ future form.", "answer": true, "explain": "hablaremos has no accent, but every other future/conditional ending does (é, ás, á, éis, án / ía, ías, ía, íamos, íais, ían)."}, {"statement": "‘Es importante que estudies’ uses the present subjunctive because of ‘que’ plus a change of subject after a trigger phrase.", "answer": true, "explain": "es importante que + new subject triggers the subjunctive: estudies."}, {"statement": "The perfect tense is formed with the PRETERITE of haber plus a past participle.", "answer": false, "explain": "The perfect uses the PRESENT of haber (he/has/ha/hemos/habéis/han) + past participle."}, {"statement": "‘saldría’ (I would leave/go out) is built from the same irregular stem as the future ‘saldré’, just with conditional endings.", "answer": true, "explain": "salir → saldr- is used for BOTH the future (saldré) and the conditional (saldría) — only the endings differ."}, {"statement": "‘vendría’ uses a regular conditional stem formed from the whole infinitive ‘venir’, unlike ‘saldría’.", "answer": false, "explain": "vendría is also IRREGULAR — venir → vendr- (the same irregular stem as the future vendré), not the regular infinitive stem."}]}, "misc": {"enabled": true, "items": [{"myth": "Voy estudiar esta noche.", "truth": "Voy a estudiar esta noche.", "check": {"question": "What is missing from ‘Voy estudiar esta noche’?", "options": ["the linking word ‘a’ (voy a estudiar)", "an accent on the final letter of ‘voy’", "the subject pronoun ‘yo’ at the start", "the word ‘esta’ before ‘noche’"], "answer": 0, "explain": "ir a + infinitive always needs ‘a’ between the conjugated ir and the infinitive."}}, {"myth": "Yo tenerá mucho dinero.", "truth": "Yo tendré mucho dinero.", "check": {"question": "Why is ‘tenerá’ wrong for the future of tener?", "options": ["tener has the irregular future stem tendr-, not tener-", "the ending should be -ería instead of the future ending -á", "‘tenerá’ is actually a correctly formed present-tense verb", "‘tenerá’ only needs an accent added on the very first e"], "answer": 0, "explain": "tener changes to the irregular stem tendr- before ANY future ending: tendré, tendrás, tendrá…"}}, {"myth": "Me gustaría estudio medicina.", "truth": "Me gustaría estudiar medicina.", "check": {"question": "Why is ‘Me gustaría estudio medicina’ wrong?", "options": ["‘gustaría’ must be followed by an infinitive, not a conjugated verb", "‘medicina’ should come before ‘gustaría’ at the start of the sentence", "‘me’ should be replaced with ‘yo’ at the front of the sentence", "‘gustaría’ should change to agree with ‘medicina’, becoming ‘gustarían’"], "answer": 0, "explain": "Like me gusta, me gustaría is followed by an infinitive: me gustaría estudiar."}}, {"myth": "Cuando llegaré a casa, cenaré.", "truth": "Cuando llegue a casa, cenaré.", "check": {"question": "Why does ‘cuando’ need the subjunctive here, not the future?", "options": ["‘cuando’ referring to a future event triggers the present subjunctive", "‘cuando’ is always followed by the preterite tense in absolutely every sentence", "‘llegaré’ is simply spelt incorrectly and needs an extra letter", "the second verb ‘cenaré’ should change too, to match the subjunctive"], "answer": 0, "explain": "A future-time ‘cuando’ clause takes the present subjunctive (llegue), while the main clause stays in the future (cenaré)."}}, {"myth": "Tendré muchas ganas de viajar si tuviera dinero.", "truth": "Tendría muchas ganas de viajar si tuviera dinero.", "check": {"question": "Why should ‘Tendré’ change to ‘Tendría’ here?", "options": ["a hypothetical ‘if I had…’ idea needs the conditional, not the future", "‘Tendré’ is missing the irregular stem tendr- at the very front", "‘viajar’ should be conjugated instead of being left as an infinitive here", "‘ganas’ needs to be made singular instead of staying plural"], "answer": 0, "explain": "A hypothetical ‘would’ idea needs the conditional (tendría), not the plain future (tendré)."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for tense endings", "html": "Future and conditional endings sound very similar — the difference is often just one syllable: hablará (future, he will speak) vs hablaría (conditional, he would speak). Listen carefully for the extra ‘-í-’ sound that marks the conditional.", "check": {"question": "You hear ‘…comería…’ rather than ‘…comerá…’. What does the extra syllable tell you?", "options": ["it is the conditional (would eat), not the future (will eat)", "it is simply a longer, more formal way of saying the same thing", "nothing changes — they mean exactly the same", "it must be a reflexive verb"], "answer": 0, "explain": "The -ía sound is the conditional marker (would); -á alone is the future marker (will)."}}, {"title": "Paper 3/4 — Grammar accuracy in reading and writing", "html": "Examiners reward accurate irregular stems (tendré, not tenerá) and the little word ‘a’ after ir (voy a…, not voy…). Build a checklist before you submit any future/conditional sentence.", "check": {"question": "Which sentence would lose an accuracy mark?", "options": ["Voy estudiar mañana por la tarde.", "Voy a estudiar mañana por la tarde.", "Mañana voy a estudiar por la tarde.", "Por la tarde, voy a estudiar mañana."], "answer": 0, "explain": "‘Voy estudiar’ is missing the essential ‘a’ — ir a + infinitive."}}, {"title": "Paper 4 — Higher writing: range of tenses", "html": "Top-band answers combine several tenses and structures in one paragraph: a plan (voy a…), a firm future (estudiaré…), a conditional wish (me gustaría…) and, for the very top, the perfect/pluperfect or a subjunctive after ‘es importante que…’.", "check": {"question": "Which answer shows the widest range of tenses for the top band?", "options": ["Voy a estudiar mucho, estudiaré todos los días y me gustaría ir a la universidad", "Estudio mucho y estudio todos los días y quiero ir a la universidad siempre también", "Voy a estudiar", "Estudiaré"], "answer": 0, "explain": "It combines the near future, simple future and conditional in one answer, showing range and accuracy rather than just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Put each verb into the tense shown in brackets. Write the <strong>full Spanish verb form</strong> only.<br>(a) estudiar (yo — future)<br>(b) tener (ella — future)<br>(c) poder (nosotros — conditional)<br>(d) hacer (tú — future)<br>(e) gustar (a mí — conditional, meaning ‘I would like’)", "marks": 5, "hint": "Regular future/conditional endings attach to the whole infinitive. tener and hacer have irregular stems (tendr-, har-) in BOTH the future and the conditional. ‘I would like’ = me gustaría.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: grammar)</h5><ul>\n                <li><strong>(a)</strong> estudiaré <em>(1)</em>.</li>\n                <li><strong>(b)</strong> tendrá <em>(1)</em>.</li>\n                <li><strong>(c)</strong> podríamos <em>(1)</em>.</li>\n                <li><strong>(d)</strong> harás <em>(1)</em>.</li>\n                <li><strong>(e)</strong> me gustaría <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent slips only if the verb form is otherwise unambiguous; missing the irregular stem (e.g. ‘hacerás’) loses the mark.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I am going to travel to Spain next summer.<br>(b) I will study a lot for the exams.<br>(c) I would like to work abroad because it would be a good experience.", "marks": 5, "hint": "(a) ir a + infinitive. (b) simple future of estudiar. (c) me gustaría + infinitive, then ‘sería’ (conditional of ser) for ‘it would be’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Voy a viajar a España el verano que viene. <em>(1)</em></li>\n                <li><strong>(b)</strong> Estudiaré mucho para los exámenes. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gustaría trabajar en el extranjero <em>(1)</em> porque <em>(1)</em> sería una buena experiencia <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. The irregular future/conditional stems must be recognisable to earn the mark.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', 'g-6-pronouns-negatives-and-connectors', 'G.6 Pronouns, Negatives and Connectors', '{"learn": {"enabled": true, "items": [{"title": "When do I use (or drop) subject pronouns?", "html": "<p>Subject pronouns are <span data-say=\"yo\">yo</span> (I), <span data-say=\"tú\">tú</span> (you), <span data-say=\"él\">él</span> / <span data-say=\"ella\">ella</span> (he/she), <span data-say=\"nosotros\">nosotros / nosotras</span> (we), <span data-say=\"vosotros\">vosotros / vosotras</span> (you all) and <span data-say=\"ellos\">ellos</span> / <span data-say=\"ellas\">ellas</span> (they).</p>\n            <p>Spanish verb endings already show <em>who</em> is doing the action, so subject pronouns are usually <strong>dropped</strong>: <span data-say=\"Hablo español.\">Hablo español.</span> (I speak Spanish) needs no ‘yo’.</p>\n            <p>Keep the pronoun only for <strong>emphasis or contrast</strong>: <span data-say=\"Yo prefiero el fútbol, pero él prefiere el baloncesto.\">Yo prefiero el fútbol, pero él prefiere el baloncesto.</span> — <em>I prefer football, but he prefers basketball.</em></p>", "check": {"question": "Why does Spanish often drop ‘yo’, ‘tú’, etc.?", "options": ["the verb ending already shows who is doing the action", "subject pronouns are considered rude in spoken Spanish", "subject pronouns only exist for plural forms", "Spanish sentences never contain a conjugated verb"], "answer": 0, "explain": "The verb ending (hablo, hablas, habla…) already tells you the subject, so the pronoun is optional unless you need emphasis or contrast."}}, {"title": "Direct object pronouns: lo, la, los, las", "html": "<p>Use a <strong>direct object pronoun</strong> to avoid repeating a noun you have just mentioned: <span data-say=\"lo\">lo</span> (him/it, masc.), <span data-say=\"la\">la</span> (her/it, fem.), <span data-say=\"los\">los</span> (them, masc.), <span data-say=\"las\">las</span> (them, fem.).</p>\n            <p>Position: put it <strong>before a conjugated verb</strong> — <span data-say=\"¿Tienes el libro?\">¿Tienes el libro?</span> <span data-say=\"Sí, lo tengo.\">Sí, lo tengo.</span> (Yes, I have it) — or <strong>attach it to an infinitive</strong>: <span data-say=\"Voy a verlo.\">Voy a verlo.</span> (I’m going to watch it).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"lo veo\">lo veo</span></td><td>I see him / it (masc.)</td></tr>\n              <tr><td><span data-say=\"la veo\">la veo</span></td><td>I see her / it (fem.)</td></tr>\n              <tr><td><span data-say=\"los veo\">los veo</span></td><td>I see them (masc.)</td></tr>\n              <tr><td><span data-say=\"las veo\">las veo</span></td><td>I see them (fem.)</td></tr>\n            </table>", "check": {"question": "Where does the direct object pronoun ‘lo’ go with a conjugated verb like ‘veo’?", "options": ["before the verb: lo veo", "after the verb with a gap: veo lo", "attached to the end of the conjugated verb: veolo", "it can never be used with a conjugated verb"], "answer": 0, "explain": "With a conjugated verb the pronoun goes immediately before it: lo veo. It only attaches to the END of an infinitive or gerund."}}, {"title": "Indirect object and reflexive pronouns", "html": "<p><strong>Indirect object pronouns</strong> (to/for whom) are <span data-say=\"me\">me</span>, <span data-say=\"te\">te</span>, <span data-say=\"le\">le</span>, <span data-say=\"nos\">nos</span>: <span data-say=\"Le doy el regalo a mi madre.\">Le doy el regalo a mi madre.</span> (I give the present to my mother.)</p>\n            <p><strong>Reflexive pronouns</strong> (me, te, se, nos, os, se) show the action is done <em>to yourself</em>: <span data-say=\"me levanto\">me levanto</span> (I get up), <span data-say=\"se levanta\">se levanta</span> (he/she gets up).</p>\n            <p><span class=\"tier-h\">H</span> When a direct AND indirect pronoun combine, ‘le’/‘les’ change to <strong>se</strong>: <span data-say=\"Se lo doy a mi hermano.\">Se lo doy a mi hermano.</span> — <em>I give it to my brother.</em></p>", "check": {"question": "Which set of pronouns is used for reflexive verbs like ‘levantarse’?", "options": ["me, te, se, nos, os, se", "lo, la, los, las", "que, quien, lo que", "muy, bastante, demasiado"], "answer": 0, "explain": "Reflexive verbs take me/te/se/nos/os/se, matching the subject doing the action to itself."}}, {"title": "Relative pronouns: que, quien, lo que", "html": "<p><span data-say=\"que\">que</span> (who/that/which) is the most common relative pronoun and works for <strong>both</strong> people and things: <span data-say=\"El chico que vive aquí es mi amigo.\">El chico que vive aquí es mi amigo.</span></p>\n            <p><span data-say=\"quien\">quien</span> / quienes <span class=\"tier-h\">H</span> means ‘who’ but is normally used only for people, especially after a preposition: <span data-say=\"la persona con quien hablo\">la persona con quien hablo</span> (the person I talk to).</p>\n            <p><span data-say=\"lo que\">lo que</span> <span class=\"tier-h\">H</span> means ‘what / that which’ — it refers to an <strong>idea</strong>, not one specific noun: <span data-say=\"Hago lo que quiero.\">Hago lo que quiero.</span> (I do what I want.)</p>", "check": {"question": "Which relative pronoun means ‘what/that which’ and refers to an idea rather than one noun?", "options": ["lo que", "que", "quien", "quienes"], "answer": 0, "explain": "‘lo que’ sums up a whole idea (‘what I want’), while ‘que’ and ‘quien(es)’ replace a specific noun."}}, {"title": "Negatives: nada, nunca, nadie, ni…ni", "html": "<p>Spanish uses a <strong>double negative</strong> — ‘no’ plus a negative word: <span data-say=\"no veo nada\">no veo nada</span> (I don’t see anything/I see nothing).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"no...nada\">no … nada</span></td><td>nothing</td></tr>\n              <tr><td><span data-say=\"no...nunca\">no … nunca</span> / <span data-say=\"jamás\">jamás</span></td><td>never</td></tr>\n              <tr><td><span data-say=\"no...nadie\">no … nadie</span></td><td>nobody</td></tr>\n              <tr><td><span data-say=\"no...ni...ni\">no … ni … ni</span></td><td>neither … nor</td></tr>\n            </table>\n            <p>Examples: <span data-say=\"no como nunca carne\">No como nunca carne.</span> (I never eat meat.) <span data-say=\"no hay nadie\">No hay nadie.</span> (There’s nobody.) <span data-say=\"no me gusta ni el fútbol ni el tenis\">No me gusta ni el fútbol ni el tenis.</span> (I like neither football nor tennis.)</p>\n            <p><span class=\"tier-h\">H</span> You can drop ‘no’ if the negative word comes BEFORE the verb: <span data-say=\"nunca voy al gimnasio\">Nunca voy al gimnasio.</span> (I never go to the gym.)</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"nada\">nada</span> and <span data-say=\"nadie\">nadie</span> can also stand ALONE as pronouns, with no ‘no’ at all, when they come before the verb: <span data-say=\"Nada es imposible.\">Nada es imposible.</span> (Nothing is impossible.) <span data-say=\"Nadie lo sabe.\">Nadie lo sabe.</span> (Nobody knows it.)</p>", "check": {"question": "How do you say ‘I don’t see anything’ correctly in Spanish?", "options": ["No veo nada.", "No veo.", "Veo nada.", "No veo algo."], "answer": 0, "explain": "Spanish needs the double negative: no + veo + nada. Dropping ‘nada’, dropping ‘no’, or using ‘algo’ (something) are all wrong."}}, {"title": "Connectors and intensifiers", "html": "<p>Basic connectors join ideas: <span data-say=\"y\">y</span> (and), <span data-say=\"pero\">pero</span> (but), <span data-say=\"porque\">porque</span> (because), <span data-say=\"también\">también</span> (also), <span data-say=\"además\">además</span> (furthermore).</p>\n            <p><span class=\"tier-h\">H</span> For top marks add: <span data-say=\"sin embargo\">sin embargo</span> (however) and <span data-say=\"aunque\">aunque</span> (although) — <span data-say=\"aunque\">aunque</span> introduces a <strong>contrast</strong>, unlike ‘además’ which adds an idea.</p>\n            <p>Intensifiers strengthen or soften an adjective: <span data-say=\"muy\">muy</span> (very), <span data-say=\"bastante\">bastante</span> (quite), <span data-say=\"demasiado\">demasiado</span> (too much/many), <span data-say=\"un poco\">un poco</span> (a bit).</p>\n            <p>Example: <span data-say=\"Me gusta el deporte, pero prefiero la música. Además, toco la guitarra. Sin embargo, no tengo mucho tiempo.\">Me gusta el deporte, pero prefiero la música. Además, toco la guitarra. Sin embargo, no tengo mucho tiempo.</span></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"sino\">sino</span> means \"but rather\" — use it instead of ‘pero’ after a negative when directly contrasting two things: <span data-say=\"No es rojo, sino azul.\">No es rojo, sino azul.</span> (It''s not red, but blue.)</p>", "check": {"question": "Which connector means ‘although’ and introduces a contrast?", "options": ["aunque", "porque", "también", "además"], "answer": 0, "explain": "‘aunque’ (although) signals a contrast; ‘porque’ gives a reason, and ‘también’/‘además’ add extra ideas rather than contrast them."}}, {"title": "Demonstratives: this/these, that/those, that (over there)", "html": "<p>Demonstratives show distance from the speaker. Spanish has three \"distances\": close (<span data-say=\"este\">este/esta</span>, this), middle (<span data-say=\"ese\">ese/esa</span>, that), and far (<span data-say=\"aquel\">aquel/aquella</span>, that … over there).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"estos libros\">estos libros</span></td><td>these books (masc., close)</td></tr>\n              <tr><td><span data-say=\"estas casas\">estas casas</span></td><td>these houses (fem., close)</td></tr>\n              <tr><td><span data-say=\"esos zapatos\">esos zapatos</span></td><td>those shoes (masc., middle distance)</td></tr>\n              <tr><td><span data-say=\"esas camisetas\">esas camisetas</span></td><td>those T-shirts (fem., middle distance)</td></tr>\n              <tr><td><span data-say=\"aquel edificio\">aquel edificio</span></td><td>that building over there (masc.)</td></tr>\n              <tr><td><span data-say=\"aquella montaña\">aquella montaña</span></td><td>that mountain over there (fem.)</td></tr>\n              <tr><td><span data-say=\"aquellos años\">aquellos años</span></td><td>those years (long ago/far, masc. pl.) <span class=\"tier-h\">H</span></td></tr>\n              <tr><td><span data-say=\"aquellas fotos\">aquellas fotos</span></td><td>those photos (far, fem. pl.) <span class=\"tier-h\">H</span></td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> When the word doesn''t point at one specific noun — just an idea or an unknown thing — Spanish uses the neuter forms <span data-say=\"esto\">esto</span> (this) and <span data-say=\"aquello\">aquello</span> (that): <span data-say=\"¿Qué es esto?\">¿Qué es esto?</span> (What is this?) <span data-say=\"Aquello que dijiste me sorprendió.\">Aquello que dijiste me sorprendió.</span> (That thing you said surprised me.)</p>", "check": {"question": "Which word means ‘this’ when you aren''t pointing at one specific noun, just an idea or unknown thing?", "options": ["esto", "estos", "estas", "aquellos"], "answer": 0, "explain": "‘esto’ is the neuter form used for an idea or unknown thing; ‘estos/estas’ agree with a specific masc./fem. noun, and ‘aquellos’ means ‘those’ far away."}}, {"title": "More prepositions: para, sin, hasta, desde", "html": "<p><span data-say=\"para\">para</span> means \"for\" or \"in order to\" — it points to a purpose, destination or recipient: <span data-say=\"Estudio para aprender.\">Estudio para aprender.</span> (I study in order to learn.) <span data-say=\"Este regalo es para ti.\">Este regalo es para ti.</span> (This present is for you.)</p>\n            <p><span data-say=\"sin\">sin</span> means \"without\": <span data-say=\"sin duda\">sin duda</span> (without doubt), <span data-say=\"Salió sin comer.\">Salió sin comer.</span> (He/she left without eating.)</p>\n            <p><span data-say=\"hasta\">hasta</span> means \"until\", \"up to\" or \"even\": <span data-say=\"hasta luego\">hasta luego</span> (see you later), <span data-say=\"Trabajé hasta las diez.\">Trabajé hasta las diez.</span> (I worked until ten.)</p>\n            <p><span data-say=\"desde\">desde</span> means \"from\" or \"since\": <span data-say=\"Vivo aquí desde 2020.\">Vivo aquí desde 2020.</span> (I''ve lived here since 2020.) <span data-say=\"desde mi casa\">desde mi casa</span> (from my house).</p>", "check": {"question": "Which preposition means ‘since’ or ‘from’ (a point in time or place)?", "options": ["desde", "hasta", "sin", "para"], "answer": 0, "explain": "‘desde’ = since/from a starting point; ‘hasta’ = until/up to an end point, ‘sin’ = without, and ‘para’ = for/in order to."}}, {"title": "otro, alguno, ninguno — another, some, none", "html": "<p><span data-say=\"otro\">otro</span> / otra means \"another\" or \"other\" — unlike English, Spanish never puts ‘un/una’ before it: <span data-say=\"otro día\">otro día</span> (another day), NOT \"un otro día\".</p>\n            <p><span data-say=\"alguno\">alguno</span> shortens to <span data-say=\"algún\">algún</span> before a masculine singular noun: <span data-say=\"algún día\">algún día</span> (some day). As a pronoun it means \"someone/some (of them)\": <span data-say=\"¿Tienes alguna idea? Sí, tengo alguna.\">¿Tienes alguna idea? Sí, tengo alguna.</span> (Do you have an idea? Yes, I have one.)</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"ninguno\">ninguno</span> shortens to <span data-say=\"ningún\">ningún</span> before a masculine singular noun and means \"no/not any\": <span data-say=\"No tengo ningún problema.\">No tengo ningún problema.</span> (I don''t have any problem.) As a pronoun: <span data-say=\"¿Tienes hermanos? No, no tengo ninguno.\">¿Tienes hermanos? No, no tengo ninguno.</span> (Do you have siblings? No, I don''t have any.)</p>", "check": {"question": "How do you say ‘I don''t have any problem’ correctly?", "options": ["No tengo ningún problema.", "No tengo otro problema.", "Tengo ningún problema.", "No tengo alguno problema."], "answer": 0, "explain": "‘ningún’ shortens before a masc. singular noun and needs ‘no’ before the verb. Option C drops ‘no’, and option D wrongly keeps the full form ‘alguno’ instead of ‘ningún’, giving the wrong meaning too."}}, {"title": "Possessive pronouns: el mío, el tuyo, el suyo, el nuestro, el vuestro", "html": "<p>Possessive pronouns replace \"mi coche\" with just \"mine\" — they agree with the noun they replace in gender and number, and usually take an article (el/la/los/las).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el mío\">el mío</span> / la mía</td><td>mine</td></tr>\n              <tr><td><span data-say=\"el tuyo\">el tuyo</span> / la tuya</td><td>yours (tú)</td></tr>\n              <tr><td><span data-say=\"el suyo\">el suyo</span> / la suya</td><td>his / hers / theirs / yours (usted)</td></tr>\n              <tr><td><span data-say=\"el nuestro\">el nuestro</span> / la nuestra</td><td>ours</td></tr>\n              <tr><td><span data-say=\"el vuestro\">el vuestro</span> / la vuestra</td><td>yours (vosotros)</td></tr>\n            </table>\n            <p>Examples: <span data-say=\"Tu casa es grande; la mía es pequeña.\">Tu casa es grande; la mía es pequeña.</span> (Your house is big; mine is small.) <span data-say=\"Vuestro coche es azul; el nuestro es rojo.\">Vuestro coche es azul; el nuestro es rojo.</span> (Your car is blue; ours is red.)</p>\n            <p><span class=\"tier-h\">H</span> Don''t confuse the possessive pronoun (<span data-say=\"el vuestro\">el vuestro</span> = yours) with the possessive determiner <span data-say=\"vuestro coche\">vuestro coche</span> (your car), which goes directly before the noun with no article.</p>", "check": {"question": "Which possessive pronoun means ‘mine’, replacing a feminine noun like ‘la casa’?", "options": ["la mía", "el mío", "la tuya", "la nuestra"], "answer": 0, "explain": "‘la mía’ agrees with a feminine noun and means ‘mine’. ‘el mío’ is masculine, and ‘la tuya’/‘la nuestra’ mean ‘yours’/‘ours’."}}, {"title": "el que / el cual — advanced relative pronouns", "html": "<p><span data-say=\"el que\">el que</span> / la que / los que / las que means \"the one(s) who/that\" — it refers back to a person or thing without repeating the noun: <span data-say=\"De todos los libros, el que más me gustó fue éste.\">De todos los libros, el que más me gustó fue éste.</span> (Of all the books, the one I liked most was this one.)</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"el cual\">el cual</span> / la cual / los cuales / las cuales is a more formal version of \"que\", used especially straight after a preposition to avoid confusion: <span data-say=\"La empresa para la cual trabajo es española.\">La empresa para la cual trabajo es española.</span> (The company for which I work is Spanish.)</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"los demás\">los demás</span> / las demás means \"the others\" or \"the rest\": <span data-say=\"Yo terminé, pero los demás todavía trabajan.\">Yo terminé, pero los demás todavía trabajan.</span> (I finished, but the others are still working.)</p>", "check": {"question": "What does ‘los demás’ mean in ‘Yo terminé, pero los demás todavía trabajan’?", "options": ["the others", "everyone, no exceptions", "none of them", "some of them"], "answer": 0, "explain": "‘los demás’ = the others/the rest of the group, unlike ‘todos’ (everyone), ‘ninguno’ (none) or ‘algunos’ (some)."}}, {"title": "Numbers: teens, tens, hundreds and thousands", "html": "<p>Some higher numbers need extra care with spelling and gender agreement.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"doce\">doce</span></td><td>12 — twelve</td></tr>\n              <tr><td><span data-say=\"diecisiete\">diecisiete</span></td><td>17 — seventeen</td></tr>\n              <tr><td><span data-say=\"diecinueve\">diecinueve</span></td><td>19 — nineteen</td></tr>\n              <tr><td><span data-say=\"veinte\">veinte</span></td><td>20 — twenty (veinti- before 21–29: veintiuno)</td></tr>\n              <tr><td><span data-say=\"sesenta\">sesenta</span></td><td>60 — sixty</td></tr>\n              <tr><td><span data-say=\"setenta\">setenta</span></td><td>70 — seventy</td></tr>\n              <tr><td><span data-say=\"ochenta\">ochenta</span></td><td>80 — eighty</td></tr>\n              <tr><td><span data-say=\"cien, ciento\">cien / ciento</span></td><td>100 — cien alone/before a noun; ciento inside a bigger number (ciento cincuenta = 150)</td></tr>\n              <tr><td><span data-say=\"setecientos\">setecientos</span></td><td>700 — seven hundred (agrees: setecientas personas)</td></tr>\n              <tr><td><span data-say=\"novecientos\">novecientos</span></td><td>900 — nine hundred (agrees: novecientas personas)</td></tr>\n              <tr><td><span data-say=\"mil\">mil</span></td><td>1.000 — a thousand (never \"un mil\")</td></tr>\n              <tr><td><span data-say=\"millón\">millón</span></td><td>1.000.000 — a million (needs \"de\": un millón de euros)</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> Hundreds agree in gender with the noun: <span data-say=\"setecientas personas\">setecientas personas</span> (700 people, fem.) but <span data-say=\"setecientos euros\">setecientos euros</span> (700 euros, masc.).</p>", "check": {"question": "Which number word never takes ‘un’ in front of it, unlike English ‘a thousand’?", "options": ["mil", "millón", "ciento", "cien"], "answer": 0, "explain": "Spanish just says ‘mil’ (a/one thousand), never ‘un mil’. ‘millón’ DOES need ‘un’ (un millón), and ‘cien/ciento’ work differently again."}}, {"title": "Question words and ‘with you’: cuánto, contigo", "html": "<p><span data-say=\"¿cuánto?\">¿cuánto?</span> / ¿cuánta? / ¿cuántos? / ¿cuántas? means \"how much/how many\" and agrees with the noun: <span data-say=\"¿Cuánto cuesta?\">¿Cuánto cuesta?</span> (How much does it cost?) <span data-say=\"¿Cuántos hermanos tienes?\">¿Cuántos hermanos tienes?</span> (How many siblings do you have?)</p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"contigo\">contigo</span> is a special contraction of \"con + ti\" meaning \"with you\" (informal singular) — it doesn''t follow the usual \"con + pronoun\" pattern: <span data-say=\"¿Puedo ir contigo?\">¿Puedo ir contigo?</span> (Can I go with you?) The equivalent for \"with me\" is <span data-say=\"conmigo\">conmigo</span>.</p>", "check": {"question": "How do you say ‘Can I go with you?’ to a friend, using the special contraction for ‘con + ti’?", "options": ["¿Puedo ir contigo?", "¿Puedo ir con tigo?", "¿Puedo ir con tú?", "¿Puedo ir sin ti?"], "answer": 0, "explain": "‘con + ti’ contracts irregularly to one word, ‘contigo’. Option B wrongly splits it into two words, option C uses the subject pronoun ‘tú’ instead of ‘ti’, and option D means ‘without you’."}}]}, "terms": {"enabled": true, "pairs": [{"term": "lo", "definition": "him / it (masculine)"}, {"term": "la", "definition": "her / it (feminine)"}, {"term": "los", "definition": "them (masculine)"}, {"term": "las", "definition": "them (feminine)"}, {"term": "me", "definition": "to/for me · myself (reflexive)"}, {"term": "te", "definition": "to/for you · yourself (reflexive)"}, {"term": "se", "definition": "himself / herself / themselves (reflexive)"}, {"term": "que", "definition": "who, that, which"}, {"term": "quien (H)", "definition": "who (after a preposition)"}, {"term": "lo que (H)", "definition": "what, that which"}, {"term": "no … nada", "definition": "nothing"}, {"term": "no … nunca", "definition": "never"}, {"term": "no … nadie", "definition": "nobody"}, {"term": "no … ni … ni", "definition": "neither … nor"}, {"term": "sin embargo (H)", "definition": "however"}, {"term": "aunque (H)", "definition": "although"}, {"term": "además", "definition": "furthermore, also"}, {"term": "un poco", "definition": "a bit"}, {"term": "el que / la que (H)", "definition": "the one who / that"}, {"term": "para", "definition": "for, in order to"}, {"term": "estos, estas", "definition": "these"}, {"term": "esos, esas", "definition": "those"}, {"term": "otro", "definition": "another, other"}, {"term": "algún, alguno", "definition": "some, any (determiner)"}, {"term": "alguno (pronoun)", "definition": "someone, some (of them)"}, {"term": "sin", "definition": "without"}, {"term": "hasta", "definition": "until, up to"}, {"term": "desde", "definition": "from, since"}, {"term": "el nuestro, la nuestra (H)", "definition": "ours"}, {"term": "nada (alone)", "definition": "nothing (used without ‘no’ before the verb)"}, {"term": "esto", "definition": "this (an idea/unknown thing, not a specific noun)"}, {"term": "aquel, aquella (H)", "definition": "that (over there)"}, {"term": "aquellos, aquellas (H)", "definition": "those (over there)"}, {"term": "sino (H)", "definition": "but rather"}, {"term": "el cual, la cual (H)", "definition": "which, who (formal)"}, {"term": "mil", "definition": "a thousand"}, {"term": "nadie (alone)", "definition": "nobody, no one (used without ‘no’ before the verb)"}, {"term": "millón", "definition": "a million"}, {"term": "ningún, ninguno", "definition": "no, not any (determiner)"}, {"term": "ninguno (pronoun)", "definition": "none, not one"}, {"term": "los demás, las demás (H)", "definition": "the others, the rest"}, {"term": "¿cuánto?, ¿cuánta?", "definition": "how much?"}, {"term": "el mío, la mía (H)", "definition": "mine"}, {"term": "veinte", "definition": "twenty"}, {"term": "el suyo, la suya (H)", "definition": "his, hers, theirs"}, {"term": "aquello (H)", "definition": "that (an idea/unknown thing)"}, {"term": "doce", "definition": "twelve"}, {"term": "sesenta", "definition": "sixty"}, {"term": "el tuyo, la tuya (H)", "definition": "yours (tú)"}, {"term": "el vuestro, la vuestra (H)", "definition": "yours (vosotros)"}, {"term": "vuestro", "definition": "your (vosotros, before a noun)"}, {"term": "setenta", "definition": "seventy"}, {"term": "ochenta", "definition": "eighty"}, {"term": "contigo (H)", "definition": "with you"}, {"term": "diecisiete", "definition": "seventeen"}, {"term": "diecinueve", "definition": "nineteen"}, {"term": "cien, ciento", "definition": "a hundred"}, {"term": "novecientos", "definition": "nine hundred"}, {"term": "setecientos", "definition": "seven hundred"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"No veo nada.\" data-listen></span><br>Listen. What does she say?", "options": ["I don''t see anything", "I never see anything", "I don''t see anybody", "I always see everything"], "answer": 0, "explain": "‘No veo nada’ = I don''t see anything. The traps swap nada→nunca, nada→nadie, or reverse the negative entirely."}, {"question": "<span data-say=\"Se lo doy a mi hermano.\" data-listen></span><br>Listen. What is being described?", "options": ["I give it to my brother", "I give it to my sister", "I gave it to my brother yesterday", "I never give it to my brother"], "answer": 0, "explain": "‘Se lo doy a mi hermano’ = I give it to my brother (se lo = le + lo). Traps swap the gender, the tense, or add a negative."}, {"question": "Complete: ‘¿Tienes las llaves? Sí, ___ tengo.’", "options": ["las", "los", "la", "le"], "answer": 0, "explain": "‘las llaves’ is feminine plural, so the pronoun must be ‘las’. The others fail to agree in gender/number or are the wrong pronoun type."}, {"question": "Which sentence means ‘I speak Spanish’ and drops the unneeded pronoun, as native speakers usually do?", "options": ["Hablo español.", "Yo hablo español todos los días.", "Habla español.", "Hablas español."], "answer": 0, "explain": "‘Hablo español’ already shows ‘I’ through the verb ending — no pronoun needed. C and D conjugate for the wrong person."}, {"question": "Complete: ‘(Yo) ___ levanto a las siete.’", "options": ["me", "te", "se", "nos"], "answer": 0, "explain": "‘(Yo) me levanto’ — the reflexive pronoun must match the subject ‘yo’. The others are for a different person."}, {"question": "Complete: ‘La chica ___ vive al lado es mi vecina.’ (who/that)", "options": ["que", "quien", "lo que", "cual"], "answer": 0, "explain": "‘que’ links a noun (la chica) to extra information. ‘quien’ needs a preposition, ‘lo que’ refers to an idea, and ‘cual’ needs an article."}, {"question": "How do you say ‘There is nobody here’?", "options": ["No hay nadie aquí.", "Hay nadie aquí.", "No hay alguien aquí.", "No hay nada aquí."], "answer": 0, "explain": "‘No hay nadie aquí’ needs the double negative. B drops ‘no’; C wrongly pairs ‘no’ with ‘alguien’ (someone); D confuses nadie (nobody) with nada (nothing)."}, {"question": "Complete: ‘No voy a la fiesta ___ tengo mucha tarea.’ (because)", "options": ["porque", "aunque", "pero", "también"], "answer": 0, "explain": "‘porque’ gives the reason. ‘aunque’ (although) reverses the logic, ‘pero’ (but) and ‘también’ (also) don''t fit a cause."}, {"question": "Which best translates ‘un poco cansado’?", "options": ["a bit tired", "extremely tired", "never tired", "the most tired of all"], "answer": 0, "explain": "‘un poco’ softens the adjective to ‘a bit’. The distractors overstate it, negate it, or turn it into a superlative."}, {"question": "How do you say ‘I see it’, referring to ‘la película’ (feminine)?", "options": ["La veo.", "Veo la.", "Lo veo.", "La veo mucho."], "answer": 0, "explain": "‘la película’ is feminine, so the pronoun ‘la’ goes before the verb: La veo. B puts it after; C uses the wrong gender; D adds a meaning-changing ‘mucho’."}, {"question": "Complete: ‘De todos los coches, ___ más me gusta es éste.’ (the one that)", "options": ["el que", "el cual", "lo que", "el mío"], "answer": 0, "explain": "‘el que’ refers back to ‘el coche’ already understood from context. ‘el cual’ is more formal, ‘lo que’ refers to an idea rather than one noun, and ‘el mío’ means ‘mine’."}, {"question": "Complete: ‘Estudio mucho ___ aprender español.’ (in order to)", "options": ["para", "por", "sin", "desde"], "answer": 0, "explain": "‘para + infinitive’ expresses purpose (in order to). ‘por’ often gives a reason/cause instead, ‘sin’ means without, and ‘desde’ means since/from."}, {"question": "How do you say ‘another day’ correctly in Spanish?", "options": ["otro día", "un otro día", "otro día más", "el otro día"], "answer": 0, "explain": "Spanish never puts ‘un’ before ‘otro’ (never ‘un otro día’). ‘el otro día’ means ‘the other day’ (a different meaning), and ‘otro día más’ adds an unnecessary ‘more’."}, {"question": "Complete: ‘¿Vas a ir ___ día a España?’ (some day)", "options": ["algún", "alguno", "ninguno", "otro"], "answer": 0, "explain": "‘alguno’ shortens to ‘algún’ before a masculine singular noun like ‘día’. ‘ninguno’ means ‘no/not any’ (opposite meaning), and ‘otro’ means ‘another’."}, {"question": "Complete: ‘Llegó ___ decir nada.’ (without saying anything)", "options": ["sin", "con", "desde", "hasta"], "answer": 0, "explain": "‘sin + infinitive’ = without doing something. ‘con’ means with, ‘desde’ means since/from, and ‘hasta’ means until."}, {"question": "Complete: ‘Trabajé ___ las diez de la noche.’ (until)", "options": ["hasta", "desde", "para", "sin"], "answer": 0, "explain": "‘hasta’ = until/up to a point in time. ‘desde’ means since/from (the opposite direction), ‘para’ means for/in order to, and ‘sin’ means without."}, {"question": "Complete: ‘Vuestro coche es azul; ___ es rojo.’ (ours)", "options": ["el nuestro", "el vuestro", "el suyo", "el mío"], "answer": 0, "explain": "‘el nuestro’ = ours, matching ‘coche’ (masc.). ‘el vuestro’ would repeat ‘yours’, ‘el suyo’ = his/hers/theirs, and ‘el mío’ = mine."}, {"question": "Which word means ‘that (over there)’, far from both speaker and listener?", "options": ["aquel", "aquellos", "esos", "estos"], "answer": 0, "explain": "‘aquel’ = that (over there), far from both people. ‘aquellos’ is the plural form of the same word, ‘esos’ = those (middle distance), and ‘estos’ = these (close)."}, {"question": "Complete: ‘No quiero té, ___ café.’ (but rather)", "options": ["sino", "pero", "aunque", "además"], "answer": 0, "explain": "After a negative, use ‘sino’ (not ‘pero’) to contrast two things directly. ‘aunque’ means although, and ‘además’ means furthermore."}, {"question": "Complete: ‘La empresa para ___ trabajo es española.’ (which — formal, after a preposition)", "options": ["la cual", "que", "quienes", "la que"], "answer": 0, "explain": "After a preposition, formal Spanish prefers ‘la cual’, agreeing with ‘la empresa’. Bare ‘que’ sounds too casual here, ‘quienes’ is plural and for people, and ‘la que’ is also possible but less common in this formal register."}, {"question": "Complete: ‘¿___ cuesta el billete?’ (how much)", "options": ["cuánto", "cuántos", "cuántas", "cuánta"], "answer": 0, "explain": "‘cuánto’ is the default (uninflected) form asking about an amount/price. ‘cuántos/cuántas’ agree with a plural noun, and ‘cuánta’ is feminine singular — none fit here since there''s no noun to agree with."}, {"question": "Complete: ‘Tu libro está aquí; ¿dónde está ___?’ (mine)", "options": ["el mío", "el tuyo", "el suyo", "el nuestro"], "answer": 0, "explain": "‘el mío’ = mine. ‘el tuyo’ = yours, ‘el suyo’ = his/hers/theirs, and ‘el nuestro’ = ours."}, {"question": "How do you write 21 correctly in Spanish (one word)?", "options": ["veintiuno", "veinte y uno", "veinte uno", "veintiúno"], "answer": 0, "explain": "21 is written as one word: veintiuno. Writing it as three separate words (‘veinte y uno’) is the old-fashioned style, and ‘veinte uno’ is missing the ‘y’ entirely."}, {"question": "Complete: ‘¿Tienes hermanos? No, no tengo ___.’ (any/none)", "options": ["ninguno", "algunos", "otro más", "todos ellos"], "answer": 0, "explain": "‘ninguno’ = none/not any, matching a previously mentioned masc. noun (hermanos). ‘algunos’ = some, ‘otro más’ = one more/another, and ‘todos ellos’ = all of them — the opposite meaning."}, {"question": "How do you say ‘a million euros’ correctly?", "options": ["un millón de euros", "cien mil euros exactos", "un millón euros", "mil euros solamente"], "answer": 0, "explain": "‘un millón’ needs ‘de’ before the noun: un millón de euros. Omitting ‘de’ (option 3) is a common mistake. ‘cien mil’ means 100,000, and ‘mil euros solamente’ just means ‘a thousand euros only’."}]}, "fib": {"enabled": true, "questions": [{"text": "¿Tienes el libro? Sí, [lo] tengo. (it — masculine, direct object pronoun)"}, {"text": "No veo [nada]. <span data-say=\"No veo nada.\" data-listen>No veo nada.</span>"}, {"text": "Voy a hacer más ejercicio, [porque] es bueno para la salud. (because)"}, {"text": "(Yo) [me] levanto a las siete. (myself — reflexive pronoun)"}, {"text": "La chica [que] vive aquí es mi amiga. (who/that)"}, {"text": "No voy [nunca] al gimnasio los domingos. (never)"}, {"text": "Juego al fútbol y, [además], hago natación. (also/furthermore)"}, {"text": "Dicen que [nada] es imposible. (nothing — used alone, no ‘no’ needed)"}, {"text": "Llamé a la puerta, pero [nadie] contestó. (nobody — used alone, no ‘no’ needed)"}, {"text": "Me encantan [estos] zapatos nuevos. (these — masculine)"}, {"text": "No me gustan [esas] camisetas. (those — feminine, middle distance)"}, {"text": "El coche cuesta [mil] euros. (a thousand)"}, {"text": "Hay [doce] meses en un año. (twelve)"}, {"text": "Mi abuela tiene [sesenta] años. (sixty)"}, {"text": "Mi hermano tiene [diecisiete] años. (seventeen)"}, {"text": "En el pueblo viven [novecientas] personas. (nine hundred — agrees with ‘personas’, feminine)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Spanish usually drops subject pronouns like ‘yo’ and ‘tú’ because the verb ending shows who is speaking.", "answer": true, "explain": "Hablo español needs no ‘yo’ — the -o ending already shows it."}, {"statement": "‘lo’ and ‘la’ are indirect object pronouns.", "answer": false, "explain": "‘lo’ and ‘la’ are DIRECT object pronouns; ‘le’ and ‘les’ are indirect."}, {"statement": "A direct object pronoun can attach to the end of an infinitive, e.g. ‘voy a verlo’.", "answer": true, "explain": "voy a verlo = I''m going to watch it, with ‘lo’ attached to the infinitive."}, {"statement": "Reflexive pronouns are only used in the plural.", "answer": false, "explain": "Reflexive pronouns exist for every person: me, te, se, nos, os, se."}, {"statement": "‘que’ can refer to both people and things.", "answer": true, "explain": "El chico que vive aquí… / El libro que compré… — que works for both."}, {"statement": "‘lo que’ means ‘the’ and goes before every noun.", "answer": false, "explain": "‘lo que’ means ‘what/that which’ and refers to a whole idea, not a single noun."}, {"statement": "Spanish uses a double negative, e.g. ‘no veo nada’.", "answer": true, "explain": "‘no’ plus a negative word (nada, nunca, nadie…) is the normal Spanish pattern."}, {"statement": "‘sin embargo’ and ‘aunque’ are examples of negatives.", "answer": false, "explain": "They are CONNECTORS (however / although), not negatives."}, {"statement": "‘otro’ can be preceded by ‘un/una’ in Spanish, e.g. ‘un otro día’.", "answer": false, "explain": "Spanish never uses ‘un/una’ before ‘otro’ — just ‘otro día’."}, {"statement": "‘alguno’ shortens to ‘algún’ before a masculine singular noun.", "answer": true, "explain": "algún día, algún amigo — the final -o drops before a masc. singular noun."}, {"statement": "‘estos’ and ‘esos’ show exactly the same distance from the speaker.", "answer": false, "explain": "‘estos’ = close to the speaker (these); ‘esos’ = a bit further away (those)."}, {"statement": "‘contigo’ is written as two separate words: ‘con tigo’.", "answer": false, "explain": "‘contigo’ is always one word — it''s an irregular contraction of con + ti."}, {"statement": "Hundreds like ‘setecientos’ and ‘novecientos’ change to agree with a feminine noun.", "answer": true, "explain": "setecientas personas, novecientas páginas — hundreds (200+) agree in gender, unlike smaller numbers."}, {"statement": "‘mil’ can be written with ‘un’ in front of it, like English ‘a thousand’ → ‘un mil’.", "answer": false, "explain": "Spanish just says ‘mil’ on its own — never ‘un mil’."}, {"statement": "‘sino’ is used instead of ‘pero’ after a negative, to contrast two things directly.", "answer": true, "explain": "No es rojo, sino azul — ‘sino’ replaces ‘pero’ after ‘no’ when directly contrasting."}]}, "misc": {"enabled": true, "items": [{"myth": "Veo lo.", "truth": "Lo veo.", "check": {"question": "Why is ‘Veo lo’ wrong?", "options": ["the object pronoun must go BEFORE a conjugated verb (Lo veo)", "the pronoun ‘lo’ should be ‘la’ instead", "the verb ‘veo’ is spelt incorrectly", "object pronouns can never be used with a conjugated verb like ‘veo’, only with an infinitive such as ‘ver’"], "answer": 0, "explain": "With a conjugated verb the pronoun comes before it; it only attaches after an infinitive or gerund."}}, {"myth": "Yo yo hablo español.", "truth": "Hablo español.", "check": {"question": "What’s wrong with doubling the pronoun in ‘Yo yo hablo’?", "options": ["the subject pronoun only needs using once, or can be dropped, since the verb ending shows ‘yo’", "‘yo’ must always be repeated twice in a row for extra emphasis in every single Spanish sentence you write", "‘hablo’ needs two subject pronouns to agree", "Spanish verbs cannot be used without two pronouns"], "answer": 0, "explain": "‘Hablo’ already carries the meaning of ‘yo’; one pronoun (or none) is correct, never a double."}}, {"myth": "El libro quien compré es interesante.", "truth": "El libro que compré es interesante.", "check": {"question": "Why is ‘el libro quien compré’ wrong?", "options": ["‘quien’ only refers to people, not things — things need ‘que’", "‘quien’ must always follow the word ‘lo’ before any noun or pronoun", "‘compré’ should be changed to ‘compro’", "‘libro’ needs a written accent on the final syllable"], "answer": 0, "explain": "‘quien/quienes’ refers to people; a thing like ‘el libro’ needs ‘que’."}}, {"myth": "No veo.", "truth": "No veo nada.", "check": {"question": "Why is ‘No veo’ alone not correct for ‘I don’t see anything’?", "options": ["Spanish needs the double negative: no + veo + nada", "‘veo’ on its own already means ‘nothing’ without adding any other word", "‘no’ on its own already means ‘nothing’", "you should never use ‘no’ together with ‘ver’"], "answer": 0, "explain": "Without ‘nada’, ‘No veo’ just means ‘I don’t see’ — it is missing what you don’t see."}}, {"myth": "Me gusta el deporte, aunque prefiero la música.", "truth": "Me gusta el deporte, además prefiero la música.", "check": {"question": "What’s the problem with ‘aunque’ here if you mean ‘as well as that’?", "options": ["‘aunque’ means ‘although’ and introduces a contrast, not an addition", "‘aunque’ is spelt incorrectly and should not appear anywhere in the sentence", "‘aunque’ can only be used to start a question", "‘aunque’ is one of the negative words like ‘nada’"], "answer": 0, "explain": "‘aunque’ signals a contrast (although); to ADD an idea you need ‘además’ or ‘también’."}}, {"myth": "Voy a leer un otro libro.", "truth": "Voy a leer otro libro.", "check": {"question": "Why is ‘un otro libro’ wrong?", "options": ["Spanish never puts ‘un/una’ before ‘otro’ — just ‘otro libro’", "‘otro’ must always come immediately after the noun it describes, never before it", "‘libro’ should be plural in this sentence", "‘un’ should be replaced with ‘el’ before ‘otro’"], "answer": 0, "explain": "‘otro’ already means ‘another’, so it never takes ‘un/una’ in front — ‘otro libro’ is correct on its own."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening: pronouns and negatives in context", "html": "Listen for whether the object pronoun is ‘lo/la’ (singular) or ‘los/las’ (plural), and for the negative word right after ‘no’ — ‘nada’, ‘nunca’ or ‘nadie’ completely change the meaning even though they sound similar.", "check": {"question": "You hear ‘no … nadie’. What does that tell you?", "options": ["nobody is involved", "nothing at all happened", "the action never happens", "everything is fine"], "answer": 0, "explain": "‘no … nadie’ = nobody, not ‘nada’ (nothing) or ‘nunca’ (never)."}}, {"title": "Paper 3 — Reading: relative pronouns link ideas", "html": "Long reading texts use ‘que’, ‘quien’ and ‘lo que’ to join sentences. Track WHO or WHAT each pronoun refers back to — that noun is usually a few words earlier in the sentence.", "check": {"question": "In ‘Hago lo que quiero’, what does ‘lo que’ refer to?", "options": ["a whole idea (‘what I want’), not one specific noun", "one masculine singular noun that was already mentioned earlier in the same sentence", "a person the speaker is talking to directly", "a place mentioned earlier in the text"], "answer": 0, "explain": "‘lo que’ sums up an idea, unlike ‘que’, which replaces one specific noun."}}, {"title": "Paper 4 — Writing: use connectors and pronouns for range", "html": "Top-band answers combine a pronoun (‘lo/la’), a negative (‘nunca’, ‘nada’) and a Higher connector (‘sin embargo’, ‘aunque’) in the same paragraph, instead of repeating ‘y’ and ‘pero’ throughout.", "check": {"question": "Which answer shows the widest range of structures?", "options": ["Me gusta el fútbol, pero nunca lo juego porque, sin embargo, prefiero nadar", "Me gusta el fútbol y me gusta nadar y me gusta el baloncesto y también me gusta el tenis", "Me gusta el deporte", "No me gusta nada"], "answer": 0, "explain": "It combines a pronoun (lo), a negative (nunca) and Higher connectors (pero, sin embargo) — range plus accuracy, not just repeated ‘y’."}}]}, "exam": {"enabled": true, "questions": [{"question": "Complete the text with <strong>one</strong> word from this list for each gap: <strong>lo, porque, que, nunca, aunque</strong>. Use each word once.<br>Mi amigo Carlos tiene un coche nuevo. Yo no (1)___ tengo, así que voy en bici. Me gusta el ciclismo (2)___ es bueno para la salud. Mi hermano, (3)___ vive cerca, viene conmigo a veces. (4)___ vamos en invierno porque hace demasiado frío. Me gusta el ciclismo, (5)___ prefiero nadar en verano.", "marks": 5, "hint": "(1) replaces ‘un coche nuevo’ (masculine). (2) gives a reason. (3) links back to ‘mi hermano’. (4) is a negative word before the verb. (5) introduces a contrast with what comes before it.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (grammar in context)</h5><ul>\n                <li><strong>(1)</strong> lo <em>(1)</em></li>\n                <li><strong>(2)</strong> porque <em>(1)</em></li>\n                <li><strong>(3)</strong> que <em>(1)</em></li>\n                <li><strong>(4)</strong> nunca <em>(1)</em></li>\n                <li><strong>(5)</strong> aunque <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Each gap is worth one mark; the word must be spelt correctly and used only once.</li>\n            </ul></div>"}, {"question": "Translate this paragraph <strong>into Spanish</strong>: ‘I like football, but I prefer basketball. However, I never play at the weekend because I have too much homework.’", "marks": 4, "hint": "‘however’ = sin embargo; ‘I never play’ needs the double negative (no juego … nunca, or nunca before the verb); ‘too much/many’ = demasiado/demasiados.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>Me gusta el fútbol</strong> <em>(1)</em></li>\n                <li><strong>pero prefiero el baloncesto</strong> <em>(1)</em></li>\n                <li><strong>Sin embargo, nunca juego los fines de semana</strong> <em>(1)</em></li>\n                <li><strong>porque tengo demasiados deberes</strong> <em>(1)</em></li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors and ‘no juego nunca’ as an alternative to ‘nunca juego’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '1-1-me-my-family-and-friends', '1.1 Me, My Family and Friends', '{"learn": {"enabled": true, "items": [{"title": "How do I introduce myself?", "html": "<p>The building blocks for talking about yourself — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"me llamo\">me llamo…</span></td><td>my name is…</td><td><span data-say=\"tengo catorce años\">tengo… años</span></td><td>I am … years old</td></tr>\n              <tr><td><span data-say=\"soy de\">soy de…</span></td><td>I am from…</td><td><span data-say=\"vivo en\">vivo en…</span></td><td>I live in…</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Me llamo Ana, tengo quince años y vivo en Madrid.\">Me llamo Ana, tengo quince años y vivo en Madrid.</span></p>\n            <p><strong>Big rule:</strong> for age Spanish uses <strong>tener</strong> (to have), not ‘ser’ — you literally ‘have’ years.</p>", "check": {"question": "How do you say ‘I am 15 years old’?", "options": ["Tengo quince años", "Soy quince años", "Estoy quince años", "Tengo quince año"], "answer": 0, "explain": "Age uses tener: ‘tengo quince años’ — never ‘soy’. ‘años’ is plural."}}, {"title": "How do I describe how I look?", "html": "<p>Use <strong>ser</strong> for build/height and <strong>tener</strong> for hair and eyes:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"soy alto\">soy alto / alta</span></td><td>I am tall</td><td><span data-say=\"soy bajo\">soy bajo / baja</span></td><td>I am short</td></tr>\n              <tr><td><span data-say=\"soy delgado\">soy delgado / delgada</span></td><td>I am slim</td><td><span data-say=\"llevo gafas\">llevo gafas</span></td><td>I wear glasses</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Soy alta y delgada, y llevo gafas.\">Soy alta y delgada, y llevo gafas.</span> <em>(alt<strong>a</strong>, delgad<strong>a</strong> — female.)</em></p>", "check": {"question": "Which verb describes hair and eyes — ‘tengo el pelo…’?", "options": ["tener (to have)", "ser (to be)", "estar (to be)", "llevar (to wear)"], "answer": 0, "explain": "Spanish ‘has’ hair and eyes: tengo el pelo…, tengo los ojos… ‘llevar’ is for glasses/clothes."}}, {"title": "How do I describe my hair and eyes?", "html": "<p>Use <strong>tengo el pelo…</strong> (I have … hair) and <strong>tengo los ojos…</strong> (I have … eyes). Note the article (‘el’, ‘los’) — Spanish keeps it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el pelo rubio\">el pelo rubio</span></td><td>blond hair</td><td><span data-say=\"el pelo moreno\">el pelo moreno</span></td><td>dark hair</td></tr>\n              <tr><td><span data-say=\"el pelo castaño\">el pelo castaño</span></td><td>brown hair</td><td><span data-say=\"corto o largo\">corto / largo</span></td><td>short / long</td></tr>\n              <tr><td><span data-say=\"los ojos azules\">los ojos azules</span></td><td>blue eyes</td><td><span data-say=\"los ojos marrones\">los ojos marrones</span></td><td>brown eyes</td></tr>\n            </table>\n            <p>Colours agree: eyes are plural, so <span data-say=\"Tengo los ojos verdes.\">Tengo los ojos verdes.</span></p>", "check": {"question": "How do you say ‘I have long hair’?", "options": ["Tengo el pelo largo", "Llevo el pelo largo casi siempre", "Soy el pelo largo", "Tengo el pelo larga"], "answer": 0, "explain": "Hair uses tener + the article ‘el’; ‘pelo’ is masculine so the colour/length agrees: largo (not larga)."}}, {"title": "Who is in my family?", "html": "<p>Family members (<strong>la familia</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"los padres\">los padres</span></td><td>parents</td><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td></tr>\n              <tr><td><span data-say=\"el hermano mayor\">el hermano mayor</span></td><td>older brother</td><td><span data-say=\"la hermana menor\">la hermana menor</span></td><td>younger sister</td></tr>\n              <tr><td><span data-say=\"el tío\">el tío / la tía</span></td><td>uncle / aunt</td><td><span data-say=\"el primo\">el primo / la prima</span></td><td>cousin</td></tr>\n            </table>\n            <p><span data-say=\"Soy hijo único.\">Soy hijo único.</span> = I’m an only child. <span data-say=\"En mi familia hay cuatro personas.\">En mi familia hay cuatro personas.</span></p>", "check": {"question": "What does ‘mi hermana menor’ mean?", "options": ["my younger sister", "my older sister", "my younger brother", "my cousin"], "answer": 0, "explain": "hermana = sister; menor = younger. mayor = older."}}, {"title": "How do I say ‘my’ and ‘your’? (possessives)", "html": "<p>Possessive adjectives agree with the <strong>number</strong> of the thing owned (one or many), NOT with you:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi hermano\">mi</span> (one thing)</td><td>my — <span data-say=\"mi hermano\">mi hermano</span></td></tr>\n              <tr><td><span data-say=\"mis hermanos\">mis</span> (more than one)</td><td>my — <span data-say=\"mis hermanos\">mis hermanos</span></td></tr>\n              <tr><td><span data-say=\"tu casa\">tu / tus</span></td><td>your — tu casa, tus amigos</td></tr>\n              <tr><td><span data-say=\"su perro\">su / sus</span></td><td>his / her / their</td></tr>\n            </table>\n            <p>So it’s <strong>mi</strong> hermano but <strong>mis</strong> hermanos — the ‑s matches the plural noun.</p>", "check": {"question": "How do you say ‘my brothers’ (more than one)?", "options": ["mis hermanos", "mi hermanos", "mío hermanos", "mis hermano"], "answer": 0, "explain": "The possessive agrees with the plural noun: mis hermanos."}}, {"title": "Higher: longer, richer descriptions", "html": "<p><span class=\"tier-h\">H</span> Add quantifiers and join clauses to describe more precisely:</p>\n            <ul>\n              <li>Quantifiers: <span data-say=\"bastante alto\">bastante alto</span> (quite tall), <span data-say=\"un poco tímido\">un poco tímido</span> (a bit shy). <span class=\"tier-h\">H</span></li>\n              <li>Relative ‘que’: <span data-say=\"Tengo un hermano que se llama Luis.\">Tengo un hermano que se llama Luis.</span> <span class=\"tier-h\">H</span></li>\n              <li>Combine appearance + who: <span data-say=\"Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.\">Mi hermana mayor, que es muy alta, tiene el pelo largo y rizado.</span> <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "‘Tengo un hermano que se llama Luis’ — what does ‘que’ do here?", "options": ["it links two ideas (‘who’ / ‘that’)", "it is used to ask a question meaning ‘what?’", "it means ‘because’", "it makes the sentence a plan"], "answer": 0, "explain": "Relative ‘que’ = who/that; it joins ‘I have a brother’ + ‘he is called Luis’."}}, {"title": "Who else is in my family? Stepfamily, ages and names", "html": "<p>Family isn''t just parents and siblings — here''s more people, and how Spanish names work:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la madrastra\">la madrastra</span></td><td>stepmother</td><td><span data-say=\"el padrastro\">el padrastro</span></td><td>stepfather</td></tr>\n              <tr><td><span data-say=\"mamá\">mamá</span></td><td>mum (informal)</td><td><span data-say=\"papá\">papá</span></td><td>dad (informal)</td></tr>\n              <tr><td><span data-say=\"una niña\">una niña</span></td><td>a (young) girl</td><td><span data-say=\"un bebé\">un bebé</span></td><td>a baby</td></tr>\n              <tr><td><span data-say=\"un anciano\">un anciano</span></td><td>an elderly man</td><td><span data-say=\"un adulto\">un adulto</span></td><td>an adult</td></tr>\n              <tr><td><span data-say=\"el nacimiento\">el nacimiento</span></td><td>birth</td><td><span data-say=\"el apellido\">el apellido</span></td><td>surname</td></tr>\n            </table>\n            <p>Spanish speakers often use <strong>two</strong> surnames — father''s then mother''s: <span data-say=\"Mi apellido es González Pérez.\">Mi apellido es González Pérez.</span> And to say ‘the youngest’ of a group, use <span data-say=\"el menor\">el menor / la menor</span>: <span class=\"tier-h\">H</span> <span data-say=\"Soy la menor de mis hermanos.\">Soy la menor de mis hermanos.</span></p>", "check": {"question": "What does ‘mi padrastro’ mean?", "options": ["my stepfather", "my stepmother", "my grandfather", "my father-in-law, my wife''s dad"], "answer": 0, "explain": "padrastro = stepfather; madrastra = stepmother."}}, {"title": "Where is my family from? Nationalities and more appearance", "html": "<p>Nationality adjectives change for a female (add ‑a) — note the accent often disappears:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"europeo\">europeo / europea</span></td><td>European</td><td><span data-say=\"alemán\">alemán / alemana</span></td><td>German</td></tr>\n              <tr><td><span data-say=\"italiano\">italiano / italiana</span></td><td>Italian</td><td><span data-say=\"británico\">británico / británica</span></td><td>British</td></tr>\n              <tr><td><span data-say=\"chino\">chino / china</span></td><td>Chinese</td><td><span data-say=\"blanco\">blanco / blanca</span></td><td>white</td></tr>\n            </table>\n            <p>More words for describing people:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el pelo gris\">el pelo gris</span></td><td>grey hair</td><td><span data-say=\"un poco gordo\">un poco gordo / gorda</span></td><td>a bit overweight</td></tr>\n              <tr><td><span data-say=\"hermoso\">hermoso / hermosa</span></td><td>beautiful</td><td><span data-say=\"precioso\">precioso / preciosa</span></td><td>beautiful, gorgeous</td></tr>\n              <tr><td><span data-say=\"un tatuaje\">un tatuaje</span></td><td>a tattoo</td><td><span data-say=\"parecerse a\">parecerse a</span></td><td>to look like, resemble</td></tr>\n            </table>\n            <p>Family resemblance: <span data-say=\"Me parezco mucho a mi madre; somos muy semejantes.\">Me parezco mucho a mi madre; somos muy semejantes.</span> = I look a lot like my mother; we are very similar. Forms often ask your <span data-say=\"sexo\">sexo</span> (sex/gender) as well as your name and age.</p>", "check": {"question": "What does ‘me parezco a mi padre’ mean?", "options": ["I look like my father", "I disagree with my father", "I live apart from my father", "I get on badly with my father, not well at all"], "answer": 0, "explain": "parecerse a = to look like/resemble. Don''t confuse it with ‘discutir’ (to argue) or ‘llevarse mal’ (get on badly)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "me llamo…", "definition": "my name is…"}, {"term": "tengo… años", "definition": "I am … years old"}, {"term": "soy de… · vivo en…", "definition": "I am from… · I live in…"}, {"term": "soy alto / bajo", "definition": "I am tall / short (ser)"}, {"term": "tengo el pelo rubio", "definition": "I have blond hair"}, {"term": "castaño · moreno", "definition": "brown · dark (hair)"}, {"term": "corto / largo · rizado / liso", "definition": "short / long · curly / straight"}, {"term": "tengo los ojos azules", "definition": "I have blue eyes"}, {"term": "los ojos marrones / verdes", "definition": "brown / green eyes"}, {"term": "llevo gafas", "definition": "I wear glasses"}, {"term": "los padres · los abuelos", "definition": "parents · grandparents"}, {"term": "el hermano mayor / menor", "definition": "older / younger brother"}, {"term": "el tío / la tía · el primo / la prima", "definition": "uncle/aunt · cousin"}, {"term": "hijo único / hija única", "definition": "only child"}, {"term": "mi / mis", "definition": "my (one / more than one)"}, {"term": "tu / tus · su / sus", "definition": "your · his/her/their"}, {"term": "bastante · un poco (H)", "definition": "quite · a bit (quantifiers)"}, {"term": "que (H)", "definition": "who / that (relative pronoun)"}, {"term": "parecer(se) a", "definition": "to seem · to look like / resemble"}, {"term": "entonces", "definition": "then, so"}, {"term": "junto / juntos", "definition": "together"}, {"term": "señor", "definition": "Mr, sir, gentleman"}, {"term": "fuera", "definition": "outside, away"}, {"term": "blanco / blanca", "definition": "white"}, {"term": "tercer / tercero", "definition": "third"}, {"term": "el menor / la menor", "definition": "the youngest"}, {"term": "dato", "definition": "fact, piece of data"}, {"term": "niña", "definition": "girl (young)"}, {"term": "mamá", "definition": "mum (informal)"}, {"term": "europeo / europea", "definition": "European"}, {"term": "alemán / alemana", "definition": "German"}, {"term": "recuerdo", "definition": "memory, souvenir"}, {"term": "deseo", "definition": "wish, desire"}, {"term": "noticia", "definition": "(piece of) news"}, {"term": "papá", "definition": "dad (informal)"}, {"term": "hermoso / hermosa", "definition": "beautiful"}, {"term": "italiano / italiana", "definition": "Italian"}, {"term": "británico / británica", "definition": "British"}, {"term": "aparte (de)", "definition": "apart from, besides"}, {"term": "chino / china", "definition": "Chinese"}, {"term": "imposible", "definition": "impossible"}, {"term": "sexo", "definition": "sex, gender"}, {"term": "adulto", "definition": "adult"}, {"term": "anciano", "definition": "elderly man"}, {"term": "gordo / gorda", "definition": "fat, overweight"}, {"term": "nacimiento", "definition": "birth"}, {"term": "gris", "definition": "grey"}, {"term": "precioso / preciosa", "definition": "beautiful, gorgeous"}, {"term": "semejante", "definition": "similar, such"}, {"term": "bebé", "definition": "baby"}, {"term": "adiós", "definition": "goodbye"}, {"term": "apellido", "definition": "surname"}, {"term": "madrastra", "definition": "stepmother"}, {"term": "padrastro", "definition": "stepfather"}, {"term": "tatuaje", "definition": "tattoo"}, {"term": "¡Enhorabuena!", "definition": "Congratulations!"}, {"term": "ocupado / ocupada", "definition": "busy"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Tengo quince años.\" data-listen></span><br>Listen. What is being said?", "options": ["I am fifteen years old", "I have fifteen euros", "There are fifteen of us at home", "I am fifty years old"], "answer": 0, "explain": "‘tengo quince años’ = I am 15 (literally ‘I have 15 years’). Traps play on ‘tengo’ and the number."}, {"question": "<span data-say=\"Tengo el pelo largo y castaño.\" data-listen></span><br>Listen. How is the hair described?", "options": ["long and brown", "short and black", "long and blond", "curly and grey"], "answer": 0, "explain": "largo = long, castaño = brown. The distractors swap one or both features."}, {"question": "<span data-say=\"Mi hermano mayor lleva gafas.\" data-listen></span><br>Listen. Which is correct?", "options": ["My older brother wears glasses", "My younger brother has a beard", "My older sister wears glasses too", "My brother wants some new glasses"], "answer": 0, "explain": "hermano mayor = older brother; lleva gafas = wears glasses. Distractors change age, gender or add detail."}, {"question": "How do you say ‘I am 14 years old’?", "options": ["Tengo catorce años", "Soy catorce años", "Tengo catorce años de vida", "Estoy catorce años"], "answer": 0, "explain": "Age = tener: tengo catorce años. ‘Soy/Estoy’ are the classic English-speaker error."}, {"question": "Which is correct for ‘I have brown eyes’?", "options": ["Tengo los ojos marrones", "Tengo los ojos de color marrón", "Tengo los ojos marrón", "Soy los ojos marrones"], "answer": 0, "explain": "los ojos is plural → the colour agrees: marrones. ‘marrón’ singular does not agree; ‘soy’ is wrong."}, {"question": "Complete: ‘___ hermanos son altos.’ (my brothers)", "options": ["Mis", "Sus", "Mi", "Tu"], "answer": 0, "explain": "The possessive agrees with the plural noun ‘hermanos’ → mis. ‘Sus’ would mean ‘their/his/her’."}, {"question": "‘Soy hijo único’ means…", "options": ["I am an only child", "I am a unique person", "I am the eldest son", "I am someone''s only true friend"], "answer": 0, "explain": "hijo único = only child. (‘único’ here is ‘only’, not ‘unique’.)"}, {"question": "Complete: ‘___ el pelo rubio.’ (I have)", "options": ["Tengo", "Soy", "Está", "Llevo"], "answer": 0, "explain": "Hair uses tener → Tengo el pelo rubio."}, {"question": "Why ‘Tengo 15 años’, not ‘Soy 15 años’?", "options": ["Spanish uses ‘tener’ (to have) for age", "‘ser’ can only describe your job", "you must always use ‘estar’ with numbers", "‘años’ has to follow the verb ‘ser’"], "answer": 0, "explain": "Age is expressed with tener in Spanish: you ‘have’ years."}, {"question": "‘Mi hermana, que es alta, tiene el pelo rizado’ — what does ‘que’ do?", "options": ["links two ideas (‘who / that’)", "shows that it is a plan for the future", "turns it into a question", "means ‘because’"], "answer": 0, "explain": "Relative ‘que’ = who/that, joining ‘my sister’ + ‘she is tall’."}, {"question": "‘Vamos juntos al cine esta noche.’ — what does ‘juntos’ mean here?", "options": ["together", "separately, each in a different car", "late, after the film starts", "for free, without paying"], "answer": 0, "explain": "juntos = together. The distractors describe how or when, not togetherness."}, {"question": "‘El señor García es mi profesor de español.’ — what does ‘señor’ mean here?", "options": ["Mr / gentleman", "sir, only used for royalty", "señora''s husband, nothing more", "an old-fashioned word for teacher"], "answer": 0, "explain": "señor = Mr / man, a polite title before a surname."}, {"question": "<span data-say=\"Mi padre trabaja fuera de la ciudad.\" data-listen></span><br>Listen. What is being said about the father?", "options": ["He works outside/away from the city", "He never leaves the house at all", "He works very hard inside the city", "He is currently out of work, unemployed"], "answer": 0, "explain": "fuera (de) = outside/away from. Distractors invert or change the meaning."}, {"question": "How do you say ‘I am the third child’?", "options": ["Soy el tercer hijo", "Soy el tercero hijo", "Soy el hijo tercer", "Soy tercer de hijo"], "answer": 0, "explain": "‘tercer’ shortens before a masculine singular noun: el tercer hijo (like ‘primer’, ‘buen’)."}, {"question": "‘Aquí tienes mis datos personales: nombre, edad y sexo.’ — what are ‘datos personales’?", "options": ["personal details/data", "personal opinions and beliefs", "personal belongings, like a bag", "a personal diary or journal"], "answer": 0, "explain": "datos personales = personal details/data (name, age, etc.), not opinions or objects."}, {"question": "<span data-say=\"Mi amigo Hans es alemán.\" data-listen></span><br>Listen. Where is Hans from?", "options": ["Germany", "Italy", "Britain", "China"], "answer": 0, "explain": "alemán = German. The other options are the other nationalities on this page."}, {"question": "‘Tengo un recuerdo precioso de mi abuela.’ — what is ‘un recuerdo’?", "options": ["a memory", "a present, a gift", "a photograph, nothing more", "a letter or postcard"], "answer": 0, "explain": "un recuerdo = a memory (also can mean souvenir), not simply a gift or photo."}, {"question": "Which word means ‘Chinese’?", "options": ["chino", "chico", "china (the country only)", "checo"], "answer": 0, "explain": "chino = Chinese. ‘chico’ = boy; ‘checo’ = Czech — classic mix-ups."}]}, "fib": {"enabled": true, "questions": [{"text": "[Tengo] quince años. <span data-say=\"Tengo quince años.\" data-listen>Tengo quince años.</span>"}, {"text": "Tengo el pelo largo y [castaño]. <span data-say=\"Tengo el pelo largo y castaño.\" data-listen>Tengo el pelo largo y castaño.</span>"}, {"text": "Mi hermano mayor [lleva] gafas. <span data-say=\"Mi hermano mayor lleva gafas.\" data-listen>Mi hermano mayor lleva gafas.</span>"}, {"text": "Tengo los ojos [marrones]. (brown — plural agreement!)"}, {"text": "[Mis] hermanos son altos. (my — more than one)"}, {"text": "Soy hijo [único]. (only child)"}, {"text": "Me [llamo] Ana y vivo en Madrid. (my name is)"}, {"text": "Me [parezco] mucho a mi madre. <span data-say=\"Me parezco mucho a mi madre.\" data-listen>Me parezco mucho a mi madre.</span>"}, {"text": "Soy el [tercer] hijo de mi familia. (third)"}, {"text": "Mi abuelo es [anciano] y tiene el pelo gris. (elderly man)"}]}, "tf": {"enabled": true, "questions": [{"statement": "For age, Spanish uses ‘tener’ — ‘tengo quince años’.", "answer": true, "explain": "You literally ‘have’ years: tengo… años. ‘Soy… años’ is wrong."}, {"statement": "Hair and eyes use ‘tener’: ‘tengo el pelo rubio’.", "answer": true, "explain": "Spanish ‘has’ hair and eyes, and keeps the article (el/los)."}, {"statement": "‘hijo único’ means ‘a unique son’.", "answer": false, "explain": "It means ‘only child’ — único here = only."}, {"statement": "‘mis hermanos’ is correct because the possessive agrees with the plural noun.", "answer": true, "explain": "mi → mis to match a plural noun (hermanos)."}, {"statement": "‘mayor’ means ‘younger’.", "answer": false, "explain": "mayor = older; menor = younger."}, {"statement": "‘Tengo los ojos marrón’ is correct.", "answer": false, "explain": "Eyes are plural, so the colour must agree: los ojos marrones."}, {"statement": "‘llevar’ is used for glasses: ‘llevo gafas’.", "answer": true, "explain": "llevar = to wear (glasses, clothes)."}, {"statement": "Build/height uses ‘ser’: ‘soy alto’.", "answer": true, "explain": "ser describes what you are like: soy alto/alta."}, {"statement": "‘tercer’ becomes ‘tercero’ before a masculine singular noun.", "answer": false, "explain": "It''s the opposite: ‘tercero’ shortens to ‘tercer’ before a masculine singular noun (el tercer hijo)."}, {"statement": "‘madrastra’ means ‘stepmother’.", "answer": true, "explain": "madrastra = stepmother; padrastro = stepfather."}, {"statement": "Spanish speakers usually only use one surname, never two.", "answer": false, "explain": "It''s common to use two surnames — father''s then mother''s, e.g. González Pérez."}]}, "misc": {"enabled": true, "items": [{"myth": "Soy quince años.", "truth": "Tengo quince años.", "check": {"question": "Why ‘Tengo quince años’, not ‘Soy…’?", "options": ["Spanish expresses age with ‘tener’ (to have)", "‘ser’ can only ever be used with jobs", "you must put the number after the verb ‘ser’", "age always needs the verb ‘estar’ instead"], "answer": 0, "explain": "In Spanish you ‘have’ years: tengo… años."}}, {"myth": "Tengo ojos azul.", "truth": "Tengo los ojos azules.", "check": {"question": "What is wrong with ‘Tengo ojos azul’?", "options": ["needs ‘los’ and the plural colour ‘azules’", "the verb here should really be ‘soy’ and not ‘tengo’", "‘ojos’ must be written in the singular", "you must add an accent to ‘azul’"], "answer": 0, "explain": "Keep the article ‘los’ and agree the colour in the plural: los ojos azules."}}, {"myth": "Mis hermano es alto.", "truth": "Mi hermano es alto.", "check": {"question": "Why ‘Mi hermano’, not ‘Mis hermano’?", "options": ["‘hermano’ is singular, so the possessive is ‘mi’", "the possessive always agrees with the person who is speaking", "you always use ‘mis’ before a family word", "‘hermano’ must become plural after ‘mis’"], "answer": 0, "explain": "The possessive matches the noun: one hermano → mi; many → mis."}}, {"myth": "único = unique (only meaning)", "truth": "hijo único = only child", "check": {"question": "In ‘hijo único’, what does ‘único’ mean?", "options": ["only (an only child)", "unique, exactly as in English", "the youngest of the family", "a lonely or sad child"], "answer": 0, "explain": "hijo único = only child; único here = only, not ‘unique’."}}, {"myth": "Tengo alto.", "truth": "Soy alto.", "check": {"question": "Why ‘Soy alto’, not ‘Tengo alto’?", "options": ["height/build uses ‘ser’ (soy alto)", "you must always use ‘estar’ for describing height", "‘alto’ is really a type of hair", "‘tener’ is only used for eyes"], "answer": 0, "explain": "Use ser for what you are like (tall/short); tener is for age, hair and eyes."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Listen for the verb: ‘tengo’ (I have — age/hair/eyes) vs ‘soy’ (I am — build). Numbers for age come up a lot, and adjective endings (‑o/‑a) tell you if it is a male or female.", "check": {"question": "You hear ‘tengo… años’. What is being described?", "options": ["the person''s age", "the person''s height", "the person''s job", "where the person lives"], "answer": 0, "explain": "‘tengo… años’ = I am … years old — age uses tener."}}, {"title": "Paper 3 — Translation into English", "html": "‘Tengo quince años’ = ‘I am fifteen’, not ‘I have fifteen years’. Keep ‘hijo único’ natural as ‘only child’. Watch the articles: ‘tengo el pelo…’ = ‘I have … hair’.", "check": {"question": "‘Tengo el pelo corto y soy bastante alto’ =", "options": ["I have short hair and I am quite tall", "I have long flowing hair and I am very short", "My hair is short but I am rather old", "I want short hair and to be taller"], "answer": 0, "explain": "corto = short, bastante alto = quite tall."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine identity + appearance + family: ‘Me llamo Ana, tengo quince años y tengo el pelo largo. En mi familia hay cuatro personas.’ At Higher, add a relative ‘que’ or a quantifier (‘bastante’, ‘un poco’).", "check": {"question": "Which answer reaches the top band?", "options": ["Tengo quince años y el pelo castaño; vivo con mi hermana, que es muy graciosa", "Tengo pelo y tengo ojos y una familia y una casa y un perro y un gato también", "Me llamo Ana", "Soy alta"], "answer": 0, "explain": "It links age, appearance, family and a relative clause — range and accuracy, not just piling on words."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Pablo says. Answer <strong>in English</strong>.<br>(a) How old is Pablo? (1)<br>(b) Give <strong>one</strong> detail about his appearance. (1)<br>(c) How many people are in his family? (1)<br>(d) Why does he mention Diego — what is Diego like? (1)", "marks": 4, "hint": "Find the number after ‘tengo’, the description after ‘soy/tengo el pelo’, ‘en mi familia somos…’, and the adjective after ‘que es…’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> 16 (years old) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> ANY ONE of: (quite) tall / short dark hair / wears glasses <em>(1)</em>.</li>\n                <li><strong>(c)</strong> five / 5 <em>(1)</em>.</li>\n                <li><strong>(d)</strong> Diego is (his best friend and is) funny <em>(1)</em>; also accept ‘lives near him’.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I am fifteen years old. <br>(b) I have short hair. <br>(c) In my family there are four people because I have two brothers.", "marks": 5, "hint": "Age = tener (Tengo… años). ‘I have short hair’ = Tengo el pelo corto. ‘there are’ = hay.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Tengo quince años. <em>(1 — must use tener)</em></li>\n                <li><strong>(b)</strong> Tengo el pelo corto. <em>(1 — keep ‘el’)</em></li>\n                <li><strong>(c)</strong> En mi familia hay cuatro personas <em>(1)</em> porque <em>(1)</em> tengo dos hermanos <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Tengo quince años’ must use tener, not ser.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '1-2-relationships-and-role-models', '1.2 Relationships and Role Models', '{"learn": {"enabled": true, "items": [{"title": "Who are the people in my life?", "html": "<p>Core people vocabulary — tap 🔊 to hear each word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la familia\">la familia</span></td><td>family</td><td><span data-say=\"los padres\">los padres</span></td><td>parents</td></tr>\n              <tr><td><span data-say=\"el hermano\">el hermano</span></td><td>brother</td><td><span data-say=\"la hermana\">la hermana</span></td><td>sister</td></tr>\n              <tr><td><span data-say=\"los abuelos\">los abuelos</span></td><td>grandparents</td><td><span data-say=\"el amigo\">el amigo / la amiga</span></td><td>friend</td></tr>\n              <tr><td><span data-say=\"el novio\">el novio / la novia</span></td><td>boyfriend / girlfriend</td><td><span data-say=\"el hijo\">el hijo / la hija</span></td><td>son / daughter</td></tr>\n            </table>\n            <p>Model: <span data-say=\"En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.\">En mi familia hay cinco personas: mis padres, mis dos hermanos y yo.</span></p>", "check": {"question": "What does ‘los padres’ mean?", "options": ["parents", "grandparents", "godparents", "priests"], "answer": 0, "explain": "los padres = parents. los abuelos = grandparents."}}, {"title": "How do I describe someone''s personality?", "html": "<p>Use <strong>ser</strong> (a permanent trait) + an adjective. The adjective must <strong>agree</strong>: change ‑o → ‑a for a female.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"simpático\">simpático / simpática</span></td><td>nice, friendly</td><td><span data-say=\"gracioso\">gracioso / graciosa</span></td><td>funny</td></tr>\n              <tr><td><span data-say=\"amable\">amable</span></td><td>kind</td><td><span data-say=\"hablador\">hablador / habladora</span></td><td>talkative</td></tr>\n              <tr><td><span data-say=\"cariñoso\">cariñoso / cariñosa</span></td><td>affectionate</td><td><span data-say=\"egoísta\">egoísta</span></td><td>selfish</td></tr>\n              <tr><td><span data-say=\"terco\">terco / terca</span></td><td>stubborn</td><td><span data-say=\"celoso\">celoso / celosa</span></td><td>jealous</td></tr>\n            </table>\n            <p><span data-say=\"Mi madre es muy cariñosa y mi hermano es gracioso.\">Mi madre es muy cariñosa y mi hermano es gracioso.</span> <em>(Note: cariños<strong>a</strong> for ‘madre’, gracios<strong>o</strong> for ‘hermano’.)</em></p>", "check": {"question": "How do you say ‘My sister is funny’?", "options": ["Mi hermana es graciosa", "Mi hermana es gracioso", "Mi hermana está graciosa", "Mi hermana es graciosos"], "answer": 0, "explain": "‘hermana’ is female → gracios­a; personality uses ser, not estar."}}, {"title": "How do I say I get on (or clash) with people?", "html": "<p>The key phrase is the reflexive <strong>llevarse bien / mal con</strong> — to get on well / badly with:</p>\n            <ul>\n              <li><span data-say=\"Me llevo bien con mi madre.\">Me llevo bien con mi madre.</span> — I get on well with my mum.</li>\n              <li><span data-say=\"Me llevo mal con mi hermano.\">Me llevo mal con mi hermano.</span> — I get on badly with my brother.</li>\n            </ul>\n            <p>Other useful verbs:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"pelearse\">pelearse</span></td><td>to fight / argue</td><td><span data-say=\"apoyar\">apoyar</span></td><td>to support</td></tr>\n              <tr><td><span data-say=\"respetar\">respetar</span></td><td>to respect</td><td><span data-say=\"confiar en\">confiar en</span></td><td>to trust</td></tr>\n            </table>", "check": {"question": "‘Me llevo bien con mi madre’ means…", "options": ["I get on well with my mum", "I look exactly like my mother does", "I take my mum out a lot", "I carry my mum''s bags"], "answer": 0, "explain": "llevarse bien con = to get on well with. (Don’t translate ‘llevo’ literally as ‘I carry’.)"}}, {"title": "How do I compare people?", "html": "<p>Use comparatives to make richer sentences:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"más… que\">más… que</span></td><td>more… than</td><td><span data-say=\"menos… que\">menos… que</span></td><td>less… than</td></tr>\n              <tr><td><span data-say=\"tan… como\">tan… como</span></td><td>as… as</td><td><span data-say=\"mejor / peor\">mejor / peor</span></td><td>better / worse</td></tr>\n            </table>\n            <p><span data-say=\"Mi hermana es más habladora que yo, pero yo soy más trabajador.\">Mi hermana es más habladora que yo, pero yo soy más trabajador.</span></p>\n            <p>Careful: ‘better’ is just <strong>mejor</strong> — never ‘más mejor’.</p>", "check": {"question": "How do you say ‘more talkative than me’?", "options": ["más habladora que yo", "más habladora de yo", "tan habladora que yo", "más mejor habladora"], "answer": 0, "explain": "‘more… than’ = más… que; ‘than me’ = que yo."}}, {"title": "How do I talk about role models?", "html": "<p>A role model is <span data-say=\"un modelo a seguir\">un modelo a seguir</span>. Say who and, crucially, <strong>why</strong>:</p>\n            <ul>\n              <li><span data-say=\"admirar\">admirar</span> — to admire; <span data-say=\"respetar\">respetar</span> — to respect</li>\n              <li><span data-say=\"trabajador\">trabajador / trabajadora</span> — hard-working; <span data-say=\"valiente\">valiente</span> — brave</li>\n            </ul>\n            <p><span data-say=\"Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.\">Mi modelo a seguir es mi abuela porque es muy trabajadora y siempre me apoya.</span></p>", "check": {"question": "What does ‘un modelo a seguir’ mean?", "options": ["a role model", "a fashion model", "a model railway", "a school subject"], "answer": 0, "explain": "un modelo a seguir = a role model (literally ‘a model to follow’)."}}, {"title": "Higher: relatives and the imperfect", "html": "<p><span class=\"tier-h\">H</span> Join ideas with relative pronouns and describe how things <em>used to be</em> with the imperfect:</p>\n            <ul>\n              <li><span data-say=\"que\">que</span> (who/that), <span data-say=\"quien\">quien</span> (who, after a preposition): <span data-say=\"Admiro a mi padre, que siempre me apoya.\">Admiro a mi padre, que siempre me apoya.</span> <span class=\"tier-h\">H</span></li>\n              <li>Imperfect for ‘used to’: <span data-say=\"De pequeño, me peleaba con mi hermano.\">De pequeño, me peleaba con mi hermano.</span> — When I was little, I used to fight with my brother. <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "‘De pequeño, me peleaba con mi hermano’ means…", "options": ["When I was little, I used to fight with my brother", "As a young child, I am going to fight with my brother", "I fought with my little brother once", "My little brother fights with me now"], "answer": 0, "explain": "The imperfect ‘me peleaba’ = ‘I used to fight’; ‘de pequeño’ = when I was little."}}, {"title": "When things go wrong — conflict, secrets and forgiveness", "html": "<p>Relationships aren''t always easy. More verbs and feelings for when things go wrong:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"romper con\">romper con</span></td><td>to break up with</td><td><span data-say=\"discutir\">discutir</span></td><td>to argue</td></tr>\n              <tr><td><span data-say=\"pegar\">pegar</span></td><td>to hit</td><td><span data-say=\"perdonar\">perdonar</span></td><td>to forgive</td></tr>\n              <tr><td><span data-say=\"un secreto\">un secreto</span></td><td>a secret</td><td><span data-say=\"una mentira\">una mentira</span></td><td>a lie</td></tr>\n              <tr><td><span data-say=\"la vergüenza\">la vergüenza</span></td><td>shame, embarrassment</td><td><span data-say=\"criticar\">criticar</span></td><td>to criticise</td></tr>\n            </table>\n            <p><span data-say=\"Estoy enojado porque mi amigo rompió con su novia y ahora se siente muy solo.\">Estoy enojado porque mi amigo rompió con su novia y ahora se siente muy solo.</span> = I am angry because my friend broke up with his girlfriend and now feels very lonely (<span data-say=\"la soledad\">la soledad</span> = loneliness). <span class=\"tier-h\">H</span> <span data-say=\"Desafortunadamente, no nos hablamos desde entonces.\">Desafortunadamente, no nos hablamos desde entonces.</span> = Unfortunately, we haven''t spoken since then.</p>", "check": {"question": "What does ‘romper con alguien’ mean?", "options": ["to break up with someone", "to make up with someone again", "to fall in love with someone", "to introduce someone to your family"], "answer": 0, "explain": "romper con = to break up with. Don''t confuse with hacer las paces (to make up) or enamorarse (to fall in love)."}}, {"title": "What makes a good role model? Personality, tolerance and feelings", "html": "<p>More personality words for describing role models — and vocabulary for talking about identity with respect:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"independiente\">independiente</span></td><td>independent</td><td><span data-say=\"capaz\">capaz</span></td><td>capable</td></tr>\n              <tr><td><span data-say=\"sencillo\">sencillo / sencilla</span></td><td>down-to-earth, simple</td><td><span data-say=\"positivo\">positivo / positiva</span></td><td>positive</td></tr>\n              <tr><td><span data-say=\"excelente\">excelente</span></td><td>excellent</td><td><span data-say=\"fiel\">fiel</span></td><td>loyal, faithful</td></tr>\n              <tr><td><span data-say=\"comprensivo\">comprensivo / comprensiva</span></td><td>understanding</td><td><span data-say=\"tolerante\">tolerante</span></td><td>tolerant</td></tr>\n            </table>\n            <p><span data-say=\"Mi modelo a seguir es fiel, comprensiva y siempre positiva. Tiene mucho sentimiento y buen humor.\">Mi modelo a seguir es fiel, comprensiva y siempre positiva. Tiene mucho sentimiento y buen humor.</span> = My role model is loyal, understanding and always positive. She has a lot of feeling and a good sense of humour.</p>\n            <p>Being tolerant means respecting everyone: <span data-say=\"Es importante ser tolerante, sea la persona gay, heterosexual o transgénero.\">Es importante ser tolerante, sea la persona gay, heterosexual o transgénero.</span> = It''s important to be tolerant, whether the person is gay, heterosexual or transgender.</p>", "check": {"question": "What does ‘comprensivo’ mean?", "options": ["understanding", "complicated, hard to follow", "comprehensive, covering everything", "competitive, always wants to win"], "answer": 0, "explain": "comprensivo = understanding (a false friend — NOT ‘comprehensive’)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la familia", "definition": "family"}, {"term": "los padres", "definition": "parents"}, {"term": "los abuelos", "definition": "grandparents"}, {"term": "el hermano / la hermana", "definition": "brother / sister"}, {"term": "simpático / simpática", "definition": "nice, friendly (false friend!)"}, {"term": "gracioso / graciosa", "definition": "funny"}, {"term": "amable", "definition": "kind"}, {"term": "cariñoso / cariñosa", "definition": "affectionate"}, {"term": "egoísta", "definition": "selfish"}, {"term": "terco · celoso", "definition": "stubborn · jealous"}, {"term": "me llevo bien / mal con", "definition": "I get on well / badly with"}, {"term": "pelearse", "definition": "to argue / fight"}, {"term": "apoyar · respetar", "definition": "to support · to respect"}, {"term": "más… que · menos… que", "definition": "more… than · less… than"}, {"term": "mejor / peor", "definition": "better / worse"}, {"term": "un modelo a seguir", "definition": "a role model"}, {"term": "trabajador / trabajadora", "definition": "hard-working"}, {"term": "que / quien (H)", "definition": "who / that (relative pronouns)"}, {"term": "entender(se)", "definition": "to understand · to understand each other / get on"}, {"term": "atención", "definition": "attention"}, {"term": "capaz", "definition": "capable"}, {"term": "suerte", "definition": "luck"}, {"term": "romper (con)", "definition": "to break (up with)"}, {"term": "duro / dura", "definition": "hard, strict, harsh"}, {"term": "civil", "definition": "civil (e.g. a civil wedding)"}, {"term": "sentimiento", "definition": "feeling"}, {"term": "esperanza", "definition": "hope"}, {"term": "sencillo / sencilla", "definition": "simple, down-to-earth"}, {"term": "pegar", "definition": "to hit"}, {"term": "independiente", "definition": "independent"}, {"term": "positivo / positiva", "definition": "positive"}, {"term": "discutir", "definition": "to argue"}, {"term": "secreto", "definition": "secret"}, {"term": "soledad", "definition": "loneliness"}, {"term": "perdonar", "definition": "to forgive"}, {"term": "nervioso / nerviosa", "definition": "nervous"}, {"term": "fiel", "definition": "loyal, faithful"}, {"term": "excelente", "definition": "excellent"}, {"term": "mentira", "definition": "lie"}, {"term": "abrazar", "definition": "to hug"}, {"term": "inútil", "definition": "useless"}, {"term": "enamorarse (de)", "definition": "to fall in love (with)"}, {"term": "criticar", "definition": "to criticise"}, {"term": "humor", "definition": "mood, humour"}, {"term": "cariño", "definition": "affection"}, {"term": "vergüenza", "definition": "shame, embarrassment"}, {"term": "comprensivo / comprensiva", "definition": "understanding (false friend!)"}, {"term": "gay", "definition": "gay"}, {"term": "hetero(sexual)", "definition": "heterosexual, straight"}, {"term": "tolerante", "definition": "tolerant"}, {"term": "transgénero", "definition": "transgender"}, {"term": "enojado / enojada", "definition": "angry"}, {"term": "desafortunadamente", "definition": "unfortunately"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Me llevo muy bien con mi madre.\" data-listen></span><br>Listen. What is being said?", "options": ["I get on very well with my mum", "I do not get on well with my mum at all", "I look a lot like my mum", "I live quite far from my mum"], "answer": 0, "explain": "‘me llevo bien con’ = I get on well with. Trap B flips bien to a negative; C/D translate ‘llevo’ wrongly."}, {"question": "<span data-say=\"Mi hermano es muy gracioso.\" data-listen></span><br>Listen. What is the brother like?", "options": ["funny", "boring and quiet", "hard-working", "very tall"], "answer": 0, "explain": "gracioso = funny. The distractors are other personality/appearance words that were not said."}, {"question": "<span data-say=\"A veces me peleo con mi hermana.\" data-listen></span><br>Listen. Which is correct?", "options": ["Sometimes I argue with my sister", "I never argue with my sister at all", "I always support my sister a lot", "I get on really well with my sister"], "answer": 0, "explain": "‘a veces me peleo’ = sometimes I argue/fight. The distractors are longer and reverse the meaning."}, {"question": "How do you say ‘My mother is kind’ (agreement + correct verb)?", "options": ["Mi madre es amable", "Mi madre es amablo", "Mi madre está amable", "Mi madre son amable"], "answer": 0, "explain": "‘amable’ has no ‑o/‑a change; personality uses ser (es), and ‘madre’ is singular (es, not son)."}, {"question": "‘simpático’ is a false friend. It means…", "options": ["nice / friendly", "sympathetic and understanding", "quite shy", "very clever"], "answer": 0, "explain": "simpático = nice/friendly, NOT ‘sympathetic’. That is the trap."}, {"question": "Which correctly says ‘more hard-working than me’?", "options": ["más trabajador que yo", "más trabajador de mí", "tan trabajador que yo", "más mejor trabajador"], "answer": 0, "explain": "‘more… than’ = más… que; ‘than me’ = que yo."}, {"question": "‘un modelo a seguir’ means a…", "options": ["role model", "fashion model", "model aeroplane", "new mobile model"], "answer": 0, "explain": "un modelo a seguir = a role model (‘a model to follow’)."}, {"question": "Complete: ‘Me llevo bien ___ mis padres.’", "options": ["con", "para", "de", "a"], "answer": 0, "explain": "llevarse bien CON = to get on well WITH."}, {"question": "Why is ‘Mi hermana es simpático’ wrong?", "options": ["‘hermana’ is female, so it needs ‘simpática’", "‘simpático’ should be in the plural form", "you must use ‘está’, not ‘es’, for people", "‘hermana’ always takes a masculine adjective"], "answer": 0, "explain": "Adjectives agree: a female (hermana) takes simpática."}, {"question": "‘De pequeño me peleaba con mi hermano’ uses which tense?", "options": ["the imperfect (used to)", "the simple future tense", "a one-off completed action", "the present tense right now"], "answer": 0, "explain": "‘me peleaba’ is the imperfect — a repeated past habit (‘used to fight’), a Higher feature."}, {"question": "<span data-say=\"Mi hermana y yo nos entendemos muy bien.\" data-listen></span><br>Listen. What is being said?", "options": ["My sister and I understand each other very well", "My sister and I never see eye to eye about anything at all", "My sister and I look very alike", "My sister and I live in different countries"], "answer": 0, "explain": "entenderse = to understand each other/get on. Distractors invert the meaning or change topic."}, {"question": "‘Mi padre es un poco duro conmigo a veces.’ — what does ‘duro’ mean here?", "options": ["hard, strict", "generous, gives me anything", "funny, always joking around", "absent, never at home"], "answer": 0, "explain": "duro (describing a person) = hard/strict. Distractors are other personality traits, not synonyms."}, {"question": "‘Mis padres tuvieron una boda civil, no religiosa.’ — what is ‘una boda civil’?", "options": ["a civil (non-religious) wedding", "a religious wedding in a church", "a huge, very expensive wedding", "a wedding with no guests at all"], "answer": 0, "explain": "boda civil = civil (non-religious) wedding — the sentence itself contrasts it with ‘religiosa’."}, {"question": "<span data-say=\"Estoy muy nervioso antes de los exámenes.\" data-listen></span><br>Listen. How does the speaker feel before exams?", "options": ["very nervous", "extremely relaxed and calm", "rather bored and disinterested", "quite proud and confident"], "answer": 0, "explain": "nervioso = nervous. The distractors are the opposite feelings."}, {"question": "‘Me enamoré de mi mejor amigo el año pasado.’ — what does ‘enamorarse de’ mean?", "options": ["to fall in love with", "to become good friends with", "to have an argument with", "to lose touch with completely"], "answer": 0, "explain": "enamorarse (de) = to fall in love (with)."}]}, "fib": {"enabled": true, "questions": [{"text": "Me llevo bien [con] mis padres. <span data-say=\"Me llevo bien con mis padres.\" data-listen>Me llevo bien con mis padres.</span>"}, {"text": "Mi hermano es muy [gracioso]. <span data-say=\"Mi hermano es muy gracioso.\" data-listen>Mi hermano es muy gracioso.</span>"}, {"text": "Mi modelo a seguir es mi [abuela]. <span data-say=\"Mi modelo a seguir es mi abuela.\" data-listen>Mi modelo a seguir es mi abuela.</span>"}, {"text": "Mi madre es muy [cariñosa]. (affectionate — she is female!)"}, {"text": "Me [llevo] mal con mi hermano. (I get on badly — reflexive)"}, {"text": "Mi hermana es más habladora [que] yo. (than)"}, {"text": "Admiro a mi abuela porque es muy [trabajadora]. (hard-working, female)"}, {"text": "Mi hermano y yo nos [entendemos] muy bien. <span data-say=\"Mi hermano y yo nos entendemos muy bien.\" data-listen>Mi hermano y yo nos entendemos muy bien.</span>"}, {"text": "Mis padres tuvieron una boda [civil], no religiosa. (civil)"}, {"text": "Estoy muy [nervioso] antes de los exámenes. (nervous)"}]}, "tf": {"enabled": true, "questions": [{"statement": "Personality traits use ‘ser’ (es simpático), not ‘estar’.", "answer": true, "explain": "ser describes permanent traits; estar is for temporary states/moods."}, {"statement": "‘simpático’ means ‘sympathetic’.", "answer": false, "explain": "False friend! simpático = nice / friendly."}, {"statement": "For a female, ‘gracioso’ becomes ‘graciosa’.", "answer": true, "explain": "Adjectives ending in ‑o change to ‑a to agree with a female."}, {"statement": "‘llevarse bien con’ means ‘to carry well with’.", "answer": false, "explain": "It means ‘to get on well with’ — don’t translate ‘llevo’ literally."}, {"statement": "‘better’ in Spanish is ‘más mejor’.", "answer": false, "explain": "‘better’ = mejor on its own; never ‘más mejor’."}, {"statement": "‘los abuelos’ means ‘grandparents’.", "answer": true, "explain": "los abuelos = grandparents; los padres = parents."}, {"statement": "‘un modelo a seguir’ means ‘a role model’.", "answer": true, "explain": "Literally ‘a model to follow’."}, {"statement": "The imperfect ‘me peleaba’ describes something you USED TO do.", "answer": true, "explain": "The imperfect expresses repeated/habitual past actions."}, {"statement": "‘comprensivo’ means ‘comprehensive’ in English.", "answer": false, "explain": "False friend! comprensivo = understanding, not ‘comprehensive’."}, {"statement": "‘romper con alguien’ means ‘to break up with someone’.", "answer": true, "explain": "romper con = to break up with."}, {"statement": "‘duro’ can describe a person who is strict or harsh.", "answer": true, "explain": "duro, describing a person, means hard/strict — not just physically hard."}]}, "misc": {"enabled": true, "items": [{"myth": "Mi madre es simpático.", "truth": "Mi madre es simpática.", "check": {"question": "Why ‘simpática’ here?", "options": ["the adjective agrees with the female ‘madre’", "‘simpático’ has to be written in the plural", "you always use the masculine form as default", "the verb ‘ser’ forces an ‑o ending"], "answer": 0, "explain": "Adjectives agree in gender: madre is female → simpática."}}, {"myth": "simpático = sympathetic", "truth": "simpático = nice / friendly", "check": {"question": "What does ‘simpático’ actually mean?", "options": ["nice / friendly", "sympathetic, as you might guess", "extremely intelligent", "rather shy and quiet"], "answer": 0, "explain": "Classic false friend: simpático = nice/friendly."}}, {"myth": "Mi hermano está gracioso.", "truth": "Mi hermano es gracioso.", "check": {"question": "Why ‘es’, not ‘está’, for ‘funny’?", "options": ["a personality trait is permanent → ser", "you must always use ‘tener’ with people", "‘gracioso’ is a plural adjective", "‘estar’ only works in the past"], "answer": 0, "explain": "Permanent personality traits use ser; estar would suggest a temporary state."}}, {"myth": "Llevo bien con mi madre.", "truth": "Me llevo bien con mi madre.", "check": {"question": "What is missing in ‘Llevo bien con…’?", "options": ["the reflexive pronoun ‘me’ (me llevo)", "an accent on the first vowel of llevo", "the linking word ‘a’ after bien", "the article ‘la’ before madre"], "answer": 0, "explain": "llevarse is reflexive: me llevo, te llevas, se lleva."}}, {"myth": "Mi hermana es más mejor que yo.", "truth": "Mi hermana es mejor que yo.", "check": {"question": "Why is ‘más mejor’ wrong?", "options": ["‘mejor’ already means ‘better’ — no ‘más’", "you always need ‘de’ instead of ‘que’ in comparisons", "‘mejor’ should be written as two words", "‘mejor’ must agree and become ‘mejora’"], "answer": 0, "explain": "mejor is already the comparative ‘better’; adding más is a double comparative."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Listen for the little words that flip the meaning: ‘bien’ vs ‘mal’ (get on well vs badly), ‘con’ (with), ‘pero’ (but). And catch adjective endings — ‑o or ‑a tells you if it’s about a male or a female.", "check": {"question": "You hear ‘me llevo mal con…’. What does ‘mal’ tell you?", "options": ["they get on badly", "they get on very well", "nobody was mentioned", "it happened in the past"], "answer": 0, "explain": "mal = badly, so ‘me llevo mal con’ = I get on badly with."}}, {"title": "Paper 3 — Translation into English", "html": "Beware false friends: ‘simpático’ = nice, not sympathetic. Don’t translate ‘me llevo bien’ literally — it means ‘I get on well’, not ‘I carry well’.", "check": {"question": "‘Mi primo es simpático pero un poco terco’ =", "options": ["My cousin is nice but a bit stubborn", "My cousin is sympathetic yet very brave", "My cousin is funny and rather generous", "My cousin is shy but really talkative"], "answer": 0, "explain": "simpático = nice; terco = stubborn."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a description, an opinion and a reason: ‘Me llevo bien con mi hermana porque es graciosa, pero a veces es egoísta.’ At Higher, add a relative pronoun (‘…que siempre me apoya’) or the imperfect (‘de pequeño…’).", "check": {"question": "Which answer reaches the top band?", "options": ["Me llevo bien con mi hermana porque es graciosa, aunque a veces es egoísta", "Mi hermana es simpática y muy simpática y también simpática y graciosa siempre", "Tengo una hermana", "Mi hermana es maja"], "answer": 0, "explain": "It links a relationship, a reason and a contrast — range and accuracy, not just piling on words."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Marta says. Answer <strong>in English</strong>.<br>(a) Why does she get on well with her mother? (1)<br>(b) Why does she sometimes argue with her brother? (1)<br>(c) Who is her role model? (1)<br>(d) Give <strong>one</strong> reason she admires that person. (1)", "marks": 4, "hint": "Find the reason after ‘porque’ (mum), the reason after ‘porque’ (brother), ‘mi modelo a seguir es…’, and the adjectives after ‘que es…’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> (because) she is affectionate / always supports her (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> (because) he is a bit selfish <em>(1)</em>.</li>\n                <li><strong>(c)</strong> her grandmother <em>(1)</em>.</li>\n                <li><strong>(d)</strong> she is hard-working / brave (ANY ONE) <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My sister is funny. <br>(b) I get on well with my parents. <br>(c) My role model is my grandmother because she is hard-working.", "marks": 5, "hint": "Agreement: ‘sister’ is female → graciosa. ‘I get on well with’ = Me llevo bien con. ‘hard-working’ (female) = trabajadora.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi hermana es graciosa. <em>(1 — must agree: graciosa)</em></li>\n                <li><strong>(b)</strong> Me llevo bien con mis padres. <em>(1)</em></li>\n                <li><strong>(c)</strong> Mi modelo a seguir es mi abuela <em>(1)</em> porque <em>(1)</em> es trabajadora <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘graciosa’ and ‘trabajadora’ must agree (female).</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', '{"learn": {"enabled": true, "items": [{"title": "What food and drink words do I need?", "html": "<p>Start with the core nouns for <strong>la comida</strong> (food) and <strong>la bebida</strong> (drink). Every Spanish word below is on the AQA list — tap 🔊 to hear it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la fruta\">la fruta</span></td><td>fruit</td><td><span data-say=\"las verduras\">las verduras</span></td><td>vegetables</td></tr>\n              <tr><td><span data-say=\"la carne\">la carne</span></td><td>meat</td><td><span data-say=\"el pescado\">el pescado</span></td><td>fish</td></tr>\n              <tr><td><span data-say=\"el pan\">el pan</span></td><td>bread</td><td><span data-say=\"el queso\">el queso</span></td><td>cheese</td></tr>\n              <tr><td><span data-say=\"el agua\">el agua</span></td><td>water</td><td><span data-say=\"la leche\">la leche</span></td><td>milk</td></tr>\n              <tr><td><span data-say=\"el azúcar\">el azúcar</span></td><td>sugar</td><td><span data-say=\"la grasa\">la grasa</span></td><td>fat</td></tr>\n            </table>\n            <p>Two useful meal words: <span data-say=\"el desayuno\">el desayuno</span> (breakfast) and <span data-say=\"la cena\">la cena</span> (dinner).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el alimento\">el alimento</span></td><td>food(stuff)</td><td><span data-say=\"el vaso\">el vaso</span></td><td>glass</td></tr>\n              <tr><td><span data-say=\"la botella\">la botella</span></td><td>bottle</td><td><span data-say=\"la sed\">la sed</span></td><td>thirst</td></tr>\n              <tr><td><span data-say=\"vegetariano\">vegetariano / vegetariana</span></td><td>vegetarian</td><td><span data-say=\"vegano\">vegano / vegana</span></td><td>vegan</td></tr>\n            </table>\n            <p>Two more useful words: <span data-say=\"el diente\">el diente</span> (tooth) — <span data-say=\"El azúcar es malo para los dientes.\">El azúcar es malo para los dientes.</span> (Sugar is bad for your teeth) — and <span data-say=\"tener sed\">tener sed</span> (to be thirsty): <span data-say=\"Cuando tengo sed, bebo un vaso de agua.\">Cuando tengo sed, bebo un vaso de agua.</span></p>", "check": {"question": "Which pair means ‘fruit and vegetables’?", "options": ["la fruta y las verduras", "las legumbres y el pescado", "la carne y el queso", "el agua y la leche"], "answer": 0, "explain": "la fruta = fruit, las verduras = vegetables. B mixes pulses and fish; C is meat and cheese."}}, {"title": "How do I describe a balanced diet?", "html": "<p>The headline phrase is <span data-say=\"una dieta equilibrada\">una dieta equilibrada</span> — <em>a balanced diet</em>. Notice the adjective <strong>equilibrada</strong> agrees with the feminine noun <strong>dieta</strong>.</p>\n            <ul>\n              <li><span data-say=\"sano\">sano</span> / <span data-say=\"saludable\">saludable</span> = healthy</li>\n              <li><span data-say=\"bueno para la salud\">bueno para la salud</span> = good for your health</li>\n              <li><span data-say=\"malo para la salud\">malo para la salud</span> = bad for your health</li>\n            </ul>\n            <p>Model sentence: <span data-say=\"Como una dieta equilibrada porque es buena para la salud.\">Como una dieta equilibrada porque es buena para la salud.</span> — <em>I eat a balanced diet because it is good for your health.</em></p>\n            <p>We can also talk about <span data-say=\"nuestra dieta\">nuestra dieta</span> (our diet), and use <span data-say=\"un régimen alimenticio\">un régimen (alimenticio)</span> — <em>a diet / eating regime</em> — as another way to say “diet”. <span data-say=\"Seguir un régimen puede ser complicado al principio.\">Seguir un régimen puede ser complicado al principio.</span> — <em>Following a diet/regime can be complicated at first.</em></p>\n            <p>Doctors recommend reducing <span data-say=\"el consumo de azúcar\">el consumo de azúcar</span> (sugar consumption), because too much can lead to <span data-say=\"el sobrepeso\">el sobrepeso</span> (being overweight). <span data-say=\"Dentro de una dieta equilibrada, se puede comer un poco de chocolate.\">Dentro de una dieta equilibrada, se puede comer un poco de chocolate.</span> — <em>Within a balanced diet, you can eat a little chocolate.</em></p>", "check": {"question": "Why does ‘equilibrada’ end in ‑a?", "options": ["It agrees with the feminine noun ‘dieta’", "It must copy the last letter of the word before it", "It is a verb ending", "It marks the plural"], "answer": 0, "explain": "Adjectives agree in gender and number with their noun: dieta is feminine singular → equilibrada (not a rule about the previous word)."}}, {"title": "How do I give advice? (se debe / hay que)", "html": "<p>To say what people <strong>should</strong> do, use these impersonal structures — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe\">se debe…</span></td><td>one must / you should…</td></tr>\n              <tr><td><span data-say=\"no se debe\">no se debe…</span></td><td>one must not…</td></tr>\n              <tr><td><span data-say=\"hay que\">hay que…</span></td><td>you have to…</td></tr>\n            </table>\n            <p>Examples:</p>\n            <ul>\n              <li><span data-say=\"Se debe comer más fruta.\">Se debe comer más fruta.</span> — One should eat more fruit.</li>\n              <li><span data-say=\"No se debe comer demasiada grasa.\">No se debe comer demasiada grasa.</span> — One must not eat too much fat.</li>\n              <li><span data-say=\"Hay que beber mucha agua.\">Hay que beber mucha agua.</span> — You have to drink lots of water.</li>\n            </ul>\n            <p>Advice often mentions a <span data-say=\"el límite\">el límite</span> (limit): <span data-say=\"Hay un límite de azúcar recomendado al día.\">Hay un límite de azúcar recomendado al día.</span> — <em>There is a recommended sugar limit per day.</em> Some people have <span data-say=\"una reacción alérgica\">una reacción alérgica</span> (an allergic reaction) to certain foods, so it is important to check the label.</p>", "check": {"question": "What kind of word follows ‘se debe’, ‘no se debe’ and ‘hay que’?", "options": ["an infinitive verb", "a fully conjugated past-tense verb", "a plural noun", "an adjective"], "answer": 0, "explain": "All three advice structures are followed by an infinitive (comer, beber, evitar…), never a conjugated form."}}, {"title": "How do I say what I am going to change?", "html": "<p>Use the near future — <strong>voy a</strong> + <strong>infinitive</strong> — to state a plan or intention:</p>\n            <ul>\n              <li><span data-say=\"Voy a comer más verduras.\">Voy a comer más verduras.</span> — I am going to eat more vegetables.</li>\n              <li><span data-say=\"Voy a evitar la comida rápida.\">Voy a evitar la comida rápida.</span> — I am going to avoid fast food.</li>\n              <li><span data-say=\"Voy a beber menos azúcar.\">Voy a beber menos azúcar.</span> — I am going to have less sugar.</li>\n            </ul>\n            <p><strong>evitar</strong> = to avoid, <strong>la comida rápida</strong> = fast food. Add a time phrase to extend: <span data-say=\"todos los días\">todos los días</span> (every day), <span data-say=\"a menudo\">a menudo</span> (often).</p>\n            <p>You can add a month too: <span data-say=\"en mayo\">en mayo</span> (in May), <span data-say=\"en julio\">en julio</span> (in July), <span data-say=\"en noviembre\">en noviembre</span> (in November) — for example: <span data-say=\"En julio como mucha fruta de temporada, pero en noviembre como más sopa.\">En julio como mucha fruta de temporada, pero en noviembre como más sopa.</span> — <em>In July I eat a lot of seasonal fruit, but in November I eat more soup.</em> <span data-say=\"Probablemente voy a comer menos azúcar el año que viene.\">Probablemente voy a comer menos azúcar el año que viene.</span> — <em>I am probably going to eat less sugar next year.</em></p>", "check": {"question": "How do you say ‘I am going to avoid fast food’?", "options": ["Voy a evitar la comida rápida", "Se debe evitar la comida rápida", "Evito la comida rápida", "Hay que evitar la comida rápida"], "answer": 0, "explain": "voy a + infinitive = a future plan; ‘I am going to avoid’ = Voy a evitar."}}, {"title": "How do I give opinions and reasons?", "html": "<p>Opinions lift your mark. Use <strong>gustar</strong>-type verbs and join ideas with connectors:</p>\n            <ul>\n              <li><span data-say=\"Me gusta la fruta.\">Me gusta la fruta.</span> — I like fruit. <em>(singular thing)</em></li>\n              <li><span data-say=\"Me gustan las verduras.\">Me gustan las verduras.</span> — I like vegetables. <em>(plural → gusta<strong>n</strong>)</em></li>\n              <li><span data-say=\"Prefiero el pescado.\">Prefiero el pescado.</span> — I prefer fish.</li>\n            </ul>\n            <p>Connectors: <span data-say=\"porque\">porque</span> (because), <span data-say=\"pero\">pero</span> (but), <span data-say=\"también\">también</span> (also). Example: <span data-say=\"Me gusta la carne, pero no como carne todos los días porque es mala para la salud.\">Me gusta la carne, pero no como carne todos los días porque es mala para la salud.</span></p>\n            <p><span data-say=\"Es extraño, pero no me gusta la fruta.\">Es extraño, pero no me gusta la fruta.</span> — <em>It’s strange, but I don’t like fruit.</em> In some <span data-say=\"casos\">casos</span> (cases), people prefer <span data-say=\"el segundo plato\">el segundo plato</span> (the second course) to the first. <span data-say=\"En la comida anterior comí demasiada grasa, así que hoy prefiero algo más ligero.\">En la comida anterior comí demasiada grasa, así que hoy prefiero algo más ligero.</span> — <em>In the previous meal I ate too much fat, so today I prefer something lighter.</em></p>", "check": {"question": "Why is it ‘Me gustan las verduras’ (not ‘gusta’)?", "options": ["verduras is plural, so the verb agrees", "it expresses a future plan, not a preference", "verduras is a feminine singular noun here", "it is simply someone’s opinion"], "answer": 0, "explain": "gustar agrees with the THING liked; verduras is plural → gustan (nothing to do with plans or opinions)."}}, {"title": "Higher: reach for the top band", "html": "<p><span class=\"tier-h\">H</span> To push into the higher band, add a <strong>conditional</strong> recommendation and a <strong>concession</strong>:</p>\n            <ul>\n              <li><span data-say=\"Se debería reducir el azúcar.\">Se debería reducir el azúcar.</span> — One <em>should</em> reduce sugar. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Lo más importante es llevar una dieta variada.\">Lo más importante es llevar una dieta variada.</span> — The most important thing is to have a varied diet. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Aunque me gusta el chocolate, intento comer sano.\">Aunque me gusta el chocolate, intento comer sano.</span> — Although I like chocolate, I try to eat healthily. <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Aim for: <strong>opinion + reason + connector + a second tense</strong> in one sentence.</p>\n            <p><span class=\"tier-h\">H</span> Compare people’s diets: <span data-say=\"Mi dieta es vegetariana; la suya es vegana.\">Mi dieta es vegetariana; la suya es vegana.</span> — <em>My diet is vegetarian; theirs/his/hers is vegan.</em> <span data-say=\"Claro, cada persona tiene su propia opinión.\">Claro, cada persona tiene su propia opinión.</span> — <em>Of course, everyone has their own opinion.</em> <span data-say=\"Desde mi juventud, intento comer sano, y el aceite de oliva es el tercer ingrediente más importante de mi dieta.\">Desde mi juventud, intento comer sano, y el aceite de oliva es el tercer ingrediente más importante de mi dieta.</span> — <em>Since my youth, I have tried to eat healthily, and olive oil is the third most important ingredient in my diet.</em> <span class=\"tier-h\">H</span></p>", "check": {"question": "Which sentence shows a typically Higher-tier feature?", "options": ["Se debería reducir el azúcar", "Me gusta mucho la fruta fresca del país", "Como pan casi todos los días", "Bebo bastante agua con las comidas"], "answer": 0, "explain": "‘se debería’ is a conditional — a Higher feature. Option B is longer but only present-tense opinion."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la fruta", "definition": "fruit"}, {"term": "las verduras", "definition": "vegetables"}, {"term": "el pescado", "definition": "fish"}, {"term": "el agua", "definition": "water"}, {"term": "el azúcar", "definition": "sugar"}, {"term": "la grasa", "definition": "fat"}, {"term": "una dieta equilibrada", "definition": "a balanced diet"}, {"term": "sano / saludable", "definition": "healthy"}, {"term": "se debe + infinitive", "definition": "one should / must…"}, {"term": "no se debe + infinitive", "definition": "one must not…"}, {"term": "hay que + infinitive", "definition": "you have to…"}, {"term": "voy a + infinitive", "definition": "I am going to… (plan)"}, {"term": "evitar", "definition": "to avoid"}, {"term": "la comida rápida", "definition": "fast food"}, {"term": "bueno / malo para la salud", "definition": "good / bad for your health"}, {"term": "porque · pero · también", "definition": "because · but · also"}, {"term": "se debería (H)", "definition": "one should… (conditional)"}, {"term": "aunque (H)", "definition": "although"}, {"term": "el alimento", "definition": "food, foodstuff"}, {"term": "un régimen (alimenticio)", "definition": "a diet, eating regime"}, {"term": "la juventud", "definition": "youth"}, {"term": "el diente", "definition": "tooth"}, {"term": "el consumo", "definition": "consumption"}, {"term": "el vaso", "definition": "glass"}, {"term": "la botella", "definition": "bottle"}, {"term": "la sed", "definition": "thirst"}, {"term": "el sobrepeso", "definition": "being overweight"}, {"term": "vegano / vegana", "definition": "vegan"}, {"term": "vegetariano / vegetariana", "definition": "vegetarian"}, {"term": "nuestro, nuestra, nuestros, nuestras", "definition": "our"}, {"term": "el caso", "definition": "case"}, {"term": "el segundo (plato)", "definition": "second (course)"}, {"term": "tercero / tercer", "definition": "third"}, {"term": "anterior", "definition": "previous"}, {"term": "dentro (de)", "definition": "inside / within"}, {"term": "julio", "definition": "July"}, {"term": "extraño", "definition": "strange"}, {"term": "mayo", "definition": "May"}, {"term": "suyo, suya, suyos, suyas", "definition": "his / hers / theirs / yours (formal)"}, {"term": "el límite", "definition": "limit"}, {"term": "una reacción (alérgica)", "definition": "an (allergic) reaction"}, {"term": "noviembre", "definition": "November"}, {"term": "claro", "definition": "clearly, of course"}, {"term": "complicado", "definition": "complicated"}, {"term": "probablemente", "definition": "probably"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Se debe comer más fruta y verduras.\" data-listen></span><br>Listen. What is the advice?", "options": ["One should eat more fruit and vegetables", "One must not eat so much fruit or fatty food", "They always eat their fruit and vegetables first", "You have to grow your own fruit and vegetables"], "answer": 0, "explain": "‘se debe comer más’ = one should eat more. Trap B flips it to a negative; C and D change the verb — you have to actually hear ‘se debe … más’."}, {"question": "<span data-say=\"Voy a beber menos azúcar.\" data-listen></span><br>Listen. What does the speaker plan to do?", "options": ["Have less sugar", "Drink more sugary things", "Give up fizzy drinks completely", "Stop drinking coffee with sugar"], "answer": 0, "explain": "‘voy a beber menos azúcar’ = I’m going to have less sugar. Trap B swaps menos→more; C and D add detail that was never said."}, {"question": "<span data-say=\"No se debe comer demasiada grasa.\" data-listen></span><br>Listen. Which is correct?", "options": ["One must not eat too much fat", "One should add a little healthy fat", "You are allowed to eat as much as you like", "It is fine to fry your food in lots of oil"], "answer": 0, "explain": "‘no se debe comer demasiada grasa’ = one must not eat too much fat. Every distractor is longer AND reverses the meaning — you must hear the ‘no’."}, {"question": "‘una dieta equilibrada’ means…", "options": ["a balanced diet", "a varied menu", "a healthy lifestyle", "a strict weight-loss plan"], "answer": 0, "explain": "equilibrada = balanced. ‘variada’ (varied), ‘vida sana’ (lifestyle) and a diet-plan are close but wrong."}, {"question": "Only ONE sentence is fully correct. Which?", "options": ["Me gustan las verduras", "Me gusta las verduras", "A mí me gusta mucho las verduras", "Yo gusto las verduras todos los días"], "answer": 0, "explain": "The thing liked is plural (verduras) so the verb is gustan. B fails to agree; C still uses gusta with a plural; D wrongly conjugates gustar as ‘yo gusto’."}, {"question": "How do you say ‘I am going to eat more vegetables’?", "options": ["Voy a comer más verduras", "Como muchas más verduras ahora", "Se debe comer más verduras hoy", "Voy comer más verduras cada día"], "answer": 0, "explain": "A plan = voy a + infinitive. B is present tense; C is impersonal advice; D drops the ‘a’ that ‘voy a’ needs."}, {"question": "In ‘Voy a evitar la comida rápida’, ‘evitar’ means to…", "options": ["avoid", "prepare it quickly", "cut down on it", "order it less often"], "answer": 0, "explain": "evitar = to avoid. The longer options are tempting ‘sort of healthy’ ideas, but none means avoid."}, {"question": "‘Bebo mucha ___.’ — which word fits BOTH the grammar and ‘I drink lots of water’?", "options": ["agua", "leche", "zumo", "café con leche"], "answer": 0, "explain": "‘mucha’ is feminine, so leche/agua both fit grammatically — but only ‘agua’ = water. zumo is masculine (mucho zumo)."}, {"question": "Which word means ‘because’ (gives a reason)?", "options": ["porque", "aunque", "también", "pero"], "answer": 0, "explain": "porque = because. ‘aunque’ (although) is the closest trap; también = also; pero = but."}, {"question": "Why is ‘Se debería reducir el azúcar’ a strong Higher-tier phrase?", "options": ["It uses the conditional", "It is in the present tense", "It gives a direct command", "It describes a completed past action"], "answer": 0, "explain": "‘se debería’ = one should (conditional) — a Higher feature. The traps name other tenses/moods of similar length."}, {"question": "What is true about ‘vegano’ and ‘vegetariano’?", "options": ["vegano is stricter than vegetariano", "vegetariano never eats cheese, eggs or milk, only vegano does", "vegano and vegetariano are just two spellings of the same word", "vegetariano is the stricter of the two and avoids all animal products"], "answer": 0, "explain": "A vegano avoids ALL animal products; a vegetariano may still eat cheese, eggs or milk — the traps swap which one is stricter or claim they are synonyms."}, {"question": "‘un régimen (alimenticio)’ is another way of saying…", "options": ["a diet", "a military base", "a type of exercise", "a medical prescription"], "answer": 0, "explain": "régimen (alimenticio) = an eating regime/diet. The distractors are false-friend guesses from ‘régimen’ sounding like ‘regiment’ or ‘regimen’ in English."}, {"question": "‘el sobrepeso’ means…", "options": ["being overweight", "losing weight quickly", "having a big appetite", "feeling very hungry"], "answer": 0, "explain": "el sobrepeso = being overweight (sobre = over + peso = weight). It is a state, not an action like losing weight or a feeling like hunger."}, {"question": "‘una reacción alérgica a un alimento’ means…", "options": ["an allergic reaction to a food", "a strong preference for a food", "a diet based around one food", "a recipe using a rare food"], "answer": 0, "explain": "reacción alérgica = allergic reaction; alimento = food. The traps reinterpret ‘reacción’ as a preference or turn ‘alimento’ into a recipe/diet."}, {"question": "Which sentence gives good advice about ‘el consumo de azúcar’?", "options": ["Se debe reducir el consumo de azúcar", "Se debe aumentar el consumo de azúcar todos los días", "No importa cuánto azúcar consumas", "El consumo de azúcar no afecta a la salud"], "answer": 0, "explain": "Good advice = reduce sugar consumption. The traps tell you to increase it, ignore it, or claim it has no effect on health."}]}, "fib": {"enabled": true, "questions": [{"text": "Se [debe] comer más fruta. <span data-say=\"Se debe comer más fruta.\" data-listen>Se debe comer más fruta.</span>"}, {"text": "Voy a [evitar] la comida rápida. <span data-say=\"Voy a evitar la comida rápida.\" data-listen>Voy a evitar la comida rápida.</span>"}, {"text": "Hay que beber mucha [agua]. <span data-say=\"Hay que beber mucha agua.\" data-listen>Hay que beber mucha agua.</span>"}, {"text": "Me [gustan] las verduras. (I like vegetables — plural!)"}, {"text": "Como una dieta [equilibrada]. (balanced)"}, {"text": "No se debe comer demasiado [azúcar]. (sugar)"}, {"text": "Prefiero el pescado [porque] es bueno para la salud. (because)"}, {"text": "Bebo un [vaso] de agua cuando tengo sed. <span data-say=\"Bebo un vaso de agua cuando tengo sed.\" data-listen>Bebo un vaso de agua cuando tengo sed.</span>"}, {"text": "Soy [vegano]. No como ningún producto animal. (vegan, masculine)"}, {"text": "Hay un [límite] de azúcar recomendado al día. (limit)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘una dieta equilibrada’ means ‘a balanced diet’.", "answer": true, "explain": "equilibrada = balanced."}, {"statement": "‘se debe’ is followed by a past-tense verb.", "answer": false, "explain": "It is followed by an infinitive: se debe comer / beber / evitar."}, {"statement": "‘Me gustan las verduras’ is correct because ‘verduras’ is plural.", "answer": true, "explain": "gustar agrees with the thing liked; plural → gustan."}, {"statement": "‘evitar’ means ‘to enjoy’.", "answer": false, "explain": "evitar = to avoid."}, {"statement": "‘voy a comer’ describes a future plan.", "answer": true, "explain": "voy a + infinitive = near future."}, {"statement": "‘el azúcar’ means ‘salt’.", "answer": false, "explain": "el azúcar = sugar; salt = la sal."}, {"statement": "‘porque’ means ‘but’.", "answer": false, "explain": "porque = because; ‘but’ = pero."}, {"statement": "‘Se debería reducir el azúcar’ uses the conditional and suits Higher tier.", "answer": true, "explain": "se debería = one should (conditional)."}, {"statement": "‘vegetariano’ and ‘vegano’ mean exactly the same thing.", "answer": false, "explain": "A vegano avoids all animal products; a vegetariano may still eat eggs, cheese or milk."}, {"statement": "‘el consumo de azúcar’ means ‘sugar consumption’.", "answer": true, "explain": "consumo = consumption."}, {"statement": "‘tener sed’ means ‘to be hungry’.", "answer": false, "explain": "tener sed = to be thirsty; tener hambre = to be hungry."}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta las verduras.", "truth": "Me gustan las verduras.", "check": {"question": "Why is it ‘Me gustan las verduras’?", "options": ["verduras is plural, so it becomes gustan", "the subject ‘yo’ is what forces the ending gustan here", "verduras is a masculine noun", "the sentence is in the past"], "answer": 0, "explain": "gustar agrees with the thing liked (verduras, plural) → gustan. It is NOT the person that drives the ending — that is the classic error."}}, {"myth": "una dieta equilibrado", "truth": "una dieta equilibrada", "check": {"question": "Why must it be ‘equilibrada’?", "options": ["the adjective agrees with the feminine noun ‘dieta’", "it copies the gender of whichever verb happens to be closest to it", "the masculine form is the safe default", "adjectives only change in the plural"], "answer": 0, "explain": "Adjectives agree with their noun in gender AND number: dieta is feminine singular → equilibrada."}}, {"myth": "Se debe comí más fruta.", "truth": "Se debe comer más fruta.", "check": {"question": "What must follow ‘se debe’?", "options": ["an infinitive (comer)", "a verb written in a past tense form", "a plural noun", "an adjective"], "answer": 0, "explain": "‘se debe’ always takes an infinitive, never a conjugated past form."}}, {"myth": "Voy comer más verduras.", "truth": "Voy a comer más verduras.", "check": {"question": "What is missing in ‘Voy comer…’?", "options": ["the linking word ‘a’ (voy a + infinitive)", "an accent on the final vowel of the infinitive comer", "the pronoun ‘me’", "the article ‘las’"], "answer": 0, "explain": "The near future is voy/vas/va + a + infinitive; the ‘a’ is compulsory."}}, {"myth": "Como comida sensible.", "truth": "Como comida sana.", "check": {"question": "Why is ‘sensible’ wrong here for ‘healthy’?", "options": ["it is a false friend meaning ‘sensitive’", "it is the plural of an adjective you can’t use", "it is a verb, not an adjective", "it simply needs a written accent"], "answer": 0, "explain": "False friend: Spanish ‘sensible’ = sensitive. Healthy = sano/sana/saludable."}}, {"myth": "Soy vegano, como queso y huevos.", "truth": "Soy vegetariano, como queso y huevos. (Un vegano no come queso, huevos ni ningún otro producto animal.)", "check": {"question": "Why is ‘Soy vegano, como queso y huevos’ a contradiction?", "options": ["a vegano eats no animal products at all, including cheese and eggs", "vegano and vegetariano are simply two different spellings of one word, so they mean exactly the same thing", "cheese and eggs are not animal products", "vegano only refers to not eating meat, cheese is always fine"], "answer": 0, "explain": "vegano = vegan (zero animal products, including dairy and eggs); vegetariano can still eat cheese and eggs — the two words are not interchangeable."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "In the dictation you hear short sentences and write them down. Listen for whole chunks you know (‘se debe comer…’, ‘voy a…’) rather than single sounds. Get the accents where you can, but a minor accent slip is not always penalised — spelling the word right matters most.", "check": {"question": "What is the best dictation strategy?", "options": ["Write the whole chunks you recognise, not single sounds", "Write down each and every individual letter that you hear", "Only ever write the very first word of each sentence", "Translate it straight into English as you listen"], "answer": 0, "explain": "You already know whole phrases (‘se debe comer’, ‘voy a…’); catching them as chunks is far more reliable than letter-by-letter."}}, {"title": "Paper 3 — Translation into English", "html": "Don’t translate word-for-word. ‘Se debe comer fruta’ is ‘One should / you should eat fruit’, not ‘It must to eat fruit’. Keep the tense: ‘voy a evitar’ = ‘I am going to avoid’.", "check": {"question": "‘Voy a evitar la comida rápida’ means…", "options": ["I am going to avoid fast food", "I am not going to avoid fast food", "I used to avoid fast food a lot", "I have already avoided fast food"], "answer": 0, "explain": "voy a + infinitive = the near future. The traps flip the meaning to a negative or a different tense — all longer than the answer."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "For top marks combine an opinion, a reason and a second tense in one sentence: ‘Me gusta la carne, pero voy a comer menos porque es mala para la salud.’ At Higher, add ‘se debería…’ or ‘aunque…’.", "check": {"question": "Which sentence would score highest?", "options": ["Me gusta la carne, pero voy a comer menos porque es mala para la salud", "A mí me gusta mucho la carne y como carne y la carne está muy rica siempre", "Me gusta la carne", "Como carne todos los días"], "answer": 0, "explain": "The winner combines an opinion, a connector, a second tense (future) AND a reason. Option B is even longer but just repeats one idea in the present — length alone is not what scores."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer the questions <strong>in English</strong>.<br>(a) What does Carlos have for breakfast? (2)<br>(b) Why doesn’t he like fast food? (1)<br>(c) Name <strong>one</strong> thing he is going to change next year. (1)", "marks": 4, "hint": "Find ‘el desayuno’, then the reason after ‘porque’, then the ‘voy a…’ plans.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> fruit / cereals <em>(1 mark each, 2 total)</em>; also accept ‘drinks lots of water’ as an alternative detail.</li>\n                <li><strong>(b)</strong> (because) it is bad for your/his health <em>(1)</em>.</li>\n                <li><strong>(c)</strong> ANY ONE of: eat less sugar / do more exercise <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English. Do not penalise spelling if the meaning is clear.</li>\n                <li>(a) needs two distinct items for both marks.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I like fruit. <br>(b) One should eat vegetables. <br>(c) I am going to avoid fast food because it is bad for your health.", "marks": 5, "hint": "‘I like’ + singular = Me gusta. ‘One should eat’ = Se debe comer. ‘I am going to avoid’ = Voy a evitar.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me gusta la fruta. <em>(1)</em></li>\n                <li><strong>(b)</strong> Se debe comer verduras / las verduras. <em>(1)</em></li>\n                <li><strong>(c)</strong> Voy a evitar la comida rápida <em>(1)</em> porque <em>(1)</em> es mala para la salud <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors; ‘mala/malo’ must agree sensibly. ‘comida rápida’ spelt without the accent is condoned once.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '2-2-exercise-health-problems-and-advice', '2.2 Exercise, Health Problems and Advice', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about exercise and sport?", "html": "<p>The key verb is <span data-say=\"hacer ejercicio\">hacer ejercicio</span> (to do exercise / to work out). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el deporte\">el deporte</span></td><td>sport</td><td><span data-say=\"correr\">correr</span></td><td>to run</td></tr>\n              <tr><td><span data-say=\"nadar\">nadar</span></td><td>to swim</td><td><span data-say=\"montar en bicicleta\">montar en bicicleta</span></td><td>to cycle</td></tr>\n              <tr><td><span data-say=\"el gimnasio\">el gimnasio</span></td><td>the gym</td><td><span data-say=\"entrenar\">entrenar</span></td><td>to train</td></tr>\n              <tr><td><span data-say=\"estar en forma\">estar en forma</span></td><td>to be fit</td><td><span data-say=\"activo\">activo / activa</span></td><td>active</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Para estar en forma, hago ejercicio tres veces por semana.\">Para estar en forma, hago ejercicio tres veces por semana.</span> — <em>To be fit, I exercise three times a week.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"fuerte\">fuerte</span></td><td>strong</td><td><span data-say=\"débil\">débil</span></td><td>weak</td></tr>\n            </table>\n            <p>Walking counts too: <span data-say=\"pasear\">pasear</span> (to walk / stroll) — <span data-say=\"Los fines de semana, paseo con mi perro para hacer ejercicio sin ir al gimnasio.\">Los fines de semana, paseo con mi perro para hacer ejercicio sin ir al gimnasio.</span> — <em>At weekends, I walk with my dog to exercise without going to the gym.</em> Some people check <span data-say=\"el reloj\">el reloj</span> (the clock/watch) to time their run — no importa si corres <span data-say=\"lento\">lento</span> (slowly) al principio.</p>", "check": {"question": "What does ‘estar en forma’ mean?", "options": ["to be fit", "to run a race", "to go to the gym building", "to fill in a paper form"], "answer": 0, "explain": "estar en forma = to be fit / in shape. It is a false friend — ‘forma’ here is not a paper ‘form’."}}, {"title": "How do I say what hurts? (me duele / me duelen)", "html": "<p>To say something hurts, use <strong>doler</strong> — and it behaves <em>exactly like</em> <strong>gustar</strong>: the verb agrees with the body part, not with you.</p>\n            <ul>\n              <li>ONE thing hurts → <span data-say=\"me duele\">me duele</span>: <span data-say=\"Me duele la cabeza.\">Me duele la cabeza.</span> (My head hurts.)</li>\n              <li>MORE THAN ONE → <span data-say=\"me duelen\">me duelen</span>: <span data-say=\"Me duelen los pies.\">Me duelen los pies.</span> (My feet hurt.)</li>\n            </ul>\n            <p>Body parts (<strong>el cuerpo</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la cabeza\">la cabeza</span></td><td>head</td><td><span data-say=\"el estómago\">el estómago</span></td><td>stomach</td></tr>\n              <tr><td><span data-say=\"la garganta\">la garganta</span></td><td>throat</td><td><span data-say=\"la espalda\">la espalda</span></td><td>back</td></tr>\n              <tr><td><span data-say=\"las piernas\">las piernas</span></td><td>legs</td><td><span data-say=\"los ojos\">los ojos</span></td><td>eyes</td></tr>\n              <tr><td><span data-say=\"la boca\">la boca</span></td><td>mouth</td><td><span data-say=\"el brazo\">el brazo</span></td><td>arm</td></tr>\n              <tr><td><span data-say=\"el corazón\">el corazón</span></td><td>heart</td><td><span data-say=\"la pierna\">la pierna</span></td><td>leg (singular)</td></tr>\n              <tr><td><span data-say=\"la piel\">la piel</span></td><td>skin</td><td><span data-say=\"el cerebro\">el cerebro</span></td><td>brain</td></tr>\n            </table>\n            <p><span data-say=\"el dolor\">el dolor</span> (pain) is the noun behind ‘doler’: <span data-say=\"Tengo un dolor de cabeza terrible.\">Tengo un dolor de cabeza terrible.</span> — <em>I have a terrible headache.</em></p>", "check": {"question": "Why is it ‘Me duelen los pies’ and not ‘Me duele los pies’?", "options": ["‘los pies’ is plural, so the verb is plural", "‘doler’ is a verb that is always plural in Spanish", "‘pies’ is a masculine noun", "it describes a future plan"], "answer": 0, "explain": "Like gustar, doler agrees with the body part; ‘los pies’ is plural → duelen (doler is NOT always plural)."}}, {"title": "How do I describe health problems?", "html": "<p>Use <strong>estar</strong> (a temporary state) for how you feel:</p>\n            <ul>\n              <li><span data-say=\"estar enfermo\">estar enfermo / enferma</span> — to be ill</li>\n              <li><span data-say=\"estar cansado\">estar cansado / cansada</span> — to be tired</li>\n              <li><span data-say=\"estar resfriado\">estar resfriado / resfriada</span> — to have a cold</li>\n              <li><span data-say=\"el estrés\">el estrés</span> — stress; <span data-say=\"estar estresado\">estar estresado</span> — to be stressed</li>\n            </ul>\n            <p>Example: <span data-say=\"Estoy muy cansado porque no duermo bien.\">Estoy muy cansado porque no duermo bien.</span> — <em>I am very tired because I don’t sleep well.</em></p>\n            <p><span data-say=\"una enfermedad\">una enfermedad</span> (an illness) can be <span data-say=\"serio\">serio / seria</span> (serious) — for example <span data-say=\"el cáncer\">el cáncer</span> (cancer), which is often linked to smoking <span data-say=\"un cigarrillo\">un cigarrillo</span> (a cigarette). Doctors also check <span data-say=\"la sangre\">la sangre</span> (blood): <span data-say=\"El médico me hizo un análisis de sangre porque estaba muy débil.\">El médico me hizo un análisis de sangre porque estaba muy débil.</span> — <em>The doctor did a blood test because I was very weak.</em></p>", "check": {"question": "Which verb do you use for ‘I am tired’ — a temporary state?", "options": ["estar → estoy cansado", "ser → soy cansado", "tener → tengo cansado", "hacer → hago cansado"], "answer": 0, "explain": "Temporary states and feelings use estar: estoy cansado. ‘ser’ would describe a permanent trait."}}, {"title": "How do I give health advice?", "html": "<p>Reuse the advice structures from 2.1 — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe descansar\">se debe descansar</span></td><td>one should rest</td></tr>\n              <tr><td><span data-say=\"no se debe fumar\">no se debe fumar</span></td><td>one must not smoke</td></tr>\n              <tr><td><span data-say=\"hay que dormir ocho horas\">hay que dormir ocho horas</span></td><td>you have to sleep eight hours</td></tr>\n              <tr><td><span data-say=\"deberías relajarte\">deberías relajarte</span> <span class=\"tier-h\">H</span></td><td>you should relax</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Para evitar el estrés, se debe descansar y hacer ejercicio.\">Para evitar el estrés, se debe descansar y hacer ejercicio.</span></p>\n            <p>The verb <span data-say=\"cuidar\">cuidar</span> (to look after / take care of) is essential: <span data-say=\"Hay que cuidar tu salud y dormir suficiente.\">Hay que cuidar tu salud y dormir suficiente.</span> — <em>You have to look after your health and sleep enough.</em> A good night’s sleep is often the most <span data-say=\"efectivo\">efectivo</span> (effective) remedy, and it helps reduce <span data-say=\"el efecto\">el efecto</span> (the effect) of stress on the body.</p>", "check": {"question": "What follows ‘se debe’, ‘hay que’ and ‘deberías’?", "options": ["an infinitive (descansar, dormir…)", "a verb conjugated in the preterite past tense", "an adjective that agrees", "a noun on its own"], "answer": 0, "explain": "All the advice structures take an infinitive."}}, {"title": "How do I talk about bad habits?", "html": "<p>Common ‘malos hábitos’ (bad habits) and how to reject them:</p>\n            <ul>\n              <li><span data-say=\"fumar\">fumar</span> — to smoke; <span data-say=\"el tabaco\">el tabaco</span> — tobacco</li>\n              <li><span data-say=\"beber alcohol\">beber alcohol</span> — to drink alcohol; <span data-say=\"las drogas\">las drogas</span> — drugs</li>\n              <li><span data-say=\"dejar de fumar\">dejar de + infinitive</span> — to stop doing something: <span data-say=\"dejar de fumar\">dejar de fumar</span> (to stop smoking)</li>\n            </ul>\n            <p><span data-say=\"No se debe fumar porque es muy malo para la salud.\">No se debe fumar porque es muy malo para la salud.</span></p>\n            <p>Good habits matter too: <span data-say=\"lavarse los dientes\">lavarse los dientes</span> (to brush/wash your teeth) after meals, and <span data-say=\"la risa\">la risa</span> (laughter) — <span data-say=\"Dicen que la risa es la mejor medicina.\">Dicen que la risa es la mejor medicina.</span> — <em>They say laughter is the best medicine.</em> Taking care of your <span data-say=\"la imagen\">la imagen</span> (image) shouldn’t mean unhealthy habits, and the local health centre is normally <span data-say=\"abierto\">abierto</span> (open) every day if you need advice.</p>", "check": {"question": "‘dejar de fumar’ means…", "options": ["to stop smoking", "to let others smoke", "to smoke a little more", "to enjoy smoking outside"], "answer": 0, "explain": "dejar de + infinitive = to stop doing something; dejar de fumar = to stop smoking."}}, {"title": "Higher: reflexives and future plans", "html": "<p><span class=\"tier-h\">H</span> Many health verbs are <strong>reflexive</strong> — the action is done to yourself, so they take <strong>me / te / se</strong>:</p>\n            <ul>\n              <li><span data-say=\"relajarse\">relajarse</span> → <span data-say=\"me relajo\">me relajo</span> (I relax)</li>\n              <li><span data-say=\"acostarse\">acostarse</span> → <span data-say=\"me acuesto temprano\">me acuesto temprano</span> (I go to bed early)</li>\n            </ul>\n            <p>Combine with a plan or a conditional for the top band:</p>\n            <ul>\n              <li><span data-say=\"Voy a dejar de fumar y acostarme más temprano.\">Voy a dejar de fumar y acostarme más temprano.</span> <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Se debería evitar el estrés para mantenerse sano.\">Se debería evitar el estrés para mantenerse sano.</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> Other useful reflexive/health verbs: <span data-say=\"caerse\">caerse</span> (to fall over) — <span data-say=\"Mi abuelo se cayó y le duele la pierna desde hace una semana.\">Mi abuelo se cayó y le duele la pierna desde hace una semana.</span> — <em>My grandad fell over and his leg has hurt for a week.</em> Don’t forget to <span data-say=\"respirar\">respirar</span> (breathe) deeply to relax. <span data-say=\"la salud mental\">la salud mental</span> (mental health) matters as much as physical health — being <span data-say=\"optimista\">optimista</span> (optimistic) helps, and a <span data-say=\"paciente\">paciente</span> (patient) who stays positive often recovers faster. <span class=\"tier-h\">H</span></p>", "check": {"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me acuesto temprano", "Acuesto temprano cada noche", "Yo acuesto muy temprano", "Se acuesto temprano"], "answer": 0, "explain": "acostarse is reflexive: (yo) me acuesto. Dropping ‘me’ or using the wrong pronoun is wrong."}}]}, "terms": {"enabled": true, "pairs": [{"term": "hacer ejercicio", "definition": "to do exercise"}, {"term": "el deporte", "definition": "sport"}, {"term": "estar en forma", "definition": "to be fit"}, {"term": "el gimnasio", "definition": "the gym"}, {"term": "me duele…", "definition": "…hurts (one thing)"}, {"term": "me duelen…", "definition": "…hurt (more than one)"}, {"term": "la cabeza · el estómago", "definition": "head · stomach"}, {"term": "la garganta · la espalda", "definition": "throat · back"}, {"term": "estar enfermo / cansado", "definition": "to be ill / tired"}, {"term": "estar resfriado / constipado", "definition": "to have a cold"}, {"term": "el estrés", "definition": "stress"}, {"term": "fumar · las drogas", "definition": "to smoke · drugs"}, {"term": "dejar de + infinitive", "definition": "to stop doing something"}, {"term": "se debe descansar", "definition": "one should rest"}, {"term": "relajarse (H)", "definition": "to relax (reflexive)"}, {"term": "acostarse (H)", "definition": "to go to bed (reflexive)"}, {"term": "deberías / se debería (H)", "definition": "you should / one should (conditional)"}, {"term": "para mantenerse sano (H)", "definition": "to stay healthy"}, {"term": "caer / caerse", "definition": "to fall / to fall over"}, {"term": "fuerte", "definition": "strong"}, {"term": "la boca", "definition": "mouth"}, {"term": "el brazo", "definition": "arm"}, {"term": "el corazón", "definition": "heart"}, {"term": "la sangre", "definition": "blood"}, {"term": "el dolor", "definition": "pain"}, {"term": "una enfermedad", "definition": "an illness"}, {"term": "la piel", "definition": "skin"}, {"term": "cuidar", "definition": "to look after, take care of"}, {"term": "la pierna", "definition": "leg"}, {"term": "serio / seria", "definition": "serious"}, {"term": "optimista", "definition": "optimistic"}, {"term": "un/a paciente", "definition": "a patient"}, {"term": "el cerebro", "definition": "brain"}, {"term": "lavar(se)", "definition": "to wash (oneself)"}, {"term": "pasear", "definition": "to walk, stroll"}, {"term": "respirar", "definition": "to breathe"}, {"term": "mental", "definition": "mental"}, {"term": "débil", "definition": "weak"}, {"term": "el cáncer", "definition": "cancer"}, {"term": "un cigarrillo", "definition": "a cigarette"}, {"term": "el efecto", "definition": "effect"}, {"term": "la imagen", "definition": "image"}, {"term": "suficiente", "definition": "enough, sufficient"}, {"term": "la risa", "definition": "laughter"}, {"term": "lento", "definition": "slow"}, {"term": "el reloj", "definition": "clock, watch"}, {"term": "efectivo", "definition": "effective"}, {"term": "abierto", "definition": "open"}, {"term": "desde hace + present tense", "definition": "for / since (a period of time)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Me duele la cabeza.\" data-listen></span><br>Listen. What is the problem?", "options": ["My head hurts", "My head and my back both hurt", "I have banged my head badly", "My headache has finally gone"], "answer": 0, "explain": "‘me duele la cabeza’ = my head hurts. The traps add a second body part, a cause, or the opposite meaning."}, {"question": "<span data-say=\"Voy a hacer más ejercicio.\" data-listen></span><br>Listen. What is the plan?", "options": ["To do more exercise", "To do a bit less exercise", "One should exercise more often", "I already exercise every day"], "answer": 0, "explain": "‘voy a hacer más ejercicio’ = I’m going to do more exercise. Trap B swaps más→less; C is impersonal advice; D is present tense."}, {"question": "<span data-say=\"No se debe fumar.\" data-listen></span><br>Listen. Which is correct?", "options": ["One must not smoke", "One should smoke only a little", "You are allowed to smoke here", "I have never smoked in my life"], "answer": 0, "explain": "‘no se debe fumar’ = one must not smoke. Every distractor is longer and reverses or weakens the ‘no’."}, {"question": "How do you say ‘my feet hurt’?", "options": ["Me duelen los pies", "Me duele los pies", "Me duelo los pies", "Yo duelo mucho los pies"], "answer": 0, "explain": "doler agrees with the body part; ‘los pies’ is plural → duelen. B fails to agree; C/D conjugate doler as if it were a normal verb."}, {"question": "Careful — ‘Estoy constipado’ means…", "options": ["I have a cold", "I am constipated", "I am very tired today", "I feel completely fine"], "answer": 0, "explain": "False friend! ‘constipado’ = having a cold, NOT constipated. The obvious guess is the trap."}, {"question": "How do you say ‘I go to bed early’?", "options": ["Me acuesto temprano", "Me acuesto muy tarde entre semana", "Acuesto temprano cada noche", "Se acuesta temprano"], "answer": 0, "explain": "acostarse is reflexive → me acuesto; ‘temprano’ = early. B says ‘tarde’ (late); C drops ‘me’; D is ‘he/she’."}, {"question": "Which sentence gives POSITIVE health advice?", "options": ["Se debe descansar más", "No se debe descansar nunca", "No se debe hacer ejercicio", "Se debe fumar a menudo"], "answer": 0, "explain": "‘se debe descansar más’ = one should rest more (good advice). The others are negatives or bad advice."}, {"question": "Complete: ‘Para estar en forma, hay que ___ ejercicio.’", "options": ["hacer", "hago", "haciendo", "hecho"], "answer": 0, "explain": "‘hay que’ takes an infinitive → hacer. The others are conjugated / non-finite forms."}, {"question": "‘Me duele la garganta’ — where does it hurt?", "options": ["throat", "stomach", "back", "head"], "answer": 0, "explain": "la garganta = throat. estómago = stomach, espalda = back, cabeza = head."}, {"question": "‘Se debería evitar el estrés’ uses which verb form?", "options": ["the conditional (should)", "a completed past-tense action", "the ordinary present tense", "a direct command"], "answer": 0, "explain": "‘se debería’ = one should → conditional, a strong Higher-tier feature."}, {"question": "Which is TRUE about smoking?", "options": ["Smoking cigarettes increases the risk of cancer", "Smoking cigarettes has no effect on your health at all", "Doctors recommend smoking to relax", "Cigarettes make you stronger and fitter"], "answer": 0, "explain": "un cigarrillo / fumar is linked to el cáncer. The traps deny any effect, or claim doctors recommend it, or that it helps fitness."}, {"question": "‘Hay que cuidar tu salud’ means…", "options": ["You have to look after your health", "You have to ignore your health completely", "You have to visit the doctor every single day", "You have to stop exercising for a while"], "answer": 0, "explain": "cuidar = to look after / take care of. The traps invert the meaning or add detail never said."}, {"question": "What is the noun that goes with the verb ‘doler’ (to hurt)?", "options": ["el dolor", "el dolido", "el duelo", "el dolorido"], "answer": 0, "explain": "el dolor = pain. ‘el duelo’ (duel/mourning) and ‘dolorido’ (sore, an adjective) are real but different words — classic look-alike traps."}, {"question": "‘Mi abuelo se cayó’ means…", "options": ["My grandad fell over", "My grandad is going to fall over", "My grandad never falls over", "My grandad falls over often"], "answer": 0, "explain": "se cayó is the preterite (past) of caerse. The traps change it to future, or add ‘never’/‘often’ that was never said."}, {"question": "Which is the best advice to relax?", "options": ["Hay que respirar profundamente", "Hay que respirar lo menos posible", "No se debe respirar durante el ejercicio", "Se debe dejar de respirar un momento"], "answer": 0, "explain": "Good advice: breathe deeply. The traps tell you to breathe as little as possible, not breathe while exercising, or stop breathing."}]}, "fib": {"enabled": true, "questions": [{"text": "Me [duele] la cabeza. <span data-say=\"Me duele la cabeza.\" data-listen>Me duele la cabeza.</span>"}, {"text": "No se debe [fumar] porque es malo para la salud. <span data-say=\"No se debe fumar porque es malo para la salud.\" data-listen>No se debe fumar porque es malo para la salud.</span>"}, {"text": "Para estar en forma, hay que hacer [ejercicio]. <span data-say=\"Para estar en forma, hay que hacer ejercicio.\" data-listen>Para estar en forma, hay que hacer ejercicio.</span>"}, {"text": "Me [duelen] los pies. (my feet hurt — plural!)"}, {"text": "Estoy muy [cansado] porque no duermo bien. (tired)"}, {"text": "Voy a [dejar] de fumar. (to stop)"}, {"text": "Me [acuesto] temprano para dormir ocho horas. (I go to bed — reflexive)"}, {"text": "Me duele mucho la [pierna] después de correr. <span data-say=\"Me duele mucho la pierna después de correr.\" data-listen>Me duele mucho la pierna después de correr.</span>"}, {"text": "Hay que [respirar] profundamente para relajarse. (to breathe)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘doler’ works like ‘gustar’ — it agrees with the body part, not the person.", "answer": true, "explain": "Me duele la cabeza / me duelen los pies — the verb matches the body part."}, {"statement": "‘Estoy constipado’ means ‘I am constipated’.", "answer": false, "explain": "False friend! It means ‘I have a cold’."}, {"statement": "‘se debe’ is followed by an infinitive.", "answer": true, "explain": "se debe descansar / fumar / dormir — always an infinitive."}, {"statement": "‘dejar de fumar’ means ‘to start smoking’.", "answer": false, "explain": "dejar de + infinitive = to STOP doing something — to stop smoking."}, {"statement": "For temporary feelings like ‘tired’ you use ‘estar’ (estoy cansado).", "answer": true, "explain": "Temporary states use estar, not ser."}, {"statement": "‘la garganta’ means ‘the stomach’.", "answer": false, "explain": "la garganta = throat; el estómago = stomach."}, {"statement": "‘acostarse’ is a reflexive verb, so ‘I go to bed’ is ‘me acuesto’.", "answer": true, "explain": "Reflexive: me acuesto, te acuestas, se acuesta."}, {"statement": "‘Se debería evitar el estrés’ uses the conditional and suits Higher tier.", "answer": true, "explain": "se debería = one should (conditional)."}, {"statement": "‘cuidar’ means ‘to take care of’.", "answer": true, "explain": "cuidar = to look after / take care of."}, {"statement": "‘la piel’ means ‘the leg’.", "answer": false, "explain": "la piel = skin; la pierna = leg."}, {"statement": "‘optimista’ describes someone with a negative attitude.", "answer": false, "explain": "optimista = optimistic — a positive attitude."}]}, "misc": {"enabled": true, "items": [{"myth": "Me duele los pies.", "truth": "Me duelen los pies.", "check": {"question": "Why is ‘Me duele los pies’ wrong?", "options": ["‘los pies’ is plural, so it must be ‘duelen’", "you must always put the verb ‘estar’ in front of it", "‘pies’ needs a written accent", "the pronoun should be ‘te’, not ‘me’"], "answer": 0, "explain": "doler agrees with the body part; plural body part → duelen."}}, {"myth": "Estoy constipado. (= I am constipated)", "truth": "Estoy constipado. (= I have a cold)", "check": {"question": "What does ‘constipado’ really mean?", "options": ["having a cold", "being constipated as you would guess", "feeling completely healthy", "being extremely tired"], "answer": 0, "explain": "Classic false friend: constipado = having a cold."}}, {"myth": "Soy cansado.", "truth": "Estoy cansado.", "check": {"question": "Why ‘Estoy cansado’, not ‘Soy cansado’?", "options": ["tiredness is a temporary state → estar", "you should always use ‘tener’ with any feeling", "‘cansado’ is a plural adjective", "‘ser’ is only for the past"], "answer": 0, "explain": "Temporary states and moods take estar; ser would mean it is a permanent trait."}}, {"myth": "Acuesto temprano.", "truth": "Me acuesto temprano.", "check": {"question": "What is missing in ‘Acuesto temprano’?", "options": ["the reflexive pronoun ‘me’ (me acuesto)", "an accent on the final letter of the verb form", "the linking word ‘a’", "the article ‘la’"], "answer": 0, "explain": "acostarse is reflexive: you need me/te/se — ‘me acuesto’."}}, {"myth": "Se debe fumar para relajarse.", "truth": "No se debe fumar; se debe descansar para relajarse.", "check": {"question": "Why is the ‘wrong’ sentence a problem?", "options": ["it recommends smoking, which is bad advice", "it is missing an infinitive after ‘se debe’", "‘relajarse’ is spelt incorrectly", "it uses the past tense by mistake"], "answer": 0, "explain": "The grammar is fine, but the ADVICE is wrong — smoking is malo para la salud."}}, {"myth": "Me duele el pie.", "truth": "Me duele la pierna. (el pie = foot; la pierna = leg — different body parts!)", "check": {"question": "What’s the difference between ‘el pie’ and ‘la pierna’?", "options": ["el pie = foot, la pierna = leg — they are different body parts", "they are simply two different spellings of the exact same Spanish word for foot", "‘pie’ is only ever used in the plural", "‘pierna’ means ‘shoe’"], "answer": 0, "explain": "el pie = foot; la pierna = leg. Mixing them up is a common GCSE slip."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Health sentences reuse chunks you know: ‘me duele…’, ‘se debe…’, ‘voy a…’. Listen for whether it is ‘duele’ (one thing) or ‘duelen’ (more than one) — the ending tells you if the body part is singular or plural.", "check": {"question": "You hear ‘…duelen…’. What does that tell you?", "options": ["more than one body part hurts", "only one single body part is actually hurting", "nothing hurts at all", "it is a future plan"], "answer": 0, "explain": "The -n ending of ‘duelen’ signals a plural body part (los pies, las piernas…)."}}, {"title": "Paper 3 — Translation into English", "html": "Watch the false friends: ‘constipado’ = having a cold, ‘estar en forma’ = to be fit. Keep ‘me duele la cabeza’ natural: ‘my head hurts’ / ‘I have a headache’, not ‘the head hurts me’.", "check": {"question": "‘Estoy resfriado y me duele la garganta’ =", "options": ["I have a cold and my throat hurts", "I am stressed out and my whole back hurts", "I am tired and my head hurts", "I am fit and my legs hurt"], "answer": 0, "explain": "resfriado = having a cold; la garganta = throat."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a problem, advice and a plan: ‘Estoy estresado, así que se debe descansar y voy a acostarme más temprano.’ At Higher, add a reflexive and a conditional: ‘se debería…’, ‘relajarse’.", "check": {"question": "Which answer reaches the top band?", "options": ["Estoy estresado, así que voy a descansar y acostarme más temprano", "Estoy muy estresado y estresado y cansado todos los días sin parar nunca", "Estoy mal", "Me duele todo"], "answer": 0, "explain": "It links a problem, a plan, a reflexive and a time phrase — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Elena says. Answer <strong>in English</strong>.<br>(a) Name <strong>one</strong> sport Elena does. (1)<br>(b) What is wrong with her this week? (1)<br>(c) Why does she never smoke? (1)<br>(d) What is she going to change next month? (1)", "marks": 4, "hint": "Find the sports after ‘hago deporte’, the problem after ‘esta semana’, the reason after ‘porque’, and the plan after ‘voy a’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> swimming / cycling (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> she has a cold / her throat hurts (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) it is very bad for your/her health <em>(1)</em>.</li>\n                <li><strong>(d)</strong> go to bed earlier / sleep eight hours <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My head hurts. <br>(b) One must not smoke. <br>(c) I am going to do more exercise because it is good for your health.", "marks": 5, "hint": "‘My head hurts’ = doler like gustar (Me duele…). ‘One must not smoke’ = No se debe… ‘I am going to do’ = Voy a hacer…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me duele la cabeza. <em>(1)</em></li>\n                <li><strong>(b)</strong> No se debe fumar. <em>(1)</em></li>\n                <li><strong>(c)</strong> Voy a hacer más ejercicio <em>(1)</em> porque <em>(1)</em> es bueno para la salud <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me duele la cabeza’ must use the singular ‘duele’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '3-1-school-life-and-subjects', '3.1 School Life and Subjects', '{"learn": {"enabled": true, "items": [{"title": "What subjects do I study? (las asignaturas)", "html": "<p>School subjects are <span data-say=\"las asignaturas\">las asignaturas</span>. Most take a definite article, and some are plural. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"las matemáticas\">las matemáticas</span></td><td>maths</td><td><span data-say=\"la historia\">la historia</span></td><td>history</td></tr>\n              <tr><td><span data-say=\"la geografía\">la geografía</span></td><td>geography</td><td><span data-say=\"las ciencias\">las ciencias</span></td><td>science</td></tr>\n              <tr><td><span data-say=\"el inglés\">el inglés</span></td><td>English</td><td><span data-say=\"el español\">el español</span></td><td>Spanish</td></tr>\n              <tr><td><span data-say=\"la educación física\">la educación física</span></td><td>PE</td><td><span data-say=\"el dibujo\">el dibujo</span></td><td>art</td></tr>\n              <tr><td><span data-say=\"la música\">la música</span></td><td>music</td><td><span data-say=\"la informática\">la informática</span></td><td>ICT / computing</td></tr>\n              <tr><td><span data-say=\"la tecnología\">la tecnología</span></td><td>technology</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Estudio matemáticas, inglés y ciencias en el instituto.\">Estudio matemáticas, inglés y ciencias en el instituto.</span> — <em>I study maths, English and science at school.</em></p>", "check": {"question": "Which subject is ‘la informática’?", "options": ["ICT / computing", "religious education, taught weekly", "physical education outdoors", "modern foreign languages generally"], "answer": 0, "explain": "la informática = ICT / computing. The traps swap in other named subjects that sound plausible."}}, {"title": "How do I give an opinion on a subject?", "html": "<p><span data-say=\"me gusta\">me gusta</span> (I like) agrees with a singular subject; <span data-say=\"me gustan\">me gustan</span> agrees with a plural subject like <span data-say=\"las matemáticas\">las matemáticas</span> or <span data-say=\"las ciencias\">las ciencias</span> — exactly like ‘gustar’ works elsewhere.</p>\n            <ul>\n              <li><span data-say=\"Me gusta el español porque es interesante.\">Me gusta el español porque es interesante.</span> (I like Spanish because it’s interesting.)</li>\n              <li><span data-say=\"Me gustan las ciencias porque son útiles.\">Me gustan las ciencias porque son útiles.</span> (I like science because it’s useful.)</li>\n            </ul>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi asignatura preferida es\">mi asignatura preferida es</span></td><td>my favourite subject is</td></tr>\n              <tr><td><span data-say=\"se me da bien\">se me da bien</span></td><td>I am good at (it)</td></tr>\n              <tr><td><span data-say=\"se me da mal\">se me da mal</span></td><td>I am bad at (it)</td></tr>\n              <tr><td><span data-say=\"es útil\">es útil</span> / <span data-say=\"es aburrido\">es aburrido</span></td><td>it’s useful / it’s boring</td></tr>\n            </table>", "check": {"question": "Why is it ‘me gustan las ciencias’ and not ‘me gusta las ciencias’?", "options": ["‘las ciencias’ is plural, so the verb is plural", "‘ciencias’ is one of the few masculine subject nouns", "it describes something that will happen in the future", "‘gustar’ never changes its form for any subject"], "answer": 0, "explain": "Like elsewhere, gustar agrees with what is liked; ‘las ciencias’ is plural → gustan."}}, {"title": "How do I compare subjects?", "html": "<p>Use <strong>más / menos + adjective + que</strong> to compare, and <span data-say=\"prefiero\">prefiero</span> (I prefer) to state a preference directly. The adjective agrees in number with the subject.</p>\n            <ul>\n              <li><span data-say=\"Las matemáticas son más difíciles que el dibujo.\">Las matemáticas son más difíciles que el dibujo.</span> (Maths is more difficult than art.)</li>\n              <li><span data-say=\"La educación física es menos aburrida que la historia.\">La educación física es menos aburrida que la historia.</span> <span class=\"tier-h\">H</span> (PE is less boring than history.)</li>\n              <li><span data-say=\"Prefiero la música a la tecnología porque soy creativo.\">Prefiero la música a la tecnología porque soy creativo.</span></li>\n            </ul>", "check": {"question": "What does ‘más difícil que’ mean?", "options": ["more difficult than", "less difficult than, in fact easier", "exactly as difficult as", "the single most difficult subject of all"], "answer": 0, "explain": "más + adjective + que = more … than. ‘menos … que’ would mean less; ‘tan … como’ would mean as … as."}}, {"title": "What is my school like? (el instituto)", "html": "<p>The school is <span data-say=\"el instituto\">el instituto</span>. Key places on site — tap 🔊 to hear each one:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el aula\">el aula</span></td><td>the classroom</td><td><span data-say=\"el laboratorio\">el laboratorio</span></td><td>the lab</td></tr>\n              <tr><td><span data-say=\"la biblioteca\">la biblioteca</span></td><td>the library</td><td><span data-say=\"el comedor\">el comedor</span></td><td>the canteen</td></tr>\n              <tr><td><span data-say=\"el patio\">el patio</span></td><td>the playground</td><td><span data-say=\"el gimnasio\">el gimnasio</span></td><td>the gym</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi instituto hay una biblioteca grande y dos laboratorios.\">En mi instituto hay una biblioteca grande y dos laboratorios.</span></p>", "check": {"question": "Which place is ‘el comedor’?", "options": ["the canteen", "the school library building", "an ordinary classroom", "the outdoor sports field"], "answer": 0, "explain": "el comedor = the canteen, where students eat lunch."}}, {"title": "What is a typical school day like?", "html": "<p>Talking about your <span data-say=\"el horario\">el horario</span> (timetable) and school day:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"empezar\">empezar</span></td><td>to start</td><td><span data-say=\"terminar\">terminar</span></td><td>to finish</td></tr>\n              <tr><td><span data-say=\"el recreo\">el recreo</span></td><td>break time</td><td><span data-say=\"los deberes\">los deberes</span></td><td>homework</td></tr>\n              <tr><td><span data-say=\"llevar uniforme\">llevar uniforme</span></td><td>to wear (a) uniform</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Las clases empiezan a las nueve y terminan a las tres y media.\">Las clases empiezan a las nueve y terminan a las tres y media.</span> — <em>Lessons start at nine and finish at half past three.</em></p>\n            <p>Also: <span data-say=\"Hago los deberes después de las clases.\">Hago los deberes después de las clases.</span></p>", "check": {"question": "What does ‘los deberes’ mean?", "options": ["homework", "the printed weekly timetable", "morning break time", "the compulsory uniform"], "answer": 0, "explain": "los deberes = homework. A common false-friend trap is thinking it means ‘duties’."}}, {"title": "Higher: teachers and school rules", "html": "<p><span class=\"tier-h\">H</span> The teacher is <span data-say=\"el profesor\">el profesor</span> / <span data-say=\"la profesora\">la profesora</span>. School rules (<span data-say=\"las normas\">las normas</span>) use impersonal structures followed by an infinitive:</p>\n            <ul>\n              <li><span data-say=\"se debe llevar uniforme\">se debe llevar uniforme</span> — one must wear uniform</li>\n              <li><span data-say=\"no se debe usar el móvil\">no se debe usar el móvil</span> — one must not use a mobile phone</li>\n              <li><span data-say=\"está prohibido comer en clase\">está prohibido comer en clase</span> <span class=\"tier-h\">H</span> — it is forbidden to eat in class</li>\n              <li><strong>hay que</strong> + infinitive — you have to (do something), e.g. respect the teachers</li>\n            </ul>\n            <p>Example: <span data-say=\"En mi instituto está prohibido llevar joyas y hay que respetar a los profesores.\">En mi instituto está prohibido llevar joyas y hay que respetar a los profesores.</span></p>", "check": {"question": "What follows ‘está prohibido’, ‘se debe’ and ‘hay que’?", "options": ["an infinitive (comer, llevar, respetar…)", "a verb conjugated in the preterite past tense", "an adjective that must agree", "a plural noun used on its own"], "answer": 0, "explain": "All three rule structures are followed by an infinitive."}}, {"title": "Who''s who at school? (people and friendships)", "html": "<p>More people you''ll meet, plus how to talk about school friendships. <span data-say=\"el señor\">el señor</span> / <span data-say=\"la señora\">la señora</span> go before a surname, like Mr/Mrs — useful for addressing teachers politely.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el compañero\">el compañero</span> / <span data-say=\"la compañera\">la compañera</span></td><td>classmate</td><td><span data-say=\"la amistad\">la amistad</span></td><td>friendship</td></tr>\n              <tr><td><span data-say=\"el alumno\">el alumno</span> / <span data-say=\"la alumna\">la alumna</span></td><td>pupil</td><td><span data-say=\"el estudiante\">el estudiante</span> / <span data-say=\"la estudiante\">la estudiante</span></td><td>student</td></tr>\n              <tr><td><span data-say=\"la autoridad\">la autoridad</span></td><td>authority</td><td><span data-say=\"el edificio\">el edificio</span></td><td>building</td></tr>\n              <tr><td><span data-say=\"la escuela\">la escuela</span></td><td>school (often primary)</td><td><span data-say=\"enseñar\">enseñar</span></td><td>to teach</td></tr>\n            </table>\n            <p>Note: <span data-say=\"la escuela\">la escuela</span> usually means a primary school, while <span data-say=\"el instituto\">el instituto</span> is secondary school — you already know both!</p>\n            <p>Example: <span data-say=\"El señor García enseña historia y siempre respeta a los alumnos.\">El señor García enseña historia y siempre respeta a los alumnos.</span> — Mr García teaches history and always respects the pupils.</p>\n            <p>Also: <span data-say=\"Mi compañera de clase y yo tenemos una buena amistad.\">Mi compañera de clase y yo tenemos una buena amistad.</span> — My classmate and I have a good friendship. <span data-say=\"Mi hermano mayor también fue alumno en este edificio.\">Mi hermano mayor también fue alumno en este edificio.</span> — My older brother was also a pupil in this building.</p>", "check": {"question": "Which Spanish word usually means a primary school, unlike ‘el instituto’?", "options": ["la escuela", "el edificio nuevo del centro", "la autoridad del director", "el estudiante universitario"], "answer": 0, "explain": "la escuela usually refers to a primary school; el instituto is secondary school."}}, {"title": "School rules, behaviour and uniform", "html": "<p>More classroom behaviour and rules — building on <span data-say=\"está prohibido\">está prohibido</span> and <span data-say=\"se debe\">se debe</span> from before.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"permitir\">permitir</span></td><td>to allow</td><td><span data-say=\"la regla\">la regla</span></td><td>the rule</td></tr>\n              <tr><td><span data-say=\"el silencio\">el silencio</span></td><td>silence</td><td><span data-say=\"callarse\">callarse</span></td><td>to be quiet</td></tr>\n              <tr><td><span data-say=\"gritar\">gritar</span></td><td>to shout</td><td><span data-say=\"castigar\">castigar</span></td><td>to punish</td></tr>\n              <tr><td><span data-say=\"estricto\">estricto</span></td><td>strict</td><td><span data-say=\"obligatorio\">obligatorio</span></td><td>compulsory</td></tr>\n              <tr><td><span data-say=\"el pantalón\">el pantalón</span></td><td>trousers</td><td><span data-say=\"la falda\">la falda</span></td><td>skirt</td></tr>\n              <tr><td><span data-say=\"entregar\">entregar</span></td><td>to hand in</td><td><span data-say=\"la culpa\">la culpa</span></td><td>blame, fault</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi instituto no se permite gritar en el pasillo; hay que callarse y guardar silencio.\">En mi instituto no se permite gritar en el pasillo; hay que callarse y guardar silencio.</span></p>\n            <p>Uniform rule: <span data-say=\"El uniforme es obligatorio: los chicos llevan pantalón y las chicas pueden llevar falda.\">El uniforme es obligatorio: los chicos llevan pantalón y las chicas pueden llevar falda.</span></p>\n            <p>Homework rule: <span data-say=\"Hay que entregar los deberes a tiempo; si no, el profesor te castiga.\">Hay que entregar los deberes a tiempo; si no, el profesor te castiga.</span> Nadie quiere <span data-say=\"echar la culpa\">echar la culpa</span> (place the blame) a un compañero cuando algo va mal.</p>\n            <p><span class=\"tier-h\">H</span> Two serious problems schools must tackle: <span data-say=\"el acoso\">el acoso</span> (bullying) and <span data-say=\"amenazar\">amenazar</span> (to threaten) — e.g. <span data-say=\"Está muy mal amenazar o acosar a otro alumno.\">Está muy mal amenazar o acosar a otro alumno.</span></p>", "check": {"question": "What does ‘el acoso’ mean in a school context?", "options": ["bullying", "a compulsory school rule about uniform", "a strict but fair teacher", "permission to leave class early"], "answer": 0, "explain": "el acoso = bullying, a serious pastoral issue schools must tackle."}}, {"title": "Succeeding — or struggling — in exams", "html": "<p>Vocabulary for talking about how well (or badly) things go at school.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el sistema\">el sistema</span></td><td>system</td><td><span data-say=\"el resultado\">el resultado</span></td><td>result</td></tr>\n              <tr><td><span data-say=\"la prueba\">la prueba</span></td><td>test/proof</td><td><span data-say=\"el esfuerzo\">el esfuerzo</span></td><td>effort</td></tr>\n              <tr><td><span data-say=\"el conocimiento\">el conocimiento</span></td><td>knowledge</td><td><span data-say=\"la memoria\">la memoria</span></td><td>memory</td></tr>\n              <tr><td><span data-say=\"el apoyo\">el apoyo</span></td><td>support</td><td><span data-say=\"merecer\">merecer</span></td><td>to deserve</td></tr>\n              <tr><td><span data-say=\"superar\">superar</span></td><td>to pass/overcome</td><td><span data-say=\"suspender\">suspender</span></td><td>to fail (an exam)</td></tr>\n              <tr><td><span data-say=\"repasar\">repasar</span></td><td>to revise</td><td><span data-say=\"la suerte\">la suerte</span></td><td>luck</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Si repasas con esfuerzo, mereces un buen resultado; si no estudias, puedes suspender.\">Si repasas con esfuerzo, mereces un buen resultado; si no estudias, puedes suspender.</span> <span data-say=\"¡Buena suerte en el examen!\">¡Buena suerte en el examen!</span> — Good luck in the exam!</p>\n            <p>Student types: <span data-say=\"listo\">listo</span> (clever), <span data-say=\"tonto\">tonto</span> (silly), <span data-say=\"vago\">vago</span> / <span data-say=\"perezoso\">perezoso</span> (lazy) and <span data-say=\"la inteligencia\">la inteligencia</span> (intelligence).</p>\n            <p>Example: <span data-say=\"Mi compañero es muy listo y tiene mucha inteligencia, pero yo soy un poco vago.\">Mi compañero es muy listo y tiene mucha inteligencia, pero yo soy un poco vago.</span></p>", "check": {"question": "What does ‘suspender un examen’ mean?", "options": ["to fail an exam", "to pass an exam with a great result", "to revise thoroughly before an exam", "to deserve extra support in class"], "answer": 0, "explain": "suspender = to fail (an exam) — a common false-friend trap, since it looks like ‘suspend’."}}, {"title": "More subjects, the school year and school life", "html": "<p>A few more useful nouns and adjectives for describing subjects, dates and everyday school life.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el idioma\">el idioma</span></td><td>language</td><td><span data-say=\"el lenguaje\">el lenguaje</span></td><td>language/speech (general)</td></tr>\n              <tr><td><span data-say=\"el castellano\">el castellano</span></td><td>Castilian Spanish</td><td><span data-say=\"la opción\">la opción</span></td><td>option</td></tr>\n              <tr><td><span data-say=\"septiembre\">septiembre</span></td><td>September</td><td><span data-say=\"la economía\">la economía</span></td><td>economics</td></tr>\n              <tr><td><span data-say=\"la mochila\">la mochila</span></td><td>backpack</td><td><span data-say=\"el bolígrafo\">el bolígrafo</span></td><td>pen</td></tr>\n              <tr><td><span data-say=\"la página\">la página</span></td><td>page</td><td><span data-say=\"la lista\">la lista</span></td><td>list</td></tr>\n              <tr><td><span data-say=\"la excursión\">la excursión</span></td><td>school trip</td><td><span data-say=\"la orquesta\">la orquesta</span></td><td>orchestra</td></tr>\n              <tr><td><span data-say=\"el concurso\">el concurso</span></td><td>competition</td><td><span data-say=\"el estadio\">el estadio</span></td><td>stadium</td></tr>\n              <tr><td><span data-say=\"deportivo\">deportivo</span></td><td>sports (adj)</td><td><span data-say=\"la bicicleta\">la bicicleta</span>, <span data-say=\"la bici\">la bici</span></td><td>bicycle</td></tr>\n              <tr><td><span data-say=\"la recepción\">la recepción</span></td><td>reception</td><td><span data-say=\"la puerta\">la puerta</span></td><td>door</td></tr>\n              <tr><td><span data-say=\"la instalación\">la instalación</span></td><td>facility</td><td><span data-say=\"numeroso\">numeroso</span></td><td>numerous</td></tr>\n              <tr><td><span data-say=\"cerrado\">cerrado</span></td><td>closed</td><td><span data-say=\"instalar\">instalar</span></td><td>to install</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Las clases empiezan en septiembre; escojo mis opciones para el próximo curso, como la economía o un segundo idioma.\">Las clases empiezan en septiembre; escojo mis opciones para el próximo curso, como la economía o un segundo idioma.</span></p>\n            <p>Also: <span data-say=\"Voy al instituto en bicicleta y guardo mis bolígrafos en la mochila.\">Voy al instituto en bicicleta y guardo mis bolígrafos en la mochila.</span> <span data-say=\"En clase de informática aprendemos a instalar programas nuevos.\">En clase de informática aprendemos a instalar programas nuevos.</span></p>\n            <p>Extras: <span data-say=\"Nuestra escuela tiene una orquesta y un equipo que gana concursos.\">Nuestra escuela tiene una orquesta y un equipo que gana concursos.</span> <span data-say=\"Cerca del estadio hay instalaciones deportivas numerosas.\">Cerca del estadio hay instalaciones deportivas numerosas.</span></p>\n            <p>On the last day of term there''s often an <span data-say=\"excursión\">excursión</span> (school trip) — <span data-say=\"¡Estoy muy emocionado por la excursión!\">¡Estoy muy emocionado por la excursión!</span> (I''m very excited about the trip!) <span data-say=\"Los visitantes esperan en la recepción, cerca de la puerta principal, que está cerrada fuera del horario escolar.\">Los visitantes esperan en la recepción, cerca de la puerta principal, que está cerrada fuera del horario escolar.</span></p>", "check": {"question": "When do Spanish school subjects and options for next year usually get chosen, according to this page?", "options": ["around September, when classes start", "only during the summer excursión", "on the very last day of the school year", "the moment you turn eighteen years old"], "answer": 0, "explain": "septiembre = September, when the school year (and choosing options) begins."}}]}, "terms": {"enabled": true, "pairs": [{"term": "las asignaturas", "definition": "school subjects"}, {"term": "las matemáticas", "definition": "maths"}, {"term": "las ciencias", "definition": "science"}, {"term": "la educación física", "definition": "PE"}, {"term": "la informática", "definition": "ICT / computing"}, {"term": "mi asignatura preferida es…", "definition": "my favourite subject is…"}, {"term": "se me da bien / mal", "definition": "I am good / bad at (it)"}, {"term": "más difícil que (H)", "definition": "more difficult than"}, {"term": "el instituto", "definition": "the school"}, {"term": "el aula · el laboratorio", "definition": "classroom · lab"}, {"term": "la biblioteca · el comedor", "definition": "library · canteen"}, {"term": "el horario", "definition": "the timetable"}, {"term": "el recreo", "definition": "break time"}, {"term": "los deberes", "definition": "homework"}, {"term": "llevar uniforme", "definition": "to wear (a) uniform"}, {"term": "el profesor / la profesora", "definition": "the teacher"}, {"term": "se debe / no se debe (H)", "definition": "one should / must not"}, {"term": "está prohibido (H)", "definition": "it is forbidden to"}, {"term": "el mayor / la mayor (H)", "definition": "the biggest / the oldest"}, {"term": "el señor / la señora", "definition": "Mr / Mrs"}, {"term": "permitir; permitirse", "definition": "to allow; to allow oneself"}, {"term": "el sistema (H)", "definition": "the system"}, {"term": "segundo", "definition": "second"}, {"term": "la puerta", "definition": "the door"}, {"term": "la escuela", "definition": "school (often primary)"}, {"term": "el resultado", "definition": "the result"}, {"term": "el silencio (H)", "definition": "silence"}, {"term": "el compañero / la compañera", "definition": "classmate"}, {"term": "verdadero (H)", "definition": "true, real"}, {"term": "el conocimiento (H)", "definition": "knowledge"}, {"term": "la autoridad (H)", "definition": "authority"}, {"term": "la página", "definition": "the page"}, {"term": "el esfuerzo", "definition": "effort"}, {"term": "enseñar", "definition": "to teach"}, {"term": "entregar; entregarse (H)", "definition": "to hand in; to devote oneself"}, {"term": "la prueba", "definition": "test, proof"}, {"term": "gritar", "definition": "to shout"}, {"term": "la suerte", "definition": "luck"}, {"term": "privado (H)", "definition": "private"}, {"term": "la economía", "definition": "economics, the economy"}, {"term": "popular", "definition": "popular"}, {"term": "el/la estudiante", "definition": "student"}, {"term": "la memoria (H)", "definition": "memory"}, {"term": "el apoyo", "definition": "support"}, {"term": "el edificio", "definition": "building"}, {"term": "el alumno / la alumna", "definition": "pupil"}, {"term": "raro", "definition": "strange, rare"}, {"term": "la frase", "definition": "sentence, phrase"}, {"term": "superar (H)", "definition": "to overcome, to pass"}, {"term": "numeroso (H)", "definition": "numerous"}, {"term": "instalar (H)", "definition": "to install"}, {"term": "el lenguaje (H)", "definition": "language, speech"}, {"term": "septiembre", "definition": "September"}, {"term": "el idioma", "definition": "language"}, {"term": "la culpa (H)", "definition": "blame, fault"}, {"term": "la opción", "definition": "option"}, {"term": "la lista", "definition": "the list"}, {"term": "cerrado", "definition": "closed"}, {"term": "merecer (H)", "definition": "to deserve"}, {"term": "el informe (H)", "definition": "the report"}, {"term": "la sorpresa", "definition": "surprise"}, {"term": "la enseñanza (H)", "definition": "teaching"}, {"term": "la regla", "definition": "rule, ruler"}, {"term": "educativo", "definition": "educational"}, {"term": "el diálogo (H)", "definition": "dialogue"}, {"term": "la amistad", "definition": "friendship"}, {"term": "callarse", "definition": "to be quiet"}, {"term": "la llegada (H)", "definition": "arrival"}, {"term": "listo", "definition": "clever (ser) / ready (estar)"}, {"term": "la discusión", "definition": "discussion, argument"}, {"term": "el puente", "definition": "bridge"}, {"term": "la orquesta (H)", "definition": "orchestra"}, {"term": "la inteligencia (H)", "definition": "intelligence"}, {"term": "precioso (H)", "definition": "beautiful, lovely"}, {"term": "amenazar (H)", "definition": "to threaten"}, {"term": "el pantalón", "definition": "trousers"}, {"term": "la instalación", "definition": "facility"}, {"term": "ligero", "definition": "light (weight)"}, {"term": "el castellano (H)", "definition": "Castilian Spanish"}, {"term": "deportivo", "definition": "sports (adj)"}, {"term": "el concurso", "definition": "competition"}, {"term": "suspender (H)", "definition": "to fail (an exam)"}, {"term": "tonto", "definition": "silly, stupid"}, {"term": "castigar (H)", "definition": "to punish"}, {"term": "el estadio", "definition": "stadium"}, {"term": "la falda", "definition": "skirt"}, {"term": "estricto (H)", "definition": "strict"}, {"term": "obligatorio (H)", "definition": "compulsory"}, {"term": "vago (H)", "definition": "lazy"}, {"term": "la bicicleta, la bici", "definition": "bicycle"}, {"term": "la recepción", "definition": "reception"}, {"term": "repasar", "definition": "to revise"}, {"term": "la excursión", "definition": "school trip"}, {"term": "el acoso", "definition": "bullying"}, {"term": "el bolígrafo", "definition": "pen"}, {"term": "la mochila", "definition": "backpack"}, {"term": "perezoso", "definition": "lazy"}, {"term": "emocionado (H)", "definition": "excited"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Mi asignatura preferida es el inglés.\" data-listen></span><br>Listen. What is the person’s favourite subject?", "options": ["English", "History and English together", "Geography, not English at all", "English was their least favourite subject"], "answer": 0, "explain": "‘mi asignatura preferida es el inglés’ = my favourite subject is English. The traps add a subject, negate it, or reverse the meaning."}, {"question": "<span data-say=\"Se me da muy bien la informática.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["I am very good at ICT", "I am actually quite bad at ICT", "ICT is very boring to me", "I stopped studying ICT last year"], "answer": 0, "explain": "‘se me da muy bien’ = I am very good at (it). Trap B flips bien→mal in meaning; C and D change the whole claim."}, {"question": "Which subject is described as ‘las ciencias’?", "options": ["science", "history", "art", "technology, in general"], "answer": 0, "explain": "las ciencias = science. ‘technology’ is a plausible STEM-subject trap of similar length."}, {"question": "Complete: ‘Me ___ las matemáticas.’ (I like maths)", "options": ["gustan", "gusta", "gustaba mucho", "gustando siempre"], "answer": 0, "explain": "‘las matemáticas’ is plural, so the verb must be plural → gustan. C and D use the wrong tense/form entirely."}, {"question": "How do you say ‘I am bad at art’?", "options": ["Se me da mal el dibujo", "Se me da bien el dibujo", "Me gusta mucho el dibujo", "No estudio el dibujo este año"], "answer": 0, "explain": "se me da mal = I am bad at (it). B flips mal→bien; C and D avoid the target structure entirely."}, {"question": "Which sentence means ‘Maths is more difficult than art’?", "options": ["Las matemáticas son más difíciles que el dibujo", "Las matemáticas son menos difíciles que el dibujo", "El dibujo es más difícil que las matemáticas", "Las matemáticas son tan difíciles como el dibujo"], "answer": 0, "explain": "más difíciles que = more difficult than. B swaps más→menos; C swaps the subjects around; D uses ‘as … as’."}, {"question": "Where would you go to borrow a book at school?", "options": ["a la biblioteca", "al comedor a comer algo", "al gimnasio para hacer deporte", "al laboratorio de ciencias"], "answer": 0, "explain": "la biblioteca = the library, where books are borrowed. The others are real school places used as traps."}, {"question": "What does ‘no se debe usar el móvil’ mean?", "options": ["you must not use your mobile phone", "you must always use your mobile phone", "you may use your mobile phone at recreo", "mobile phones are only allowed in the library"], "answer": 0, "explain": "‘no se debe’ = one must not. Trap B removes the ‘no’; C and D invent exceptions that aren’t stated."}, {"question": "Which is the Higher-tier way to say ‘it is forbidden to eat in class’?", "options": ["Está prohibido comer en clase", "Se puede comer en clase sin ningún problema", "Hay que comer siempre en el aula", "Está prohibido comer en el comedor"], "answer": 0, "explain": "está prohibido + infinitive = it is forbidden to. B says it IS allowed; C says you must eat; D changes the location."}, {"question": "<span data-say=\"Las clases empiezan a las nueve.\" data-listen></span><br>Listen. What time do lessons start?", "options": ["at nine o’clock", "at half past nine", "at three o’clock instead", "lessons have already finished for today"], "answer": 0, "explain": "‘empiezan a las nueve’ = they start at nine. The traps shift the time or claim the opposite event."}, {"question": "<span data-say=\"Mi compañera y yo tenemos una buena amistad.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["She and her classmate have a good friendship", "She dislikes her classmate a great deal these days", "Her classmate moved to a completely different school", "She is not allowed to talk to her classmate at all"], "answer": 0, "explain": "‘tenemos una buena amistad’ = we have a good friendship. The traps invent dislike, a move, or a rule that isn''t there."}, {"question": "Which Spanish verb means ‘to fail an exam’?", "options": ["suspender", "aprobar con nota excelente", "repasar todos los apuntes", "merecer una buena nota"], "answer": 0, "explain": "suspender = to fail (an exam) — a false-friend trap, since it looks like the English ‘suspend’."}, {"question": "Complete: ‘Si repasas con _____, mereces un buen resultado.’ (effort)", "options": ["esfuerzo", "conocimiento", "silencio", "apoyo"], "answer": 0, "explain": "esfuerzo = effort, the missing word here. The other nouns are real but don''t fit this specific sentence."}, {"question": "What is ‘el acoso escolar’?", "options": ["school bullying", "a strict school uniform policy", "a compulsory Spanish exam", "permission to leave school early"], "answer": 0, "explain": "el acoso (escolar) = (school) bullying, a serious issue. The traps invent unrelated school rules."}, {"question": "<span data-say=\"Voy al instituto en bicicleta.\" data-listen></span><br>Listen. How does the speaker get to school?", "options": ["by bicycle", "by car with their parents", "on foot, always alone", "by school bus every day"], "answer": 0, "explain": "‘en bicicleta’ = by bicycle. The traps invent a different, equally plausible way of getting to school."}, {"question": "Which best describes someone who is ‘vago’?", "options": ["lazy, avoiding effort and work", "clever and hard-working always", "strict but fair with everyone", "numerous and full of energy"], "answer": 0, "explain": "vago = lazy. The traps swap in unrelated positive or unrelated adjectives from this same page."}, {"question": "How would you say ‘Our school has an orchestra’?", "options": ["Nuestra escuela tiene una orquesta", "Nuestro instituto tiene un concurso", "Nuestra escuela tiene una prueba", "Nuestro edificio tiene una recepción"], "answer": 0, "explain": "Nuestra escuela tiene una orquesta = our school has an orchestra. The traps swap in a different, equally long noun."}]}, "fib": {"enabled": true, "questions": [{"text": "Mi asignatura [preferida] es el español. <span data-say=\"Mi asignatura preferida es el español.\" data-listen>Mi asignatura preferida es el español.</span>"}, {"text": "Las clases [empiezan] a las nueve. <span data-say=\"Las clases empiezan a las nueve.\" data-listen>Las clases empiezan a las nueve.</span>"}, {"text": "Se me da bien la [informática]. <span data-say=\"Se me da bien la informática.\" data-listen>Se me da bien la informática.</span>"}, {"text": "Me gustan las [ciencias]. (science)"}, {"text": "Está prohibido usar el [móvil]. (mobile phone)"}, {"text": "Hago los [deberes] después de las clases. (homework)"}, {"text": "En mi instituto hay una [biblioteca] grande. (library)"}, {"text": "Voy al instituto en [bicicleta]. <span data-say=\"Voy al instituto en bicicleta.\" data-listen>Voy al instituto en bicicleta.</span>"}, {"text": "Mi [compañera] de clase se llama Ana. (classmate, f)"}, {"text": "Si no estudias, puedes [suspender] el examen. (to fail)"}, {"text": "Guardo mis bolígrafos en la [mochila]. (backpack)"}, {"text": "El uniforme es [obligatorio]: hay que llevarlo todos los días. (compulsory)"}, {"text": "Está muy mal el [acoso] escolar. (bullying) <span data-say=\"Está muy mal el acoso escolar.\" data-listen>Está muy mal el acoso escolar.</span>"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘Me gustan las matemáticas’ is correct because ‘matemáticas’ is plural.", "answer": true, "explain": "gustar agrees with what is liked; a plural subject needs ‘gustan’."}, {"statement": "‘El instituto’ means a university institute for adults.", "answer": false, "explain": "False friend! el instituto = a secondary school."}, {"statement": "‘Se me da bien’ means ‘I am good at’ something.", "answer": true, "explain": "se me da bien = I am good at it (literally ‘it gives itself well to me’)."}, {"statement": "‘Los deberes’ means ‘the duties of a teacher’.", "answer": false, "explain": "False friend! los deberes = homework, not job duties."}, {"statement": "‘Está prohibido’ is always followed by an infinitive verb.", "answer": true, "explain": "está prohibido comer / llevar / usar — always an infinitive."}, {"statement": "‘El aula’ means ‘the hall’, not ‘the classroom’.", "answer": false, "explain": "el aula = the classroom. ‘the hall’ would be el pasillo or el salón de actos."}, {"statement": "Comparatives use ‘más + adjective + que’ to say ‘more … than’.", "answer": true, "explain": "más difícil que = more difficult than."}, {"statement": "‘El recreo’ is when students can go outside to the patio.", "answer": true, "explain": "el recreo = break time, often spent in el patio."}, {"statement": "‘La escuela’ usually means a secondary school for teenagers.", "answer": false, "explain": "False! la escuela usually means a primary school; el instituto is secondary school."}, {"statement": "‘Suspender un examen’ means to fail it.", "answer": true, "explain": "suspender = to fail (a false-friend trap, since it looks like the English ‘suspend’)."}, {"statement": "‘Vago’ and ‘perezoso’ both mean ‘lazy’.", "answer": true, "explain": "Both vago and perezoso describe a lazy student."}, {"statement": "‘El acoso’ means friendly teasing that is harmless.", "answer": false, "explain": "False! el acoso = bullying, a serious problem, not harmless teasing."}, {"statement": "September (‘septiembre’) is when the Spanish school year usually begins.", "answer": true, "explain": "septiembre = September, the start of the school year."}, {"statement": "‘Estricto’ means relaxed and easy-going.", "answer": false, "explain": "False! estricto means strict, the opposite of relaxed."}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta las matemáticas.", "truth": "Me gustan las matemáticas.", "check": {"question": "Why is ‘Me gusta las matemáticas’ wrong?", "options": ["‘las matemáticas’ is plural, so it must be ‘gustan’", "‘matemáticas’ needs a written accent on the first syllable", "the pronoun should be ‘te’, not ‘me’", "‘gustar’ should never be used with school subjects"], "answer": 0, "explain": "gustar agrees with what is liked; a plural subject needs the plural verb form."}}, {"myth": "‘El colegio’ significa ‘the college’ (una universidad).", "truth": "‘El colegio’ significa ‘the school’.", "check": {"question": "What does ‘el colegio’ mean?", "options": ["a school", "a university college for adults", "a public library building", "an after-school sports club"], "answer": 0, "explain": "False friend! el colegio = a school (often primary), not an English ‘college’."}}, {"myth": "‘Asistir a clase’ significa ‘to assist in class’ (ayudar).", "truth": "‘Asistir a clase’ significa ‘to attend class’.", "check": {"question": "What does ‘asistir a clase’ actually mean?", "options": ["to attend class", "to assist or help in class", "to skip class deliberately", "to teach a class"], "answer": 0, "explain": "False friend! asistir = to attend, not to assist. ‘Ayudar’ is the verb for ‘to help’."}}, {"myth": "Se me da bien las matemáticas.", "truth": "Se me dan bien las matemáticas.", "check": {"question": "Why is it ‘se me dan bien’, not ‘se me da bien’, here?", "options": ["‘las matemáticas’ is plural, so ‘dar’ agrees as ‘dan’", "‘dar’ must always be written as ‘dan’, whatever the subject happens to be", "‘matemáticas’ is treated as a masculine noun here", "it is describing a completed past action, not now"], "answer": 0, "explain": "Just like gustar, ‘se me da/dan bien’ agrees with the subject: plural subject → dan."}}, {"myth": "El profesora es simpática.", "truth": "La profesora es simpática.", "check": {"question": "What is wrong with ‘El profesora es simpática’?", "options": ["the article should be feminine ‘la’, matching profesora", "‘profesora’ should always come before the article, not after it", "nothing at all — the sentence is already completely correct", "‘simpática’ should not end in a final letter ‘a’"], "answer": 0, "explain": "profesora is feminine, so it needs the feminine article ‘la’, not ‘el’."}}, {"myth": "Soy listo ahora mismo, voy a clase.", "truth": "Estoy listo ahora mismo, voy a clase.", "check": {"question": "Why must this sentence use ‘estoy’, not ‘soy’, with ‘listo’ here?", "options": ["‘estar listo’ means ready (temporary); ‘ser listo’ means clever (a trait)", "‘listo’ can only ever be used together with the verb ‘ser’, in every single sentence", "‘listo’ must agree with a plural subject in this exact sentence, according to this rule", "‘ir a clase’ always requires the verb ‘estar’ beforehand, in absolutely every case"], "answer": 0, "explain": "ser listo = to be clever (a lasting trait); estar listo = to be ready (a temporary state) — a classic ser/estar contrast."}}, {"myth": "El acoso es sólo una broma sin importancia.", "truth": "El acoso es un problema serio que hay que denunciar.", "check": {"question": "What is wrong with treating ‘el acoso’ as a harmless joke?", "options": ["bullying is a serious issue that should always be reported", "‘acoso’ actually just means a funny nickname between friends", "‘acoso’ is simply another word for a school trip", "nothing — a harmless joke is exactly what ‘acoso’ means"], "answer": 0, "explain": "el acoso = bullying, a serious problem — never a harmless joke."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for agreement", "html": "Opinion sentences reuse chunks you know: ‘me gusta(n)…’, ‘se me da(n) bien…’. Listen closely for the -n ending — it tells you whether the subject being discussed is singular (el inglés) or plural (las matemáticas).", "check": {"question": "You hear ‘…me gustan…’. What does that tell you?", "options": ["the subject being liked is plural", "the subject being liked is definitely singular", "the speaker dislikes the subject", "it is describing a future plan"], "answer": 0, "explain": "The -n ending of ‘gustan’ signals a plural subject (las ciencias, las matemáticas…)."}}, {"title": "Paper 3 — Translation into English", "html": "Watch the false friends: ‘el colegio’ = a school (not ‘college’), ‘los deberes’ = homework (not ‘duties’), ‘asistir’ = to attend (not ‘to assist’). Keep ‘se me da bien’ natural: ‘I am good at it’, not a literal word-for-word translation.", "check": {"question": "‘Asisto al colegio y se me da bien la informática’ means…", "options": ["I attend school and I am good at ICT", "I assist at university and I dislike ICT", "I skip school because ICT is too hard", "I teach ICT at my local college"], "answer": 0, "explain": "asistir = to attend; el colegio = school; se me da bien = I am good at."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine an opinion, a reason and a comparison for the top band: ‘Mi asignatura preferida es la informática porque se me da bien y es más útil que la historia.’ At Higher, add a school rule with ‘está prohibido’ or ‘hay que’.", "check": {"question": "Which answer reaches the top band?", "options": ["Mi asignatura preferida es la informática porque se me da bien y es muy útil para el futuro", "Me gusta todo y no me gusta nada, es difícil y fácil a la vez, sin explicar nunca claramente por qué", "Me gusta el instituto", "Estudio mucho"], "answer": 0, "explain": "It links an opinion, a reason and a justification with connectives — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) Name <strong>one</strong> facility at his school. (1)<br>(b) What is his favourite subject? (1)<br>(c) Give <strong>one</strong> reason he likes it. (1)<br>(d) Why does he dislike maths? (1)<br>(e) Name <strong>one</strong> school rule mentioned. (1)", "marks": 5, "hint": "Find the facilities after ‘donde hay’, the favourite subject after ‘preferida es’, the reason after ‘porque’, the maths complaint after ‘porque son’, and the rule after ‘está prohibido’ or ‘hay que’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> a library / two science labs (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> ICT / computing <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) he is good at it / it is useful for the future (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (because) it is very difficult <em>(1)</em>.</li>\n                <li><strong>(e)</strong> no mobile phones in class / must wear uniform every day (ANY ONE) <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My favourite subject is Spanish. <br>(b) I am very good at science. <br>(c) Lessons start at nine and it is forbidden to use mobile phones.", "marks": 5, "hint": "‘My favourite subject is’ = Mi asignatura preferida es… ‘I am very good at’ = Se me da(n) muy bien… (check the agreement!). ‘it is forbidden to’ = está prohibido + infinitive.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi asignatura preferida es el español. <em>(1)</em></li>\n                <li><strong>(b)</strong> Se me dan muy bien las ciencias. <em>(1)</em></li>\n                <li><strong>(c)</strong> Las clases empiezan a las nueve <em>(1)</em> y <em>(1)</em> está prohibido usar el móvil <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Se me dan bien las ciencias’ must use the plural ‘dan’ to agree with ‘las ciencias’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '3-2-future-study-jobs-and-ambitions', '3.2 Future Study, Jobs and Ambitions', '{"learn": {"enabled": true, "items": [{"title": "How do I say what job someone does?", "html": "<p>The key structure is <strong>ser + job</strong> — and Spanish drops the article: <span data-say=\"Soy profesor.\">Soy profesor.</span> (I am a teacher), NOT “soy un profesor”.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el médico\">el médico</span></td><td>doctor (m)</td><td><span data-say=\"la médica\">la médica</span></td><td>doctor (f)</td></tr>\n              <tr><td><span data-say=\"el profesor\">el profesor</span></td><td>teacher (m)</td><td><span data-say=\"la profesora\">la profesora</span></td><td>teacher (f)</td></tr>\n              <tr><td><span data-say=\"el abogado\">el abogado</span></td><td>lawyer (m)</td><td><span data-say=\"la abogada\">la abogada</span></td><td>lawyer (f)</td></tr>\n              <tr><td><span data-say=\"el ingeniero\">el ingeniero</span></td><td>engineer (m)</td><td><span data-say=\"la ingeniera\">la ingeniera</span></td><td>engineer (f)</td></tr>\n              <tr><td><span data-say=\"el enfermero\">el enfermero</span></td><td>nurse (m)</td><td><span data-say=\"la enfermera\">la enfermera</span></td><td>nurse (f)</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Mi madre es ingeniera y mi padre es enfermero.\">Mi madre es ingeniera y mi padre es enfermero.</span> — My mum is an engineer and my dad is a nurse.</p>", "check": {"question": "Which sentence follows the Spanish rule for stating a job?", "options": ["Soy profesor", "Soy un profesor", "Soy profesor bueno", "Trabajo profesor"], "answer": 0, "explain": "ser + job takes NO article: Soy profesor. Adding ‘un’ (a false transfer from English) or misplacing the adjective are the common errors."}}, {"title": "More jobs — masculine and feminine endings", "html": "<p>More jobs on the wordlist. Notice the feminine pattern <strong>-ero → -era</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el dependiente\">el dependiente</span></td><td>shop assistant (m)</td><td><span data-say=\"la dependienta\">la dependienta</span></td><td>shop assistant (f)</td></tr>\n              <tr><td><span data-say=\"el camarero\">el camarero</span></td><td>waiter</td><td><span data-say=\"la camarera\">la camarera</span></td><td>waitress</td></tr>\n              <tr><td><span data-say=\"el mecánico\">el mecánico</span></td><td>mechanic (m)</td><td><span data-say=\"la mecánica\">la mecánica</span></td><td>mechanic (f)</td></tr>\n              <tr><td><span data-say=\"el peluquero\">el peluquero</span></td><td>hairdresser (m)</td><td><span data-say=\"la peluquera\">la peluquera</span></td><td>hairdresser (f)</td></tr>\n              <tr><td><span data-say=\"el hombre de negocios\">el hombre de negocios</span></td><td>businessman</td><td><span data-say=\"la mujer de negocios\">la mujer de negocios</span></td><td>businesswoman</td></tr>\n            </table>\n            <p>Also useful: <span data-say=\"el trabajo\">el trabajo</span> (job/work) and <span data-say=\"la profesión\">la profesión</span> (profession). Example: <span data-say=\"Mi hermana es dependienta y trabaja en una tienda.\">Mi hermana es dependienta y trabaja en una tienda.</span></p>", "check": {"question": "Which pair correctly shows the masculine and feminine forms of ‘hairdresser’?", "options": ["el peluquero / la peluquera", "el peluquero / la peluquero", "el peluquera / la peluquero", "el peluquero / el peluquera"], "answer": 0, "explain": "Feminine -ero jobs change to -era: el peluquero → la peluquera. Forgetting the ending or mixing up ‘el/la’ are the traps here."}}, {"title": "How do I talk about my ambitions?", "html": "<p>Three levels of certainty for future ambitions — all followed by ser/estudiar with NO article after ser:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"quiero ser\">quiero ser</span></td><td>I want to be</td></tr>\n              <tr><td><span data-say=\"me gustaría ser\">me gustaría ser</span></td><td>I would like to be</td></tr>\n              <tr><td><span data-say=\"voy a estudiar\">voy a estudiar</span></td><td>I am going to study</td></tr>\n              <tr><td><span data-say=\"en el futuro\">en el futuro</span></td><td>in the future</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Quiero ser médica en el futuro.\">Quiero ser médica en el futuro.</span> — I want to be a doctor in the future.</p>\n            <p>Another: <span data-say=\"Me gustaría ser abogado porque me interesa la ley.\">Me gustaría ser abogado porque me interesa la ley.</span></p>", "check": {"question": "Which sentence correctly expresses an ambition?", "options": ["Quiero ser médica", "Quiero ser una médica", "Quiero ser médica bien", "Quiero a ser médica"], "answer": 0, "explain": "quiero ser + job, with no article and no extra preposition. ‘una’, a stray adjective, or an unwanted ‘a’ are all real slips."}}, {"title": "How do I talk about further study?", "html": "<p>Two routes after school — academic or vocational:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la universidad\">la universidad</span></td><td>university</td></tr>\n              <tr><td><span data-say=\"seguir estudiando\">seguir estudiando</span></td><td>to continue studying</td></tr>\n              <tr><td><span data-say=\"hacer un aprendizaje\">hacer un aprendizaje</span></td><td>to do an apprenticeship</td></tr>\n              <tr><td><span data-say=\"sacar buenas notas\">sacar buenas notas</span></td><td>to get good marks</td></tr>\n              <tr><td><span data-say=\"aprobar los exámenes\">aprobar los exámenes</span></td><td>to pass the exams</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Voy a seguir estudiando en la universidad si apruebo los exámenes.\">Voy a seguir estudiando en la universidad si apruebo los exámenes.</span></p>\n            <p>Or a vocational route: <span data-say=\"Prefiero hacer un aprendizaje en vez de ir a la universidad.\">Prefiero hacer un aprendizaje en vez de ir a la universidad.</span></p>\n            <p><span class=\"tier-h\">H</span> In Spain, after the GCSE-equivalent stage, students choose between <span data-say=\"el Bachillerato\">el Bachillerato</span> (two years of academic study, similar to Sixth Form) and vocational training. Studies at university level are <span data-say=\"universitario\">universitarios</span>: <span data-say=\"Después del Bachillerato, quiero hacer estudios universitarios.\">Después del Bachillerato, quiero hacer estudios universitarios.</span></p>", "check": {"question": "What does ‘hacer un aprendizaje’ mean?", "options": ["to do an apprenticeship after school", "to keep on studying at the same school", "to pass all of this year''s exams", "to get the best possible marks"], "answer": 0, "explain": "hacer un aprendizaje = to do an apprenticeship (a vocational route). Confusing it with ‘seguir estudiando’ (to continue studying) is the classic trap."}}, {"title": "How do I give reasons for my choice?", "html": "<p>Give reasons with <strong>porque</strong> (because + clause) or <strong>para</strong> (in order to + infinitive):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"porque me interesa\">porque me interesa</span></td><td>because it interests me</td></tr>\n              <tr><td><span data-say=\"para ganar dinero\">para ganar dinero</span></td><td>in order to earn money</td></tr>\n              <tr><td><span data-say=\"para ayudar a la gente\">para ayudar a la gente</span></td><td>in order to help people</td></tr>\n              <tr><td><span data-say=\"para viajar\">para viajar</span></td><td>in order to travel</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Quiero ser médica porque me interesa la ciencia y para ayudar a la gente.\">Quiero ser médica porque me interesa la ciencia y para ayudar a la gente.</span></p>", "check": {"question": "After ‘para’, what form of the verb do you use?", "options": ["the infinitive (ganar, viajar, ayudar)", "a present-tense verb conjugated for ‘yo’", "the past participle (ganado, viajado)", "the present subjunctive form of the verb"], "answer": 0, "explain": "para + infinitive: para ganar dinero. Conjugating the verb after para (e.g. ‘para gano dinero’) is a very common error."}}, {"title": "Higher: cuando + present subjunctive", "html": "<p><span class=\"tier-h\">H</span> For a future idea with <strong>cuando</strong> (when), Spanish uses the <strong>present subjunctive</strong>, not the present indicative:</p>\n            <ul>\n              <li><span data-say=\"cuando sea mayor\">cuando sea mayor</span> — when I am older</li>\n              <li><span data-say=\"Cuando sea mayor, quiero ser abogada.\">Cuando sea mayor, quiero ser abogada.</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Compare: <span data-say=\"Cuando soy mayor\">Cuando soy mayor</span> (present indicative) is WRONG for a future idea — examiners reward <span data-say=\"sea\">sea</span> here.</p>\n            <p>Combine with a reason for the top band: <span data-say=\"Cuando sea mayor, me gustaría trabajar en el extranjero para viajar y ganar dinero.\">Cuando sea mayor, me gustaría trabajar en el extranjero para viajar y ganar dinero.</span> <span class=\"tier-h\">H</span></p>", "check": {"question": "Which is correct for a future idea with ‘cuando’?", "options": ["Cuando sea mayor, quiero ser médica", "Cuando soy mayor, quiero ser médica", "Cuando era mayor, quiero ser médica", "Cuando seré mayor, quiero ser médica"], "answer": 0, "explain": "cuando + present subjunctive (sea) for future time clauses. soy = present indicative, era = imperfect, seré wrongly duplicates the future — all real learner slips."}}, {"title": "Where might I work? Places, sectors and companies", "html": "<p>Key nouns for talking about businesses, sectors and where people work.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la empresa\">la empresa</span></td><td>company, firm</td><td><span data-say=\"la compañía\">la compañía</span></td><td>company</td></tr>\n              <tr><td><span data-say=\"el negocio\">el negocio</span></td><td>business</td><td><span data-say=\"la oficina\">la oficina</span></td><td>office</td></tr>\n              <tr><td><span data-say=\"el banco\">el banco</span></td><td>bank</td><td><span data-say=\"la fábrica\">la fábrica</span></td><td>factory</td></tr>\n              <tr><td><span data-say=\"el comercio\">el comercio</span></td><td>trade, commerce</td><td><span data-say=\"los servicios\">los servicios</span></td><td>services (sector)</td></tr>\n              <tr><td><span data-say=\"la construcción\">la construcción</span></td><td>construction</td><td><span data-say=\"fabricar\">fabricar</span></td><td>to manufacture</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi padre trabaja en una empresa grande; mi madre tiene su propio negocio.\">Mi padre trabaja en una empresa grande; mi madre tiene su propio negocio.</span> — My dad works for a big company; my mum has her own business.</p>\n            <p>The main sectors of the economy are <span data-say=\"la construcción, el comercio y los servicios.\">la construcción, el comercio y los servicios.</span> En la fábrica, <span data-say=\"fabrican coches.\">fabrican coches.</span> — In the factory, they manufacture cars.</p>", "check": {"question": "Which word describes ‘the services sector’ of the economy?", "options": ["los servicios", "la construcción de edificios", "el comercio internacional", "una compañía muy pequeña"], "answer": 0, "explain": "los servicios = services (the services sector). The traps name real, different sectors of the economy."}}, {"title": "Applying and preparing for a job", "html": "<p>The language of job adverts and applications — often seen in Paper 3 reading texts.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se necesita\">se necesita</span></td><td>wanted / needed (job advert)</td><td><span data-say=\"solicitar\">solicitar</span></td><td>to apply for</td></tr>\n              <tr><td><span data-say=\"el título\">el título</span></td><td>qualification, degree</td><td><span data-say=\"la formación\">la formación</span></td><td>training</td></tr>\n              <tr><td><span data-say=\"la oferta\">la oferta</span></td><td>offer</td><td><span data-say=\"el empleo\">el empleo</span></td><td>employment, job</td></tr>\n              <tr><td><span data-say=\"la oportunidad\">la oportunidad</span></td><td>opportunity</td><td><span data-say=\"la selección\">la selección</span></td><td>selection (process)</td></tr>\n              <tr><td><span data-say=\"el documento\">el documento</span></td><td>document</td><td><span data-say=\"la carta\">la carta</span></td><td>letter</td></tr>\n              <tr><td><span data-say=\"el correo electrónico\">el correo electrónico</span></td><td>email</td><td><span data-say=\"la cita\">la cita</span></td><td>appointment</td></tr>\n              <tr><td><span data-say=\"el consejo\">el consejo</span></td><td>advice</td><td><span data-say=\"la emoción\">la emoción</span></td><td>emotion, excitement</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Se necesita camarero con experiencia; hay que solicitar el puesto por correo electrónico y adjuntar tu título.\">Se necesita camarero con experiencia; hay que solicitar el puesto por correo electrónico y adjuntar tu título.</span></p>\n            <p>My first job: <span data-say=\"Mi primer empleo fue una gran oportunidad y sentí mucha emoción cuando conseguí una cita para la entrevista.\">Mi primer empleo fue una gran oportunidad y sentí mucha emoción cuando conseguí una cita para la entrevista.</span> Pedí <span data-say=\"consejo\">consejo</span> a mi profesora antes de enviar los documentos.</p>", "check": {"question": "What does ‘se necesita’ mean at the start of a job advert?", "options": ["wanted / needed", "no longer available", "fully qualified only", "for females only, always"], "answer": 0, "explain": "se necesita = wanted/needed — the standard opening phrase of a Spanish job advert."}}, {"title": "People at work", "html": "<p>More job titles and workplace people, beyond the doctors, teachers and engineers from Topics 1–2.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el jefe\">el jefe</span> / <span data-say=\"la jefa\">la jefa</span></td><td>boss</td><td><span data-say=\"el cliente\">el cliente</span> / <span data-say=\"la clienta\">la clienta</span></td><td>customer</td></tr>\n              <tr><td><span data-say=\"el empleado\">el empleado</span> / <span data-say=\"la empleada\">la empleada</span></td><td>employee</td><td><span data-say=\"el dueño\">el dueño</span> / <span data-say=\"la dueña\">la dueña</span></td><td>owner</td></tr>\n              <tr><td><span data-say=\"el empresario\">el empresario</span> / <span data-say=\"la empresaria\">la empresaria</span></td><td>entrepreneur</td><td><span data-say=\"el obrero\">el obrero</span> / <span data-say=\"la obrera\">la obrera</span></td><td>(manual) worker</td></tr>\n              <tr><td><span data-say=\"el policía\">el policía</span> / <span data-say=\"la policía\">la policía</span></td><td>police officer</td><td><span data-say=\"el soldado\">el soldado</span></td><td>soldier</td></tr>\n              <tr><td><span data-say=\"el periodista\">el periodista</span> / <span data-say=\"la periodista\">la periodista</span></td><td>journalist</td><td><span data-say=\"el secretario\">el secretario</span> / <span data-say=\"la secretaria\">la secretaria</span></td><td>secretary</td></tr>\n              <tr><td><span data-say=\"el científico\">el científico</span> / <span data-say=\"la científica\">la científica</span></td><td>scientist</td><td><span data-say=\"químico\">químico</span></td><td>chemical, chemist</td></tr>\n              <tr><td><span data-say=\"el representante\">el representante</span></td><td>representative</td><td><span data-say=\"el experto\">el experto</span> / <span data-say=\"la experta\">la experta</span></td><td>expert</td></tr>\n              <tr><td><span data-say=\"el cuidador\">el cuidador</span> / <span data-say=\"la cuidadora\">la cuidadora</span></td><td>carer</td><td><span data-say=\"el guía\">el guía</span> / <span data-say=\"la guía\">la guía</span></td><td>guide</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi jefe trabaja con un equipo de empleados en una reunión cada lunes.\">Mi jefe trabaja con un equipo de empleados en una reunión cada lunes.</span> — My boss works with a team of employees in a meeting every Monday.</p>\n            <p>More careers: <span data-say=\"El dueño de la empresa es también empresario y diseña una campaña con un experto en diseño.\">El dueño de la empresa es también empresario y diseña una campaña con un experto en diseño.</span> El cliente paga en la <span data-say=\"caja\">caja</span>.</p>", "check": {"question": "Which job title means ‘entrepreneur’?", "options": ["el empresario", "el policía municipal", "el periodista deportivo", "el cuidador de niños"], "answer": 0, "explain": "el empresario = entrepreneur/businessman. The traps name other real jobs taught on this page."}}, {"title": "The world of work and the economy", "html": "<p><span class=\"tier-h\">H</span> More abstract nouns and adjectives for discussing jobs, rights and the economy at a higher level.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el gobierno\">el gobierno</span></td><td>government</td><td><span data-say=\"el derecho\">el derecho</span></td><td>right; law (subject)</td></tr>\n              <tr><td><span data-say=\"el salario\">el salario</span></td><td>salary</td><td><span data-say=\"el paro\">el paro</span></td><td>unemployment</td></tr>\n              <tr><td><span data-say=\"la huelga\">la huelga</span></td><td>strike</td><td><span data-say=\"la tasa\">la tasa</span></td><td>rate</td></tr>\n              <tr><td><span data-say=\"laboral\">laboral</span></td><td>work-related</td><td><span data-say=\"la independencia\">la independencia</span></td><td>independence</td></tr>\n              <tr><td><span data-say=\"el adulto\">el adulto</span> / <span data-say=\"la adulta\">la adulta</span></td><td>adult</td><td><span data-say=\"la responsabilidad\">la responsabilidad</span></td><td>responsibility</td></tr>\n              <tr><td><span data-say=\"responsable\">responsable</span></td><td>responsible</td><td><span data-say=\"profesional\">profesional</span></td><td>professional</td></tr>\n              <tr><td><span data-say=\"ambicioso\">ambicioso</span></td><td>ambitious</td><td><span data-say=\"ideal\">ideal</span></td><td>ideal</td></tr>\n              <tr><td><span data-say=\"la importancia\">la importancia</span></td><td>importance</td><td><span data-say=\"el interés\">el interés</span></td><td>interest</td></tr>\n              <tr><td><span data-say=\"la confianza\">la confianza</span></td><td>confidence, trust</td><td><span data-say=\"la igualdad\">la igualdad</span></td><td>equality</td></tr>\n              <tr><td><span data-say=\"el género\">el género</span></td><td>gender</td><td><span data-say=\"económico\">económico</span></td><td>economic</td></tr>\n              <tr><td><span data-say=\"el ejército\">el ejército</span></td><td>army</td><td><span data-say=\"la bolsa\">la bolsa</span></td><td>stock exchange</td></tr>\n              <tr><td><span data-say=\"el aspecto\">el aspecto</span></td><td>aspect</td><td><span data-say=\"la manifestación\">la manifestación</span></td><td>demonstration</td></tr>\n              <tr><td><span data-say=\"la seguridad\">la seguridad</span></td><td>security</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando sea mayor, quiero un trabajo ambicioso e ideal, con un buen salario y seguridad laboral.\">Cuando sea mayor, quiero un trabajo ambicioso e ideal, con un buen salario y seguridad laboral.</span></p>\n            <p><span class=\"tier-h\">H</span> A serious economic issue: <span data-say=\"la tasa de paro\">la tasa de paro</span> (the unemployment rate) can lead to <span data-say=\"una huelga\">una huelga</span> (a strike) or even <span data-say=\"una manifestación\">una manifestación</span> (a demonstration). <span data-say=\"El gobierno debe proteger el derecho a la igualdad de género en el trabajo.\">El gobierno debe proteger el derecho a la igualdad de género en el trabajo.</span></p>\n            <p>Other useful ideas: <span data-say=\"Un aspecto importante de ser adulto es tener independencia económica y confianza en ti mismo.\">Un aspecto importante de ser adulto es tener independencia económica y confianza en ti mismo.</span> Algunas personas invierten dinero <span data-say=\"en la bolsa\">en la bolsa</span>.</p>", "check": {"question": "What does ‘la tasa de paro’ measure?", "options": ["the unemployment rate", "average monthly salary levels", "how many strikes happen", "how many people work part-time"], "answer": 0, "explain": "la tasa de paro = the unemployment rate — a key economic/job-market statistic."}}, {"title": "Higher: key verbs for talking about work", "html": "<p><span class=\"tier-h\">H</span> Verbs that come up again and again when describing careers, achievements and plans.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"conseguir\">conseguir</span></td><td>to get, achieve</td><td><span data-say=\"lograr\">lograr</span></td><td>to achieve</td></tr>\n              <tr><td><span data-say=\"convertirse en\">convertirse en</span></td><td>to become</td><td><span data-say=\"construir\">construir</span></td><td>to build</td></tr>\n              <tr><td><span data-say=\"vender\">vender</span></td><td>to sell</td><td><span data-say=\"servir\">servir</span></td><td>to serve</td></tr>\n              <tr><td><span data-say=\"emplear\">emplear</span></td><td>to employ</td><td><span data-say=\"atender\">atender</span></td><td>to attend to, serve</td></tr>\n              <tr><td><span data-say=\"firmar\">firmar</span></td><td>to sign</td><td><span data-say=\"comunicar\">comunicar</span></td><td>to communicate</td></tr>\n              <tr><td><span data-say=\"investigar\">investigar</span></td><td>to research</td><td><span data-say=\"la investigación\">la investigación</span></td><td>research</td></tr>\n              <tr><td><span data-say=\"soñar con\">soñar con</span></td><td>to dream of</td><td><span data-say=\"reflejar\">reflejar</span></td><td>to reflect</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Trabajé mucho para conseguir mi primer empleo y por fin logré convertirme en enfermera.\">Trabajé mucho para conseguir mi primer empleo y por fin logré convertirme en enfermera.</span></p>\n            <p><span class=\"tier-h\">H</span> A very useful Higher structure is <strong>acabar de + infinitive</strong> (to have just done something): <span data-say=\"Acabo de firmar el contrato.\">Acabo de firmar el contrato.</span> — I have just signed the contract.</p>\n            <p>More examples: <span data-say=\"El empleado tiene que atender a los clientes y comunicar bien con el equipo.\">El empleado tiene que atender a los clientes y comunicar bien con el equipo.</span> <span data-say=\"Siempre soñé con investigar nuevas medicinas.\">Siempre soñé con investigar nuevas medicinas.</span> — I always dreamed of researching new medicines. <span data-say=\"Mi trabajo refleja mis valores.\">Mi trabajo refleja mis valores.</span></p>", "check": {"question": "What does ‘acabar de + infinitive’ mean?", "options": ["to have just done something", "to be about to do something soon", "to have finished doing something years ago", "to never have done something at all"], "answer": 0, "explain": "acabar de + infinitive = to have just (done something) — a Higher-tier structure, e.g. acabo de firmar = I''ve just signed."}}]}, "terms": {"enabled": true, "pairs": [{"term": "quiero ser", "definition": "I want to be"}, {"term": "me gustaría ser", "definition": "I would like to be"}, {"term": "voy a estudiar", "definition": "I am going to study"}, {"term": "en el futuro", "definition": "in the future"}, {"term": "el médico / la médica", "definition": "doctor"}, {"term": "el profesor / la profesora", "definition": "teacher"}, {"term": "el abogado / la abogada", "definition": "lawyer"}, {"term": "el ingeniero / la ingeniera", "definition": "engineer"}, {"term": "el enfermero / la enfermera", "definition": "nurse"}, {"term": "el dependiente / la dependienta", "definition": "shop assistant"}, {"term": "el camarero / la camarera", "definition": "waiter / waitress"}, {"term": "el peluquero / la peluquera", "definition": "hairdresser"}, {"term": "el hombre / la mujer de negocios", "definition": "businessman / businesswoman"}, {"term": "la universidad", "definition": "university"}, {"term": "seguir estudiando", "definition": "to continue studying"}, {"term": "hacer un aprendizaje", "definition": "to do an apprenticeship"}, {"term": "para ganar dinero", "definition": "in order to earn money"}, {"term": "cuando sea mayor (H)", "definition": "when I am older"}, {"term": "primer", "definition": "first"}, {"term": "el gobierno (H)", "definition": "government"}, {"term": "convertirse en (H)", "definition": "to become"}, {"term": "el derecho (H)", "definition": "right; law (as a subject)"}, {"term": "conseguir (H)", "definition": "to get, achieve"}, {"term": "lograr (H)", "definition": "to achieve"}, {"term": "los servicios", "definition": "services (sector)"}, {"term": "económico (H)", "definition": "economic"}, {"term": "servir", "definition": "to serve"}, {"term": "la empresa", "definition": "company, firm"}, {"term": "el interés", "definition": "interest"}, {"term": "el aspecto", "definition": "aspect"}, {"term": "la investigación (H)", "definition": "research"}, {"term": "vender", "definition": "to sell"}, {"term": "la seguridad (H)", "definition": "security"}, {"term": "la oportunidad", "definition": "opportunity"}, {"term": "construir", "definition": "to build"}, {"term": "la carta", "definition": "letter"}, {"term": "el policía / la policía", "definition": "police officer"}, {"term": "la compañía", "definition": "company"}, {"term": "responsable", "definition": "responsible"}, {"term": "la importancia", "definition": "importance"}, {"term": "profesional (H)", "definition": "professional"}, {"term": "el negocio", "definition": "business"}, {"term": "el título (H)", "definition": "qualification, degree"}, {"term": "el jefe / la jefa", "definition": "boss"}, {"term": "el banco", "definition": "bank"}, {"term": "la construcción (H)", "definition": "construction"}, {"term": "la formación (H)", "definition": "training"}, {"term": "el ejército", "definition": "army"}, {"term": "el consejo", "definition": "advice"}, {"term": "la responsabilidad (H)", "definition": "responsibility"}, {"term": "emplear (H)", "definition": "to employ"}, {"term": "la reunión (H)", "definition": "meeting"}, {"term": "el documento (H)", "definition": "document"}, {"term": "la campaña (H)", "definition": "campaign"}, {"term": "atender (H)", "definition": "to attend to, serve"}, {"term": "firmar (H)", "definition": "to sign"}, {"term": "el cliente / la clienta", "definition": "customer"}, {"term": "la oficina", "definition": "office"}, {"term": "la caja", "definition": "till, checkout"}, {"term": "el comercio (H)", "definition": "trade, commerce"}, {"term": "reflejar (H)", "definition": "to reflect"}, {"term": "el periodista / la periodista", "definition": "journalist"}, {"term": "el género (H)", "definition": "gender"}, {"term": "el dueño / la dueña", "definition": "owner"}, {"term": "soñar (con)", "definition": "to dream (of)"}, {"term": "comunicar", "definition": "to communicate"}, {"term": "solicitar (H)", "definition": "to apply for"}, {"term": "el secretario / la secretaria", "definition": "secretary"}, {"term": "universitario (H)", "definition": "university (adj)"}, {"term": "el diseño (H)", "definition": "design"}, {"term": "la confianza", "definition": "confidence, trust"}, {"term": "el representante (H)", "definition": "representative"}, {"term": "el empleo", "definition": "employment, job"}, {"term": "la emoción (H)", "definition": "emotion, excitement"}, {"term": "el soldado (H)", "definition": "soldier"}, {"term": "investigar (H)", "definition": "to research"}, {"term": "el adulto / la adulta (H)", "definition": "adult"}, {"term": "la bolsa", "definition": "stock exchange; bag"}, {"term": "laboral", "definition": "work-related"}, {"term": "la selección (H)", "definition": "selection"}, {"term": "químico (H)", "definition": "chemical, chemist"}, {"term": "el correo (electrónico)", "definition": "email"}, {"term": "la sección (H)", "definition": "section"}, {"term": "la independencia (H)", "definition": "independence"}, {"term": "el científico / la científica", "definition": "scientist"}, {"term": "la oferta", "definition": "offer"}, {"term": "el vuelo", "definition": "flight"}, {"term": "el empleado / la empleada", "definition": "employee"}, {"term": "el obrero / la obrera (H)", "definition": "(manual) worker"}, {"term": "el experto / la experta (H)", "definition": "expert"}, {"term": "la tasa (H)", "definition": "rate"}, {"term": "la manifestación (H)", "definition": "demonstration"}, {"term": "el empresario / la empresaria (H)", "definition": "entrepreneur"}, {"term": "fabricar (H)", "definition": "to manufacture"}, {"term": "la cita (H)", "definition": "appointment"}, {"term": "diseñar", "definition": "to design"}, {"term": "el salario", "definition": "salary"}, {"term": "la fábrica", "definition": "factory"}, {"term": "el guía / la guía (H)", "definition": "guide"}, {"term": "ideal", "definition": "ideal"}, {"term": "la huelga (H)", "definition": "strike"}, {"term": "la igualdad (H)", "definition": "equality"}, {"term": "el paro", "definition": "unemployment"}, {"term": "ambicioso (H)", "definition": "ambitious"}, {"term": "el cuidador / la cuidadora", "definition": "carer"}, {"term": "el Bachillerato", "definition": "Bachillerato (Spanish Sixth-Form equivalent)"}, {"term": "acabar de + infinitivo (H)", "definition": "to have just (done something)"}, {"term": "se necesita", "definition": "wanted / needed (job advert)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Quiero ser médica.\" data-listen></span><br>Listen. What is the ambition?", "options": ["To become a doctor", "To become a lawyer", "To become an engineer", "To become a nurse"], "answer": 0, "explain": "‘quiero ser médica’ = I want to be a doctor. All four are plausible jobs — you must catch médica specifically."}, {"question": "<span data-say=\"Voy a hacer un aprendizaje.\" data-listen></span><br>Listen. What is the plan?", "options": ["To do an apprenticeship after school", "To go to a big university to study law", "To pass all of this year''s exams", "To travel around Europe for a year"], "answer": 0, "explain": "‘voy a hacer un aprendizaje’ = I’m going to do an apprenticeship. Every option is a real future-plan phrase — listen for the specific verb."}, {"question": "<span data-say=\"No quiero ir a la universidad.\" data-listen></span><br>Listen. Which is correct?", "options": ["I don''t want to go to university", "I want to go to university", "I don''t want to do an apprenticeship", "I have already finished university"], "answer": 0, "explain": "‘No quiero ir a la universidad’ = I don''t want to go to university. Distractors flip the negative or swap the destination."}, {"question": "How do you say ‘I would like to be an engineer’?", "options": ["Me gustaría ser ingeniera", "Me gustaría ser una ingeniera", "Quiero ser ingeniera ya", "Me gusta ser ingeniera"], "answer": 0, "explain": "‘me gustaría’ = I would like (conditional). ‘una’ is the article error again; ‘me gusta’ is wrongly present tense."}, {"question": "Complete: ‘Quiero ser abogado porque ___ la ley.’", "options": ["me interesa", "me interesan", "me gusta", "me gustan"], "answer": 0, "explain": "interesar works like gustar: singular subject (la ley) → interesa. A plural verb or the wrong verb (gustar) are common slips."}, {"question": "Which sentence uses ‘para + infinitive’ correctly for a reason?", "options": ["Trabajo mucho para ganar dinero", "Trabajo mucho para gano dinero", "Trabajo mucho porque ganar dinero", "Trabajo mucho para dinero"], "answer": 0, "explain": "para + infinitive (para ganar dinero). Conjugating after para, using porque with an infinitive, or dropping the verb are the classic slips."}, {"question": "‘Voy a seguir estudiando’ means…", "options": ["I am going to continue studying", "I have already stopped studying", "I want to start studying again", "I used to study a long time ago"], "answer": 0, "explain": "‘voy a seguir estudiando’ = I''m going to continue studying — a near-future plan, not a past or a stop."}, {"question": "Which shows the correct feminine form of ‘hairdresser’?", "options": ["la peluquera", "la peluquero", "el peluquera", "las peluquero"], "answer": 0, "explain": "-ero → -era for feminine: la peluquera. Forgetting the ending change or mixing up articles are common."}, {"question": "Higher: complete ‘Cuando ___ mayor, quiero ser dentista.’", "options": ["sea", "soy", "era", "seré"], "answer": 0, "explain": "cuando + present subjunctive (sea) for future time. soy/era/seré are all real tense-confusion errors here."}, {"question": "How do you say ‘I want to earn money to travel’?", "options": ["Quiero ganar dinero para viajar", "Quiero ganar dinero porque viajar", "Quiero ganar dinero para viajo", "Quiero gano dinero para viajar"], "answer": 0, "explain": "para + infinitive (para viajar). ‘porque’ + infinitive, a conjugated verb after ‘para’, or a double-conjugated ‘quiero gano’ are the traps."}, {"question": "<span data-say=\"Se necesita camarero con experiencia.\" data-listen></span><br>Listen. What kind of text is this?", "options": ["a job advert looking for a waiter", "a menu at a restaurant", "a complaint from an unhappy customer", "an invitation to a job interview"], "answer": 0, "explain": "‘se necesita…’ = wanted/needed — the standard opening of a job advert. The traps name other plausible workplace text types."}, {"question": "Which word means ‘entrepreneur’, someone who owns and runs a business?", "options": ["el empresario", "el empleado de la tienda", "el cliente habitual", "el obrero de la fábrica"], "answer": 0, "explain": "el empresario = entrepreneur. The traps name other real jobs from this topic."}, {"question": "Complete: ‘El gobierno debe proteger el derecho a la _____ de género.’ (equality)", "options": ["igualdad", "seguridad", "importancia", "confianza"], "answer": 0, "explain": "igualdad = equality, the missing word. The other nouns are real but don''t fit this specific sentence."}, {"question": "What does ‘la tasa de paro’ refer to?", "options": ["the unemployment rate", "how many people are on strike", "average annual salary", "the working week''s total hours"], "answer": 0, "explain": "la tasa de paro = the unemployment rate. The traps invent other plausible economic statistics."}, {"question": "What does ‘acabo de firmar el contrato’ mean?", "options": ["I have just signed the contract", "I am about to sign the contract soon", "I signed the contract a long time ago", "I refuse to sign the contract at all"], "answer": 0, "explain": "acabar de + infinitive = to have just (done something). The traps shift the timing or the meaning entirely."}, {"question": "Which sentence means ‘My boss works with a team of employees’?", "options": ["Mi jefe trabaja con un equipo de empleados", "Mi jefe trabaja solo, sin ningún empleado", "Mi empleado trabaja con un equipo de jefes", "Mi cliente trabaja con un equipo de dueños"], "answer": 0, "explain": "Mi jefe trabaja con un equipo de empleados = my boss works with a team of employees. The traps swap or negate the roles."}, {"question": "Which best completes: ‘Siempre soñé con _____ nuevas medicinas.’ (to research)", "options": ["investigar", "vender a otras empresas", "firmar todos los documentos", "emplear a mucha gente nueva"], "answer": 0, "explain": "investigar = to research/investigate, the missing verb here. The other verbs are real but don''t fit this context."}]}, "fib": {"enabled": true, "questions": [{"text": "Quiero [ser] médica. <span data-say=\"Quiero ser médica.\" data-listen>Quiero ser médica.</span>"}, {"text": "Me [gustaría] ser abogado porque me interesa la ley. (would like)"}, {"text": "Voy a seguir [estudiando] en la universidad. (studying)"}, {"text": "Quiero hacer un [aprendizaje] en vez de ir a la universidad. (apprenticeship)"}, {"text": "Trabajo mucho para [ganar] dinero. (to earn)"}, {"text": "Cuando [sea] mayor, quiero ser dentista. <span data-say=\"Cuando sea mayor, quiero ser dentista.\" data-listen>Cuando sea mayor, quiero ser dentista.</span>"}, {"text": "Para [ayudar] a la gente, quiero ser enfermera. (to help)"}, {"text": "Se [necesita] camarero con experiencia. (wanted/needed) <span data-say=\"Se necesita camarero con experiencia.\" data-listen>Se necesita camarero con experiencia.</span>"}, {"text": "Hay que [solicitar] el puesto por correo electrónico. (to apply for)"}, {"text": "Mi [jefe] trabaja con un equipo de empleados. (boss)"}, {"text": "El gobierno debe proteger el derecho a la [igualdad]. (equality)"}, {"text": "La [tasa] de paro subió el año pasado. (rate) <span data-say=\"La tasa de paro subió el año pasado.\" data-listen>La tasa de paro subió el año pasado.</span>"}, {"text": "Acabo de [firmar] el contrato. (to sign) (H)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘Soy profesor’ does not need an article before the job.", "answer": true, "explain": "ser + job drops the article in Spanish: soy profesor, not soy un profesor."}, {"statement": "‘la dependienta’ means a male shop assistant.", "answer": false, "explain": "la dependienta is female; el dependiente is the male form."}, {"statement": "‘me gustaría’ is the conditional form meaning ‘I would like’.", "answer": true, "explain": "me gustaría ser = I would like to be — conditional tense."}, {"statement": "After ‘para’, you use a verb conjugated for ‘yo’.", "answer": false, "explain": "para is followed by the infinitive: para ganar dinero, not para gano dinero."}, {"statement": "‘sacar buenas notas’ means ‘to get good marks’.", "answer": true, "explain": "sacar buenas notas = to get good marks/grades."}, {"statement": "‘cuando sea mayor’ uses the present subjunctive because it refers to future time.", "answer": true, "explain": "cuando + subjunctive (sea) is required for a future time clause — a Higher-tier feature."}, {"statement": "‘hacer un aprendizaje’ means ‘to go to university’.", "answer": false, "explain": "hacer un aprendizaje = to do an apprenticeship, the vocational alternative to university."}, {"statement": "‘porque me interesa’ is followed by an infinitive, just like ‘para’.", "answer": false, "explain": "porque is followed by a full clause with a conjugated verb, not an infinitive."}, {"statement": "‘Se necesita’ at the start of a text usually introduces a job advert.", "answer": true, "explain": "se necesita = wanted/needed, the standard opening of a Spanish job advert."}, {"statement": "‘El empresario’ means an ordinary employee with no responsibility.", "answer": false, "explain": "False! el empresario = entrepreneur/businessman, someone who owns or runs a business."}, {"statement": "‘La tasa de paro’ measures the level of unemployment.", "answer": true, "explain": "la tasa de paro = the unemployment rate, a key economic statistic."}, {"statement": "‘Acabar de + infinitive’ means to have just done something.", "answer": true, "explain": "acabar de firmar = to have just signed — a Higher-tier structure for recent past actions."}, {"statement": "‘La huelga’ means a work meeting between colleagues.", "answer": false, "explain": "False! la huelga = a strike, not a meeting (that would be la reunión)."}, {"statement": "‘Laboral’ describes anything related to work.", "answer": true, "explain": "laboral = work-related, e.g. el mercado laboral (the job market)."}]}, "misc": {"enabled": true, "items": [{"myth": "Soy un profesor.", "truth": "Soy profesor.", "check": {"question": "Why is ‘un’ wrong here?", "options": ["ser + job drops the article in Spanish", "‘profesor’ needs a feminine ending instead", "the verb should be ‘estoy’, not ‘soy’, here", "‘un’ should come after the noun"], "answer": 0, "explain": "Spanish never uses an article between ser and an unmodified job: soy profesor."}}, {"myth": "La dependiente trabaja en la tienda.", "truth": "La dependienta trabaja en la tienda.", "check": {"question": "What''s wrong with ‘la dependiente’?", "options": ["the feminine form is ‘la dependienta’, not ‘la dependiente’", "‘dependiente’ should never follow the article ‘la’ at all, ever", "‘tienda’ should be spelt ‘tiendo’ instead", "the verb ‘trabaja’ is spelt wrong here"], "answer": 0, "explain": "dependiente/dependienta is an irregular feminine pattern — it doesn''t just drop the -e."}}, {"myth": "Trabajo para gano dinero.", "truth": "Trabajo para ganar dinero.", "check": {"question": "Why is ‘para gano’ incorrect?", "options": ["‘para’ must be followed by an infinitive (ganar)", "‘gano’ should be ‘ganamos’ to agree with ‘trabajo’", "‘para’ should simply be replaced with ‘porque’", "the sentence needs an extra ‘un’ before ‘dinero’"], "answer": 0, "explain": "para always takes the infinitive, never a conjugated verb form."}}, {"myth": "Cuando soy mayor, quiero ser dentista.", "truth": "Cuando sea mayor, quiero ser dentista.", "check": {"question": "Why does the Higher answer need ‘sea’, not ‘soy’?", "options": ["‘cuando’ + future time needs the present subjunctive", "‘soy’ is actually a plural verb form here", "‘dentista’ must agree in gender with ‘soy’", "‘cuando’ is only ever correctly used with the past tense"], "answer": 0, "explain": "A future-time clause with cuando triggers the present subjunctive: cuando sea mayor."}}, {"myth": "Me gusta ser ingeniera.", "truth": "Me gustaría ser ingeniera.", "check": {"question": "What''s the error in using ‘me gusta’ for an ambition?", "options": ["‘me gusta’ is present tense; ‘I would like’ needs the conditional ‘me gustaría’", "‘me gusta’ should agree with a plural noun such as ‘las ingenieras’ in this exact case", "‘ingeniera’ needs the indefinite article ‘una’ placed before it", "‘ser’ should be ‘estar’ here"], "answer": 0, "explain": "‘me gusta’ says what you like now, not what you would like to become — that needs the conditional me gustaría."}}, {"myth": "Acabo de firmar significa que voy a firmar pronto.", "truth": "Acabo de firmar significa que ya firmé hace un momento.", "check": {"question": "What does ‘acabar de + infinitive’ actually describe?", "options": ["an action that has just happened, a moment ago", "an action that will happen very soon in the future", "an action repeated every single day without fail", "an action that never actually happened at all"], "answer": 0, "explain": "acabar de + infinitive = to have JUST done something (recent past), not a future plan."}}, {"myth": "La tasa es una bebida caliente que tomamos por la mañana.", "truth": "La tasa es un porcentaje o índice, como la tasa de paro.", "check": {"question": "What does ‘la tasa’ mean in an economics context?", "options": ["a rate or percentage, e.g. the unemployment rate", "a hot drink you have first thing every single morning", "a type of school uniform item worn on Fridays only", "a formal letter always sent by a company to a bank"], "answer": 0, "explain": "la tasa = a rate/percentage. It sounds like ‘la taza’ (a cup), a classic homophone trap."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for job vocabulary", "html": "Job vocabulary is everywhere in Paper 1. Listen for the ending of the job noun (-o masculine, -a feminine: ingeniero/ingeniera) and for whether the tense is quiero ser (ambition), soy (current job) or voy a (near-future plan).", "check": {"question": "You hear ‘Quiero ser ingeniera’. What does this tell you?", "options": ["The speaker (female) wants to be an engineer", "The speaker (male) wants to be an engineer instead", "The speaker (female) wants to be a teacher one day", "The speaker (male) already works as an engineer eventually"], "answer": 0, "explain": "‘ingeniera’ (-a ending) signals a female speaker; ‘quiero ser’ = I want to be (an ambition, not a current job)."}}, {"title": "Paper 3 — Reading: ser without an article", "html": "When you read ‘Mi hermano es mecánico’ or ‘Quiero ser abogada’, translate naturally into English WITH ‘a’/‘an’ — Spanish drops the article, English needs it. Don''t be thrown by the missing ‘un/una’.", "check": {"question": "How should you translate ‘Mi hermano es mecánico’?", "options": ["My brother is a mechanic", "My brother is mechanic", "My brother is the mechanic", "My brothers are mechanics"], "answer": 0, "explain": "Spanish drops the article (es mecánico); English needs ‘a mechanic’. Omitting ‘a’, adding ‘the’, or making it plural are the traps."}}, {"title": "Paper 4 — Writing & speaking: giving reasons", "html": "Top-band answers combine an ambition, a reason and a time phrase: ‘Cuando sea mayor, me gustaría ser abogada porque me interesa la justicia.’ At Higher, cuando + subjunctive and a clear reason clause both show range.", "check": {"question": "Which answer reaches the top band?", "options": ["Cuando sea mayor, me gustaría ser abogada porque me interesa la justicia", "Quiero ser abogada porque me interesa la abogada y la abogada y la abogada", "Voy a ser abogada un día quizás en el futuro tal vez algún día", "Me gustaría ser abogada"], "answer": 0, "explain": "It combines cuando + subjunctive, an ambition and a genuine reason. Repetition without added meaning, vague hedging, or a bare statement don''t reach the top band."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What job would Carlos like to do, and why? (2)<br>(b) What does Carlos want to do after school, according to the text? (1)<br>(c) Why does his sister prefer to do an apprenticeship? (1)", "marks": 4, "hint": "Find the job after ‘me gustaría ser’, the reason after ‘porque’, his plan after ‘quiero’, and his sister''s reason after ‘porque quiere’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> engineer <em>(1)</em> + because he is (very) interested in technology <em>(1)</em>.</li>\n                <li><strong>(b)</strong> go to university <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) she wants to earn money quickly <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I want to be a nurse. <br>(b) I would like to study at university. <br>(c) When I am older, I am going to travel to earn money.", "marks": 5, "hint": "‘I want to be’ = Quiero ser (no article). ‘I would like to’ = Me gustaría + infinitive. ‘When I am older’ (future) = Cuando sea mayor + subjunctive.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Quiero ser enfermera. <em>(1)</em></li>\n                <li><strong>(b)</strong> Me gustaría estudiar en la universidad. <em>(1)</em></li>\n                <li><strong>(c)</strong> Cuando sea mayor <em>(1)</em>, voy a viajar <em>(1)</em> para ganar dinero <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Cuando sea mayor’ must use the subjunctive ‘sea’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '4-1-sport-hobbies-and-going-out', '4.1 Sport, Hobbies and Going Out', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about playing sport? (jugar al vs hacer)", "html": "<p>Use <span data-say=\"jugar\">jugar</span> + <strong>a + el = al</strong> for ball / racquet sports, but <span data-say=\"hacer\">hacer</span> for other kinds of sport.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"jugar al fútbol\">jugar al fútbol</span></td><td>to play football</td><td><span data-say=\"jugar al baloncesto\">jugar al baloncesto</span></td><td>to play basketball</td></tr>\n              <tr><td><span data-say=\"jugar al tenis\">jugar al tenis</span></td><td>to play tennis</td><td><span data-say=\"el equipo\">el equipo</span></td><td>the team</td></tr>\n              <tr><td><span data-say=\"hacer deporte\">hacer deporte</span></td><td>to do sport</td><td><span data-say=\"nadar\">nadar</span></td><td>to swim</td></tr>\n              <tr><td><span data-say=\"montar en bicicleta\">montar en bicicleta</span></td><td>to cycle</td><td><span data-say=\"el deporte\">el deporte</span></td><td>sport</td></tr>\n            </table>\n            <p>Model: <span data-say=\"Juego al fútbol con mi equipo los sábados.\">Juego al fútbol con mi equipo los sábados.</span> — <em>I play football with my team on Saturdays.</em></p>", "check": {"question": "Which is correct for ‘I play tennis’?", "options": ["Juego al tenis", "Juego tenis", "Hago al tenis", "Juega el tenis"], "answer": 0, "explain": "jugar takes ‘al’ before a ball/racquet sport: juego al tenis. Dropping ‘al’ or swapping in ‘hago’ are the classic errors."}}, {"title": "How do I talk about hobbies and free time?", "html": "<p>Key nouns: <span data-say=\"el tiempo libre\">el tiempo libre</span> (free time), <span data-say=\"el pasatiempo\">el pasatiempo</span> (hobby/pastime), <span data-say=\"la afición\">la afición</span> (hobby/interest).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"coleccionar\">coleccionar</span></td><td>to collect</td><td><span data-say=\"coleccionar sellos\">coleccionar sellos</span></td><td>to collect stamps</td></tr>\n              <tr><td><span data-say=\"cocinar\">cocinar</span></td><td>to cook</td><td><span data-say=\"leer\">leer</span></td><td>to read</td></tr>\n              <tr><td><span data-say=\"tocar un instrumento\">tocar un instrumento</span></td><td>to play an instrument</td><td><span data-say=\"jugar a videojuegos\">jugar a videojuegos</span></td><td>to play video games</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi tiempo libre, mi afición es coleccionar sellos.\">En mi tiempo libre, mi afición es coleccionar sellos.</span> — <em>In my free time, my hobby is collecting stamps.</em></p>\n            <p>More hobby words: <span data-say=\"la actividad\">la actividad</span> (activity), <span data-say=\"probar\">probar</span> (to try). Example: <span data-say=\"Me gusta probar actividades nuevas, y mi mascota también es parte de mi tiempo libre.\">Me gusta probar actividades nuevas, y mi mascota también es parte de mi tiempo libre.</span> — <em>I like trying new activities, and my pet is also part of my free time.</em></p>", "check": {"question": "What does ‘el pasatiempo’ mean?", "options": ["hobby / pastime", "a time in the past", "a paid job", "a type of team sport played daily"], "answer": 0, "explain": "el pasatiempo = a hobby/pastime — a false-friend trap is confusing it with ‘pasado’ (past)."}}, {"title": "How do I say what I like doing? (gustar/encantar + infinitive)", "html": "<p><span data-say=\"gustar\">gustar</span> and <span data-say=\"encantar\">encantar</span> work like ‘doler’ — before an infinitive they always stay <strong>singular</strong>, even if you name more than one activity.</p>\n            <ul>\n              <li><span data-say=\"me gusta jugar al fútbol\">me gusta jugar al fútbol</span> — I like playing football (ONE infinitive → gusta)</li>\n              <li><span data-say=\"me gustan los deportes de equipo\">me gustan los deportes de equipo</span> — I like team sports (PLURAL noun → gustan)</li>\n              <li><span data-say=\"me encanta salir con amigos\">me encanta salir con amigos</span> — I love going out with friends</li>\n              <li><span data-say=\"no me gusta nada cocinar\">no me gusta nada cocinar</span> — I don’t like cooking at all</li>\n            </ul>\n            <p>Model: <span data-say=\"Me encanta jugar al baloncesto, pero no me gusta nada nadar.\">Me encanta jugar al baloncesto, pero no me gusta nada nadar.</span></p>", "check": {"question": "Complete: ‘Me ___ jugar al tenis.’ (I like playing tennis)", "options": ["gusta", "gustan", "gusto", "gustaría"], "answer": 0, "explain": "Before a single infinitive, gustar stays singular: me gusta jugar. ‘gustan’ is only for plural nouns; ‘gustaría’ shifts to the conditional."}}, {"title": "How do I talk about going out with friends?", "html": "<p>Common ways to talk about going out (<strong>salir</strong>):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"salir con amigos\">salir con amigos</span></td><td>to go out with friends</td><td><span data-say=\"quedar con\">quedar con</span></td><td>to meet up with</td></tr>\n              <tr><td><span data-say=\"ir al cine\">ir al cine</span></td><td>to go to the cinema</td><td><span data-say=\"ir al parque\">ir al parque</span></td><td>to go to the park</td></tr>\n              <tr><td><span data-say=\"ir a la bolera\">ir a la bolera</span></td><td>to go bowling</td><td><span data-say=\"la fiesta\">la fiesta</span></td><td>the party</td></tr>\n              <tr><td><span data-say=\"bailar\">bailar</span></td><td>to dance</td><td><span data-say=\"dar un paseo\">dar un paseo</span></td><td>to go for a walk</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Normalmente quedo con mis amigos y vamos a la bolera o al cine.\">Normalmente quedo con mis amigos y vamos a la bolera o al cine.</span></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la exposición\">la exposición</span></td><td>the exhibition</td><td><span data-say=\"el destino\">el destino</span></td><td>the destination</td></tr>\n              <tr><td><span data-say=\"el parque temático\">el parque temático</span></td><td>the theme park</td><td><span data-say=\"la corrida\">la corrida</span></td><td>the bullfight</td></tr>\n              <tr><td><span data-say=\"tomar el sol\">tomar el sol</span></td><td>to sunbathe</td><td><span data-say=\"sentarse\">sentarse</span></td><td>to sit down</td></tr>\n              <tr><td><span data-say=\"charlar\">charlar</span></td><td>to chat</td><td><span data-say=\"la cámara\">la cámara</span></td><td>the camera</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Nuestro destino favorito es un parque temático donde nos sentamos, tomamos el sol y charlamos, con una cámara para sacar fotos.\">Nuestro destino favorito es un parque temático donde nos sentamos, tomamos el sol y charlamos, con una cámara para sacar fotos.</span> — <em>Our favourite destination is a theme park where we sit down, sunbathe and chat, with a camera to take photos.</em></p>\n            <p>At a restaurant: <span data-say=\"Después de comer, pedimos la cuenta.\">Después de comer, pedimos la cuenta.</span> — <em>After eating, we ask for the bill.</em> <span data-say=\"Aun sin mucho dinero, siempre pasamos un buen rato.\">Aun sin mucho dinero, siempre pasamos un buen rato.</span> — <em>Even without much money, we always have a good time.</em></p>\n            <p><span class=\"tier-h\">H</span> Cultural outing: <span data-say=\"Fuimos a ver una exposición de arte y luego una corrida en la plaza.\">Fuimos a ver una exposición de arte y luego una corrida en la plaza.</span> <span class=\"tier-h\">H</span> — <em>We went to see an art exhibition and then a bullfight in the square.</em></p>", "check": {"question": "What does ‘quedar con’ mean?", "options": ["to meet up with (someone)", "to stay at home alone all day", "to remain completely silent", "to complain loudly about something"], "answer": 0, "explain": "quedar con = to meet up / arrange to meet with someone — a false-friend trap with ‘quedarse’ (to stay)."}}, {"title": "How do I say how often I do something?", "html": "<p>Frequency expressions usually sit at the start or end of the sentence:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"a menudo\">a menudo</span></td><td>often</td><td><span data-say=\"a veces\">a veces</span></td><td>sometimes</td></tr>\n              <tr><td><span data-say=\"todos los días\">todos los días</span></td><td>every day</td><td><span data-say=\"una vez a la semana\">una vez a la semana</span></td><td>once a week</td></tr>\n              <tr><td><span data-say=\"los fines de semana\">los fines de semana</span></td><td>at weekends</td><td><span data-say=\"nunca\">nunca</span></td><td>never</td></tr>\n            </table>\n            <p>Example: <span data-say=\"A menudo salgo con amigos, pero nunca voy a la bolera.\">A menudo salgo con amigos, pero nunca voy a la bolera.</span></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"¿Con qué frecuencia sales con amigos?\">¿Con qué frecuencia sales con amigos?</span> <span class=\"tier-h\">H</span> — <em>How often do you go out with friends?</em> (la frecuencia = frequency)</p>", "check": {"question": "‘Nunca voy a la bolera’ means…", "options": ["I never go bowling", "I sometimes go bowling", "I go bowling every single day", "I used to go bowling"], "answer": 0, "explain": "nunca = never. It negates the verb completely — not ‘sometimes’, ‘every day’ or ‘used to’."}}, {"title": "Higher: last weekend (preterite) and soler + infinitive", "html": "<p><span class=\"tier-h\">H</span> To talk about <strong>last weekend</strong>, use the <strong>preterite</strong> (simple past):</p>\n            <ul>\n              <li><span data-say=\"jugar\">jugar</span> → <span data-say=\"jugué al tenis\">jugué al tenis</span> (I played tennis)</li>\n              <li><span data-say=\"ir\">ir</span> → <span data-say=\"fui al cine\">fui al cine</span> (I went to the cinema) — irregular!</li>\n              <li><span data-say=\"salir\">salir</span> → <span data-say=\"salí con amigos\">salí con amigos</span> (I went out with friends)</li>\n            </ul>\n            <p>Model: <span data-say=\"El fin de semana pasado jugué al tenis y luego fui a una fiesta.\">El fin de semana pasado jugué al tenis y luego fui a una fiesta.</span> <span class=\"tier-h\">H</span></p>\n            <p><span class=\"tier-h\">H</span> For habits, use <strong>soler + infinitive</strong> (to usually do something):</p>\n            <ul>\n              <li><span data-say=\"suelo salir los sábados\">suelo salir los sábados</span> — I usually go out on Saturdays <span class=\"tier-h\">H</span></li>\n            </ul>", "check": {"question": "‘El fin de semana pasado jugué al tenis’ is in which tense?", "options": ["the preterite (a completed past action)", "the ordinary present tense", "the near future, using voy a + the infinitive form", "the conditional (would)"], "answer": 0, "explain": "jugué is the yo form of the preterite — a single completed action last weekend, signalled by ‘el fin de semana pasado’."}}, {"title": "How do I talk about the cost of going out?", "html": "<p>Talking about money when you go out:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el precio\">el precio</span></td><td>the price</td><td><span data-say=\"costar\">costar</span></td><td>to cost</td></tr>\n              <tr><td><span data-say=\"los gastos\">los gastos</span></td><td>expenses</td><td><span data-say=\"gastar\">gastar</span></td><td>to spend (money)</td></tr>\n              <tr><td><span data-say=\"el euro\">el euro</span></td><td>the euro</td><td><span data-say=\"gratis\">gratis</span></td><td>free (no cost)</td></tr>\n            </table>\n            <p>Example: <span data-say=\"La entrada al parque temático cuesta quince euros, pero para los niños es gratis.\">La entrada al parque temático cuesta quince euros, pero para los niños es gratis.</span> — <em>The entrance to the theme park costs fifteen euros, but for children it''s free.</em></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"No me gustan mis gastos porque gasto demasiado dinero saliendo con amigos.\">No me gustan mis gastos porque gasto demasiado dinero saliendo con amigos.</span> <span class=\"tier-h\">H</span> — <em>I don''t like my expenses because I spend too much money going out with friends.</em></p>", "check": {"question": "What does ‘gratis’ mean?", "options": ["free (no cost)", "extremely expensive", "reduced by half price", "completely sold out today"], "answer": 0, "explain": "gratis = free/no cost. The distractors describe other prices, not the absence of one."}}, {"title": "Salir a comer: eating out with friends", "html": "<p>Eating out is part of going out too. Key food nouns:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el bocadillo\">el bocadillo</span></td><td>the sandwich</td><td><span data-say=\"las patatas fritas\">las patatas fritas</span></td><td>chips</td></tr>\n              <tr><td><span data-say=\"la ensalada\">la ensalada</span></td><td>the salad</td><td><span data-say=\"el pollo\">el pollo</span></td><td>the chicken</td></tr>\n              <tr><td><span data-say=\"el arroz\">el arroz</span></td><td>the rice</td><td><span data-say=\"el huevo\">el huevo</span></td><td>the egg</td></tr>\n              <tr><td><span data-say=\"la verdura\">la verdura</span></td><td>vegetables</td><td><span data-say=\"dulce\">dulce</span></td><td>sweet</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando salimos a comer, suelo pedir un bocadillo de pollo con patatas fritas, y de postre algo dulce.\">Cuando salimos a comer, suelo pedir un bocadillo de pollo con patatas fritas, y de postre algo dulce.</span> — <em>When we go out to eat, I usually order a chicken sandwich with chips, and something sweet for dessert.</em></p>\n            <p><span data-say=\"Un plato típico español es la tortilla, hecha con huevo, patatas y a veces verdura.\">Un plato típico español es la tortilla, hecha con huevo, patatas y a veces verdura.</span> — <em>A typical Spanish dish is the tortilla, made with egg, potatoes and sometimes vegetables.</em> <span data-say=\"En algunos restaurantes puedes pedir una gran cantidad de arroz por un precio bajo.\">En algunos restaurantes puedes pedir una gran cantidad de arroz por un precio bajo.</span> <span class=\"tier-h\">H</span> — <em>In some restaurants you can order a large quantity of rice for a low price.</em></p>", "check": {"question": "What does ‘un plato típico’ mean?", "options": ["a typical dish", "an unusual foreign dish", "a plate that is very large", "a dish you must never eat"], "answer": 0, "explain": "un plato típico = a typical dish. The distractors invent meanings ‘típico’ doesn''t have."}}, {"title": "Matches, feelings and injuries", "html": "<p>More match-day language: results, feelings, and reasons things happen.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el partido\">el partido</span></td><td>the match</td><td><span data-say=\"la copa\">la copa</span></td><td>the cup/trophy</td></tr>\n              <tr><td><span data-say=\"físico\">físico</span></td><td>physical</td><td><span data-say=\"el peso\">el peso</span></td><td>the weight</td></tr>\n              <tr><td><span data-say=\"acuático\">acuático</span></td><td>aquatic (sport)</td><td><span data-say=\"la herida\">la herida</span></td><td>the injury</td></tr>\n              <tr><td><span data-say=\"duro\">duro</span></td><td>hard/tough</td><td><span data-say=\"entero\">entero</span></td><td>whole/entire</td></tr>\n              <tr><td><span data-say=\"justo\">justo</span></td><td>fair</td><td><span data-say=\"correcto\">correcto</span></td><td>correct</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Vi el partido entero en directo: fue un partido justo, pero mi jugador favorito se hizo una herida y perdió la copa.\">Vi el partido entero en directo: fue un partido justo, pero mi jugador favorito se hizo una herida y perdió la copa.</span> — <em>I watched the whole match live: it was a fair match, but my favourite player got injured and lost the cup.</em></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"El entrenamiento físico fue muy duro, y debido a la lluvia, el partido se canceló. Afortunadamente, nadie se enojó.\">El entrenamiento físico fue muy duro, y debido a la lluvia, el partido se canceló. Afortunadamente, nadie se enojó.</span> <span class=\"tier-h\">H</span> — <em>The physical training was very hard, and due to the rain, the match was cancelled. Fortunately, nobody got angry.</em> Hacer ejercicio físico ayuda a controlar el peso.</p>", "check": {"question": "What does ‘debido a la lluvia’ mean?", "options": ["due to the rain", "in spite of the rain", "instead of the rain falling", "long before the rain started"], "answer": 0, "explain": "debido a = due to/because of. The distractors reverse or misplace the cause-and-effect link."}}]}, "terms": {"enabled": true, "pairs": [{"term": "jugar al fútbol / al baloncesto / al tenis", "definition": "to play football / basketball / tennis"}, {"term": "hacer deporte", "definition": "to do sport"}, {"term": "hacer natación", "definition": "to do swimming (not jugar!)"}, {"term": "el equipo", "definition": "the team"}, {"term": "montar en bicicleta", "definition": "to cycle"}, {"term": "el tiempo libre", "definition": "free time"}, {"term": "el pasatiempo · la afición", "definition": "hobby / pastime · hobby / interest"}, {"term": "coleccionar sellos", "definition": "to collect stamps"}, {"term": "cocinar", "definition": "to cook"}, {"term": "me gusta / me gustan", "definition": "I like (+ infinitive / + plural noun)"}, {"term": "me encanta salir con amigos", "definition": "I love going out with friends"}, {"term": "quedar con", "definition": "to meet up with (someone)"}, {"term": "ir a la bolera · la fiesta", "definition": "to go bowling · the party"}, {"term": "bailar · dar un paseo", "definition": "to dance · to go for a walk"}, {"term": "ir de compras", "definition": "to go shopping"}, {"term": "a menudo · a veces · nunca", "definition": "often · sometimes · never"}, {"term": "jugué al tenis / fui al cine (H)", "definition": "I played tennis / I went to the cinema (preterite)"}, {"term": "soler + infinitive (H)", "definition": "to usually do something"}, {"term": "la cuenta · pedir la cuenta", "definition": "the bill · to ask for the bill"}, {"term": "sentarse", "definition": "to sit down"}, {"term": "el partido", "definition": "the match / game"}, {"term": "la actividad", "definition": "the activity"}, {"term": "los gastos · gastar", "definition": "expenses · to spend (money)"}, {"term": "el peso", "definition": "the weight"}, {"term": "el precio · costar", "definition": "the price · to cost"}, {"term": "físico · el ejercicio físico", "definition": "physical · physical exercise"}, {"term": "la cámara", "definition": "the camera"}, {"term": "probar", "definition": "to try"}, {"term": "el destino", "definition": "the destination"}, {"term": "la exposición", "definition": "the exhibition"}, {"term": "la copa", "definition": "the cup / trophy"}, {"term": "la herida", "definition": "the injury"}, {"term": "el euro · gratis", "definition": "the euro · free (no cost)"}, {"term": "el huevo", "definition": "the egg"}, {"term": "el arroz", "definition": "the rice"}, {"term": "charlar", "definition": "to chat"}, {"term": "el pollo", "definition": "the chicken"}, {"term": "la verdura", "definition": "vegetables"}, {"term": "acuático", "definition": "aquatic (sport)"}, {"term": "el bocadillo", "definition": "the sandwich"}, {"term": "la ensalada", "definition": "the salad"}, {"term": "la mascota", "definition": "the pet"}, {"term": "el parque temático", "definition": "the theme park"}, {"term": "las patatas fritas", "definition": "chips"}, {"term": "tomar el sol", "definition": "to sunbathe"}, {"term": "la corrida", "definition": "the bullfight"}, {"term": "dulce", "definition": "sweet"}, {"term": "la frecuencia", "definition": "frequency"}, {"term": "pasar un buen rato", "definition": "to have a good time"}, {"term": "en directo", "definition": "live (broadcast)"}, {"term": "típico", "definition": "typical"}, {"term": "afortunadamente", "definition": "fortunately"}, {"term": "enojado", "definition": "angry"}, {"term": "la cantidad", "definition": "the quantity / amount"}, {"term": "duro", "definition": "hard / tough"}, {"term": "debido a", "definition": "due to / because of"}, {"term": "entero", "definition": "whole / entire"}, {"term": "correcto", "definition": "correct"}, {"term": "aun", "definition": "even (still)"}, {"term": "justo", "definition": "fair"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Juego al fútbol los sábados.\" data-listen></span><br>Listen. What is being said?", "options": ["I play football on Saturdays", "I play football every day", "I watch football on Saturdays", "I played football last Saturday"], "answer": 0, "explain": "‘juego al fútbol los sábados’ = I play football on Saturdays. Traps swap the frequency, the verb (watch) or the tense (played)."}, {"question": "<span data-say=\"Me encanta salir con amigos los fines de semana.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["I love going out with friends at weekends", "I hate going out with friends at weekends", "I love going out with family at weekends", "I sometimes go out with friends at weekends"], "answer": 0, "explain": "‘me encanta’ = I love; ‘con amigos’ = with friends. Traps reverse the opinion, swap friends→family, or weaken encanta to ‘sometimes’."}, {"question": "<span data-say=\"Suelo jugar al tenis los domingos.\" data-listen></span><br>Listen. What is the habit?", "options": ["Usually playing tennis on Sundays", "Usually playing football on Saturdays", "Never playing tennis on Sundays", "Having played tennis last Sunday"], "answer": 0, "explain": "‘suelo jugar al tenis los domingos’ = I usually play tennis on Sundays. Traps swap sport/day, negate it, or shift it to the past."}, {"question": "How do you say ‘I play basketball’ correctly?", "options": ["Juego al baloncesto", "Juego baloncesto", "Hago al baloncesto", "Juega al baloncesto cada semana"], "answer": 0, "explain": "jugar takes ‘al’ before a ball sport: juego al baloncesto. B drops ‘al’, C swaps in hacer, D uses the wrong subject (juega = he/she, not yo)."}, {"question": "Complete: ‘Me ___ los deportes de equipo.’ (I like team sports)", "options": ["gustan", "gusta", "gustas", "gustaría"], "answer": 0, "explain": "‘los deportes’ is plural, so gustar agrees: me gustan. ‘gusta’ fails to agree; ‘gustaría’ shifts to the conditional (I would like)."}, {"question": "Which sentence means ‘I never go to parties’?", "options": ["Nunca voy a fiestas", "Voy a veces a fiestas", "Siempre voy a fiestas", "Nunca voy a fiestas los fines de semana solamente"], "answer": 0, "explain": "nunca = never. B swaps in ‘sometimes’, C reverses it to ‘always’, D adds a limiting detail (weekends only) that changes the meaning."}, {"question": "‘Fui al cine el sábado pasado’ means…", "options": ["I went to the cinema last Saturday", "I go to the cinema every Saturday", "I am going to the cinema next Saturday", "I would go to the cinema on Saturdays"], "answer": 0, "explain": "fui (preterite of ir) + el sábado pasado = I went last Saturday. The traps swap in present, future or conditional."}, {"question": "Which sentence uses ‘soler + infinitive’ correctly for a habit?", "options": ["Suelo salir los sábados por la noche", "Suelo salgo los sábados por la noche", "Soy salir los sábados por la noche", "Suelo saliendo los sábados por la noche"], "answer": 0, "explain": "soler is followed by an infinitive: suelo salir. B conjugates salir again, C uses the wrong verb (soy), D uses the gerund (saliendo)."}, {"question": "Which is correct for ‘I do (go) swimming’?", "options": ["Hago natación", "Juego a natación", "Juego al natación", "Hace natación yo"], "answer": 0, "explain": "Swimming isn’t a ‘jugar’ sport — use hacer + noun: hago natación. Adding ‘a’/‘al’ or swapping the subject are the traps."}, {"question": "What does ‘dar un paseo’ mean?", "options": ["to go for a walk", "to give a present or gift", "to pass an exam easily", "to pay for a bus ticket"], "answer": 0, "explain": "dar un paseo = to go for a walk. False-friend traps: ‘dar’ (to give) and ‘paseo’ sounding like ‘pasar’/‘pagar’."}, {"question": "<span data-say=\"Mi equipo ganó la copa después de un partido muy justo.\" data-listen></span><br>Listen. What happened?", "options": ["My team won the cup after a very fair match", "My team lost the cup after a very fair match", "My team won the cup after a very unfair match", "My team won a medal after a friendly match"], "answer": 0, "explain": "‘ganó la copa’ = won the cup; ‘un partido muy justo’ = a very fair match. Traps flip win/lose, flip fair/unfair, or swap cup→medal."}, {"question": "How do you say ‘It cost me a lot of money’?", "options": ["Me costó mucho dinero", "Me costará mucho dinero", "Me cuesta mucho dinero ayer", "Me costaba mucho dinero mañana"], "answer": 0, "explain": "‘costó’ is the preterite (a completed cost). B shifts to the future; C and D mix a present/imperfect verb with a past or future time word, which cannot go together."}, {"question": "What does ‘se hizo una herida’ mean?", "options": ["he/she got injured", "he/she felt very happy", "he/she scored a goal", "he/she won the trophy easily"], "answer": 0, "explain": "hacerse una herida = to get injured/hurt yourself. The distractors describe unrelated, positive match outcomes."}, {"question": "Which sentence means ‘I like trying new activities’?", "options": ["Me gusta probar actividades nuevas", "Me gusta probar actividades viejas", "No me gusta probar actividades nuevas", "Me gustaba probar actividades nuevas"], "answer": 0, "explain": "probar actividades nuevas = to try new activities. Traps swap new→old, add a negative, or shift into the imperfect (used to like)."}]}, "fib": {"enabled": true, "questions": [{"text": "Juego al [fútbol] con mi equipo. <span data-say=\"Juego al fútbol con mi equipo.\" data-listen>Juego al fútbol con mi equipo.</span>"}, {"text": "Mi afición es [coleccionar] sellos. (to collect)"}, {"text": "Me gusta [jugar] al baloncesto. (to play — infinitive after gustar)"}, {"text": "Normalmente [quedo] con mis amigos los sábados. (to meet up — yo form)"}, {"text": "El fin de semana pasado [jugué] al tenis. (I played — preterite)"}, {"text": "Nunca voy a [fiestas]. (parties)"}, {"text": "Suelo [salir] los sábados por la noche. (to go out — infinitive after soler) <span class=\"tier-h\">H</span>"}, {"text": "Me gusta probar una [actividad] nueva cada mes. (activity)"}, {"text": "No me gustan mis [gastos] porque gasto demasiado. (expenses)"}, {"text": "Nos gusta [charlar] en el parque después del partido. (to chat)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘jugar al fútbol’ needs the word ‘al’ before a ball sport.", "answer": true, "explain": "jugar takes a+el=al before a ball/racquet sport: jugar al fútbol."}, {"statement": "‘hacer natación’ is used because swimming is not a ‘jugar’ sport.", "answer": true, "explain": "Non-ball activities use hacer + noun: hago natación."}, {"statement": "‘Me gusta jugar’ should really be ‘Me gustan jugar’ because jugar is an activity.", "answer": false, "explain": "Before a single infinitive, gustar stays singular: me gusta jugar. ‘gustan’ is only for plural nouns."}, {"statement": "‘quedar con’ means ‘to stay at home’.", "answer": false, "explain": "quedar con = to meet up with someone; quedarse (reflexive) = to stay."}, {"statement": "Frequency words like ‘a menudo’ and ‘a veces’ can go at the start or end of a sentence.", "answer": true, "explain": "Both positions are correct in Spanish."}, {"statement": "‘Fui al cine’ is in the present tense.", "answer": false, "explain": "‘fui’ is the (irregular) preterite of ir — a completed past action."}, {"statement": "‘nunca’ means ‘sometimes’.", "answer": false, "explain": "nunca = never; a veces = sometimes."}, {"statement": "‘soler + infinitive’ describes a usual habit, and is Higher tier.", "answer": true, "explain": "soler + infinitive = to usually do something, e.g. suelo salir los sábados."}, {"statement": "‘sentarse’ means ‘to sit down’.", "answer": true, "explain": "sentarse (reflexive) = to sit down."}, {"statement": "‘la cámara’ means ‘the bedroom’.", "answer": false, "explain": "la cámara = the camera; the bedroom is el dormitorio/la habitación."}, {"statement": "‘gratis’ means the same as ‘caro’ (expensive).", "answer": false, "explain": "gratis = free (no cost); caro = expensive — opposites."}]}, "misc": {"enabled": true, "items": [{"myth": "Juego fútbol los sábados.", "truth": "Juego al fútbol los sábados.", "check": {"question": "What is missing in ‘Juego fútbol’?", "options": ["the word ‘al’ (a + el) before the sport", "an accent on the letter ó in fútbol", "the pronoun ‘yo’ written at the very start of the sentence", "the article ‘la’ before fútbol"], "answer": 0, "explain": "jugar is always followed by ‘al’ before a ball sport: juego al fútbol."}}, {"myth": "Hago fútbol todos los días.", "truth": "Juego al fútbol todos los días.", "check": {"question": "Why is ‘Hago fútbol’ wrong?", "options": ["ball sports use jugar al, not hacer", "fútbol must always be written with a capital letter", "hacer needs a written accent here", "todos los días has to come first"], "answer": 0, "explain": "‘hacer’ is for non-ball activities (hacer natación); ball sports use jugar al: juego al fútbol."}}, {"myth": "Me gustan jugar al tenis.", "truth": "Me gusta jugar al tenis.", "check": {"question": "Why is ‘Me gustan jugar’ incorrect?", "options": ["before a single infinitive, gustar always stays singular", "jugar always needs a plural verb form because ‘tenis’ ends in -s", "‘tenis’ is treated as a plural noun in Spanish", "gustar can never appear before an infinitive"], "answer": 0, "explain": "gustar/encantar + infinitive is always singular, whatever the infinitive is: me gusta jugar."}}, {"myth": "Quedo en casa todo el fin de semana. (= I meet up all weekend)", "truth": "Me quedo en casa todo el fin de semana. (= I stay home all weekend)", "check": {"question": "What is the real difference between ‘quedar con’ and ‘quedarse’?", "options": ["quedar con = to meet up; quedarse = to stay (reflexive)", "they are simply two different spellings of exactly the same verb", "quedarse can only be used in the future tense", "quedar con is only ever used with family members"], "answer": 0, "explain": "quedar con alguien = to arrange to meet someone; quedarse (reflexive) = to stay/remain."}}, {"myth": "El sábado pasado juego al tenis.", "truth": "El sábado pasado jugué al tenis.", "check": {"question": "Why is ‘juego’ wrong after ‘el sábado pasado’?", "options": ["‘el sábado pasado’ signals the past, so it needs the preterite jugué", "‘juego’ is correct in absolutely any tense you choose", "‘pasado’ must always be immediately followed by an infinitive verb", "the sentence actually needs ‘voy a’ placed in front of the verb instead"], "answer": 0, "explain": "‘el sábado pasado’ (last Saturday) is a past-time marker, so the verb must be preterite: jugué."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for frequency and habits", "html": "Listen for the frequency word AND the verb ending together: ‘suelo salir’ (habit) vs ‘salí’ (one past event) vs ‘voy a salir’ (future plan) sound different but are easy to confuse under time pressure.", "check": {"question": "You hear ‘…suelo jugar…’. What does that signal?", "options": ["a usual habit, not a single past event", "something that happened only once, yesterday", "a plan for next weekend only", "a command telling someone else to play"], "answer": 0, "explain": "soler + infinitive describes a regular habit — not a one-off past action or a command."}}, {"title": "Paper 3 — Reading: gustar/encantar agreement", "html": "When you read ‘me gustan’ vs ‘me gusta’, check what follows: a plural noun (los deportes) takes gustan; an infinitive (jugar, salir) always takes the singular gusta, however many activities you list.", "check": {"question": "‘Me gustan el fútbol y el baloncesto’ — why plural gustan?", "options": ["two nouns together are treated as a plural subject", "gustar is always plural before a noun", "fútbol on its own is a plural word", "encantar and gustar always agree with the subject pronoun ‘yo’"], "answer": 0, "explain": "Two (or more) nouns joined by ‘y’ act as a plural subject, so gustar agrees: gustan."}}, {"title": "Paper 4 — Writing: mixing tenses and soler for range", "html": "For the top band, combine a present habit, a preterite last-weekend action and an opinion with a reason: ‘Suelo jugar al fútbol los sábados. El fin de semana pasado fui a una fiesta y me encantó porque bailé mucho.’", "check": {"question": "Which answer reaches the top band?", "options": ["Suelo jugar al fútbol, pero el sábado pasado fui a una fiesta", "Me gusta el deporte y me gusta el deporte y también me gusta mucho salir", "Juego al fútbol", "Salgo"], "answer": 0, "explain": "It mixes a present habit (suelo) with a past event (fui) and links ideas — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What is Carlos''s favourite hobby? (1)<br>(b) When does he play basketball? (1)<br>(c) What did he do last weekend? (1)<br>(d) Why does he never go shopping? (1)", "marks": 4, "hint": "Find the hobby after ‘mi pasatiempo favorito es’, the timing after ‘los fines de semana’, the past action after ‘el fin de semana pasado’, and the reason after ‘porque’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> collecting stamps <em>(1)</em>.</li>\n                <li><strong>(b)</strong> at weekends (with his team) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> went to a party / danced all night (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (because) he doesn''t like it at all <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I play football with my team. <br>(b) I love going out with my friends. <br>(c) Last weekend I went to the cinema because I like films.", "marks": 5, "hint": "‘I play football’ = jugar al fútbol. ‘I love going out’ = Me encanta + infinitive. ‘Last weekend I went’ = El fin de semana pasado + preterite (fui).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Juego al fútbol con mi equipo. <em>(1)</em></li>\n                <li><strong>(b)</strong> Me encanta salir con mis amigos. <em>(1)</em></li>\n                <li><strong>(c)</strong> El fin de semana pasado <em>(1)</em> fui al cine <em>(1)</em> porque me gustan las películas <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Fui al cine’ must use the preterite, not the present.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '4-2-music-tv-film-and-reading', '4.2 Music, TV, Film and Reading', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about music?", "html": "<p>The key verb is <span data-say=\"escuchar música\">escuchar música</span> (to listen to music). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la música\">la música</span></td><td>music</td><td><span data-say=\"la canción\">la canción</span></td><td>the song</td></tr>\n              <tr><td><span data-say=\"el cantante\">el cantante / la cantante</span></td><td>the singer</td><td><span data-say=\"el grupo\">el grupo</span></td><td>the band/group</td></tr>\n              <tr><td><span data-say=\"tocar la guitarra\">tocar la guitarra</span></td><td>to play the guitar</td><td><span data-say=\"tocar el piano\">tocar el piano</span></td><td>to play the piano</td></tr>\n              <tr><td><span data-say=\"el concierto\">el concierto</span></td><td>the concert</td><td><span data-say=\"el pop, el rock, el rap\">el pop / el rock / el rap</span></td><td>pop / rock / rap</td></tr>\n            </table>\n            <p>Because <strong>gustar</strong> and <strong>encantar</strong> agree with the noun that follows, watch the plural: <span data-say=\"Me encantan las canciones de mi grupo favorito.\">Me encantan las canciones de mi grupo favorito.</span> — <em>I love the songs of my favourite band.</em> (plural canciones → encantan)</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el teclado\">el teclado</span></td><td>the keyboard</td><td><span data-say=\"el volumen\">el volumen</span></td><td>the volume</td></tr>\n              <tr><td><span data-say=\"el flamenco\">el flamenco</span></td><td>flamenco (music/dance)</td><td><span data-say=\"el tema\">el tema</span></td><td>the track/theme</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Aprendí a tocar el teclado, y mi tema favorito es distinto cada semana.\">Aprendí a tocar el teclado, y mi tema favorito es distinto cada semana.</span> — <em>I learned to play the keyboard, and my favourite track is different every week.</em> <span data-say=\"Tuve la oportunidad de subir el volumen en un concierto de flamenco.\">Tuve la oportunidad de subir el volumen en un concierto de flamenco.</span> — <em>I had the opportunity to turn up the volume at a flamenco concert.</em></p>", "check": {"question": "Why does the verb end in ‘-an’ in ‘Me encantan las canciones’?", "options": ["‘las canciones’ is plural, so the verb agrees with it", "‘encantar’ is an irregular verb that always ends in ‘-an’", "the subject of this particular sentence is ‘yo’, not ‘tú’", "it is describing a single completed action in the simple past tense"], "answer": 0, "explain": "Like gustar, encantar agrees with the noun that follows it; a plural noun (las canciones) needs the plural verb form (encantan)."}}, {"title": "How do I talk about TV programmes?", "html": "<p>The key verb is <span data-say=\"ver la tele\">ver la tele</span> (to watch TV).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la televisión\">la televisión</span></td><td>television</td><td><span data-say=\"el programa\">el programa</span></td><td>the programme</td></tr>\n              <tr><td><span data-say=\"la serie\">la serie</span></td><td>the series</td><td><span data-say=\"las noticias\">las noticias</span></td><td>the news</td></tr>\n              <tr><td><span data-say=\"los dibujos animados\">los dibujos animados</span></td><td>cartoons</td><td><span data-say=\"el actor\">el actor / la actriz</span></td><td>the actor / actress</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Veo la tele todos los días, sobre todo las series.\">Veo la tele todos los días, sobre todo las series.</span> — <em>I watch TV every day, especially series.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el documental\">el documental</span></td><td>the documentary</td><td><span data-say=\"la telenovela\">la telenovela</span></td><td>the soap opera</td></tr>\n              <tr><td><span data-say=\"la temporada\">la temporada</span></td><td>the season (of a show)</td><td><span data-say=\"un programa de belleza\">un programa de belleza</span></td><td>a beauty/makeover show</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Nunca veo telenovelas, pero vi el resto de la temporada de un documental sobre un programa de belleza.\">Nunca veo telenovelas, pero vi el resto de la temporada de un documental sobre un programa de belleza.</span> — <em>I never watch soap operas, but I watched the rest of the season of a documentary about a beauty show.</em></p>", "check": {"question": "What does ‘los dibujos animados’ mean?", "options": ["cartoons", "the news", "a drawing competition", "a documentary about animals"], "answer": 0, "explain": "los dibujos animados = cartoons/animated shows. It is not the news (las noticias) nor a documentary."}}, {"title": "How do I talk about films and give opinions?", "html": "<p>Learn the film genres and reuse the opinion + reason pattern from earlier topics.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la película\">la película</span></td><td>the film</td><td><span data-say=\"una película de terror\">una película de terror</span></td><td>a horror film</td></tr>\n              <tr><td><span data-say=\"una película de acción\">una película de acción</span></td><td>an action film</td><td><span data-say=\"una película de ciencia ficción\">una película de ciencia ficción</span></td><td>a sci-fi film</td></tr>\n              <tr><td><span data-say=\"una comedia\">una comedia</span></td><td>a comedy</td><td><span data-say=\"divertido, emocionante, aburrido, gracioso\">divertido / emocionante / aburrido / gracioso</span></td><td>fun / exciting / boring / funny</td></tr>\n            </table>\n            <p>Example with plural agreement: <span data-say=\"Me gustan las películas de acción porque son emocionantes.\">Me gustan las películas de acción porque son emocionantes.</span> — <em>I like action films because they are exciting.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"una película de aventuras\">una película de aventuras</span></td><td>an adventure film</td><td><span data-say=\"violento, romántico\">violento / romántico</span></td><td>violent / romantic</td></tr>\n              <tr><td><span data-say=\"la escena\">la escena</span></td><td>the scene</td><td><span data-say=\"la risa, reírse\">la risa · reírse</span></td><td>laughter · to laugh</td></tr>\n              <tr><td><span data-say=\"alquilar una película\">alquilar una película</span></td><td>to rent a film</td><td><span data-say=\"el comienzo\">el comienzo</span></td><td>the beginning</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Alquilamos una película de aventuras: el comienzo fue un poco violento, pero también había una escena romántica que nos hizo reírse.\">Alquilamos una película de aventuras: el comienzo fue un poco violento, pero también había una escena romántica que nos hizo reírse.</span> — <em>We rented an adventure film: the beginning was a bit violent, but there was also a romantic scene that made us laugh.</em></p>\n            <p><span data-say=\"No me gustó la risa forzada del actor — la película fue horrible.\">No me gustó la risa forzada del actor — la película fue horrible.</span> — <em>I didn''t like the actor''s forced laugh — the film was horrible.</em></p>", "check": {"question": "In ‘Me gustan las películas de acción porque son emocionantes’, why is it ‘gustan’ and not ‘gusta’?", "options": ["‘las películas de acción’ is plural", "‘acción’ is a feminine noun", "the sentence gives a reason with ‘porque’", "‘emocionante’ is an adjective, not a verb"], "answer": 0, "explain": "gustar agrees with the plural noun ‘las películas de acción’, so it must be ‘gustan’."}}, {"title": "How do I talk about reading?", "html": "<p>The key verb is <span data-say=\"leer\">leer</span> (to read).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el libro\">el libro</span></td><td>the book</td><td><span data-say=\"la novela\">la novela</span></td><td>the novel</td></tr>\n              <tr><td><span data-say=\"la revista\">la revista</span></td><td>the magazine</td><td><span data-say=\"el periódico\">el periódico</span></td><td>the newspaper</td></tr>\n            </table>\n            <p>Careful with gender: <span data-say=\"la revista\">la revista</span> is feminine, so it is always <strong>la revista</strong>, never <em>el revista</em>. Example: <span data-say=\"Cada noche, leo una novela antes de dormir.\">Cada noche, leo una novela antes de dormir.</span> — <em>Every night, I read a novel before I sleep.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el artículo\">el artículo</span></td><td>the article</td><td><span data-say=\"recomendar\">recomendar</span></td><td>to recommend</td></tr>\n              <tr><td><span data-say=\"relajante\">relajante</span></td><td>relaxing</td><td><span data-say=\"tuyo, tuya\">tuyo / tuya</span></td><td>yours</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Te recomiendo este artículo de la revista — trata un asunto muy interesante.\">Te recomiendo este artículo de la revista — trata un asunto muy interesante.</span> — <em>I recommend this magazine article to you — it deals with a very interesting subject.</em> <span data-say=\"Leer una novela es muy relajante. ¿Es tuya esta novela?\">Leer una novela es muy relajante. ¿Es tuya esta novela?</span> — <em>Reading a novel is very relaxing. Is this novel yours?</em></p>", "check": {"question": "Which article goes with ‘revista’ (magazine)?", "options": ["la revista — it is feminine", "el revista — it is masculine", "los revista — it is plural", "un revista — no article is needed"], "answer": 0, "explain": "‘revista’ is a feminine noun, so it takes ‘la’: la revista, never el revista."}}, {"title": "How do I say what I did yesterday, and talk about going online?", "html": "<p>Compare a <strong>present-tense habit</strong> with a <strong>preterite</strong> (completed past) action:</p>\n            <ul>\n              <li>habit → <span data-say=\"Veo la tele todos los días.\">Veo la tele todos los días.</span> (I watch TV every day.)</li>\n              <li>preterite → <span data-say=\"Ayer vi una película de terror con mis amigos.\">Ayer vi una película de terror con mis amigos.</span> (Yesterday I watched a horror film with my friends.)</li>\n            </ul>\n            <p>Online/downloading vocabulary:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"descargar\">descargar</span></td><td>to download</td><td><span data-say=\"en línea\">en línea</span></td><td>online</td></tr>\n              <tr><td><span data-say=\"el móvil\">el móvil</span></td><td>the mobile phone</td><td><span data-say=\"Ayer descargué una canción nueva en mi móvil.\">Ayer descargué una canción nueva en mi móvil.</span></td><td>Yesterday I downloaded a new song on my phone.</td></tr>\n            </table>\n            <p><span class=\"tier-h\">H</span> Comparing a childhood habit with now (imperfect tense): <span data-say=\"De pequeño, veías muchos dibujos animados, pero ya no veo tantos.\">De pequeño, veías muchos dibujos animados, pero ya no veo tantos.</span> <span class=\"tier-h\">H</span> — <em>As a child, you used to watch a lot of cartoons, but I don''t watch as many now.</em> (‘bajar’ is another way to say ‘to download’: <span data-say=\"bajar una canción\">bajar una canción</span>.)</p>", "check": {"question": "Which word tells you the verb must be in the preterite (past)?", "options": ["ayer (yesterday)", "todos los días (every day)", "normalmente (normally)", "siempre (always)"], "answer": 0, "explain": "‘ayer’ signals a completed action in the past, so the verb changes to the preterite (vi, not veo)."}}, {"title": "Higher: giving stronger opinions and comparing", "html": "<p><span class=\"tier-h\">H</span> Use <strong>lo que más me gusta es…</strong> (what I like most is…) to add range:</p>\n            <ul>\n              <li><span data-say=\"Lo que más me gusta es leer novelas.\">Lo que más me gusta es leer novelas.</span> <span class=\"tier-h\">H</span> — What I like most is reading novels.</li>\n            </ul>\n            <p>Use <strong>preferir + a</strong> to compare two things:</p>\n            <ul>\n              <li><span data-say=\"Prefiero la música pop a la clásica.\">Prefiero la música pop a la clásica.</span> <span class=\"tier-h\">H</span> — I prefer pop music to classical music.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"La mayoría de mis amigos prefieren el rock clásico, pero vale la pena probar otros estilos.\">La mayoría de mis amigos prefieren el rock clásico, pero vale la pena probar otros estilos.</span> <span class=\"tier-h\">H</span> — <em>Most of my friends prefer classic rock, but it''s worth trying other styles.</em></p>", "check": {"question": "What does ‘Lo que más me gusta es leer novelas’ mean?", "options": ["What I like most is reading novels", "What I like least is reading novels", "I sometimes like reading a novel", "I used to like reading novels"], "answer": 0, "explain": "‘lo que más me gusta es…’ = what I like most is…, a Higher-tier structure for a stronger opinion."}}, {"title": "How do I talk about the internet and technology?", "html": "<p>Media today is mostly online. Key words for blogs, channels and devices:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el blog\">el blog</span></td><td>the blog</td><td><span data-say=\"el canal\">el canal</span></td><td>the channel</td></tr>\n              <tr><td><span data-say=\"colgar\">colgar</span></td><td>to post/upload (online)</td><td><span data-say=\"el dispositivo\">el dispositivo</span></td><td>the device</td></tr>\n              <tr><td><span data-say=\"bienvenido\">bienvenido</span></td><td>welcome</td><td><span data-say=\"descargar, en línea\">descargar, en línea</span></td><td>to download, online</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Bienvenidos a mi canal — hoy voy a colgar un vídeo sobre mi blog de música.\">Bienvenidos a mi canal — hoy voy a colgar un vídeo sobre mi blog de música.</span> — <em>Welcome to my channel — today I''m going to post a video about my music blog.</em></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"Veo mis series favoritas en cualquier dispositivo, no solo en la tele.\">Veo mis series favoritas en cualquier dispositivo, no solo en la tele.</span> <span class=\"tier-h\">H</span> — <em>I watch my favourite series on any device, not just on the TV.</em></p>", "check": {"question": "What does ‘colgar un vídeo’ mean?", "options": ["to post/upload a video", "to delete a video completely", "to watch a video twice", "to hang a poster on the wall"], "answer": 0, "explain": "colgar (online) = to post/upload. The literal meaning ‘to hang’ is why a poster-on-the-wall trap is included, but online it means upload."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la música", "definition": "music"}, {"term": "el cantante / la cantante", "definition": "the singer"}, {"term": "la canción", "definition": "the song"}, {"term": "el grupo", "definition": "the band / group"}, {"term": "tocar la guitarra", "definition": "to play the guitar"}, {"term": "tocar el piano", "definition": "to play the piano"}, {"term": "el concierto", "definition": "the concert"}, {"term": "ver la tele", "definition": "to watch TV"}, {"term": "el programa · la serie", "definition": "the programme · the series"}, {"term": "las noticias", "definition": "the news"}, {"term": "los dibujos animados", "definition": "cartoons"}, {"term": "el actor · la actriz", "definition": "the actor · the actress"}, {"term": "una película de terror / de acción", "definition": "a horror film / an action film"}, {"term": "una comedia · de ciencia ficción", "definition": "a comedy · a sci-fi film"}, {"term": "leer · la novela", "definition": "to read · the novel"}, {"term": "la revista · el periódico", "definition": "the magazine · the newspaper"}, {"term": "descargar en línea / en el móvil", "definition": "to download online / on your phone"}, {"term": "lo que más me gusta es… (H)", "definition": "what I like most is…"}, {"term": "veías (de pequeño)", "definition": "you used to watch/see (imperfect)"}, {"term": "tanto, tantos", "definition": "so much, so many"}, {"term": "el tema", "definition": "the theme / track"}, {"term": "distinto", "definition": "different"}, {"term": "la mayoría", "definition": "the majority / most"}, {"term": "aprender", "definition": "to learn"}, {"term": "el artículo", "definition": "the article"}, {"term": "bajar (una canción)", "definition": "to download (a song)"}, {"term": "el resto", "definition": "the rest / remainder"}, {"term": "la oportunidad", "definition": "the opportunity"}, {"term": "el asunto", "definition": "the subject / matter"}, {"term": "reírse · la risa", "definition": "to laugh · laughter"}, {"term": "el blog", "definition": "the blog"}, {"term": "el comienzo", "definition": "the beginning"}, {"term": "clásico / clásica", "definition": "classic / classical"}, {"term": "la escena", "definition": "the scene"}, {"term": "recomendar", "definition": "to recommend"}, {"term": "el canal", "definition": "the channel"}, {"term": "tuyo, tuya", "definition": "yours"}, {"term": "la temporada", "definition": "the season (of a show)"}, {"term": "un programa de belleza", "definition": "a beauty / makeover show"}, {"term": "el volumen", "definition": "the volume"}, {"term": "colgar (en línea)", "definition": "to post/upload (online)"}, {"term": "una película de aventuras", "definition": "an adventure film"}, {"term": "violento", "definition": "violent"}, {"term": "el dispositivo", "definition": "the device"}, {"term": "romántico", "definition": "romantic"}, {"term": "alquilar (una película)", "definition": "to rent (a film)"}, {"term": "bienvenido", "definition": "welcome"}, {"term": "el teclado", "definition": "the keyboard"}, {"term": "el documental", "definition": "the documentary"}, {"term": "relajante", "definition": "relaxing"}, {"term": "la telenovela", "definition": "the soap opera"}, {"term": "el flamenco", "definition": "flamenco (music/dance)"}, {"term": "horrible", "definition": "horrible"}, {"term": "vale la pena", "definition": "it''s worth it"}, {"term": "nunca", "definition": "never"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Me gustan las películas de acción.\" data-listen></span><br>Listen. What does the speaker like?", "options": ["action films (more than one)", "one action film in particular", "adventure films instead", "she doesn''t like action films"], "answer": 0, "explain": "‘me gustan las películas de acción’ = I like action films (plural). The traps narrow it to one film, swap the genre, or reverse the meaning."}, {"question": "<span data-say=\"Ayer vi una película de terror.\" data-listen></span><br>Listen. What is being described?", "options": ["Yesterday I watched a horror film", "Tomorrow I will watch a horror film", "Yesterday I watched a comedy film", "I watch horror films every single day"], "answer": 0, "explain": "‘ayer vi…’ = yesterday I watched (preterite). Trap B swaps to the future, C swaps the genre, D swaps to a present-tense habit."}, {"question": "<span data-say=\"Toco la guitarra en un grupo.\" data-listen></span><br>Listen. What does the speaker do?", "options": ["Plays the guitar in a band", "Sings in a band without playing an instrument", "Listens to a band''s guitar music", "Plays the piano in a band"], "answer": 0, "explain": "‘toco la guitarra’ = I play the guitar. The traps swap the action to singing/listening, or swap the instrument to piano."}, {"question": "Which sentence correctly agrees with the plural noun?", "options": ["Me gustan las películas de acción", "Me gusta las películas de acción", "Me gusto las películas de acción", "Me gustas las películas de acción"], "answer": 0, "explain": "gustar agrees with the plural noun that follows → gustan. B fails to agree; C/D wrongly conjugate gustar for ‘I/you’ instead of the thing liked."}, {"question": "What does ‘el periódico’ mean?", "options": ["the newspaper", "a period of time", "the magazine", "the weekly TV guide"], "answer": 0, "explain": "el periódico = the newspaper. It is a false friend — it does NOT mean ‘period’ (that is ‘el período’)."}, {"question": "What does ‘la revista’ mean?", "options": ["the magazine", "a review of a film", "the newspaper", "the weekly TV schedule"], "answer": 0, "explain": "la revista = the magazine. It is not a ‘review’ (that would be ‘la reseña/crítica’) nor the newspaper (el periódico)."}, {"question": "Which sentence correctly uses the preterite of ‘ver’ (to watch/see)?", "options": ["Ayer vi una película con mis amigos", "Ayer veo una película con mis amigos", "Ayer viendo una película con mis amigos", "Ayer ver una película con mis amigos"], "answer": 0, "explain": "‘ayer’ needs the preterite: vi. B is present tense, C is a gerund, D is the infinitive — none fit after ‘ayer’."}, {"question": "Which is the grammatically correct article for ‘serie’ (series)?", "options": ["una serie interesante", "un serie interesante", "unos serie interesante", "uno serie interesante"], "answer": 0, "explain": "‘serie’ is feminine, so it takes ‘una’: una serie. The others wrongly use masculine or plural forms."}, {"question": "<span data-say=\"Prefiero la música pop a la clásica.\">Prefiero la música pop a la clásica.</span> <span class=\"tier-h\">H</span> — what does this mean?", "options": ["I prefer pop music to classical music", "I prefer classical music to pop music", "I only like classical music", "I don''t like any type of music"], "answer": 0, "explain": "preferir X a Y = to prefer X to Y, so pop is preferred over classical. B reverses the comparison."}, {"question": "<span data-say=\"Lo que más me gusta es leer novelas.\">Lo que más me gusta es leer novelas.</span> <span class=\"tier-h\">H</span> — what does this mean?", "options": ["What I like most is reading novels", "What I like least is reading novels", "I sometimes like reading a novel", "I used to like reading novels, but not anymore"], "answer": 0, "explain": "‘lo que más me gusta es…’ = what I like most is…, a Higher-tier opinion structure."}, {"question": "Which sentence uses the imperfect tense correctly for ‘you used to watch cartoons’?", "options": ["Veías dibujos animados", "Ves dibujos animados", "Viste dibujos animados", "Verás dibujos animados"], "answer": 0, "explain": "‘veías’ is the imperfect (tú form) — a repeated past habit. B is present, C is preterite (a single past event), D is future."}, {"question": "What does ‘mi tema favorito del álbum’ mean?", "options": ["my favourite track on the album", "my favourite singer on the album", "my least favourite track on the album", "my favourite album from last year"], "answer": 0, "explain": "‘el tema’ here means the track/song. Traps swap track→singer, add ‘least’, or swap track→album."}]}, "fib": {"enabled": true, "questions": [{"text": "Me [encanta] mucho la música pop. <span data-say=\"Me encanta mucho la música pop.\" data-listen>Me encanta mucho la música pop.</span>"}, {"text": "Me [gustan] las películas de acción porque son emocionantes. (plural gustar)"}, {"text": "Ayer [vi] una película de terror con mis amigos. (preterite of ver)"}, {"text": "Toco la [guitarra] en un grupo de música. (guitar)"}, {"text": "Cada noche, [leo] una novela antes de dormir. <span data-say=\"Cada noche, leo una novela antes de dormir.\" data-listen>Cada noche, leo una novela antes de dormir.</span>"}, {"text": "Se debe [leer] más para mejorar el vocabulario. (to read)"}, {"text": "Ayer [descargué] una canción nueva en mi móvil. <span data-say=\"Ayer descargué una canción nueva en mi móvil.\" data-listen>Ayer descargué una canción nueva en mi móvil.</span>"}, {"text": "[Nunca] veo telenovelas, prefiero los documentales. (never)"}, {"text": "Cada cantante tiene un estilo [distinto]. (different)"}, {"text": "Vi el [resto] de la temporada en un fin de semana. (the rest)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘Me gustan las películas de acción’ uses the plural verb because ‘películas’ is plural.", "answer": true, "explain": "gustar/encantar agree with the noun that follows — plural noun, plural verb."}, {"statement": "‘la revista’ means ‘the newspaper’.", "answer": false, "explain": "la revista = the magazine; the newspaper is el periódico."}, {"statement": "‘Vi’ is the preterite (past) form of ‘ver’ (to watch/see).", "answer": true, "explain": "ver → vi (preterite, I watched/saw)."}, {"statement": "‘los dibujos animados’ means ‘the news’.", "answer": false, "explain": "los dibujos animados = cartoons; the news is las noticias."}, {"statement": "To say you play an instrument, you use ‘tocar’ + the instrument, e.g. ‘toco la guitarra’.", "answer": true, "explain": "tocar la guitarra / el piano = to play the guitar / piano."}, {"statement": "‘una comedia’ is a type of book, not a type of film.", "answer": false, "explain": "una comedia = a comedy FILM (a genre, like terror or acción)."}, {"statement": "‘Lo que más me gusta es…’ is a Higher-tier structure meaning ‘What I like most is…’.", "answer": true, "explain": "Correct — it is used to give a stronger, more developed opinion."}, {"statement": "‘Prefiero la música pop a la clásica’ means ‘I prefer classical music to pop music’.", "answer": false, "explain": "preferir X a Y = prefer X TO Y — here pop is preferred over classical, the opposite of the statement."}, {"statement": "‘la mayoría’ means ‘the majority/most’.", "answer": true, "explain": "la mayoría = the majority/most (of something)."}, {"statement": "‘aprender’ means ‘to teach’.", "answer": false, "explain": "aprender = to learn; to teach is enseñar."}, {"statement": "‘un artículo’ can mean a magazine or newspaper article.", "answer": true, "explain": "un artículo = an article (in a magazine, blog or newspaper)."}]}, "misc": {"enabled": true, "items": [{"myth": "Me gusta las películas de acción.", "truth": "Me gustan las películas de acción.", "check": {"question": "Why is ‘Me gusta las películas de acción’ wrong?", "options": ["‘películas’ is plural, so it must be ‘gustan’", "the verb ‘gustar’ never changes its form no matter what follows it", "‘acción’ needs a written accent added", "the pronoun should be ‘te’ rather than ‘me’"], "answer": 0, "explain": "gustar agrees with the plural noun that follows; plural noun → gustan."}}, {"myth": "Leo el revista todos los meses.", "truth": "Leo la revista todos los meses.", "check": {"question": "Why is ‘el revista’ wrong?", "options": ["‘revista’ is a feminine noun, so it needs ‘la’", "‘revista’ is actually a plural noun, so it should take ‘los’ instead", "‘revista’ never takes an article", "‘el’ is only used for people, not objects"], "answer": 0, "explain": "revista is feminine → la revista, never el revista."}}, {"myth": "Ayer veo una película con mi familia.", "truth": "Ayer vi una película con mi familia.", "check": {"question": "Why is ‘Ayer veo…’ wrong?", "options": ["‘ayer’ signals the past, so the verb must be preterite ‘vi’", "‘veo’ is spelt incorrectly and should be ‘veio’", "‘película’ needs a plural verb", "‘ayer’ can only ever be used together with ‘ir a’ + infinitive"], "answer": 0, "explain": "‘ayer’ (yesterday) needs a completed past action: vi, not the present veo."}}, {"myth": "Me gusta mucho los dibujos animados.", "truth": "Me gustan mucho los dibujos animados.", "check": {"question": "Why must it be ‘gustan’ here?", "options": ["‘los dibujos animados’ is plural", "‘dibujos’ is a feminine noun", "‘mucho’ forces the singular form", "cartoons are always described with ‘es’"], "answer": 0, "explain": "los dibujos animados is plural, so gustar agrees: gustan, not gusta."}}, {"myth": "El periódico significa ‘el período de tiempo’.", "truth": "El periódico significa ‘el diario / the newspaper’.", "check": {"question": "What does ‘el periódico’ actually mean?", "options": ["the newspaper", "a period of time, as you might guess", "a magazine published every week", "a school timetable"], "answer": 0, "explain": "Classic false friend: periódico = newspaper, NOT ‘period’ (that word is período)."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Media sentences reuse chunks you know: ‘me gustan…’, ‘ayer vi…’, ‘toco la guitarra…’. Listen for whether the noun is singular or plural — it changes ‘gusta’ to ‘gustan’ — and whether the verb is present or preterite.", "check": {"question": "You hear ‘…gustan…’ instead of ‘…gusta…’. What does that tell you?", "options": ["the thing being liked is plural", "the sentence is definitely about the past", "the speaker dislikes the thing", "the sentence is a question"], "answer": 0, "explain": "The -n ending of ‘gustan’ signals a plural noun (las películas, las canciones…)."}}, {"title": "Paper 3 — Translation into English", "html": "Watch the false friends: ‘periódico’ = newspaper (not ‘period’), ‘revista’ = magazine (not ‘review’). Keep ‘me gustan las películas de acción’ natural: ‘I like action films’, not ‘to me they like the films of action’.", "check": {"question": "‘Prefiero leer una novela a ver la tele’ =", "options": ["I prefer reading a novel to watching TV", "I prefer watching TV to reading a novel", "I never read novels, only watch TV", "I used to prefer watching TV"], "answer": 0, "explain": "preferir X a Y = prefer X to Y; here reading a novel is preferred over watching TV."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine an activity, an opinion and a reason: ‘Me gustan las películas de acción porque son emocionantes.’ At Higher, add a comparison and a stronger opinion structure: ‘Prefiero…a…’, ‘Lo que más me gusta es…’.", "check": {"question": "Which answer reaches the top band?", "options": ["Me encantan las películas de ciencia ficción porque son emocionantes, pero lo que más me gusta es leer novelas", "Me gustan las películas, las series, los libros y las canciones, pero nunca digo las razones por las que de verdad me gustan", "Veo la tele y leo un libro y veo la tele otra vez sin parar nunca", "Me gusta"], "answer": 0, "explain": "It links an opinion, a reason, and a Higher-tier structure (lo que más me gusta) — range and accuracy, not just a long list with no reasons."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) Name <strong>one</strong> instrument Carlos plays. (1)<br>(b) Which type of film does he prefer, and why? (1)<br>(c) What did he do yesterday? (1)<br>(d) What does he do most nights before he sleeps? (1)", "marks": 4, "hint": "Find the instrument after ‘toco’, the preference after ‘prefiero’, the past action after ‘ayer’, and the habit after ‘leo’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> the guitar <em>(1)</em>.</li>\n                <li><strong>(b)</strong> sci-fi films, because they are more exciting <em>(1)</em>.</li>\n                <li><strong>(c)</strong> watched a comedy with his sister (and it was very funny) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> reads a novel (almost every night before he sleeps) <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I like watching series. <br>(b) One must read more. <br>(c) Yesterday I downloaded a song because it is very good.", "marks": 5, "hint": "‘I like watching series’ = Me gusta ver series. ‘One must read more’ = Se debe leer más. ‘Yesterday I downloaded’ = Ayer descargué…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me gusta ver series. <em>(1)</em></li>\n                <li><strong>(b)</strong> Se debe leer más. <em>(1)</em></li>\n                <li><strong>(c)</strong> Ayer descargué una canción <em>(1)</em> porque <em>(1)</em> es muy buena <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Ayer descargué’ must use the preterite ‘descargué’, not the present.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '5-1-food-customs-and-daily-life', '5.1 Food Customs and Daily Life', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about mealtimes?", "html": "<p>Spanish families usually eat three main meals, plus a light snack in the afternoon. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el desayuno\">el desayuno</span></td><td>breakfast</td><td><span data-say=\"la comida\">la comida</span></td><td>lunch</td></tr>\n              <tr><td><span data-say=\"la merienda\">la merienda</span></td><td>afternoon snack</td><td><span data-say=\"la cena\">la cena</span></td><td>dinner</td></tr>\n              <tr><td><span data-say=\"desayunar\">desayunar</span></td><td>to have breakfast</td><td><span data-say=\"cenar\">cenar</span></td><td>to have dinner</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En España, se cena muy tarde, normalmente a las diez de la noche.\">En España, se cena muy tarde, normalmente a las diez de la noche.</span> — <em>In Spain, people have dinner very late, usually at ten at night.</em></p>\n            <p><span class=\"tier-h\">H</span> It is also a <span data-say=\"costumbre\">costumbre</span> (custom) in many Spanish homes to <span data-say=\"recibir a los invitados con mucha comida\">recibir a los invitados con mucha comida</span> — to welcome guests with lots of food. <span data-say=\"Por otra parte, en el Reino Unido no es tan común recibir a los invitados con una comida tan grande.\">Por otra parte, en el Reino Unido no es tan común recibir a los invitados con una comida tan grande.</span> — <em>On the other hand, in the UK it isn''t as common to welcome guests with such a big meal.</em></p>", "check": {"question": "What is ‘la merienda’?", "options": ["a light snack eaten in the afternoon", "the main hot meal of the day", "a big hot meal that is eaten very late at night", "a small coffee before breakfast"], "answer": 0, "explain": "la merienda = a light afternoon snack, eaten between la comida and la cena."}}, {"title": "What is typical Spanish food?", "html": "<p>Some dishes come up again and again in reading and listening exams:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la tortilla de patatas\">la tortilla de patatas</span></td><td>Spanish omelette</td><td><span data-say=\"la paella\">la paella</span></td><td>paella (rice dish)</td></tr>\n              <tr><td><span data-say=\"las tapas\">las tapas</span></td><td>small shared dishes</td><td><span data-say=\"el gazpacho\">el gazpacho</span></td><td>cold tomato soup</td></tr>\n              <tr><td><span data-say=\"el jamón\">el jamón</span></td><td>ham</td><td><span data-say=\"el pan\">el pan</span></td><td>bread</td></tr>\n            </table>\n            <p><span data-say=\"el aceite de oliva\">el aceite de oliva</span> (olive oil) is used in almost everything. Model sentence: <span data-say=\"Me gusta mucho la tortilla porque es muy rica.\">Me gusta mucho la tortilla porque es muy rica.</span> — <em>I really like the omelette because it is very tasty.</em></p>\n            <p>At a Spanish market you will see <span data-say=\"puestos\">puestos</span> (stalls) selling fresh <span data-say=\"uvas\">uvas</span> (grapes) and <span data-say=\"caramelos\">caramelos</span> (sweets) for the children. Many adults drink <span data-say=\"vino\">vino</span> (wine) with a meal, though it is <span data-say=\"cierto\">cierto</span> (true/certain) that eating too much fatty food is a <span data-say=\"riesgo\">riesgo</span> (risk) for your health. <span data-say=\"En el mercado hay puestos que venden uvas, y es cierto que el vino es típico en las comidas, pero comer demasiada grasa es un riesgo para la salud.\">En el mercado hay puestos que venden uvas, y es cierto que el vino es típico en las comidas, pero comer demasiada grasa es un riesgo para la salud.</span> — <em>At the market there are stalls that sell grapes, and it''s true that wine is typical at meals, but eating too much fat is a risk to your health.</em></p>", "check": {"question": "‘El gazpacho’ is best described as…", "options": ["a cold tomato soup", "a hot meat stew served in winter", "a type of sweet dessert pastry", "a hot spicy rice dish with chicken"], "answer": 0, "explain": "el gazpacho = a cold tomato soup, typically eaten in summer. Students often wrongly assume all soup is hot."}}, {"title": "How do I describe my daily routine?", "html": "<p>Routine verbs are <strong>reflexive</strong> — the action is done to yourself, so they need <strong>me / te / se</strong>.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"levantarse\">levantarse</span> → <span data-say=\"me levanto\">me levanto</span></td><td>to get up → I get up</td></tr>\n              <tr><td><span data-say=\"ducharse\">ducharse</span> → <span data-say=\"me ducho\">me ducho</span></td><td>to shower → I shower</td></tr>\n              <tr><td><span data-say=\"vestirse\">vestirse</span> → <span data-say=\"me visto\">me visto</span></td><td>to get dressed → I get dressed</td></tr>\n              <tr><td><span data-say=\"acostarse\">acostarse</span> → <span data-say=\"me acuesto\">me acuesto</span></td><td>to go to bed → I go to bed</td></tr>\n            </table>\n            <p>After breakfast: <span data-say=\"voy al instituto\">voy al instituto</span> (I go to school); after school: <span data-say=\"vuelvo a casa\">vuelvo a casa</span> (I return home). Many Spaniards also have <span data-say=\"la siesta\">la siesta</span> — a short afternoon rest.</p>\n            <p>Model sentence: <span data-say=\"Todos los días me levanto, me ducho y desayuno antes de ir al instituto.\">Todos los días me levanto, me ducho y desayuno antes de ir al instituto.</span></p>\n            <p>Not everyone drives — many students <span data-say=\"caminan\">caminan</span> (walk) to school: <span data-say=\"voy caminando por el mismo camino todos los días\">voy caminando por el mismo camino todos los días</span> — I walk along the same route every day. At home, food is often cooked <span data-say=\"a fuego lento\">a fuego lento</span> (on a low flame), and after lunch, <span data-say=\"incluso\">incluso</span> (even) grandparents rest <span data-say=\"a la sombra\">a la sombra</span> (in the shade) during the siesta.</p>", "check": {"question": "Why does ‘levantarse’ become ‘me levanto’ for ‘I get up’?", "options": ["it is reflexive, so it needs a pronoun (me/te/se)", "all -arse verbs drop the final -o in the present tense", "‘levanto’ on its own already means ‘I get up’", "the pronoun ‘me’ is only used with irregular verbs"], "answer": 0, "explain": "Reflexive verbs take a matching pronoun: (yo) me levanto, (tú) te levantas, (él/ella) se levanta."}}, {"title": "How do I sequence my day with time phrases?", "html": "<p>Use clock times and sequencing words to build a full routine paragraph.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"por la mañana\">por la mañana</span></td><td>in the morning</td><td><span data-say=\"por la tarde\">por la tarde</span></td><td>in the afternoon</td></tr>\n              <tr><td><span data-say=\"por la noche\">por la noche</span></td><td>at night</td><td><span data-say=\"todos los días\">todos los días</span></td><td>every day</td></tr>\n              <tr><td><span data-say=\"primero\">primero</span></td><td>first</td><td><span data-say=\"luego\">luego</span></td><td>then</td></tr>\n              <tr><td><span data-say=\"después\">después</span></td><td>afterwards</td><td><span data-say=\"normalmente\">normalmente</span></td><td>normally</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Normalmente me levanto a las siete, luego desayuno y después voy al instituto.\">Normalmente me levanto a las siete, luego desayuno y después voy al instituto.</span></p>", "check": {"question": "Which word means ‘afterwards / after that’?", "options": ["después", "primero", "normalmente", "todos los días"], "answer": 0, "explain": "después = afterwards; primero = first; normalmente = normally; todos los días = every day."}}, {"title": "How do Spanish and British customs compare?", "html": "<p>Use the <strong>impersonal se</strong> to describe what ‘people’ or ‘one’ generally does — perfect for comparing countries.</p>\n            <ul>\n              <li><span data-say=\"en España se cena tarde\">en España se cena tarde</span> — in Spain, people have dinner late</li>\n              <li><span data-say=\"en el Reino Unido se cena más temprano\">en el Reino Unido se cena más temprano</span> — in the UK, people have dinner earlier</li>\n            </ul>\n            <p>Compare with <span data-say=\"diferente\">diferente</span> (different) and <span data-say=\"parecido\">parecido</span> (similar): <span data-say=\"En mi opinión, las costumbres son bastante diferentes.\">En mi opinión, las costumbres son bastante diferentes.</span></p>\n            <p><span class=\"tier-h\">H</span> When you compare customs, add real opinion language: <span data-say=\"Tengo mucho interés en las costumbres españolas.\">Tengo mucho interés en las costumbres españolas.</span> (I have a lot of interest in Spanish customs), and <span data-say=\"en realidad\">en realidad</span> (in reality/actually), the <span data-say=\"organización\">organización</span> (organisation) of a Spanish day is quite different — <span data-say=\"conocimiento\">conocimiento</span> (knowledge) of these differences helps in the exam. From my <span data-say=\"punto de vista\">punto de vista</span> (point of view), the <span data-say=\"habitantes\">habitantes</span> (inhabitants) of a small town near the <span data-say=\"puerto\">puerto</span> (port) often keep older customs, and there is a real <span data-say=\"posibilidad\">posibilidad</span> (possibility) they still eat later than in the UK. <span data-say=\"¡Ojalá! pudiera probarlo yo mismo algún día.\">¡Ojalá! pudiera probarlo yo mismo algún día.</span> (I wish / hopefully I could try it myself one day!)</p>", "check": {"question": "What does ‘se cena’ mean in ‘en España se cena tarde’?", "options": ["people (in general) have dinner", "she personally is having dinner right now", "you must have dinner immediately", "dinner has already finished"], "answer": 0, "explain": "The impersonal se + verb describes what people in general do — se cena = people have dinner / one has dinner."}}, {"title": "Higher: a fuller routine and past habits", "html": "<p><span class=\"tier-h\">H</span> For the top band, link several reflexive actions in order and add an opinion:</p>\n            <p><span data-say=\"Después de desayunar, me visto rápidamente y salgo de casa a las ocho.\">Después de desayunar, me visto rápidamente y salgo de casa a las ocho.</span> <span class=\"tier-h\">H</span></p>\n            <p>To describe a <strong>past habit</strong> (what you used to do), use the <strong>imperfect tense</strong>: <span data-say=\"de pequeño\">de pequeño</span> (as a child) + <span data-say=\"me acostaba temprano\">me acostaba temprano</span> (I used to go to bed early).</p>\n            <p>Example: <span data-say=\"De pequeño, me acostaba muy temprano, pero ahora me acuesto mucho más tarde.\">De pequeño, me acostaba muy temprano, pero ahora me acuesto mucho más tarde.</span> <span class=\"tier-h\">H</span> — <em>As a child, I used to go to bed very early, but now I go to bed much later.</em></p>\n            <p><span class=\"tier-h\">H</span> More imperfect-tense practice: <span data-say=\"De pequeño tenía un caballo y otros animales en el pueblo de mis abuelos.\">De pequeño tenía un caballo y otros animales en el pueblo de mis abuelos.</span> <span class=\"tier-h\">H</span> — <em>As a child I had a horse and other animals in my grandparents'' village.</em> <span data-say=\"También me interesaba mucho la lengua y la literatura españolas.\">También me interesaba mucho la lengua y la literatura españolas.</span> <span class=\"tier-h\">H</span> — <em>I was also very interested in the Spanish language and literature.</em></p>", "check": {"question": "What tense is ‘me acostaba’ in ‘de pequeño me acostaba temprano’?", "options": ["the imperfect tense, for a past habit", "the present tense, for something happening now", "the near future, for an upcoming plan", "a direct command telling someone what to do"], "answer": 0, "explain": "‘de pequeño’ signals a repeated past habit, so the imperfect (me acostaba) is used, not the present (me acuesto)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "el desayuno", "definition": "breakfast"}, {"term": "la comida", "definition": "lunch"}, {"term": "la merienda", "definition": "afternoon snack"}, {"term": "la cena", "definition": "dinner"}, {"term": "desayunar · cenar", "definition": "to have breakfast · to have dinner"}, {"term": "la tortilla de patatas", "definition": "Spanish omelette"}, {"term": "la paella", "definition": "paella (rice dish)"}, {"term": "las tapas", "definition": "small shared dishes"}, {"term": "el gazpacho", "definition": "cold tomato soup"}, {"term": "el aceite de oliva", "definition": "olive oil"}, {"term": "levantarse → me levanto", "definition": "to get up → I get up"}, {"term": "ducharse → me ducho", "definition": "to shower → I shower"}, {"term": "acostarse → me acuesto", "definition": "to go to bed → I go to bed"}, {"term": "la siesta", "definition": "afternoon rest"}, {"term": "por la mañana / tarde / noche", "definition": "in the morning / afternoon / at night"}, {"term": "se cena / se come (H)", "definition": "people have dinner / lunch (impersonal se)"}, {"term": "de pequeño (H)", "definition": "as a child"}, {"term": "me acostaba (H)", "definition": "I used to go to bed (imperfect)"}, {"term": "recibir", "definition": "to receive / to welcome"}, {"term": "el animal", "definition": "the animal"}, {"term": "el camino", "definition": "the path / the way"}, {"term": "el interés", "definition": "the interest"}, {"term": "la vista", "definition": "the view / the sight"}, {"term": "caminar", "definition": "to walk"}, {"term": "la lengua", "definition": "the tongue / the language"}, {"term": "la literatura", "definition": "literature"}, {"term": "la sombra", "definition": "the shade / the shadow"}, {"term": "el riesgo", "definition": "the risk"}, {"term": "el fuego", "definition": "the fire"}, {"term": "el caballo", "definition": "the horse"}, {"term": "la costumbre", "definition": "the custom / the habit"}, {"term": "el puesto", "definition": "the market stall"}, {"term": "el puerto", "definition": "the port"}, {"term": "el habitante", "definition": "the inhabitant"}, {"term": "el vino", "definition": "the wine"}, {"term": "el caramelo", "definition": "the sweet / the candy"}, {"term": "la uva", "definition": "the grape"}, {"term": "parte (por otra parte)", "definition": "part (on the other hand)"}, {"term": "cierto", "definition": "true / certain"}, {"term": "la realidad (en realidad)", "definition": "reality (actually / in fact)"}, {"term": "incluso", "definition": "even (adverb)"}, {"term": "¡Ojalá!", "definition": "I wish! / Hopefully!"}, {"term": "la posibilidad", "definition": "the possibility"}, {"term": "la organización", "definition": "the organisation"}, {"term": "el conocimiento", "definition": "the knowledge"}, {"term": "la medida", "definition": "the measure / the measurement"}, {"term": "común", "definition": "common"}, {"term": "oscuro", "definition": "dark"}, {"term": "máximo", "definition": "maximum"}, {"term": "junio", "definition": "June"}, {"term": "encima", "definition": "on top / above"}, {"term": "la juventud", "definition": "youth"}, {"term": "exacto", "definition": "exact"}, {"term": "vacío", "definition": "empty"}, {"term": "suave", "definition": "soft / smooth / mild"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Desayuno a las siete y media.\" data-listen></span><br>Listen. What time is breakfast?", "options": ["Half past seven", "Seven o''clock exactly", "Half past eight", "A quarter past seven"], "answer": 0, "explain": "‘a las siete y media’ = at half past seven. The traps swap the hour or the minutes."}, {"question": "<span data-say=\"Nos levantamos muy temprano los lunes.\" data-listen></span><br>Listen. What happens on Mondays?", "options": ["We get up very early", "We go to bed very early", "We get up quite late", "They get up very early"], "answer": 0, "explain": "‘nos levantamos temprano’ = we get up early. B swaps the reflexive verb; C reverses ‘temprano’; D changes the subject."}, {"question": "What does ‘la merienda’ mean?", "options": ["a light snack in the afternoon", "the biggest meal of the whole day", "a formal three-course dinner", "a hot drink taken before bedtime"], "answer": 0, "explain": "la merienda = a light afternoon snack, between comida and cena."}, {"question": "Which food is ‘el aceite de oliva’?", "options": ["olive oil", "cold tomato soup", "cured ham on bread", "a rice dish with seafood"], "answer": 0, "explain": "el aceite de oliva = olive oil, used in almost every Spanish dish."}, {"question": "Complete: ‘Todos los días (yo) ___ a las siete.’", "options": ["me levanto", "levanto", "se levanta", "levantarse"], "answer": 0, "explain": "‘yo’ needs the reflexive pronoun ‘me’: me levanto. B drops the pronoun, C is ‘he/she’, D is the infinitive."}, {"question": "What does the impersonal ‘se’ mean in ‘en España se cena tarde’?", "options": ["people in general have dinner", "she is having dinner by herself", "you personally must eat now", "dinner was cancelled today"], "answer": 0, "explain": "Impersonal se describes what people generally do: se cena = people have dinner. It is not the reflexive ‘herself’."}, {"question": "Which sentence correctly uses a reflexive verb?", "options": ["Me acuesto a las diez", "Acuesto a las diez cada noche", "Yo acuesto muy tarde siempre", "Se acuesto a las diez"], "answer": 0, "explain": "acostarse is reflexive: (yo) me acuesto. B drops ‘me’, C/D use the wrong pronoun form."}, {"question": "‘El gazpacho’ often surprises students because…", "options": ["it is a soup that is served cold", "it is actually a type of sweet dessert", "it contains no vegetables at all", "it is only ever eaten at breakfast"], "answer": 0, "explain": "gazpacho is a cold tomato soup — students often assume soup must be hot."}, {"question": "Which word means ‘first’, used to start a routine paragraph?", "options": ["primero", "después", "normalmente", "todos los días"], "answer": 0, "explain": "primero = first; después = afterwards; normalmente = normally; todos los días = every day."}, {"question": "‘De pequeño, me acostaba temprano’ describes…", "options": ["a habit from the past, using the imperfect tense", "something that is happening right at this very moment", "a plan for tomorrow, using the near future", "an instruction telling someone what to do"], "answer": 0, "explain": "‘de pequeño’ + the imperfect (me acostaba) describes a repeated childhood habit."}, {"question": "What does ‘recibir a los invitados’ mean?", "options": ["to welcome/receive the guests", "to say goodbye to the guests", "to invite guests for next year", "to cook a meal for one person"], "answer": 0, "explain": "recibir = to welcome/receive; the traps confuse it with saying goodbye, inviting, or an unrelated action."}, {"question": "What does ‘el riesgo’ mean?", "options": ["the risk", "the advice", "the landscape", "the building"], "answer": 0, "explain": "el riesgo = the risk. The distractors are other common nouns students may confuse it with."}]}, "fib": {"enabled": true, "questions": [{"text": "Me [levanto] a las siete. <span data-say=\"Me levanto a las siete.\" data-listen>Me levanto a las siete.</span>"}, {"text": "En España, se [cena] muy tarde, normalmente a las diez. <span data-say=\"En España, se cena muy tarde, normalmente a las diez.\" data-listen>En España, se cena muy tarde, normalmente a las diez.</span>"}, {"text": "El gazpacho es una sopa de tomate que se come [fría]. (cold)"}, {"text": "Todos los días me ducho y [desayuno] antes de ir al instituto. (I have breakfast)"}, {"text": "[Después] del instituto, hago los deberes y ceno con mi familia. (afterwards)"}, {"text": "De pequeño, me [acostaba] muy temprano, pero ahora me acuesto más tarde. (used to go to bed)"}, {"text": "Muchas familias españolas comen [jamón] con pan y aceite de oliva. (ham)"}, {"text": "En el mercado hay [puestos] que venden fruta fresca. (market stalls)"}, {"text": "Muchos españoles beben [vino] con la comida. (wine)"}, {"text": "De pequeño, mi abuelo tenía un [caballo] en el pueblo. (horse)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘La merienda’ is a light snack eaten in the afternoon.", "answer": true, "explain": "Correct — la merienda comes between la comida and la cena."}, {"statement": "In Spain, ‘la cena’ usually happens earlier than in the UK.", "answer": false, "explain": "The opposite is true — Spanish dinner (la cena) is usually much later, often around ten."}, {"statement": "‘El gazpacho’ is normally served hot.", "answer": false, "explain": "Gazpacho is a cold tomato soup, typically eaten in summer."}, {"statement": "‘Levantarse’ is a reflexive verb, so ‘I get up’ is ‘me levanto’.", "answer": true, "explain": "Reflexive: me levanto, te levantas, se levanta."}, {"statement": "The impersonal ‘se’ (as in ‘se cena tarde’) describes what people in general do.", "answer": true, "explain": "se cena tarde = people (in general) have dinner late."}, {"statement": "‘Por la mañana’ means ‘at night’.", "answer": false, "explain": "por la mañana = in the morning; por la noche = at night."}, {"statement": "‘De pequeño me acostaba temprano’ uses the imperfect tense for a past habit.", "answer": true, "explain": "de pequeño signals a repeated past habit → the imperfect (me acostaba)."}, {"statement": "‘El aceite de oliva’ means ‘orange juice’.", "answer": false, "explain": "el aceite de oliva = olive oil. Orange juice is el zumo de naranja."}, {"statement": "‘La costumbre’ means ‘the custom’ or ‘the habit’.", "answer": true, "explain": "la costumbre = the custom/habit — a key word for this whole topic."}, {"statement": "‘El puesto’ can mean a stall at a market.", "answer": true, "explain": "el puesto = the stall (as well as ‘the position/job’ in other contexts)."}, {"statement": "‘Caminar’ means ‘to drive a car’.", "answer": false, "explain": "caminar = to walk. To drive is conducir."}]}, "misc": {"enabled": true, "items": [{"myth": "Levanto a las siete.", "truth": "Me levanto a las siete.", "check": {"question": "What is missing from ‘Levanto a las siete’?", "options": ["the reflexive pronoun ‘me’ (me levanto)", "an accent on the word ‘siete’", "the definite article ‘la’ before the word ‘siete’", "the word ‘hay’ at the start"], "answer": 0, "explain": "levantarse is reflexive; you must include me/te/se — me levanto."}}, {"myth": "En España se cena temprano.", "truth": "En España se cena tarde.", "check": {"question": "Why is ‘se cena temprano’ wrong for Spain?", "options": ["Spanish dinner is usually late, not early", "‘temprano’ is not a real Spanish word", "‘cena’ should be ‘cenar’ in this sentence", "the impersonal se cannot be used with cenar"], "answer": 0, "explain": "Spanish dinner customs are usually much later than in the UK — se cena tarde, not temprano."}}, {"myth": "El gazpacho se come caliente.", "truth": "El gazpacho se come frío.", "check": {"question": "What mistake is in ‘El gazpacho se come caliente’?", "options": ["gazpacho is a soup eaten cold, not hot", "‘caliente’ is spelt incorrectly", "gazpacho is a drink, not a food", "the verb ‘comer’ cannot be used with soup"], "answer": 0, "explain": "Gazpacho is famously served cold — caliente (hot) is the opposite of the truth."}}, {"myth": "Me acuesto temprano cada noche, sin excepción, siempre a la misma hora exacta.", "truth": "Me acuesto temprano.", "check": {"question": "What is the real problem with the ‘wrong’ version here?", "options": ["it is unnecessarily long and repeats the same idea three times", "it uses the wrong reflexive pronoun for the subject of the sentence", "‘temprano’ should be replaced with ‘tarde’", "it is missing the verb completely"], "answer": 0, "explain": "The grammar is fine, but padding a sentence with repeated ideas does not add marks — clear, accurate Spanish does."}}, {"myth": "La merienda es la comida principal del día.", "truth": "La comida es la comida principal del día.", "check": {"question": "Why is calling ‘la merienda’ the main meal wrong?", "options": ["la merienda is only a light afternoon snack", "‘merienda’ actually means breakfast, not a snack", "Spanish people never eat a main meal at midday", "‘principal’ is the wrong word for ‘main’"], "answer": 0, "explain": "la merienda is a light snack — la comida (lunch) is the main hot meal of the day in Spain."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Mealtime and routine sentences reuse chunks you know: ‘me levanto…’, ‘se cena…’, ‘desayuno a las…’. Listen carefully for the clock time and for whether the verb has a reflexive pronoun (me/se) or not.", "check": {"question": "You hear ‘se cena a las diez’. What should you write down?", "options": ["se cena a las diez", "me ceno a las diez", "cena a la diez y media", "se cenó a las diez"], "answer": 0, "explain": "Dictation needs the exact impersonal form and time heard: se cena a las diez."}}, {"title": "Paper 3 — Reading comprehension", "html": "Watch for the impersonal ‘se’ (se cena, se come) when comparing Spanish and British customs, and don’t confuse ‘la comida’ (lunch) with ‘la merienda’ (a small afternoon snack) or ‘la cena’ (dinner).", "check": {"question": "‘En España se come a las dos y se cena a las diez’ means…", "options": ["people eat lunch at two and dinner at ten", "people only eat once, at two in the afternoon", "breakfast is at two and lunch is at ten", "nobody eats dinner in Spain at all"], "answer": 0, "explain": "se come = people have lunch; se cena = people have dinner — at the times given."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine routine, time phrases, food opinions and a past-habit comparison: ‘Normalmente me levanto a las siete, pero de pequeño me levantaba mucho más tarde.’ At Higher, always try to add the imperfect for extra range.", "check": {"question": "Which answer reaches the top band?", "options": ["Normalmente ceno a las nueve, pero de pequeño cenaba mucho antes", "Como", "Ceno ceno ceno todos los días sin parar nunca jamás en toda mi vida", "Me gusta"], "answer": 0, "explain": "It links a present routine with a contrasting past habit (imperfect) — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What time does Carlos get up? (1)<br>(b) What is his favourite dish and why? (1)<br>(c) What time is dinner in his house? (1)<br>(d) How has his bedtime changed since he was a child? (1)", "marks": 4, "hint": "Find the time after ‘me levanto’, the dish after ‘mi plato favorito es’, the time after ‘se cena’, and compare ‘de pequeño’ with ‘ahora’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> (at) seven (o''clock) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> Spanish omelette / tortilla de patatas, because it is (very) tasty <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (at) ten (o''clock) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> he used to go to bed earlier (around half past eight) / now he goes to bed later <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I get up at seven. <br>(b) In Spain, people have dinner late. <br>(c) I like the omelette because it is very tasty.", "marks": 5, "hint": "‘I get up’ = reflexive (me levanto). ‘People have dinner’ = impersonal se (se cena). ‘I like’ = me gusta + noun.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Me levanto a las siete. <em>(1)</em></li>\n                <li><strong>(b)</strong> En España, se cena tarde. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gusta la tortilla <em>(1)</em> porque <em>(1)</em> es muy rica <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me levanto’ must keep the reflexive pronoun ‘me’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '5-2-festivals-and-traditions', '5.2 Festivals and Traditions', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about festivals and special days?", "html": "<p>The key verb is <span data-say=\"celebrar\">celebrar</span> (to celebrate). Here is the core festival vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la fiesta\">la fiesta</span></td><td>the party / festival</td><td><span data-say=\"el festival\">el festival</span></td><td>the festival</td></tr>\n              <tr><td><span data-say=\"la Navidad\">la Navidad</span></td><td>Christmas</td><td><span data-say=\"la Nochebuena\">la Nochebuena</span></td><td>Christmas Eve</td></tr>\n              <tr><td><span data-say=\"el Año Nuevo\">el Año Nuevo</span></td><td>New Year</td><td><span data-say=\"los Reyes Magos\">los Reyes Magos</span></td><td>the Three Kings (6 Jan)</td></tr>\n              <tr><td><span data-say=\"la Semana Santa\">la Semana Santa</span></td><td>Holy Week</td><td><span data-say=\"el cumpleaños\">el cumpleaños</span></td><td>birthday</td></tr>\n              <tr><td><span data-say=\"Feliz Navidad\">Feliz Navidad</span></td><td>Merry Christmas</td><td><span data-say=\"Feliz Año Nuevo\">Feliz Año Nuevo</span></td><td>Happy New Year</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Celebramos la Navidad con toda la familia.\">Celebramos la Navidad con toda la familia.</span> — <em>We celebrate Christmas with the whole family.</em></p>\n            <p>Some celebrations connect to a <span data-say=\"santo\">santo</span> (saint) — many Spaniards celebrate <span data-say=\"el día del santo\">el día del santo</span> (their saint''s day) as well as their birthday. The <span data-say=\"Día de Reyes\">Día de Reyes</span> (short for los Reyes Magos) is named after the <span data-say=\"rey\">rey</span> (king) — actually three kings — and it is a <span data-say=\"tradición\">tradición</span> (tradition) that goes back many <span data-say=\"siglos\">siglos</span> (centuries). <span data-say=\"El Día de Reyes es una tradición muy antigua, de hace muchos siglos.\">El Día de Reyes es una tradición muy antigua, de hace muchos siglos.</span> — <em>Día de Reyes is a very old tradition, from many centuries ago.</em></p>", "check": {"question": "What is ‘la Nochebuena’?", "options": ["Christmas Eve", "New Year''s Eve", "the night of the Three Kings", "a birthday party at night"], "answer": 0, "explain": "la Nochebuena = Christmas Eve (24 December); la Nochevieja is New Year''s Eve — a common mix-up."}}, {"title": "How do I talk about celebrating together?", "html": "<p>Celebrations centre on family and food. Key phrases:</p>\n            <ul>\n              <li><span data-say=\"la familia se reúne\">la familia se reúne</span> — the family gets together (reflexive!)</li>\n              <li><span data-say=\"los regalos\">los regalos</span> — the presents; <span data-say=\"regalar\">regalar</span> — to give (as a present)</li>\n              <li><span data-say=\"cenar juntos\">cenar juntos</span> — to have dinner together</li>\n              <li><span data-say=\"bailar\">bailar</span> — to dance; <span data-say=\"los fuegos artificiales\">los fuegos artificiales</span> — fireworks</li>\n            </ul>\n            <p>Example: <span data-say=\"En Nochevieja, vemos los fuegos artificiales y bailamos toda la noche.\">En Nochevieja, vemos los fuegos artificiales y bailamos toda la noche.</span> — <em>On New Year''s Eve, we watch the fireworks and dance all night.</em></p>\n            <p>People don''t just watch — they <span data-say=\"participan\">participan</span> (take part) actively: friends <span data-say=\"invitan a toda la familia\">invitan a toda la familia</span> (invite the whole family), everyone <span data-say=\"canta\">canta</span> (sings) traditional songs, and some festivals are decorated with <span data-say=\"flores\">flores</span> (flowers). All of this creates real <span data-say=\"alegría\">alegría</span> (joy). <span data-say=\"Cuando participamos en la fiesta, cantamos, bailamos y hay mucha alegría.\">Cuando participamos en la fiesta, cantamos, bailamos y hay mucha alegría.</span> — <em>When we take part in the festival, we sing, we dance and there is a lot of joy.</em></p>", "check": {"question": "Why does ‘reunirse’ need ‘se’ in ‘la familia se reúne’?", "options": ["it is reflexive — the family gathers itself", "‘se’ makes the whole verb negative instead", "‘se’ shows the action has already finished", "‘se’ is only ever used before certain plural nouns"], "answer": 0, "explain": "reunirse is reflexive: la familia se reúne = the family gets (itself) together."}}, {"title": "How do I talk about costumes, processions and famous fiestas?", "html": "<p>Some celebrations involve costumes and processions:</p>\n            <ul>\n              <li><span data-say=\"disfrazarse\">disfrazarse</span> — to dress up / wear a costume; <span data-say=\"el disfraz\">el disfraz</span> — the costume</li>\n              <li><span data-say=\"la procesión\">la procesión</span> — the procession; <span data-say=\"el encierro\">el encierro</span> — the running of the bulls</li>\n            </ul>\n            <p>Famous Spanish and Hispanic festivals:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"Las Fallas\">Las Fallas</span></td><td>Valencia, March — giant sculptures are burned</td></tr>\n              <tr><td><span data-say=\"La Tomatina\">La Tomatina</span></td><td>Buñol, August — a huge tomato fight</td></tr>\n              <tr><td><span data-say=\"San Fermín\">San Fermín</span></td><td>Pamplona, July — the running of the bulls</td></tr>\n              <tr><td><span data-say=\"el Día de los Muertos\">el Día de los Muertos</span></td><td>Mexico, 1–2 November — remembering the dead</td></tr>\n            </table>\n            <p><span data-say=\"En Semana Santa hay procesiones grandes por las calles.\">En Semana Santa hay procesiones grandes por las calles.</span></p>\n            <p>These events aren''t just for locals — an <span data-say=\"evento\">evento</span> (event) like San Fermín (also called <span data-say=\"los Sanfermines\">los Sanfermines</span>) can <span data-say=\"atraer\">atraer</span> (attract) thousands of visitors from other countries. People often wear a traditional <span data-say=\"traje\">traje</span> (outfit/costume) — white with a red scarf for San Fermín — and some say it feels a little <span data-say=\"loco\">loco</span> (crazy) to run in front of bulls in the <span data-say=\"plaza de toros\">plaza de toros</span> (bullring)!</p>\n            <p>Mexico''s <span data-say=\"Día de Muertos\">Día de Muertos</span> (another name for el Día de los Muertos) is calmer: instead of fearing <span data-say=\"la muerte\">la muerte</span> (death), families remember those who have died with music and flowers.</p>\n            <p>Spain''s religious buildings reflect its history too: alongside Catholic churches there are also a few <span data-say=\"mezquitas\">mezquitas</span> (mosques), <span data-say=\"sinagogas\">sinagogas</span> (synagogues) and ancient <span data-say=\"templos\">templos</span> (temples). If you get jostled in a crowd watching a procession, you say <span data-say=\"¡Perdón!\">¡Perdón!</span> (Sorry!); and at a children''s party, a <span data-say=\"piñata rota\">piñata rota</span> (broken piñata) means the sweets have fallen out — a moment everyone walking <span data-say=\"detrás\">detrás</span> (behind) the piñata loves!</p>", "check": {"question": "Where does ‘La Tomatina’ take place?", "options": ["Buñol", "Pamplona", "Valencia", "Sevilla"], "answer": 0, "explain": "La Tomatina (the tomato fight) is in Buñol; Pamplona hosts San Fermín and Valencia hosts Las Fallas."}}, {"title": "How do I say what happened at a festival? (preterite)", "html": "<p>Use the <strong>preterite</strong> for a completed action at a specific past festival — what happened once:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"celebramos\">celebramos</span></td><td>we celebrated</td><td><span data-say=\"fui\">fui</span></td><td>I went</td></tr>\n              <tr><td><span data-say=\"comimos\">comimos</span></td><td>we ate</td><td><span data-say=\"bailamos\">bailamos</span></td><td>we danced</td></tr>\n              <tr><td><span data-say=\"lo pasé bien\">lo pasé bien</span></td><td>I had a good time</td><td><span data-say=\"lo pasé genial\">lo pasé genial</span></td><td>I had a great time</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El año pasado celebramos la Navidad en casa de mis abuelos y lo pasé genial.\">El año pasado celebramos la Navidad en casa de mis abuelos y lo pasé genial.</span> — <em>Last year we celebrated Christmas at my grandparents'' house and I had a great time.</em></p>\n            <p>You can also describe festivals from other Spanish-speaking countries using nationality adjectives: <span data-say=\"cubano\">cubano</span> (Cuban), <span data-say=\"mexicano\">mexicano</span> (Mexican), <span data-say=\"argentino\">argentino</span> (Argentine) and <span data-say=\"colombiano\">colombiano</span> (Colombian). Example: <span data-say=\"El verano pasado, fui a un festival cubano y probé la música tradicional.\">El verano pasado, fui a un festival cubano y probé la música tradicional.</span> — <em>Last summer, I went to a Cuban festival and tried the traditional music.</em></p>", "check": {"question": "Which time phrase signals you need the PRETERITE, not the present?", "options": ["el año pasado (last year)", "normalmente (normally)", "todos los años (every year)", "los domingos (on Sundays)"], "answer": 0, "explain": "‘el año pasado’ points to one completed past event → preterite. The others signal habitual, repeated actions."}}, {"title": "How do I say what usually happens? (imperfect / soler)", "html": "<p>For habits and things that happened <strong>repeatedly</strong>, use <strong>soler</strong> + infinitive or the imperfect tense:</p>\n            <ul>\n              <li><span data-say=\"solemos reunirnos\">solemos reunirnos</span> — we usually get together (present habit)</li>\n              <li><span data-say=\"solíamos ir\">solíamos ir</span> — we used to go (past habit) <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"normalmente celebramos\">normalmente celebramos</span> — we normally celebrate</li>\n              <li><span data-say=\"todos los años\">todos los años</span> — every year</li>\n            </ul>\n            <p>Example: <span data-say=\"Cuando era niño, solíamos ir a ver los fuegos artificiales cada Año Nuevo.\">Cuando era niño, solíamos ir a ver los fuegos artificiales cada Año Nuevo.</span> — <em>When I was a child, we used to go and see the fireworks every New Year.</em></p>\n            <p>Many festivals have a <span data-say=\"religioso\">religioso</span> (religious) origin. Spain''s main <span data-say=\"religión\">religión</span> (religion) is <span data-say=\"cristiana\">cristiana</span> (Christian), specifically <span data-say=\"católica\">católica</span> (Catholic) — which is why Semana Santa is so important. But Spain is also home to <span data-say=\"judías\">judías</span> (Jewish) and <span data-say=\"musulmanas\">musulmanas</span> (Muslim) communities, who suelen celebrar (usually celebrate) their own festivals too. <span data-say=\"Mucha gente en España es católica, pero también hay comunidades judías y musulmanas que suelen celebrar sus propias fiestas.\">Mucha gente en España es católica, pero también hay comunidades judías y musulmanas que suelen celebrar sus propias fiestas.</span> — <em>Many people in Spain are Catholic, but there are also Jewish and Muslim communities who usually celebrate their own festivals.</em></p>", "check": {"question": "‘Solíamos ir a ver los fuegos artificiales’ describes…", "options": ["a repeated habit in the past", "one single event that just happened", "something that will happen next year", "an order someone gave you"], "answer": 0, "explain": "soler in the imperfect (solíamos) + infinitive = used to do something repeatedly."}}, {"title": "Higher: combining preterite and imperfect", "html": "<p><span class=\"tier-h\">H</span> The strongest Higher-tier answers <strong>combine</strong> the imperfect (background/description) with the preterite (the event that interrupted it):</p>\n            <ul>\n              <li><span data-say=\"Era Navidad y toda la familia estaba en casa cuando mi abuela preparó una cena enorme.\">Era Navidad y toda la familia estaba en casa cuando mi abuela preparó una cena enorme.</span> <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Hacía mucho calor durante La Tomatina cuando alguien me tiró un tomate.\">Hacía mucho calor durante La Tomatina cuando alguien me tiró un tomate.</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Pattern: <strong>imperfect</strong> (era / estaba / hacía…) sets the scene, <strong>preterite</strong> (preparó / tiró…) is the action that happened.</p>\n            <p><span class=\"tier-h\">H</span> Another strong combination: <span data-say=\"La gente se pintaba la cara de colores cuando de repente empezaron los fuegos artificiales, y me sorprendió mucho.\">La gente se pintaba la cara de colores cuando de repente empezaron los fuegos artificiales, y me sorprendió mucho.</span> <span class=\"tier-h\">H</span> — <em>People were painting their faces with colours when suddenly the fireworks started, and it surprised me a lot.</em></p>", "check": {"question": "In ‘Era Navidad y toda la familia estaba en casa cuando mi abuela preparó una cena enorme’, which verb is the PRETERITE?", "options": ["preparó", "era", "estaba", "preparaba"], "answer": 0, "explain": "‘preparó’ is the single completed action (preterite); ‘era’ and ‘estaba’ are imperfect, setting the scene, and ‘preparaba’ would be the imperfect of the same verb."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la fiesta", "definition": "the party / festival"}, {"term": "celebrar", "definition": "to celebrate"}, {"term": "la Navidad", "definition": "Christmas"}, {"term": "la Nochebuena", "definition": "Christmas Eve"}, {"term": "el Año Nuevo", "definition": "New Year"}, {"term": "los Reyes Magos", "definition": "the Three Kings (6 Jan)"}, {"term": "la Semana Santa", "definition": "Holy Week"}, {"term": "el cumpleaños", "definition": "birthday"}, {"term": "la familia se reúne", "definition": "the family gets together"}, {"term": "los regalos · regalar", "definition": "presents · to give (a present)"}, {"term": "los fuegos artificiales", "definition": "fireworks"}, {"term": "disfrazarse · el disfraz", "definition": "to dress up · the costume"}, {"term": "la procesión", "definition": "the procession"}, {"term": "lo pasé genial", "definition": "I had a great time"}, {"term": "solemos reunirnos", "definition": "we usually get together"}, {"term": "solíamos ir (H)", "definition": "we used to go"}, {"term": "La Tomatina · San Fermín", "definition": "tomato fight (Buñol) · running of the bulls (Pamplona)"}, {"term": "Era Navidad… cuando… (H)", "definition": "combining imperfect + preterite for a past festival"}, {"term": "el siglo", "definition": "the century"}, {"term": "la muerte", "definition": "death"}, {"term": "el traje", "definition": "the outfit / the costume / the suit"}, {"term": "el santo / el día del santo", "definition": "the saint / one''s saint''s day"}, {"term": "participar", "definition": "to take part / to participate"}, {"term": "cubano/a", "definition": "Cuban"}, {"term": "el rey", "definition": "the king"}, {"term": "cantar", "definition": "to sing"}, {"term": "la flor", "definition": "the flower"}, {"term": "invitar", "definition": "to invite"}, {"term": "religioso/a", "definition": "religious"}, {"term": "loco/a", "definition": "crazy / mad"}, {"term": "mexicano/a", "definition": "Mexican"}, {"term": "sorprender", "definition": "to surprise"}, {"term": "cristiano/a", "definition": "Christian"}, {"term": "argentino/a", "definition": "Argentine / Argentinian"}, {"term": "la tradición", "definition": "the tradition"}, {"term": "la alegría", "definition": "joy / happiness"}, {"term": "pintar · pintarse", "definition": "to paint · to paint oneself"}, {"term": "la religión", "definition": "religion"}, {"term": "católico/a", "definition": "Catholic"}, {"term": "el evento", "definition": "the event"}, {"term": "atraer", "definition": "to attract"}, {"term": "colombiano/a", "definition": "Colombian"}, {"term": "judío/a", "definition": "Jewish"}, {"term": "musulmán / musulmana", "definition": "Muslim"}, {"term": "el templo", "definition": "the temple"}, {"term": "la mezquita", "definition": "the mosque"}, {"term": "la sinagoga", "definition": "the synagogue"}, {"term": "el Día de Reyes", "definition": "Three Kings'' Day (6 January)"}, {"term": "el Día de Muertos", "definition": "the Day of the Dead (another name for el Día de los Muertos)"}, {"term": "la plaza de toros", "definition": "the bullring"}, {"term": "los Sanfermines", "definition": "the San Fermín festival (running of the bulls)"}, {"term": "¡Perdón!", "definition": "Sorry!"}, {"term": "detrás (de)", "definition": "behind"}, {"term": "roto/a", "definition": "broken"}, {"term": "quemar · quemarse", "definition": "to burn · to get burnt"}, {"term": "el vestido", "definition": "the dress"}, {"term": "latino/a", "definition": "Latin American"}, {"term": "la reina", "definition": "the queen"}, {"term": "la cola", "definition": "the queue / the tail"}, {"term": "chileno/a", "definition": "Chilean"}, {"term": "divertir · divertirse", "definition": "to entertain · to have fun"}, {"term": "el toro", "definition": "the bull"}, {"term": "la boda", "definition": "the wedding"}, {"term": "la celebración", "definition": "the celebration"}, {"term": "el juguete", "definition": "the toy"}, {"term": "el desfile", "definition": "the parade"}, {"term": "al aire libre", "definition": "outdoors / in the open air"}, {"term": "hispanohablante", "definition": "Spanish-speaking"}, {"term": "¡Enhorabuena!", "definition": "Congratulations!"}, {"term": "asqueroso/a", "definition": "disgusting"}, {"term": "finalmente", "definition": "finally"}, {"term": "¿Cómo es?", "definition": "What is it like?"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Celebramos la Navidad en familia.\" data-listen></span><br>Listen. What does this mean?", "options": ["We celebrate Christmas with family", "We celebrated Christmas with family last year", "We used to celebrate Christmas with family", "We are going to celebrate Christmas with family"], "answer": 0, "explain": "‘celebramos la Navidad en familia’ is present tense: we celebrate. The traps add a past-time marker, an imperfect meaning, or a future plan."}, {"question": "<span data-say=\"Nos disfrazamos y vamos a la procesión.\" data-listen></span><br>Listen. What does this mean?", "options": ["We dress up in costumes and go to the procession", "We get dressed up and go to see the fireworks", "We used to dress up and go to processions every year", "They dress up and go to the procession"], "answer": 0, "explain": "‘nos disfrazamos’ (reflexive, present) = we dress up; ‘la procesión’ = the procession, not fireworks. Trap D swaps ‘nos’ for ‘they’."}, {"question": "Complete: ‘El año pasado, mi familia y yo ___ la Navidad en casa de mis abuelos.’", "options": ["celebramos", "celebrábamos", "celebra", "vamos a celebrar"], "answer": 0, "explain": "‘el año pasado’ = a completed past event → preterite ‘celebramos’. B is imperfect, C is 3rd person singular, D is a future plan."}, {"question": "Complete: ‘Normalmente, mi familia ___ reunirse en Nochebuena.’", "options": ["suele", "solía", "solemos", "sueles"], "answer": 0, "explain": "‘mi familia’ is 3rd person singular → suele. ‘solía’ is imperfect (used to), ‘solemos’/‘sueles’ do not agree with ‘mi familia’."}, {"question": "Which sentence means ‘The family gets together on Christmas Eve’?", "options": ["La familia se reúne en Nochebuena.", "La familia se reunió en Nochebuena.", "La familia reúne en Nochebuena.", "La familia se reúne en Nochevieja."], "answer": 0, "explain": "Present reflexive ‘se reúne’ + ‘Nochebuena’. B is preterite, C drops the reflexive ‘se’, D swaps to New Year''s Eve."}, {"question": "‘Los Reyes Magos’ celebrates…", "options": ["the Three Kings'' arrival with gifts (6 Jan)", "the King and Queen of Spain''s official wedding anniversary", "the crowning of a brand new king somewhere in Spain", "New Year''s Eve, celebrated with a royal television speech"], "answer": 0, "explain": "Los Reyes Magos (6 January) is when the Three Kings bring gifts to children in Spain — not the King and Queen of Spain, a new coronation, or Nochevieja."}, {"question": "<span data-say=\"Fuimos a ver los fuegos artificiales y lo pasamos genial.\" data-listen></span><br>Listen. What does this mean?", "options": ["We went to see the fireworks and had a great time", "We go to see the fireworks every year and have a great time", "We are going to see the fireworks and will have a great time", "We used to go and see the fireworks and always had a good time"], "answer": 0, "explain": "‘fuimos’ (preterite of ir) + ‘lo pasamos genial’ = we went and had a great time — a single past event, not a habit or future plan."}, {"question": "La Tomatina takes place in which month, and what happens?", "options": ["August — people throw tomatoes in Buñol", "July — people run in front of bulls through the streets of Pamplona", "March — people burn giant sculptures in the city of Valencia", "November — people visit graves to remember the dead in Mexico"], "answer": 0, "explain": "La Tomatina is a tomato fight in Buñol in August. B describes San Fermín, C describes Las Fallas, D describes el Día de los Muertos."}, {"question": "Complete: ‘Este año, los niños ___ de superhéroes para el carnaval.’", "options": ["se disfrazan", "disfrazan", "se disfrazaron", "se disfrazaban"], "answer": 0, "explain": "disfrazarse is reflexive, present tense → se disfrazan. B drops ‘se’, C is preterite, D is imperfect."}, {"question": "How do you say ‘We ate together and danced all night’?", "options": ["Comimos juntos y bailamos toda la noche.", "Comemos juntos y bailamos toda la noche.", "Comíamos juntos y bailábamos toda la noche.", "Vamos a comer juntos y a bailar toda la noche."], "answer": 0, "explain": "A completed one-off past event needs the preterite: comimos, bailamos. B is present, C is imperfect (used to), D is a future plan."}, {"question": "What does ‘atraer turistas’ mean?", "options": ["to attract tourists", "to avoid tourists", "to charge tourists money", "to guide tourists home"], "answer": 0, "explain": "atraer = to attract. The traps are other things a festival might do to/with tourists."}, {"question": "What is ‘la plaza de toros’?", "options": ["the bullring", "the town hall square", "the central market square", "the football stadium"], "answer": 0, "explain": "la plaza de toros = the bullring, where events like San Fermín''s bullfights take place."}]}, "fib": {"enabled": true, "questions": [{"text": "Celebramos la [Nochebuena] con mi familia el 24 de diciembre. <span data-say=\"Celebramos la Nochebuena con mi familia el 24 de diciembre.\" data-listen>Celebramos la Nochebuena con mi familia el 24 de diciembre.</span>"}, {"text": "El seis de enero celebramos el día de los [Reyes] Magos. (Three Kings)"}, {"text": "En Navidad, toda la familia se [reúne] en casa de mis abuelos. (reunirse)"}, {"text": "Vemos los [fuegos] artificiales a medianoche en Nochevieja. (fireworks)"}, {"text": "Para Halloween, nos [disfrazamos] de personajes de miedo. (disfrazarse — we dress up)"}, {"text": "El año pasado, lo [pasé] genial en la fiesta de cumpleaños. <span data-say=\"El año pasado, lo pasé genial en la fiesta de cumpleaños.\" data-listen>El año pasado, lo pasé genial en la fiesta de cumpleaños.</span>"}, {"text": "Cuando éramos pequeños, [solíamos] ir a ver la procesión de Semana Santa. (soler, imperfect)"}, {"text": "Esta tradición tiene más de un [siglo] de historia. (century)"}, {"text": "El Día de los Muertos honra a los que ya no están, sin miedo a la [muerte] . (death)"}, {"text": "Durante la fiesta, mucha gente se [pinta] la cara de colores. (pintarse — paints)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘Los Reyes Magos’ is celebrated on 6th January.", "answer": true, "explain": "6 January — Epiphany, when the Three Kings bring presents in Spain."}, {"statement": "‘La Tomatina’ takes place in Pamplona.", "answer": false, "explain": "La Tomatina is in Buñol; Pamplona hosts San Fermín (the running of the bulls)."}, {"statement": "‘Reunirse’ is reflexive, so ‘the family gets together’ is ‘la familia se reúne’.", "answer": true, "explain": "Reflexive verbs need me/te/se — se reúne."}, {"statement": "The preterite tense is used to describe what usually happens every year.", "answer": false, "explain": "Habitual actions use soler/imperfect; the preterite is for one completed past event."}, {"statement": "‘El Día de los Muertos’ is a Mexican celebration.", "answer": true, "explain": "El Día de los Muertos (1–2 November) is celebrated across Mexico."}, {"statement": "‘Lo pasé genial’ means ‘I had a great time’.", "answer": true, "explain": "pasarlo genial/bien = to have a great/good time."}, {"statement": "‘Vamos a celebrar la Navidad juntos’ describes something that already happened.", "answer": false, "explain": "‘vamos a’ + infinitive is a future plan, not a completed past event."}, {"statement": "San Fermín is famous for the running of the bulls in Pamplona.", "answer": true, "explain": "San Fermín (July) in Pamplona is famous for el encierro, the running of the bulls."}, {"statement": "‘La mezquita’ is a Christian church.", "answer": false, "explain": "la mezquita = the mosque, a Muslim place of worship. A church is la iglesia."}, {"statement": "‘Los Sanfermines’ refers to the same festival as San Fermín.", "answer": true, "explain": "los Sanfermines is another name for the San Fermín festival in Pamplona."}, {"statement": "‘Roto’ means ‘broken’.", "answer": true, "explain": "roto/rota = broken, e.g. una piñata rota."}]}, "misc": {"enabled": true, "items": [{"myth": "Yo celebro la Navidad el año pasado.", "truth": "Yo celebré la Navidad el año pasado.", "check": {"question": "Why is ‘celebro’ wrong with ‘el año pasado’?", "options": ["‘el año pasado’ needs the preterite, celebré", "‘celebro’ should always be conjugated in the plural", "‘Navidad’ needs a capital C written at the end", "the sentence is missing the linking word ‘que’"], "answer": 0, "explain": "A specific past time phrase like ‘el año pasado’ requires the preterite: celebré."}}, {"myth": "La familia reúne en Nochebuena.", "truth": "La familia se reúne en Nochebuena.", "check": {"question": "What is missing from ‘La familia reúne en Nochebuena’?", "options": ["the reflexive pronoun ‘se’ (se reúne)", "the definite article before ‘familia’", "an accent on the word ‘familia’", "the word ‘mucho’ at the end"], "answer": 0, "explain": "reunirse is reflexive — you need ‘se’: la familia se reúne."}}, {"myth": "La Tomatina es en Pamplona.", "truth": "La Tomatina es en Buñol.", "check": {"question": "Why is ‘La Tomatina es en Pamplona’ wrong?", "options": ["La Tomatina is actually held in Buñol, not Pamplona", "‘Tomatina’ should really be spelt ‘Tomatino’ instead", "Pamplona does not exist as a real city in Spain", "‘es’ should be replaced with ‘está’ in this sentence"], "answer": 0, "explain": "La Tomatina (the tomato fight) is in Buñol; Pamplona is famous for San Fermín instead."}}, {"myth": "Los Reyes Magos es el 25 de diciembre.", "truth": "Los Reyes Magos es el 6 de enero.", "check": {"question": "Why is ‘el 25 de diciembre’ the wrong date here?", "options": ["that is Christmas Day — Los Reyes Magos is 6 January", "Los Reyes Magos does not actually have any fixed date at all", "25 December really is the correct date for this festival", "dates are never mentioned together with festival names"], "answer": 0, "explain": "25 December is Christmas Day (la Navidad); Los Reyes Magos is celebrated on 6 January."}}, {"myth": "Ayer, solemos reunirnos en casa de mi abuela.", "truth": "Ayer, nos reunimos en casa de mi abuela.", "check": {"question": "Why doesn''t ‘solemos’ work with ‘ayer’ (yesterday)?", "options": ["‘ayer’ names one day, so it needs the preterite instead", "‘solemos’ is simply spelt incorrectly in this whole sentence", "‘ayer’ must always be placed at the very end of a sentence", "‘reunirnos’ is not actually a real Spanish verb at all"], "answer": 0, "explain": "soler + present describes a habit, but ‘ayer’ points to a single completed day — use the preterite instead."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for tense and dates", "html": "Festival questions often hinge on a single tense marker or date. For -ar verbs like ‘celebramos’, present and preterite can look identical, so listen for time phrases like ‘el año pasado’ or ‘normalmente’ around the verb, and note exact dates (6 de enero vs 25 de diciembre).", "check": {"question": "You hear ‘normalmente’ before a verb about a festival. What does that signal?", "options": ["a habitual action, not a one-off past event", "a completed action that only ever happened once", "a plan for something in the future", "a mistake accidentally made by the speaker"], "answer": 0, "explain": "‘normalmente’ signals a habitual/repeated action — pair it with soler or the present, not the preterite."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Watch for reflexive verbs (la familia se reúne) and false festival-date traps. Keep translations natural: ‘lo pasé genial’ = ‘I had a great time’, not a stiff word-for-word translation.", "check": {"question": "How should you translate ‘Nos disfrazamos para el carnaval’?", "options": ["We dress up in costumes for the carnival", "We watch other people dress up for the carnival", "We used to dress up for the carnival every year", "We are going to dress up for the carnival"], "answer": 0, "explain": "‘nos disfrazamos’ is present tense: we dress up (ourselves)."}}, {"title": "Paper 4 — Writing & translation into Spanish (Higher)", "html": "For the strongest answers, mix tenses: describe a past festival with the preterite for what happened (celebramos, fuimos, bailamos) and the imperfect for background description (era Navidad, hacía frío, toda la familia estaba en casa).", "check": {"question": "Which sentence reaches the top band for describing a past festival?", "options": ["Era Navidad y toda la familia estaba en casa cuando mi abuela preparó una cena enorme", "Navidad es muy buena y me gusta mucho la Navidad todos los años", "Celebramos la Navidad y también nos gusta mucho el Año Nuevo", "Hay una fiesta muy grande, bonita y tradicional en mi ciudad todos los años sin falta"], "answer": 0, "explain": "It combines the imperfect (era, estaba) with the preterite (preparó) — the Higher-tier marker examiners reward, not just present-tense opinions."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Pablo says. Answer <strong>in English</strong>.<br>(a) What does Pablo''s family usually do at Christmas? (1)<br>(b) Where did he go last year, and for what festival? (1)<br>(c) Name <strong>one</strong> thing he saw or ate there. (1)<br>(d) What is he going to do next year? (1)", "marks": 4, "hint": "Find the habit after ‘todos los años’, the place and festival after ‘fuimos a’, a detail after ‘vimos’ or ‘comimos’, and the plan after ‘voy a’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> celebrate Christmas together (as a family) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> Sevilla, for (the festivities of) Semana Santa / Holy Week <em>(1)</em>.</li>\n                <li><strong>(c)</strong> the processions in the streets / (he ate) a lot of turrón (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> go back to Sevilla for the Feria de Abril <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) We celebrate Christmas with the family. <br>(b) Last year we danced all night. <br>(c) I am going to dress up as a superhero for the carnival.", "marks": 5, "hint": "‘We celebrate’ = present tense (celebramos). ‘Last year we danced’ = preterite (bailamos). ‘I am going to dress up’ = voy a disfrazarme (reflexive).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Celebramos la Navidad con la familia. <em>(1)</em></li>\n                <li><strong>(b)</strong> El año pasado bailamos toda la noche. <em>(1)</em></li>\n                <li><strong>(c)</strong> Voy a disfrazarme <em>(1)</em> de superhéroe <em>(1)</em> para el carnaval <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. Part (b) must use the preterite ‘bailamos’, not the present.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '6-1-celebrities-influencers-and-fame', '6.1 Celebrities, Influencers and Fame', '{"learn": {"enabled": true, "items": [{"title": "Who and what is famous? (fame vocabulary)", "html": "<p>The key noun is <span data-say=\"la fama\">la fama</span> (fame). Someone who has it is <span data-say=\"famoso\">famoso</span> / <span data-say=\"famosa\">famosa</span> (famous). Tap 🔊 to hear the core vocabulary.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la estrella\">la estrella</span></td><td>the star (celebrity)</td><td><span data-say=\"el cantante\">el cantante / la cantante</span></td><td>singer</td></tr>\n              <tr><td><span data-say=\"el actor\">el actor</span></td><td>actor</td><td><span data-say=\"la actriz\">la actriz</span></td><td>actress</td></tr>\n              <tr><td><span data-say=\"el futbolista\">el futbolista / la futbolista</span></td><td>footballer</td><td><span data-say=\"el influencer\">el influencer / la influencer</span></td><td>influencer</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Mi ídolo es una cantante muy famosa.\">Mi ídolo es una cantante muy famosa.</span> — <em>My idol is a very famous singer.</em></p>", "check": {"question": "What does ‘la estrella’ mean in this context?", "options": ["the (celebrity) star", "the actual night sky", "a type of award ceremony", "a person who dislikes fame"], "answer": 0, "explain": "la estrella = the star, meaning a famous celebrity — not a star in the sky."}}, {"title": "Social media and success", "html": "<p>Fame today is closely linked to <span data-say=\"las redes sociales\">las redes sociales</span> (social media). To follow someone, use <strong>seguir a</strong> — always with the personal <strong>a</strong> before a person.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"seguir a\">seguir a (alguien)</span></td><td>to follow (someone)</td><td><span data-say=\"el seguidor\">el seguidor / la seguidora</span></td><td>follower</td></tr>\n              <tr><td><span data-say=\"tener éxito\">tener éxito</span></td><td>to be successful</td><td><span data-say=\"el éxito\">el éxito</span></td><td>success</td></tr>\n              <tr><td><span data-say=\"ser rico\">ser rico / rica</span></td><td>to be rich</td><td><span data-say=\"ganar mucho dinero\">ganar mucho dinero</span></td><td>to earn a lot of money</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Sigo a mi cantante favorita porque tiene mucho éxito.\">Sigo a mi cantante favorita porque tiene mucho éxito.</span> — <em>I follow my favourite singer because she is very successful.</em></p>", "check": {"question": "‘tener éxito’ is a false friend. What does it actually mean?", "options": ["to be successful", "to have an exit", "to lose all your money", "to feel very tired"], "answer": 0, "explain": "tener éxito = to be successful. It looks like the English word ‘exit’ but does not mean that at all."}}, {"title": "How do I give an opinion about a celebrity?", "html": "<p>Start an opinion with a set phrase, then give a <strong>reason</strong> with <span data-say=\"porque\">porque</span>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"creo que\">creo que…</span></td><td>I think that…</td><td><span data-say=\"pienso que\">pienso que…</span></td><td>I think that…</td></tr>\n              <tr><td><span data-say=\"en mi opinión\">en mi opinión…</span></td><td>in my opinion…</td><td><span data-say=\"me parece que\">me parece que…</span></td><td>it seems to me that…</td></tr>\n            </table>\n            <p>Role-model vocabulary: <span data-say=\"mi ídolo\">mi ídolo</span> (my idol), <span data-say=\"admirar\">admirar</span> (to admire), <span data-say=\"respetar\">respetar</span> (to respect), and <span data-say=\"un buen modelo a seguir\">un buen modelo a seguir</span> / <span data-say=\"un mal modelo a seguir\">un mal modelo a seguir</span> (a good / bad role model).</p>\n            <p>Example: <span data-say=\"Creo que es un buen modelo a seguir porque ayuda a mucha gente.\">Creo que es un buen modelo a seguir porque ayuda a mucha gente.</span></p>", "check": {"question": "Which word introduces the REASON in an opinion sentence?", "options": ["porque (because)", "sin embargo (however)", "cuando (when)", "donde (where)"], "answer": 0, "explain": "porque = because, introducing the reason after an opinion phrase like ‘creo que’. ‘sin embargo’ is a genuine trap — it also links ideas, but it means ‘however’, not ‘because’."}}, {"title": "The advantages of fame", "html": "<p>Famous people can use their platform positively:</p>\n            <ul>\n              <li><span data-say=\"la ventaja\">la ventaja</span> — the advantage</li>\n              <li><span data-say=\"ayudar a la gente\">ayudar a la gente</span> — to help people</li>\n              <li><span data-say=\"dar dinero a organizaciones benéficas\">dar dinero a organizaciones benéficas</span> — to give money to charities</li>\n              <li><span data-say=\"ser una buena influencia\">ser una buena influencia</span> — to be a good influence</li>\n            </ul>\n            <p>Example: <span data-say=\"Una ventaja de la fama es que puedes ayudar a la gente y dar dinero a organizaciones benéficas.\">Una ventaja de la fama es que puedes ayudar a la gente y dar dinero a organizaciones benéficas.</span></p>", "check": {"question": "‘dar dinero a organizaciones benéficas’ means…", "options": ["to give money to charities", "to borrow money from a bank", "to earn money from adverts", "to spend money on clothes"], "answer": 0, "explain": "dar dinero a organizaciones benéficas = to give money to charities — a common advantage of fame in exam answers."}}, {"title": "The disadvantages of fame", "html": "<p>Exam answers should also weigh up the negatives — <span data-say=\"la desventaja\">la desventaja</span> (the disadvantage):</p>\n            <ul>\n              <li><span data-say=\"perder la privacidad\">perder la privacidad</span> — to lose your privacy</li>\n              <li><span data-say=\"sentir mucha presión\">sentir mucha presión</span> — to feel a lot of pressure</li>\n              <li><span data-say=\"ser una mala influencia\">ser una mala influencia</span> — to be a bad influence</li>\n            </ul>\n            <p>Example: <span data-say=\"Sin embargo, los famosos pierden la privacidad y sienten mucha presión.\">Sin embargo, los famosos pierden la privacidad y sienten mucha presión.</span> — <em>However, celebrities lose their privacy and feel a lot of pressure.</em></p>", "check": {"question": "What is ‘sentir mucha presión’ describing?", "options": ["feeling a lot of pressure", "feeling completely relaxed", "earning a lot of money", "losing a lot of followers"], "answer": 0, "explain": "sentir mucha presión = to feel a lot of pressure, a key disadvantage of fame."}}, {"title": "Higher: the subjunctive and comparatives", "html": "<p><span class=\"tier-h\">H</span> After a <strong>POSITIVE</strong> opinion, Spanish uses the normal indicative: <span data-say=\"Creo que es un buen modelo a seguir.\">Creo que es un buen modelo a seguir.</span></p>\n            <p><span class=\"tier-h\">H</span> But after a <strong>NEGATIVE</strong> opinion (<em>no creo que…</em>), Spanish switches to the <strong>subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"No creo que sea un buen modelo a seguir.\">No creo que sea un buen modelo a seguir.</span> <span class=\"tier-h\">H</span> — I don’t think he/she is a good role model.</li>\n              <li><span data-say=\"No creo que la fama sea fácil.\">No creo que la fama sea fácil.</span> <span class=\"tier-h\">H</span> — I don’t think fame is easy.</li>\n            </ul>\n            <p>Comparatives use <strong>más… que</strong> (more… than):</p>\n            <p><span data-say=\"Es más famoso que su hermano.\">Es más famoso que su hermano.</span> — <em>He is more famous than his brother.</em></p>", "check": {"question": "Which sentence correctly uses the subjunctive after a NEGATIVE opinion?", "options": ["No creo que sea un buen modelo a seguir.", "No creo que es un buen modelo a seguir de verdad.", "Creo que sea un buen modelo a seguir.", "No creo un buen modelo a seguir."], "answer": 0, "explain": "no creo que + subjunctive → sea. Option B wrongly uses the indicative ‘es’ (plus ‘de verdad’, really); C uses the subjunctive after a POSITIVE opinion by mistake."}}, {"title": "Love, marriage and family status", "html": "<p>Celebrity gossip often centres on <span data-say=\"el amor\">el amor</span> (love) and <span data-say=\"la relación\">la relación</span> (relationship). Two people who are together are <span data-say=\"la pareja\">la pareja</span> (a couple/partner).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"casarse con\">casarse (con)</span></td><td>to get married (to)</td><td><span data-say=\"casado\">casado / casada</span></td><td>married</td></tr>\n              <tr><td><span data-say=\"el matrimonio\">el matrimonio</span></td><td>marriage</td><td><span data-say=\"el marido\">el marido</span></td><td>husband</td></tr>\n              <tr><td><span data-say=\"separarse\">separarse</span></td><td>to split up</td><td><span data-say=\"divorciarse\">divorciarse</span></td><td>to get divorced</td></tr>\n              <tr><td><span data-say=\"soltero\">soltero / soltera</span></td><td>single</td><td><span data-say=\"nacer\">nacer</span></td><td>to be born</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"La actriz se casó con el cantante en 2019, pero se separaron el año pasado y ahora está soltera otra vez.\">La actriz se casó con el cantante en 2019, pero se separaron el año pasado y ahora está soltera otra vez.</span> — <em>The actress married the singer in 2019, but they split up last year and now she is single again.</em></p>\n            <p>Sadly, some stars have <span data-say=\"muerto\">muerto</span> (died) young — the press calls this a tragedy.</p>", "check": {"question": "What does ‘se separaron’ mean?", "options": ["they split up", "they got married", "they were born", "they became famous overnight"], "answer": 0, "explain": "separarse = to split up / separate. It is the opposite of casarse (to get married)."}}, {"title": "Media: press, TV, radio and interviews", "html": "<p>Fame is created and spread by <span data-say=\"los medios de comunicación\">los medios de comunicación</span> (the media): <span data-say=\"la prensa\">la prensa</span> (the press), <span data-say=\"la radio\">la radio</span> (radio) and <span data-say=\"la tele\">la tele</span> / <span data-say=\"la televisión\">la televisión</span> (TV).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la entrevista\">la entrevista</span></td><td>the interview</td><td><span data-say=\"el comentario\">el comentario</span></td><td>comment</td></tr>\n              <tr><td><span data-say=\"el anuncio\">el anuncio</span></td><td>advert / announcement</td><td><span data-say=\"el espectáculo\">el espectáculo</span></td><td>the show</td></tr>\n              <tr><td><span data-say=\"grabar\">grabar</span></td><td>to record</td><td><span data-say=\"el sonido\">el sonido</span></td><td>sound</td></tr>\n              <tr><td><span data-say=\"digital\">digital</span> <span class=\"tier-h\">H</span></td><td>digital</td><td><span data-say=\"la telerrealidad\">la telerrealidad</span></td><td>reality TV</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En la entrevista, la estrella hizo un comentario sobre la telerrealidad y luego grabó un anuncio para la tele.\">En la entrevista, la estrella hizo un comentario sobre la telerrealidad y luego grabó un anuncio para la tele.</span> — <em>In the interview, the star made a comment about reality TV and then recorded an advert for TV.</em></p>", "check": {"question": "What is ‘la telerrealidad’?", "options": ["reality TV", "a local radio station", "a newspaper article", "a live outdoor concert"], "answer": 0, "explain": "la telerrealidad = reality TV, a TV genre often linked to celebrity culture."}}, {"title": "Fame, society, nation and politics", "html": "<p>Some celebrities use their fame to talk about <span data-say=\"la sociedad\">la sociedad</span> (society) and <span data-say=\"la política\">la política</span> <span class=\"tier-h\">H</span> (politics) — for example, encouraging fans to <span data-say=\"votar\">votar</span> (to vote).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"nacional\">nacional</span> <span class=\"tier-h\">H</span></td><td>national</td><td><span data-say=\"internacional\">internacional</span> <span class=\"tier-h\">H</span></td><td>international</td></tr>\n              <tr><td><span data-say=\"mundial\">mundial</span> <span class=\"tier-h\">H</span></td><td>world(wide)</td><td><span data-say=\"la cultura\">la cultura</span></td><td>culture</td></tr>\n              <tr><td><span data-say=\"cultural\">cultural</span></td><td>cultural</td><td><span data-say=\"la identidad\">la identidad</span></td><td>identity</td></tr>\n              <tr><td><span data-say=\"la nacionalidad\">la nacionalidad</span> <span class=\"tier-h\">H</span></td><td>nationality</td><td><span data-say=\"la discriminación\">la discriminación</span> <span class=\"tier-h\">H</span></td><td>discrimination</td></tr>\n              <tr><td><span data-say=\"el conflicto\">el conflicto</span> <span class=\"tier-h\">H</span></td><td>conflict</td><td><span data-say=\"la víctima\">la víctima</span> <span class=\"tier-h\">H</span></td><td>victim</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Es una cantante de fama mundial que habla sobre la discriminación en la sociedad y anima a sus fans a votar.\">Es una cantante de fama mundial que habla sobre la discriminación en la sociedad y anima a sus fans a votar.</span> — <em>She is a singer of worldwide fame who talks about discrimination in society and encourages her fans to vote.</em></p>\n            <p>Some celebrities campaign for the <span data-say=\"la realidad\">la realidad</span> (reality) of the <span data-say=\"víctimas\">víctimas</span> of conflict to be taken seriously.</p>", "check": {"question": "What does ‘la discriminación’ mean?", "options": ["discrimination", "a discount on a concert ticket", "a type of TV discussion show", "a national election result"], "answer": 0, "explain": "la discriminación = discrimination — many celebrities campaign against it in society."}}, {"title": "Careers in the arts and sport", "html": "<p>Fame comes from many different careers — <span data-say=\"la carrera\">la carrera</span> (career). Someone creative is <span data-say=\"el artista\">el artista / la artista</span> (artist).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el escritor\">el escritor / la escritora</span></td><td>writer</td><td><span data-say=\"el autor\">el autor / la autora</span></td><td>author</td></tr>\n              <tr><td><span data-say=\"el músico\">el músico / la música</span></td><td>musician</td><td><span data-say=\"la banda\">la banda</span></td><td>band</td></tr>\n              <tr><td><span data-say=\"el pintor\">el pintor / la pintora</span></td><td>painter</td><td><span data-say=\"el protagonista\">el/la protagonista</span> <span class=\"tier-h\">H</span></td><td>main character</td></tr>\n              <tr><td><span data-say=\"el deportista\">el/la deportista</span></td><td>sportsperson</td><td><span data-say=\"el jugador\">el jugador / la jugadora</span></td><td>player</td></tr>\n              <tr><td><span data-say=\"el personaje\">el personaje</span></td><td>the character</td><td><span data-say=\"la obra\">la obra</span> <span class=\"tier-h\">H</span></td><td>the (creative) work</td></tr>\n            </table>\n            <p>To start something new, use <span data-say=\"fundar\">fundar</span> <span class=\"tier-h\">H</span> (to found) and <span data-say=\"dirigir\">dirigir</span> <span class=\"tier-h\">H</span> (to direct/manage). Example: <span data-say=\"El escritor fundó su propia editorial y ahora dirige un nuevo proyecto en la industria musical.\">El escritor fundó su propia editorial y ahora dirige un nuevo proyecto en la industria musical.</span> — <em>The writer founded his own publishing house and now directs a new project in the music industry.</em></p>", "check": {"question": "What does ‘dirigir’ mean in this context?", "options": ["to direct or manage", "to write a whole song''s lyrics", "to sell tickets for a concert", "to give a short television interview"], "answer": 0, "explain": "dirigir = to direct or manage (a project, a company, a film)."}}, {"title": "Personality, talent, image and trends", "html": "<p>Fans often discuss a celebrity''s <span data-say=\"la personalidad\">la personalidad</span> (personality) and <span data-say=\"el carácter\">el carácter</span> (character) — plus their <span data-say=\"la imagen\">la imagen</span> (image) and <span data-say=\"el estilo\">el estilo</span> (style).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el talento\">el talento</span> <span class=\"tier-h\">H</span></td><td>talent</td><td><span data-say=\"la generación\">la generación</span> <span class=\"tier-h\">H</span></td><td>generation</td></tr>\n              <tr><td><span data-say=\"artístico\">artístico / artística</span></td><td>artistic</td><td><span data-say=\"musical\">musical</span></td><td>musical</td></tr>\n              <tr><td><span data-say=\"la moda\">la moda</span></td><td>fashion</td><td><span data-say=\"de moda\">de moda</span></td><td>fashionable / trendy</td></tr>\n              <tr><td><span data-say=\"la tendencia\">la tendencia</span> <span class=\"tier-h\">H</span></td><td>trend</td><td><span data-say=\"el lujo\">el lujo</span> <span class=\"tier-h\">H</span></td><td>luxury</td></tr>\n              <tr><td><span data-say=\"el sueño\">el sueño</span></td><td>dream</td><td><span data-say=\"la imaginación\">la imaginación</span> <span class=\"tier-h\">H</span></td><td>imagination</td></tr>\n              <tr><td><span data-say=\"orgulloso\">orgulloso / orgullosa</span> <span class=\"tier-h\">H</span></td><td>proud</td><td><span data-say=\"apropiado\">apropiado / apropiada</span> <span class=\"tier-h\">H</span></td><td>appropriate</td></tr>\n              <tr><td><span data-say=\"guapo\">guapo / guapa</span></td><td>good-looking</td><td colspan=\"2\"></td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Tiene mucho talento e imaginación, siempre lleva ropa de moda y está muy orgullosa de su estilo artístico.\">Tiene mucho talento e imaginación, siempre lleva ropa de moda y está muy orgullosa de su estilo artístico.</span> — <em>She has a lot of talent and imagination, she always wears fashionable clothes and is very proud of her artistic style.</em></p>", "check": {"question": "What does ‘orgullosa’ describe in this sentence?", "options": ["feeling proud", "feeling embarrassed", "feeling completely exhausted", "feeling nervous about an interview"], "answer": 0, "explain": "orgulloso/orgullosa = proud. It agrees in gender with the person it describes."}}]}, "terms": {"enabled": true, "pairs": [{"term": "famoso / famosa", "definition": "famous"}, {"term": "la fama", "definition": "fame"}, {"term": "la estrella", "definition": "the star (celebrity)"}, {"term": "el/la cantante", "definition": "singer"}, {"term": "el actor / la actriz", "definition": "actor / actress"}, {"term": "el/la futbolista", "definition": "footballer"}, {"term": "el/la influencer", "definition": "influencer"}, {"term": "las redes sociales", "definition": "social media"}, {"term": "seguir a (alguien)", "definition": "to follow (someone)"}, {"term": "el/la seguidor(a)", "definition": "follower"}, {"term": "tener éxito", "definition": "to be successful"}, {"term": "ganar mucho dinero", "definition": "to earn a lot of money"}, {"term": "mi ídolo", "definition": "my idol"}, {"term": "un buen / mal modelo a seguir", "definition": "a good / bad role model"}, {"term": "la ventaja · la desventaja", "definition": "advantage · disadvantage"}, {"term": "perder la privacidad", "definition": "to lose your privacy"}, {"term": "dar dinero a organizaciones benéficas", "definition": "to give money to charities"}, {"term": "no creo que sea… (H)", "definition": "I don’t think it is… (subjunctive)"}, {"term": "la obra", "definition": "the (creative) work"}, {"term": "el nombre", "definition": "the name"}, {"term": "nacional", "definition": "national"}, {"term": "la realidad", "definition": "reality"}, {"term": "la relación", "definition": "the relationship"}, {"term": "el amor", "definition": "love"}, {"term": "la sociedad", "definition": "society"}, {"term": "(tú) juegas", "definition": "(you) play"}, {"term": "el proyecto", "definition": "the project"}, {"term": "la imagen", "definition": "the image"}, {"term": "dirigir", "definition": "to direct / manage"}, {"term": "reconocer", "definition": "to recognise"}, {"term": "nacer", "definition": "to be born"}, {"term": "especial", "definition": "special"}, {"term": "la política", "definition": "politics"}, {"term": "el sueño", "definition": "dream"}, {"term": "internacional", "definition": "international"}, {"term": "la cultura", "definition": "culture"}, {"term": "la carrera", "definition": "career"}, {"term": "el comentario", "definition": "the comment"}, {"term": "el autor / la autora", "definition": "the author"}, {"term": "el miembro", "definition": "the member"}, {"term": "mundial", "definition": "world(wide)"}, {"term": "el personaje", "definition": "the character"}, {"term": "el estilo", "definition": "style"}, {"term": "llorar", "definition": "to cry"}, {"term": "casarse (con)", "definition": "to get married (to)"}, {"term": "el impuesto", "definition": "tax"}, {"term": "cultural", "definition": "cultural"}, {"term": "popular", "definition": "popular"}, {"term": "separar / separarse", "definition": "to separate / to split up"}, {"term": "el carácter", "definition": "character (personality)"}, {"term": "el/la artista", "definition": "the artist"}, {"term": "la tele / la televisión", "definition": "TV / television"}, {"term": "el escritor / la escritora", "definition": "the writer"}, {"term": "la pareja", "definition": "couple / partner"}, {"term": "la generación", "definition": "generation"}, {"term": "la radio", "definition": "radio"}, {"term": "el marido", "definition": "husband"}, {"term": "la letra", "definition": "the lyrics / the letter"}, {"term": "la prensa", "definition": "the press"}, {"term": "la industria", "definition": "industry"}, {"term": "el jugador / la jugadora", "definition": "the player"}, {"term": "el conflicto", "definition": "conflict"}, {"term": "el sonido", "definition": "sound"}, {"term": "el premio", "definition": "the prize / award"}, {"term": "el respeto", "definition": "respect"}, {"term": "muerto / muerta", "definition": "dead"}, {"term": "el matrimonio", "definition": "marriage"}, {"term": "la víctima", "definition": "the victim"}, {"term": "relacionarse con", "definition": "to interact / relate to"}, {"term": "musical", "definition": "musical"}, {"term": "la marca", "definition": "the brand"}, {"term": "fundar", "definition": "to found / establish"}, {"term": "la tendencia", "definition": "the trend"}, {"term": "la banda", "definition": "the band"}, {"term": "artístico / artística", "definition": "artistic"}, {"term": "la moda / de moda", "definition": "fashion / fashionable, trendy"}, {"term": "la personalidad", "definition": "personality"}, {"term": "grabar", "definition": "to record"}, {"term": "la entrevista", "definition": "the interview"}, {"term": "la droga", "definition": "drug"}, {"term": "promover", "definition": "to promote"}, {"term": "el comportamiento", "definition": "behaviour"}, {"term": "el espectáculo", "definition": "the show"}, {"term": "la identidad", "definition": "identity"}, {"term": "votar", "definition": "to vote"}, {"term": "la actuación", "definition": "the performance"}, {"term": "el pintor / la pintora", "definition": "the painter"}, {"term": "la imaginación", "definition": "imagination"}, {"term": "el/la protagonista", "definition": "the main character"}, {"term": "engañar", "definition": "to deceive / trick"}, {"term": "el músico / la música", "definition": "the musician"}, {"term": "el anuncio", "definition": "advert / announcement"}, {"term": "el lujo", "definition": "luxury"}, {"term": "el talento", "definition": "talent"}, {"term": "digital", "definition": "digital"}, {"term": "orgulloso / orgullosa", "definition": "proud"}, {"term": "apropiado / apropiada", "definition": "appropriate"}, {"term": "el aficionado / la aficionada", "definition": "the fan (enthusiast)"}, {"term": "casado / casada", "definition": "married"}, {"term": "la discriminación", "definition": "discrimination"}, {"term": "la nacionalidad", "definition": "nationality"}, {"term": "guapo / guapa", "definition": "good-looking"}, {"term": "soltero / soltera", "definition": "single (unmarried)"}, {"term": "el/la deportista", "definition": "the sportsperson"}, {"term": "divorciarse", "definition": "to get divorced"}, {"term": "los medios de comunicación", "definition": "the media"}, {"term": "la telerrealidad", "definition": "reality TV"}, {"term": "el mejor / la mejor", "definition": "the best"}, {"term": "la manera", "definition": "the way / manner"}, {"term": "igual", "definition": "equal / the same"}, {"term": "el principio", "definition": "the beginning / principle"}, {"term": "seguro / segura", "definition": "sure / safe"}, {"term": "próximo / próxima", "definition": "next"}, {"term": "la diferencia", "definition": "the difference"}, {"term": "el objeto", "definition": "the object"}, {"term": "mío / mía", "definition": "mine"}, {"term": "la pena", "definition": "shame / pity"}, {"term": "la expresión", "definition": "the expression"}, {"term": "la distancia", "definition": "the distance"}, {"term": "actualmente", "definition": "nowadays / currently (false friend — not ‘actually’)"}, {"term": "septiembre", "definition": "September"}, {"term": "marzo", "definition": "March"}, {"term": "dispuesto / dispuesta", "definition": "willing"}, {"term": "el evento", "definition": "the event"}, {"term": "la iniciativa", "definition": "the initiative"}, {"term": "un montón (de)", "definition": "a lot (of) / loads (of)"}, {"term": "negativo / negativa", "definition": "negative"}, {"term": "el permiso", "definition": "permission"}, {"term": "el martes", "definition": "Tuesday"}, {"term": "buenos días", "definition": "good morning"}, {"term": "guay", "definition": "cool / great (informal)"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Mi ídolo es una cantante.\" data-listen></span><br>Listen. What does the speaker say?", "options": ["Her idol is a singer", "Her idol is a famous footballer", "Her idol is a very rich actress", "Her idol used to be a singer"], "answer": 0, "explain": "‘Mi ídolo es una cantante’ = my idol is a singer. The traps swap the profession or add untrue extra detail (very rich, used to be)."}, {"question": "<span data-say=\"Sigo a muchos famosos en las redes sociales.\" data-listen></span><br>Listen. What does she say?", "options": ["She follows lots of celebrities on social media", "She never follows any celebrities on social media at all", "She used to follow one celebrity online", "She only follows one influencer nowadays"], "answer": 0, "explain": "‘sigo a muchos famosos en las redes sociales’ = I follow lots of celebrities on social media. B reverses it with ‘nunca’; C/D change the quantity and the tense."}, {"question": "What does ‘tener éxito’ mean?", "options": ["to be successful", "to have an exit nearby", "to feel very tired", "to lose all your money"], "answer": 0, "explain": "tener éxito = to be successful / have success. It is a classic false-friend trap — ‘éxito’ looks like ‘exit’ but does not mean that."}, {"question": "Complete: ‘Creo que Rosalía ___ un buen modelo a seguir.’", "options": ["es", "sea", "está", "fue"], "answer": 0, "explain": "A POSITIVE opinion (creo que) takes the ordinary indicative → es. ‘sea’ (subjunctive) is only needed after a NEGATIVE opinion like ‘no creo que’."}, {"question": "Higher: complete: ‘No creo que la fama ___ fácil.’", "options": ["sea", "es", "será", "era"], "answer": 0, "explain": "After the NEGATIVE opinion ‘no creo que’, Spanish needs the SUBJUNCTIVE → sea, not the indicative ‘es’."}, {"question": "What does ‘perder la privacidad’ mean?", "options": ["to lose your privacy", "to win a privacy prize", "to protect your privacy well", "to share your privacy online"], "answer": 0, "explain": "perder la privacidad = to lose your privacy, a key disadvantage of fame. The other options invert or misdirect the meaning."}, {"question": "<span data-say=\"Los famosos sienten mucha presión.\" data-listen></span><br>Listen. What is being described?", "options": ["Celebrities feel a lot of pressure", "Celebrities never feel any pressure", "Celebrities enjoy a little pressure", "Celebrities used to feel pressure"], "answer": 0, "explain": "‘sienten mucha presión’ = they feel a lot of pressure. B reverses it with ‘nunca’; C weakens ‘mucha’ to ‘a little’; D changes the tense."}, {"question": "Which sentence uses ‘seguir a’ correctly?", "options": ["Sigo a mi cantante favorita en Instagram.", "Sigo mi cantante favorita en Instagram.", "Sigo de mi cantante favorita en Instagram.", "Soy sigo mi cantante favorita en Instagram."], "answer": 0, "explain": "seguir a + a person needs the personal ‘a’: sigo A mi cantante favorita. B drops the ‘a’; C/D use the wrong preposition or an extra verb."}, {"question": "How do you say ‘more famous than’?", "options": ["más famoso que", "más famoso como", "tan famoso que", "el más famoso"], "answer": 0, "explain": "Comparative ‘more … than’ = más + adjective + QUE. ‘como’ means ‘as’; ‘tan…que’ is a different structure; ‘el más’ is the superlative."}, {"question": "Which sentence combines an OPINION with a REASON (porque)?", "options": ["Creo que es un buen modelo a seguir porque ayuda a mucha gente.", "Es muy famosa y tiene mucho dinero y mucho éxito todo el tiempo.", "Pienso que es famosa.", "Ayuda a la gente."], "answer": 0, "explain": "Only option A has an opinion phrase (creo que) AND a reason (porque). B is just a longer list of facts with no opinion phrase or reason at all."}, {"question": "What does ‘reconocer a alguien’ mean?", "options": ["to recognise someone", "to interview someone on the radio", "to lose weight before an event", "to give a short television interview"], "answer": 0, "explain": "reconocer = to recognise. Fans often ‘reconocen’ a celebrity in the street."}, {"question": "What does ‘un aficionado del fútbol’ mean?", "options": ["a football fan", "a football referee", "a professional football player", "a worker at a football stadium"], "answer": 0, "explain": "un aficionado / una aficionada = a fan or enthusiast, not a professional — that word is jugador (player)."}, {"question": "What does ‘engañar a los fans’ mean?", "options": ["to deceive the fans", "to thank the fans warmly", "to meet the fans in person", "to disappoint the fans slightly"], "answer": 0, "explain": "engañar = to deceive or trick. A scandal often happens when a celebrity is caught engañando (deceiving) the public."}, {"question": "Muchos famosos promueven un estilo de vida saludable. What does ‘promover’ mean?", "options": ["to promote", "to forbid completely", "to copy exactly", "to criticise very heavily"], "answer": 0, "explain": "promover = to promote. Celebrities often use their platform to promover (promote) good causes."}, {"question": "In celebrity news, what does ‘un problema con las drogas’ describe?", "options": ["a drug problem", "a money problem", "a marriage problem", "a problem with the press"], "answer": 0, "explain": "la droga = drug(s). This phrase is common in stories about a celebrity''s struggles."}, {"question": "What does ‘la letra de la canción’ mean?", "options": ["the lyrics of the song", "the melody and rhythm of a song", "the price of a single song download", "the length of the song in minutes"], "answer": 0, "explain": "la letra = the lyrics (of a song) — also means ‘letter’ of the alphabet in other contexts."}, {"question": "What does ‘un buen comportamiento’ mean?", "options": ["good behaviour", "a good haircut", "a good salary", "a good relationship with fans"], "answer": 0, "explain": "el comportamiento = behaviour. The press often comments on a celebrity''s comportamiento."}, {"question": "What does ‘relacionarse con los fans’ mean?", "options": ["to interact with the fans", "to ignore the fans completely", "to avoid meeting the fans", "to sell tickets to the fans"], "answer": 0, "explain": "relacionarse con = to interact / relate to. Many celebrities relacionarse con (interact with) fans on social media."}, {"question": "Which phrase correctly means ‘the best actor’?", "options": ["el mejor actor", "el más actor", "el actor mejor que", "un actor más bueno"], "answer": 0, "explain": "‘el mejor’ is the irregular superlative of bueno and already means ‘the best’ — Spanish never adds ‘más’ in front of it."}, {"question": "What does ‘Estoy seguro de que va a ganar el premio’ mean?", "options": ["I am sure that she is going to win the prize", "I am afraid that she is going to lose the prize", "I hope that she is going to win the prize eventually", "I doubt that she is ever going to win the prize"], "answer": 0, "explain": "estar seguro de que = to be sure that. The other options change the meaning to fear, hope or doubt."}]}, "fib": {"enabled": true, "questions": [{"text": "Mi ídolo es una [cantante]. <span data-say=\"Mi ídolo es una cantante.\" data-listen>Mi ídolo es una cantante.</span>"}, {"text": "Los famosos [sienten] mucha presión. <span data-say=\"Los famosos sienten mucha presión.\" data-listen>Los famosos sienten mucha presión.</span>"}, {"text": "Sigo [a] mi cantante favorita en Instagram. (the personal preposition before a person)"}, {"text": "Creo que [es] un buen modelo a seguir. (to be — present tense, positive opinion)"}, {"text": "No creo que la fama [sea] fácil. (H — to be, subjunctive after a negative opinion)"}, {"text": "Los famosos pierden la [privacidad]. (privacy)"}, {"text": "Da dinero a organizaciones [benéficas]. (charitable)"}, {"text": "Su [nombre] artístico es distinto de su identidad legal real. (stage name)"}, {"text": "Tú [juegas] un papel muy importante en esta película, ¿verdad? (you play — tú form)"}, {"text": "Esta estrella tiene un talento muy [especial] para la música. (special)"}, {"text": "Ella es [miembro] del grupo desde 2015. (member)"}, {"text": "El actor empezó a [llorar] durante la entrevista emotiva. (to cry)"}, {"text": "Los famosos ricos tienen que pagar mucho [impuesto] cada año. (tax)"}, {"text": "Esta cantante es muy [popular] entre los jóvenes. (popular)"}, {"text": "Ganó un [premio] importante por su nuevo álbum. (prize)"}, {"text": "Los fans le tienen mucho [respeto] a su ídolo. (respect)"}, {"text": "El futbolista tiene su propia [marca] de ropa deportiva. (brand)"}, {"text": "Todo el público aplaudió su [actuación] en el concierto. (H — performance)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘la fama’ means ‘the family’.", "answer": false, "explain": "la fama = fame; la familia = family — similar spelling, different meaning."}, {"statement": "‘seguir a’ + a person needs the personal ‘a’.", "answer": true, "explain": "Sigo A mi cantante favorita — the personal ‘a’ is required before a person."}, {"statement": "After ‘creo que’ (a positive opinion), Spanish uses the ordinary indicative: creo que es…", "answer": true, "explain": "Positive opinions keep the indicative; only a NEGATIVE opinion triggers the subjunctive."}, {"statement": "After ‘no creo que’ (a negative opinion), Spanish uses the subjunctive: no creo que sea…", "answer": true, "explain": "H: no creo que + subjunctive (sea), not the indicative (es)."}, {"statement": "‘tener éxito’ means ‘to have an exit’.", "answer": false, "explain": "False friend! tener éxito means to be successful."}, {"statement": "‘más famoso que’ means ‘as famous as’.", "answer": false, "explain": "más…que = more…than. ‘As…as’ would be tan…como."}, {"statement": "Giving money to charity is an example of using fame in a positive way.", "answer": true, "explain": "dar dinero a organizaciones benéficas is a classic advantage of fame."}, {"statement": "Losing your privacy is listed as an ADVANTAGE of being famous.", "answer": false, "explain": "Losing your privacy (perder la privacidad) is a DISADVANTAGE, not an advantage."}, {"statement": "‘Estoy seguro de que…’ means ‘I doubt that…’.", "answer": false, "explain": "estar seguro de que = to be sure that — the opposite of doubting (dudar que)."}, {"statement": "‘el mejor actor’ means ‘the best actor’.", "answer": true, "explain": "el mejor is the irregular superlative of bueno, meaning ‘the best’."}, {"statement": "‘Se separaron el año pasado’ means they got married last year.", "answer": false, "explain": "separarse = to split up, the opposite of casarse (to get married)."}, {"statement": "‘la telerrealidad’ refers to reality TV shows.", "answer": true, "explain": "la telerrealidad = reality TV, a genre closely linked to celebrity culture."}, {"statement": "‘Tiene mucho talento’ means ‘she has a lot of luck’.", "answer": false, "explain": "el talento = talent; luck is la suerte — a common mix-up."}]}, "misc": {"enabled": true, "items": [{"myth": "Sigo mi cantante favorita.", "truth": "Sigo a mi cantante favorita.", "check": {"question": "What is missing from ‘Sigo mi cantante favorita’?", "options": ["the personal ‘a’ before a person", "an accent on the word ‘cantante’", "the article ‘la’ before ‘cantante’", "the reflexive pronoun ‘me’"], "answer": 0, "explain": "seguir a + a person always needs the personal ‘a’: sigo A mi cantante favorita."}}, {"myth": "Creo que es un modelo a seguir bueno.", "truth": "Creo que es un buen modelo a seguir.", "check": {"question": "Why does ‘bueno’ change to ‘buen’ here?", "options": ["‘bueno’ shortens to ‘buen’ before a masculine singular noun", "‘bueno’ is always spelt ‘buen’ in Spanish", "‘modelo’ is actually a feminine noun, so the adjective form has to change here", "adjectives always go after the noun in Spanish"], "answer": 0, "explain": "bueno shortens to buen directly before a masculine singular noun (un buen modelo), unlike most adjectives which follow the noun. ‘modelo’ is in fact masculine, which is what makes option C a real trap."}}, {"myth": "No creo que es un buen modelo a seguir.", "truth": "No creo que sea un buen modelo a seguir.", "check": {"question": "Why is ‘No creo que es…’ wrong at Higher tier?", "options": ["a negative opinion (no creo que) always needs the verb in the subjunctive, here ‘sea’", "‘es’ should always become ‘está’ after the word ‘que’, whatever the opinion happens to be", "the sentence needs the word ‘porque’ added", "‘creo’ should be ‘creí’ (past tense)"], "answer": 0, "explain": "H: no creo que + SUBJUNCTIVE (sea). Using the indicative ‘es’ after a negative opinion is the classic Higher-tier error."}}, {"myth": "Tiene mucho éxito. (I understand this as ‘has many exits’)", "truth": "Tiene mucho éxito. (= is very successful)", "check": {"question": "What does ‘éxito’ really mean here?", "options": ["success", "an exit from a building", "money or riches", "fame on social media only"], "answer": 0, "explain": "éxito = success (false friend with English ‘exit’, which in Spanish is ‘la salida’)."}}, {"myth": "Es más famoso como su hermano.", "truth": "Es más famoso que su hermano.", "check": {"question": "Which linking word completes a comparative (‘more…than’)?", "options": ["que", "como", "cuando", "donde"], "answer": 0, "explain": "más + adjective + QUE = more…than. ‘como’ (as) is used in a different structure (tan…como)."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Celebrity-culture sentences reuse chunks you know: ‘creo que…’, ‘sigo a…’, ‘tiene éxito’. Listen for whether an opinion is positive (creo que + indicative) or negative (no creo que + subjunctive) — the verb ending changes.", "check": {"question": "You hear ‘…no creo que sea…’. What form is ‘sea’?", "options": ["the subjunctive, after a negative opinion", "just the ordinary present tense, nothing special", "a completed past-tense action", "a direct command"], "answer": 0, "explain": "‘sea’ is the subjunctive form of ser, triggered by the negative opinion ‘no creo que’."}}, {"title": "Paper 3 — Reading &amp; translation into English", "html": "Watch the false friends: ‘éxito’ = success, not exit; ‘privacidad’ = privacy. Keep translations natural: ‘she loses her privacy’, not a word-for-word rendering.", "check": {"question": "‘Los famosos pierden la privacidad y sienten mucha presión’ =", "options": ["Celebrities lose their privacy and feel a lot of pressure", "Celebrities carefully protect their privacy and feel very relaxed", "Celebrities earn a lot of money and gain many followers", "Celebrities admire their idols and respect their fans"], "answer": 0, "explain": "pierden la privacidad = lose their privacy; sienten mucha presión = feel a lot of pressure."}}, {"title": "Paper 4 — Writing &amp; translation into Spanish", "html": "Combine an opinion, a reason and a weighed-up view: ‘Creo que es un buen modelo a seguir porque ayuda a la gente, pero no creo que la fama sea fácil.’ At Higher, the subjunctive after a negative opinion is a strong feature to include.", "check": {"question": "Which answer reaches the top band?", "options": ["Creo que es un buen modelo a seguir porque ayuda a la gente, pero no creo que la fama sea fácil", "Es famosa y muy famosa y increíblemente famosa y tiene mucho dinero y mucho éxito todo el tiempo sin parar nunca", "Es famosa", "Tiene éxito"], "answer": 0, "explain": "It links a positive opinion with a reason AND a Higher-tier subjunctive clause — range and accuracy beats a rambling, repetitive list of adjectives."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Sofía says. Answer <strong>in English</strong>.<br>(a) Who is Sofía''s idol and what does she do? (1)<br>(b) Give <strong>one</strong> reason Sofía admires her. (1)<br>(c) Name <strong>one</strong> disadvantage of fame mentioned. (1)<br>(d) Why doesn''t Sofía want to be famous? (1)", "marks": 4, "hint": "Find the profession after ‘una cantante española’, the reasons after ‘porque’, the disadvantages after ‘desventajas’, and the final reason after the last ‘porque’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> Rosalía / a (Spanish) singer <em>(1)</em>.</li>\n                <li><strong>(b)</strong> she is successful / she helps people / she gives money to charities (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> losing privacy / feeling a lot of pressure (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> she prefers her quiet/calm life <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) In my opinion, she is a good role model. <br>(b) I don''t think fame is easy. <br>(c) Footballers earn a lot of money because they have a lot of success.", "marks": 5, "hint": "‘In my opinion’ = En mi opinión… ‘I don''t think’ (negative opinion) needs the SUBJUNCTIVE: No creo que… sea… ‘have a lot of success’ = tienen mucho éxito.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> En mi opinión, es un buen modelo a seguir. <em>(1)</em></li>\n                <li><strong>(b)</strong> No creo que la fama sea fácil. <em>(1)</em></li>\n                <li><strong>(c)</strong> Los futbolistas ganan mucho dinero <em>(1)</em> porque <em>(1)</em> tienen mucho éxito <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘No creo que la fama sea fácil’ must use the subjunctive ‘sea’, not ‘es’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '7-1-holidays-transport-and-places', '7.1 Holidays, Transport and Places', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about holidays and places?", "html": "<p>The key expression is <span data-say=\"ir de vacaciones\">ir de vacaciones</span> (to go on holiday). Here is the core vocabulary for holiday destinations — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"las vacaciones\">las vacaciones</span></td><td>holidays</td><td><span data-say=\"ir de vacaciones\">ir de vacaciones</span></td><td>to go on holiday</td></tr>\n              <tr><td><span data-say=\"la playa\">la playa</span></td><td>the beach</td><td><span data-say=\"la montaña\">la montaña</span></td><td>the mountain</td></tr>\n              <tr><td><span data-say=\"el campo\">el campo</span></td><td>the countryside</td><td><span data-say=\"el pasaporte\">el pasaporte</span></td><td>passport</td></tr>\n              <tr><td><span data-say=\"el turista\">el turista</span></td><td>tourist (m)</td><td><span data-say=\"la turista\">la turista</span></td><td>tourist (f)</td></tr>\n              <tr><td><span data-say=\"Sudamérica\">Sudamérica</span></td><td>South America</td><td><span data-say=\"disfrutar de\">disfrutar de</span></td><td>to enjoy</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En verano, me gusta ir de vacaciones a la playa.\">En verano, me gusta ir de vacaciones a la playa.</span> — <em>In summer, I like to go on holiday to the beach.</em></p>\n            <p>Some students dream of travelling further afield: <span data-say=\"Me gustaría viajar a Sudamérica y disfrutar de la cultura.\">Me gustaría viajar a Sudamérica y disfrutar de la cultura.</span> — <em>I would like to travel to South America and enjoy the culture.</em></p>", "check": {"question": "What does ‘la montaña’ mean?", "options": ["the mountain", "the countryside", "the beach", "the passport"], "answer": 0, "explain": "la montaña = the mountain. el campo = the countryside, la playa = the beach, el pasaporte = the passport."}}, {"title": "How do I talk about accommodation?", "html": "<p>To describe where you stay, you need these nouns and verbs — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el hotel\">el hotel</span></td><td>the hotel</td><td><span data-say=\"el camping\">el camping</span></td><td>the campsite</td></tr>\n              <tr><td><span data-say=\"la maleta\">la maleta</span></td><td>the suitcase</td><td><span data-say=\"reservar\">reservar</span></td><td>to book</td></tr>\n              <tr><td><span data-say=\"la habitación\">la habitación</span></td><td>the room</td><td><span data-say=\"alojarse\">alojarse</span></td><td>to stay (lodge)</td></tr>\n              <tr><td><span data-say=\"quedarse\">quedarse</span></td><td>to stay</td><td><span data-say=\"hacer la maleta\">hacer la maleta</span></td><td>to pack</td></tr>\n              <tr><td><span data-say=\"el alojamiento\">el alojamiento</span></td><td>the accommodation</td><td><span data-say=\"la llave\">la llave</span></td><td>the key</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Reservé una habitación en un hotel cerca de la playa.\">Reservé una habitación en un hotel cerca de la playa.</span> — <em>I booked a room in a hotel near the beach.</em></p>\n            <p>Not everything goes to plan: <span data-say=\"El alojamiento era barato, pero tuve que quejarme porque el hotel estaba lleno.\">El alojamiento era barato, pero tuve que quejarme porque el hotel estaba lleno.</span> — <em>The accommodation was cheap, but I had to complain because the hotel was full.</em> <span data-say=\"El otro hotel era más caro, pero tenía la llave lista para nosotros.\">El otro hotel era más caro, pero tenía la llave lista para nosotros.</span> — <em>The other hotel was more expensive, but had the key ready for us.</em></p>\n            <p>When booking, remember to check the date: <span data-say=\"Reservé el alojamiento para el diez de octubre.\">Reservé el alojamiento para el diez de octubre.</span> — <em>I booked the accommodation for the tenth of October.</em> <span data-say=\"No podía cambiar la fecha de la reserva.\">No podía cambiar la fecha de la reserva.</span> — <em>I couldn''t change the date of the booking.</em></p>", "check": {"question": "What does ‘la habitación’ mean?", "options": ["the room", "the suitcase", "the hotel", "the passport"], "answer": 0, "explain": "la habitación = the room. la maleta = the suitcase, el hotel = the hotel, el pasaporte = the passport."}}, {"title": "How do I talk about transport?", "html": "<p>Use <strong>viajar en</strong> + transport (to travel by), or <strong>coger</strong>/<strong>tomar</strong> (to catch/take) + transport. Note that Spanish uses <strong>en</strong>, not ‘by’.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el tren\">el tren</span></td><td>the train</td><td><span data-say=\"el avión\">el avión</span></td><td>the plane</td></tr>\n              <tr><td><span data-say=\"el autobús\">el autobús</span></td><td>the bus</td><td><span data-say=\"el coche\">el coche</span></td><td>the car</td></tr>\n              <tr><td><span data-say=\"el barco\">el barco</span></td><td>the boat</td><td><span data-say=\"la bicicleta\">la bicicleta</span></td><td>the bicycle</td></tr>\n              <tr><td><span data-say=\"coger el tren\">coger el tren</span></td><td>to catch the train</td><td><span data-say=\"tomar el autobús\">tomar el autobús</span></td><td>to take the bus</td></tr>\n              <tr><td><span data-say=\"el billete\">el billete</span></td><td>the ticket</td><td><span data-say=\"un vuelo directo\">un vuelo directo</span></td><td>a direct flight</td></tr>\n            </table>\n            <p>Model sentences: <span data-say=\"Normalmente viajamos en avión, pero el año pasado cogimos el tren.\">Normalmente viajamos en avión, pero el año pasado cogimos el tren.</span> — <em>We normally travel by plane, but last year we caught the train.</em> <span data-say=\"Mis padres siempre viajan en coche.\">Mis padres siempre viajan en coche.</span> — <em>My parents always travel by car.</em></p>\n            <p>Buying tickets takes care: <span data-say=\"Antes de comprar el billete, lee la letra pequeña.\">Antes de comprar el billete, lee la letra pequeña.</span> — <em>Before buying the ticket, read the small print.</em> <span data-say=\"Tuve dificultad para reservar un billete de ida y vuelta directo.\">Tuve dificultad para reservar un billete de ida y vuelta directo.</span> — <em>I had difficulty booking a direct return ticket.</em></p>", "check": {"question": "How do you say ‘we travelled by boat’?", "options": ["Viajamos en barco", "Viajamos en coche", "Viajamos en tren", "Viajamos en autobús"], "answer": 0, "explain": "barco = boat. The distractors swap in other real transport nouns — a genuine word-recall trap."}}, {"title": "Exam skill: the PRETERITE for past holidays", "html": "<p>To describe a holiday that has already happened, use the <strong>preterite</strong> (simple past). These verbs come up constantly:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"fui\">fui</span></td><td>I went</td><td><span data-say=\"viajé\">viajé</span></td><td>I travelled</td></tr>\n              <tr><td><span data-say=\"visité\">visité</span></td><td>I visited</td><td><span data-say=\"saqué fotos\">saqué fotos</span></td><td>I took photos</td></tr>\n              <tr><td><span data-say=\"tomé el sol\">tomé el sol</span></td><td>I sunbathed</td><td><span data-say=\"compré recuerdos\">compré recuerdos</span></td><td>I bought souvenirs</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"El verano pasado fui a España. Viajé en avión y visité muchos lugares.\">El verano pasado fui a España. Viajé en avión y visité muchos lugares.</span> — <em>Last summer I went to Spain. I travelled by plane and visited many places.</em></p>\n            <p>Not every holiday moment is perfect: <span data-say=\"Al final de las vacaciones, me sentí un poco triste.\">Al final de las vacaciones, me sentí un poco triste.</span> — <em>At the end of the holiday, I felt a little sad.</em></p>", "check": {"question": "Which sentence is in the PRETERITE (a completed past action)?", "options": ["Visité el museo el sábado.", "Visito el museo cada sábado.", "Voy a visitar el museo el sábado.", "Estoy visitando el museo ahora mismo."], "answer": 0, "explain": "Visité = I visited (preterite, one completed action). The others are present, near-future and present continuous — all real tense-confusion traps."}}, {"title": "How do I talk about activities and future plans?", "html": "<p>Holiday activities combine with the near future (<strong>voy a</strong> + infinitive) or the simple future (<strong>-é / -á / -án</strong>) to describe plans.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"visitar\">visitar</span></td><td>to visit</td><td><span data-say=\"hacer turismo\">hacer turismo</span></td><td>to go sightseeing</td></tr>\n              <tr><td><span data-say=\"descansar\">descansar</span></td><td>to relax/rest</td><td><span data-say=\"ir de compras\">ir de compras</span></td><td>to go shopping</td></tr>\n              <tr><td><span data-say=\"voy a visitar\">voy a visitar</span></td><td>I am going to visit</td><td><span data-say=\"iré a la playa\">iré a la playa</span></td><td>I will go to the beach</td></tr>\n              <tr><td><span data-say=\"practicar deportes\">practicar deportes</span></td><td>to practise sports</td><td><span data-say=\"una actividad\">una actividad</span></td><td>an activity</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"El año que viene voy a ir a Francia. Voy a hacer turismo y sacar muchas fotos.\">El año que viene voy a ir a Francia. Voy a hacer turismo y sacar muchas fotos.</span> — <em>Next year I am going to go to France. I am going to go sightseeing and take lots of photos.</em></p>\n            <p>Deciding what to do takes time: <span data-say=\"De momento, no he tomado una decisión sobre las actividades.\">De momento, no he tomado una decisión sobre las actividades.</span> — <em>At the moment, I haven''t made a decision about the activities.</em></p>", "check": {"question": "How do you say ‘I am going to go shopping tomorrow’?", "options": ["Voy a ir de compras mañana", "Fui de compras ayer", "Voy de compras cada semana", "Iba de compras cuando era joven"], "answer": 0, "explain": "voy a + infinitive = near future. The distractors are preterite, present-habit and imperfect — real tense mix-ups."}}, {"title": "Higher: the conditional and the imperfect", "html": "<p><span class=\"tier-h\">H</span> Use the <strong>conditional</strong> (me gustaría = I would like) for polite wishes, and the <strong>imperfect</strong> to describe what a past holiday <em>was like</em> (background/description, not a single completed action):</p>\n            <ul>\n              <li><span data-say=\"me gustaría visitar\">me gustaría visitar</span> — I would like to visit</li>\n              <li><span data-say=\"hacía sol\">hacía sol</span> — it was sunny (ongoing weather)</li>\n              <li><span data-say=\"el hotel era muy grande\">el hotel era muy grande</span> — the hotel was very big (a description)</li>\n              <li><span data-say=\"había mucha gente\">había mucha gente</span> — there were a lot of people</li>\n            </ul>\n            <p>Combine both for the top band: <span data-say=\"Hacía sol y el hotel era muy grande. Me gustaría volver algún día.\">Hacía sol y el hotel era muy grande. Me gustaría volver algún día.</span> <span class=\"tier-h\">H</span></p>", "check": {"question": "Which sentence uses the CONDITIONAL to say what you would like to do?", "options": ["Me gustaría visitar Japón.", "Visité Japón el año pasado.", "Voy a visitar Japón este verano.", "Visitaba Japón todos los años."], "answer": 0, "explain": "Me gustaría = I would like (conditional). The others are preterite, near-future and imperfect — genuine tense traps."}}]}, "terms": {"enabled": true, "pairs": [{"term": "las vacaciones", "definition": "holidays"}, {"term": "la playa", "definition": "the beach"}, {"term": "la montaña", "definition": "the mountain"}, {"term": "el campo", "definition": "the countryside"}, {"term": "el pasaporte", "definition": "passport"}, {"term": "el turista / la turista", "definition": "tourist"}, {"term": "el hotel", "definition": "the hotel"}, {"term": "el camping", "definition": "the campsite"}, {"term": "la maleta", "definition": "the suitcase"}, {"term": "reservar una habitación", "definition": "to book a room"}, {"term": "quedarse / alojarse", "definition": "to stay"}, {"term": "el tren · el avión", "definition": "the train · the plane"}, {"term": "el autobús · el barco", "definition": "the bus · the boat"}, {"term": "viajar en tren", "definition": "to travel by train"}, {"term": "fui · viajé · visité", "definition": "I went · I travelled · I visited"}, {"term": "saqué fotos · tomé el sol", "definition": "I took photos · I sunbathed"}, {"term": "me gustaría visitar (H)", "definition": "I would like to visit"}, {"term": "hacía sol · era grande (H)", "definition": "it was sunny · it was big"}, {"term": "disfrutar (de)", "definition": "to enjoy"}, {"term": "la vuelta · de ida y vuelta", "definition": "the return · return (ticket)"}, {"term": "directo/a", "definition": "direct"}, {"term": "practicar", "definition": "to practise, to do (a sport)"}, {"term": "la llave", "definition": "the key"}, {"term": "quejarse", "definition": "to complain"}, {"term": "barato/a", "definition": "cheap"}, {"term": "caro/a", "definition": "expensive"}, {"term": "el billete", "definition": "the ticket"}, {"term": "el alojamiento", "definition": "the accommodation"}, {"term": "Sudamérica", "definition": "South America"}, {"term": "de momento", "definition": "at the moment, for now"}, {"term": "una actividad", "definition": "an activity"}, {"term": "una decisión", "definition": "a decision"}, {"term": "lleno/a", "definition": "full"}, {"term": "la fecha", "definition": "the date"}, {"term": "la letra (pequeña)", "definition": "the letter · the small print"}, {"term": "la dificultad", "definition": "the difficulty"}, {"term": "octubre", "definition": "October"}, {"term": "triste", "definition": "sad"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"El verano pasado fui a España.\" data-listen></span><br>Listen. What happened?", "options": ["I went to Spain last summer", "I am going to Spain next summer", "I go to Spain every summer", "I have never been to Spain in my life"], "answer": 0, "explain": "‘el verano pasado fui a España’ = I went to Spain last summer (preterite). The traps swap in future, habitual and negative meanings."}, {"question": "<span data-say=\"Viajamos en tren a la montaña.\" data-listen></span><br>Listen. How did they travel?", "options": ["by train", "by plane", "by bus", "by bicycle"], "answer": 0, "explain": "‘viajamos en tren’ = we travelled by train. All four are real transport words — a genuine listening trap."}, {"question": "<span data-say=\"Voy a reservar una habitación en un hotel.\" data-listen></span><br>Listen. What are they going to do?", "options": ["book a hotel room", "cancel a hotel room booking they already made", "stay in a campsite instead of a hotel", "look for a cheap hostel online"], "answer": 0, "explain": "‘voy a reservar una habitación’ = I am going to book a room. Option B reverses the meaning — a genuine mishearing trap."}, {"question": "Which sentence describes something that already happened (the preterite)?", "options": ["Visité el museo ayer.", "Visito el museo todos los años.", "Voy a visitar el museo mañana.", "Me gustaría visitar el museo algún día."], "answer": 0, "explain": "Visité = I visited (preterite + ayer = yesterday). D is the conditional, a real trap for weaker students."}, {"question": "Complete: ‘Mis padres siempre viajan ___ coche.’", "options": ["en", "a", "de", "por"], "answer": 0, "explain": "viajar en + transport = to travel by. Spanish never uses ‘a coche’ or ‘de coche’ for this meaning."}, {"question": "What does ‘el barco’ mean?", "options": ["the boat", "the beach", "the bus stop", "the mountain range"], "answer": 0, "explain": "el barco = the boat. The distractors are other travel-topic nouns — a genuine vocabulary mix-up."}, {"question": "How do you say ‘I am going to go to France next year’?", "options": ["Voy a ir a Francia el año que viene", "Fui a Francia el año pasado", "Iba a Francia cada año", "Quiero ir a Francia pero no puedo este año"], "answer": 0, "explain": "voy a + infinitive = near future plan. B is preterite, C is imperfect, D is present — all real tense confusions."}, {"question": "What does ‘hacer turismo’ mean?", "options": ["to go sightseeing", "to go shopping for souvenirs", "to book a hotel room", "to travel by public transport"], "answer": 0, "explain": "hacer turismo = to go sightseeing. The distractors are other real holiday activities on the wordlist."}, {"question": "Which sentence uses the imperfect to describe the WEATHER during a past holiday?", "options": ["Hacía sol todos los días.", "Hizo sol solo el sábado pasado.", "Va a hacer sol mañana.", "Ha hecho mucho sol este verano."], "answer": 0, "explain": "Hacía sol = it was sunny (imperfect, ongoing background). B is preterite, C is future, D is present perfect — genuine tense traps."}, {"question": "How do you say ‘I would like to visit Mexico’?", "options": ["Me gustaría visitar México", "Me gusta visitar México", "Voy a visitar México", "Visité México el año pasado"], "answer": 0, "explain": "Me gustaría = I would like (conditional). B drops the conditional, C is near-future, D is preterite — real errors."}, {"question": "What does ‘disfrutar de las vacaciones’ mean?", "options": ["to enjoy the holidays", "to complain about the holidays", "to book the holidays online", "to postpone the holidays again"], "answer": 0, "explain": "disfrutar de = to enjoy. The distractors are other real holiday-related actions students confuse it with."}, {"question": "What does ‘el hotel estaba lleno’ mean?", "options": ["the hotel was full", "the hotel was very cheap (barato)", "the hotel was very expensive (caro)", "the hotel was completely empty"], "answer": 0, "explain": "lleno = full. barato = cheap and caro = expensive are real distractor nouns from the same accommodation vocabulary; ‘empty’ is the opposite meaning."}, {"question": "What does ‘un billete de ida y vuelta directo’ mean?", "options": ["a direct return ticket", "a one-way ticket with two changes", "a cheap last-minute single ticket", "a delayed connecting flight ticket"], "answer": 0, "explain": "billete de ida y vuelta = return ticket; directo = direct (no changes). The distractors invent plausible but wrong ticket types."}]}, "fib": {"enabled": true, "questions": [{"text": "El verano pasado [fui] a España. <span data-say=\"El verano pasado fui a España.\" data-listen>El verano pasado fui a España.</span>"}, {"text": "Viajé en [tren] porque es más rápido que el autobús. (train)"}, {"text": "Voy a [reservar] una habitación en el hotel. (to book)"}, {"text": "El año que viene [iré] a Portugal. (I will go — future tense)"}, {"text": "Mi hermano [sacó] fotos de la playa todos los días. <span data-say=\"Mi hermano sacó fotos de la playa todos los días.\" data-listen>Mi hermano sacó fotos de la playa todos los días.</span>"}, {"text": "Hacía sol y el hotel [era] muy grande. (was — imperfect) <span class=\"tier-h\">H</span>"}, {"text": "Me [gustaría] visitar México algún día. (I would like — conditional) <span class=\"tier-h\">H</span>"}, {"text": "Reservé el alojamiento para el diez de [octubre]. (October)"}, {"text": "El primer hotel era barato, pero el segundo era más [caro]. (expensive)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘Ir de vacaciones’ means ‘to go on holiday’.", "answer": true, "explain": "ir de vacaciones = to go on holiday."}, {"statement": "‘El avión’ means ‘the boat’.", "answer": false, "explain": "el avión = the plane. ‘the boat’ is el barco."}, {"statement": "To describe a past holiday you normally use the preterite tense (fui, viajé, visité).", "answer": true, "explain": "The preterite describes completed past actions — exactly what a past holiday needs."}, {"statement": "‘Viajar en coche’ means ‘to travel on foot’.", "answer": false, "explain": "viajar en coche = to travel by car. ‘on foot’ is a pie."}, {"statement": "‘Me gustaría’ is an example of the conditional tense, used to say what you would like.", "answer": true, "explain": "me gustaría = I would like (conditional)."}, {"statement": "‘Reservar una habitación’ means ‘to sell a room’.", "answer": false, "explain": "reservar una habitación = to book a room, not to sell one."}, {"statement": "The imperfect tense (hacía sol, era grande) describes the background or ongoing description of a past holiday, like the weather.", "answer": true, "explain": "The imperfect sets the scene — weather, how things were — rather than single completed events."}, {"statement": "‘Sacar fotos’ means ‘to buy souvenirs’.", "answer": false, "explain": "sacar fotos = to take photos. ‘to buy souvenirs’ is comprar recuerdos."}, {"statement": "‘Practicar deportes’ means ‘to practise sports’.", "answer": true, "explain": "practicar = to practise/do (an activity); deportes = sports."}, {"statement": "‘La letra pequeña’ means ‘the big letter’.", "answer": false, "explain": "la letra pequeña = the small print (literally ‘the small letter’); pequeña = small, not big."}]}, "misc": {"enabled": true, "items": [{"myth": "Voy a quedar en un hotel.", "truth": "Voy a quedarme en un hotel.", "check": {"question": "What is missing from ‘Voy a quedar en un hotel’?", "options": ["the reflexive pronoun ‘me’ — quedarse needs it (quedarme)", "the word ‘hotel’ needs to be replaced by the word ‘hostal’ instead", "an accent should be added to the final vowel of ‘quedar’", "the preposition ‘a’ before ‘un’ should be removed completely"], "answer": 0, "explain": "quedarse is reflexive: (yo) me quedo / voy a quedarme — the pronoun cannot be dropped."}}, {"myth": "Viajamos tren a la playa.", "truth": "Viajamos en tren a la playa.", "check": {"question": "What is missing in ‘Viajamos tren a la playa’?", "options": ["the preposition ‘en’ before the transport (viajamos EN tren)", "an accent should be added somewhere on the word ‘tren’ itself", "the personal ‘a’ needs to be inserted before the word ‘tren’", "the article ‘la’ before ‘playa’ should be changed to ‘el’"], "answer": 0, "explain": "viajar en + transport always needs ‘en’; Spanish never says ‘viajar tren’."}}, {"myth": "El hotel fue muy grande.", "truth": "El hotel era muy grande.", "check": {"question": "Why should you use ‘era’ rather than ‘fue’ here?", "options": ["describing what something WAS LIKE (a background description) needs the imperfect, era", "‘fue’ is the correct preterite form of ir, not ser, so it absolutely must be used here", "‘grande’ must always be preceded by the exact word ‘fue’ in every single sentence", "both words are completely interchangeable with no difference in meaning whatsoever"], "answer": 0, "explain": "Descriptions/background (what the hotel was like) use the imperfect era, not the preterite fue."}}, {"myth": "Hice mi maletas para las vacaciones.", "truth": "Hice mis maletas para las vacaciones.", "check": {"question": "Why must ‘mi’ change to ‘mis’ here?", "options": ["‘maletas’ is plural, so the possessive must agree and become ‘mis’", "‘maletas’ is a masculine noun in Spanish, so it always needs ‘mis’", "‘hice’ is simply the wrong verb to use for packing a suitcase", "‘para’ should be replaced everywhere by the word ‘por’ instead"], "answer": 0, "explain": "Possessives agree in number with the noun: mi maleta (singular) but mis maletas (plural)."}}, {"myth": "Voy a fui a España el año que viene.", "truth": "Voy a ir a España el año que viene.", "check": {"question": "Why is ‘Voy a fui a España’ wrong?", "options": ["‘voy a’ must be followed by an infinitive, not a conjugated preterite verb", "the word ‘España’ needs the capital letter removed before it can be used correctly", "‘voy a’ should simply be changed to ‘fui a’ instead, deleting the rest", "the sentence is missing a written accent somewhere on the word ‘voy’ itself"], "answer": 0, "explain": "voy a + infinitive (ir, not fui) — mixing the near future with a conjugated preterite verb is a common error."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening / dictation", "html": "Holiday sentences constantly switch tense: listen for the ‑é / ‑í endings of the preterite (fui, viajé, visité) versus ‘voy a’ for future plans and ‘hacía / era’ for descriptions. The tense tells you WHEN, not just WHAT.", "check": {"question": "You hear ‘…hacía sol…’. What does this tell you?", "options": ["it is a background description in the imperfect (ongoing weather)", "it describes one single completed action that finished in the preterite tense", "it is a plan for next year using the near future construction", "it is a question being asked right now about today’s weather"], "answer": 0, "explain": "hacía = imperfect, used for ongoing background description such as the weather during a holiday."}}, {"title": "Paper 3 — Reading / translation into English", "html": "Watch for tense signals and prepositions: ‘en tren/avión/coche’ never translates as ‘in’ — it means ‘by train/plane/car’. Keep ‘fui de vacaciones’ natural: ‘I went on holiday’, not ‘I was of holidays’.", "check": {"question": "‘El año pasado viajamos en avión y nos alojamos en un hotel’ means…", "options": ["Last year we travelled by plane and stayed in a hotel", "Next year we will travel by train and stay in a campsite", "Every year we travel by boat and stay with family", "This year we are travelling by car and staying at home"], "answer": 0, "explain": "el año pasado = last year (preterite context); viajamos en avión = we travelled by plane; nos alojamos = we stayed."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a past holiday, a description and a future wish for the top band: ‘El verano pasado fui a la playa, hacía mucho sol y me gustaría volver.’ Mixing preterite, imperfect and the conditional shows real range.", "check": {"question": "Which answer reaches the top band?", "options": ["El verano pasado fui a la playa, hacía sol y me gustaría volver", "Fui a la playa y luego fui a la playa otra vez muchas veces seguidas", "Fui bien", "Me gusta la playa"], "answer": 0, "explain": "It links a completed past action, a background description and a conditional wish — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carla says. Answer <strong>in English</strong>.<br>(a) How did Carla and her family travel? (1)<br>(b) Where did they stay? (1)<br>(c) What did they do on the day the weather was bad? (1)<br>(d) What would Carla like to do next year? (1)", "marks": 4, "hint": "Find the transport after ‘viajamos en’, the accommodation after ‘nos alojamos’, the activity after ‘así que’, and the wish after ‘me gustaría’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> by plane <em>(1)</em>.</li>\n                <li><strong>(b)</strong> in a (very comfortable) hotel near the beach <em>(1)</em>.</li>\n                <li><strong>(c)</strong> they went shopping <em>(1)</em>.</li>\n                <li><strong>(d)</strong> visit Italy <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I went on holiday to the beach. <br>(b) We travelled by train. <br>(c) I would like to visit Portugal next year.", "marks": 5, "hint": "‘I went’ = preterite of ir (fui). ‘We travelled by train’ = Viajamos en tren. ‘I would like’ = conditional (Me gustaría).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Fui de vacaciones a la playa. <em>(1)</em></li>\n                <li><strong>(b)</strong> Viajamos en tren. <em>(1)</em></li>\n                <li><strong>(c)</strong> Me gustaría visitar Portugal <em>(1)</em> el año que viene <em>(1)</em> — accurate conditional form <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Me gustaría’ must show the conditional, not ‘me gusta’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '7-2-my-region-and-places-of-interest', '7.2 My Region and Places of Interest', '{"learn": {"enabled": true, "items": [{"title": "How do I describe my area or region?", "html": "<p>Use these nouns to say what kind of place you live in, and the compass points to say where it is. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi región\">mi región</span></td><td>my region</td><td><span data-say=\"mi ciudad\">mi ciudad</span></td><td>my city</td></tr>\n              <tr><td><span data-say=\"el pueblo\">el pueblo</span></td><td>the town / village</td><td><span data-say=\"la costa\">la costa</span></td><td>the coast</td></tr>\n              <tr><td><span data-say=\"el campo\">el campo</span></td><td>the countryside</td><td><span data-say=\"el norte\">el norte</span></td><td>the north</td></tr>\n              <tr><td><span data-say=\"el sur\">el sur</span></td><td>the south</td><td><span data-say=\"el este\">el este</span></td><td>the east</td></tr>\n              <tr><td><span data-say=\"el oeste\">el oeste</span></td><td>the west</td><td><span data-say=\"vivo en\">vivo en…</span></td><td>I live in…</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Vivo en un pueblo pequeño en el norte de España, cerca de la costa.\">Vivo en un pueblo pequeño en el norte de España, cerca de la costa.</span> — <em>I live in a small town in the north of Spain, near the coast.</em></p>\n            <p>Comparing towns is a great way to add detail: <span data-say=\"Ambos pueblos están cerca de la costa, pero tengo mi propio pueblo favorito porque es un lugar maravilloso.\">Ambos pueblos están cerca de la costa, pero tengo mi propio pueblo favorito porque es un lugar maravilloso.</span> — <em>Both towns are near the coast, but I have my own favourite town because it''s a marvellous place.</em></p>", "check": {"question": "What does ‘el campo’ mean?", "options": ["the north coastline", "the town centre square", "the countryside", "the eastern border area"], "answer": 2, "explain": "el campo = the countryside. The distractors invent locations that aren’t what campo means."}}, {"title": "What places of interest are there? (hay + noun)", "html": "<p>To say something exists somewhere, use <strong>hay</strong> (there is / there are) — it never changes form, whether the noun is singular or plural.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el museo\">el museo</span></td><td>the museum</td><td><span data-say=\"el castillo\">el castillo</span></td><td>the castle</td></tr>\n              <tr><td><span data-say=\"la catedral\">la catedral</span></td><td>the cathedral</td><td><span data-say=\"la iglesia\">la iglesia</span></td><td>the church</td></tr>\n              <tr><td><span data-say=\"la plaza\">la plaza</span></td><td>the square</td><td><span data-say=\"el monumento\">el monumento</span></td><td>the monument</td></tr>\n              <tr><td><span data-say=\"el parque\">el parque</span></td><td>the park</td><td><span data-say=\"el mercado\">el mercado</span></td><td>the market</td></tr>\n              <tr><td><span data-say=\"el teatro\">el teatro</span></td><td>the theatre</td><td><span data-say=\"hay\">hay</span></td><td>there is / are</td></tr>\n              <tr><td><span data-say=\"un sitio turístico\">un sitio turístico</span></td><td>a tourist spot</td><td><span data-say=\"hace falta visitar\">hace falta visitar</span></td><td>it''s necessary to visit</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi ciudad hay un castillo histórico, una catedral bonita y muchos museos.\">En mi ciudad hay un castillo histórico, una catedral bonita y muchos museos.</span> — <em>In my city there is a historic castle, a pretty cathedral and lots of museums.</em></p>\n            <p>There''s always more to see: <span data-say=\"Todavía hay muchos sitios turísticos que no he visitado; hace falta volver algún día.\">Todavía hay muchos sitios turísticos que no he visitado; hace falta volver algún día.</span> — <em>There are still many tourist spots I haven''t visited; it''s necessary to come back someday.</em></p>", "check": {"question": "Which word means ‘there is / there are’ and never changes form?", "options": ["está", "hay", "son", "tiene"], "answer": 1, "explain": "hay is invariable — un castillo hay, dos castillos hay. está/son/tiene all change and need a different structure."}}, {"title": "How do I describe places? (ser vs estar)", "html": "<p>Use <strong>ser</strong> for a permanent characteristic (what a place is like), and <strong>estar</strong> for where it is located — never mix them up.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"histórico\">histórico / histórica</span></td><td>historic</td><td><span data-say=\"turístico\">turístico / turística</span></td><td>touristy</td></tr>\n              <tr><td><span data-say=\"tranquilo\">tranquilo / tranquila</span></td><td>quiet, peaceful</td><td><span data-say=\"animado\">animado / animada</span></td><td>lively</td></tr>\n              <tr><td><span data-say=\"bonito\">bonito / bonita</span></td><td>pretty</td><td><span data-say=\"industrial\">industrial</span></td><td>industrial</td></tr>\n              <tr><td><span data-say=\"moderno\">moderno / moderna</span></td><td>modern</td><td><span data-say=\"antiguo\">antiguo / antigua</span></td><td>old, ancient</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi ciudad es muy turística y animada, pero está lejos de la costa.\">Mi ciudad es muy turística y animada, pero está lejos de la costa.</span> — <em>My city is very touristy and lively, but it is far from the coast.</em></p>\n            <p>Older buildings often stand out: <span data-say=\"El castillo es de la Edad Media, así que da una sensación de historia.\">El castillo es de la Edad Media, así que da una sensación de historia.</span> — <em>The castle is from the Middle Ages, so it gives a sense of history.</em> <span data-say=\"La mitad del pueblo es antigua y la otra mitad es moderna.\">La mitad del pueblo es antigua y la otra mitad es moderna.</span> — <em>Half the town is old and the other half is modern.</em></p>", "check": {"question": "Which verb do you use for ‘my town IS historic’ — a permanent characteristic?", "options": ["estar → mi pueblo está histórico", "hay → mi pueblo hay histórico", "tener → mi pueblo tiene histórico", "ser → mi pueblo es histórico"], "answer": 3, "explain": "A lasting characteristic uses ser: es histórico. estar/hay/tener cannot combine with an adjective this way."}}, {"title": "How do I ask for and give directions?", "html": "<p>Use <strong>estar</strong> to say exactly where something is once it has already been introduced with hay.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"¿dónde está?\">¿Dónde está…?</span></td><td>Where is…?</td><td><span data-say=\"a la derecha\">a la derecha</span></td><td>to the right</td></tr>\n              <tr><td><span data-say=\"a la izquierda\">a la izquierda</span></td><td>to the left</td><td><span data-say=\"todo recto\">todo recto</span></td><td>straight on</td></tr>\n              <tr><td><span data-say=\"cerca de\">cerca de</span></td><td>close to, near</td><td><span data-say=\"lejos de\">lejos de</span></td><td>far from</td></tr>\n              <tr><td><span data-say=\"al lado de\">al lado de</span></td><td>next to</td><td><span data-say=\"en el centro\">en el centro</span></td><td>in the centre</td></tr>\n              <tr><td><span data-say=\"el plano\">el plano</span></td><td>the map</td><td><span data-say=\"delante de\">delante de</span></td><td>in front of</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El museo está al lado de la catedral: todo recto y luego a la derecha.\">El museo está al lado de la catedral: todo recto y luego a la derecha.</span> — <em>The museum is next to the cathedral: straight on and then to the right.</em></p>\n            <p>Directions are easier with help: <span data-say=\"Si estás perdido, mira el plano: el museo está delante de la plaza.\">Si estás perdido, mira el plano: el museo está delante de la plaza.</span> — <em>If you are lost, look at the map: the museum is in front of the square.</em> <span data-say=\"¿Puede hablar más despacio, por favor?\">¿Puede hablar más despacio, por favor?</span> — <em>Can you speak more slowly, please?</em></p>", "check": {"question": "What does ‘lejos de’ mean?", "options": ["far from", "close to, near", "next to, beside", "straight on ahead"], "answer": 0, "explain": "lejos de = far from — the opposite of cerca de (close to)."}}, {"title": "How do I talk about the weather and climate?", "html": "<p>Weather is usually described with <strong>hacer</strong> or an impersonal verb like <strong>llover</strong> (to rain).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"hace sol\">hace sol</span></td><td>it’s sunny</td><td><span data-say=\"hace calor\">hace calor</span></td><td>it’s hot</td></tr>\n              <tr><td><span data-say=\"hace frío\">hace frío</span></td><td>it’s cold</td><td><span data-say=\"hace viento\">hace viento</span></td><td>it’s windy</td></tr>\n              <tr><td><span data-say=\"llueve\">llueve</span></td><td>it rains</td><td><span data-say=\"el clima\">el clima</span></td><td>the climate</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi región el clima es agradable: hace sol en verano, pero llueve mucho en invierno.\">En mi región el clima es agradable: hace sol en verano, pero llueve mucho en invierno.</span> — <em>In my region the climate is pleasant: it’s sunny in summer, but it rains a lot in winter.</em></p>\n            <p>Climate can vary a lot within one country: <span data-say=\"El clima en el sur es completamente diferente al clima en el norte.\">El clima en el sur es completamente diferente al clima en el norte.</span> — <em>The climate in the south is completely different to the climate in the north.</em></p>", "check": {"question": "What does ‘llueve’ mean?", "options": ["it is windy today", "it is very sunny", "it rains", "it is freezing cold"], "answer": 2, "explain": "llueve = it rains, from llover. The distractors describe other weather words entirely."}}, {"title": "Higher: relative clauses, superlatives and se puede", "html": "<p><span class=\"tier-h\">H</span> Use <strong>que</strong> to join two ideas about the same noun, a superlative for ‘the most…’, and <strong>se puede</strong> + infinitive for ‘you can…’.</p>\n            <ul>\n              <li><span data-say=\"una ciudad que tiene mucha historia\">una ciudad que tiene mucha historia</span> — a city that has a lot of history</li>\n              <li><span data-say=\"lo más interesante es el castillo\">lo más interesante es el castillo</span> — the most interesting thing is the castle</li>\n              <li><span data-say=\"se puede visitar el museo\">se puede visitar el museo</span> — you can visit the museum</li>\n            </ul>\n            <p>Combine for the top band: <span data-say=\"Lo más interesante de mi región es el castillo, que tiene más de quinientos años; se puede visitar todos los días.\">Lo más interesante de mi región es el castillo, que tiene más de quinientos años; se puede visitar todos los días.</span> <span class=\"tier-h\">H</span></p>\n            <p><span class=\"tier-h\">H</span> Higher-tier opinions often need impersonal expressions: <span data-say=\"Es evidente que hay mucho que hacer, pero hay que ser consciente del turismo excesivo.\">Es evidente que hay mucho que hacer, pero hay que ser consciente del turismo excesivo.</span> — <em>It''s evident there''s a lot to do, but you have to be aware of excessive tourism.</em> <span class=\"tier-h\">H</span></p>", "check": {"question": "Which sentence correctly uses the relative pronoun ‘que’?", "options": ["Es una ciudad quien tiene mucha historia", "Es una ciudad que tiene mucha historia", "Es una ciudad cual tiene mucha historia", "Es una ciudad donde tiene mucha historia"], "answer": 1, "explain": "‘que’ is the standard relative pronoun linking a noun to extra information here; quien/cual/donde don’t fit this structure."}}]}, "terms": {"enabled": true, "pairs": [{"term": "mi región", "definition": "my region"}, {"term": "el pueblo", "definition": "the town / village"}, {"term": "la costa", "definition": "the coast"}, {"term": "el campo", "definition": "the countryside"}, {"term": "el norte · el sur", "definition": "north · south"}, {"term": "el este · el oeste", "definition": "east · west"}, {"term": "el museo", "definition": "the museum"}, {"term": "el castillo", "definition": "the castle"}, {"term": "la catedral", "definition": "the cathedral"}, {"term": "la iglesia", "definition": "the church"}, {"term": "la plaza · el mercado", "definition": "the square · the market"}, {"term": "histórico / turístico", "definition": "historic / touristy"}, {"term": "tranquilo / animado", "definition": "quiet / lively"}, {"term": "antiguo / moderno", "definition": "old / modern"}, {"term": "a la derecha / a la izquierda", "definition": "to the right / to the left"}, {"term": "cerca de / lejos de", "definition": "close to / far from"}, {"term": "hace sol · llueve", "definition": "it’s sunny · it rains"}, {"term": "se puede + infinitive (H)", "definition": "you can… (+ verb)"}, {"term": "propio/a", "definition": "own"}, {"term": "todavía", "definition": "still, yet"}, {"term": "la edad · la Edad Media", "definition": "the age · the Middle Ages"}, {"term": "un sitio (turístico)", "definition": "a (tourist) place, site"}, {"term": "ambos / ambas", "definition": "both"}, {"term": "la mitad", "definition": "the half"}, {"term": "una sensación", "definition": "a feeling, sensation"}, {"term": "maravilloso/a", "definition": "marvellous, wonderful"}, {"term": "evidente (H)", "definition": "evident, obvious"}, {"term": "delante de", "definition": "in front of"}, {"term": "consciente (H)", "definition": "aware, conscious"}, {"term": "despacio", "definition": "slowly"}, {"term": "completamente", "definition": "completely"}, {"term": "hace falta + infinitivo (H)", "definition": "it''s necessary to…"}, {"term": "el plano", "definition": "the map (of a town/metro)"}, {"term": "perdido/a", "definition": "lost"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"En mi ciudad hay un castillo histórico.\" data-listen></span><br>Listen. What is in the city?", "options": ["A modern art museum", "A historic castle", "An old stone church", "A small local market"], "answer": 1, "explain": "‘hay un castillo histórico’ = there is a historic castle. The other buildings are all plausible but not what was said."}, {"question": "<span data-say=\"El museo está a la derecha de la plaza.\" data-listen></span><br>Listen. Where is the museum?", "options": ["To the left of the square", "Straight ahead of the market", "Next to the cathedral entrance", "To the right of the square"], "answer": 3, "explain": "‘a la derecha de’ = to the right of. Distractors swap the direction word or the landmark named."}, {"question": "<span data-say=\"Hace mucho frío en invierno.\" data-listen></span><br>Listen. What is the weather like?", "options": ["It’s very cold in winter", "It’s very hot in summer", "It’s quite windy on the coast", "It rains a lot in the spring"], "answer": 0, "explain": "‘hace frío’ = it’s cold; ‘invierno’ = winter. Distractors swap the season or the weather word."}, {"question": "Which word means ‘the countryside’?", "options": ["el pueblo", "la costa", "el campo", "el mercado"], "answer": 2, "explain": "el campo = the countryside. pueblo = town/village, costa = coast, mercado = market — all real vocab, easy to muddle."}, {"question": "Complete: ‘En mi región ___ un castillo y una catedral.’", "options": ["es", "hay", "está", "son"], "answer": 1, "explain": "‘hay’ (there is/are) introduces something and never changes form. es/está/son all need a specific, already-known subject."}, {"question": "Which sentence correctly uses ‘estar’ for location?", "options": ["Mi pueblo es en el sur de España", "Mi pueblo hay en el sur de España", "Mi pueblo tiene en el sur de España", "Mi pueblo está en el sur de España"], "answer": 3, "explain": "Location takes estar: está en el sur. ser/hay/tener cannot be used to say where something is."}, {"question": "Which sentence correctly uses ‘ser’ for a permanent description?", "options": ["Mi ciudad es histórica y turística", "Mi ciudad está histórica y turística", "Mi ciudad hay histórica y turística", "Mi ciudad tiene histórica y turística"], "answer": 0, "explain": "A lasting characteristic uses ser: es histórica. The other verbs cannot combine with an adjective this way."}, {"question": "What does ‘lejos de’ mean?", "options": ["close to, nearby", "right next to", "far from", "straight on ahead"], "answer": 2, "explain": "lejos de = far from, the opposite of cerca de (close to)."}, {"question": "Higher: which sentence uses the relative pronoun correctly?", "options": ["Es una ciudad quien tiene mucha historia", "Es una ciudad cual tiene mucha historia", "Es una ciudad donde tiene mucha historia", "Es una ciudad que tiene mucha historia"], "answer": 3, "explain": "‘que’ links the noun to extra information here; quien/cual/donde are the wrong relative words for this structure."}, {"question": "Complete: ‘Se puede ___ el castillo los fines de semana.’", "options": ["visita", "visitar", "visitando", "visitado"], "answer": 1, "explain": "‘se puede’ + infinitive → visitar. visita/visitando/visitado are conjugated or non-finite forms that don’t follow se puede."}, {"question": "<span data-say=\"Si estás perdido, mira el plano.\" data-listen></span><br>Listen. What should you do if you are lost?", "options": ["look at the map", "ask a different tourist for help", "go back to the hotel immediately", "wait at the museum entrance"], "answer": 0, "explain": "mira el plano = look at the map. The distractors are other plausible actions a lost tourist might take."}, {"question": "What does ‘todavía hay muchos sitios que visitar’ mean?", "options": ["there are still many places to visit", "there were many places to visit before", "there will be many places to visit soon", "there aren''t any places left to visit"], "answer": 0, "explain": "todavía hay = there are still. The distractors swap in past, future and negative meanings — genuine tense/negation traps."}]}, "fib": {"enabled": true, "questions": [{"text": "[hay] <span data-say=\"En mi ciudad hay un castillo histórico.\" data-listen></span>"}, {"text": "Mi pueblo [está] en el norte de España. (location — estar)"}, {"text": "Mi ciudad [es] muy histórica y turística. (permanent description — ser)"}, {"text": "El parque está [al lado] de la catedral, muy cerca. (next to)"}, {"text": "En mi región [llueve] mucho en invierno. (it rains)"}, {"text": "Se puede [visitar] el castillo los fines de semana. (to visit — infinitive)"}, {"text": "El museo está [cerca], a diez minutos andando. (close by)"}, {"text": "El castillo es de la Edad Media, así que la [mitad] del pueblo parece muy antigua. (half)"}, {"text": "¿Puede hablar más [despacio], por favor? (slowly)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘hay’ means ‘there is / there are’ and never changes form.", "answer": true, "explain": "hay un castillo, hay dos castillos — hay is always invariable."}, {"statement": "You use ‘ser’ to say exactly where a place is located.", "answer": false, "explain": "Location uses estar (está en el norte); ser is for permanent characteristics."}, {"statement": "‘todo recto’ means ‘straight on’.", "answer": true, "explain": "todo recto = straight on/ahead when giving directions."}, {"statement": "‘lejos de’ means ‘close to’.", "answer": false, "explain": "lejos de = far from; cerca de = close to."}, {"statement": "‘llueve’ means ‘it rains’.", "answer": true, "explain": "llueve comes from llover, to rain."}, {"statement": "‘se puede’ + infinitive means ‘you can…’.", "answer": true, "explain": "se puede visitar = you can visit."}, {"statement": "‘antiguo’ means ‘modern’.", "answer": false, "explain": "antiguo means old/ancient; moderno means modern."}, {"statement": "‘que’ can introduce a relative clause, e.g. ‘una ciudad que tiene mucha historia’.", "answer": true, "explain": "que links a noun to extra information — a Higher-tier structure."}, {"statement": "‘Ambos pueblos’ means ‘both towns’.", "answer": true, "explain": "ambos = both; pueblos = towns."}, {"statement": "‘Mi propio pueblo’ means ‘someone else''s town’.", "answer": false, "explain": "propio = own; mi propio pueblo = my own town, not someone else''s."}, {"statement": "‘Es evidente que…’ means ‘it is evident/obvious that…’.", "answer": true, "explain": "evidente = evident/obvious, used to introduce an opinion."}, {"statement": "‘Consciente’ means ‘unaware’.", "answer": false, "explain": "consciente = aware/conscious — the opposite of unaware."}, {"statement": "‘Hace falta visitar el castillo’ means ‘it isn''t necessary to visit the castle’.", "answer": false, "explain": "hace falta + infinitive = it is necessary to…; this does NOT mean unnecessary."}]}, "misc": {"enabled": true, "items": [{"myth": "Mi ciudad está histórica y turística.", "truth": "Mi ciudad es histórica y turística.", "check": {"question": "Why is ‘es’ correct here, not ‘está’?", "options": ["you should always use estar before any kind of descriptive adjective", "histórica actually describes a location, not a characteristic", "histórica is a lasting characteristic, so it needs ser", "es is only ever used for jobs and nationalities"], "answer": 2, "explain": "Lasting characteristics take ser: es histórica. estar would only be right for a temporary state or a location."}}, {"myth": "El castillo hay en el centro de la ciudad.", "truth": "El castillo está en el centro de la ciudad.", "check": {"question": "Why is ‘está’ correct, not ‘hay’, once the castle is a specific known place?", "options": ["hay only introduces something new; a specific thing’s location uses estar", "hay and estar always mean exactly the same thing in absolutely every context", "hay can only ever be used inside a question, never inside a statement", "está cannot ever be used to talk about buildings or historic monuments"], "answer": 0, "explain": "hay introduces (there is a castle); estar then says where that specific castle is."}}, {"myth": "‘antiguo’ significa ‘moderno’.", "truth": "‘antiguo’ significa ‘viejo, de hace mucho tiempo’.", "check": {"question": "What does ‘antiguo’ actually mean?", "options": ["modern and brand new", "industrial and busy", "touristy and crowded", "old, ancient"], "answer": 3, "explain": "antiguo = old/ancient — almost the opposite of moderno."}}, {"myth": "‘lejos de’ significa ‘cerca de’.", "truth": "‘lejos de’ significa ‘far from’, lo opuesto de ‘cerca de’.", "check": {"question": "What does ‘lejos de’ mean?", "options": ["close to, nearby", "far from", "right next to", "straight on ahead"], "answer": 1, "explain": "lejos de = far from; cerca de (close to) is the opposite, a common mix-up."}}, {"myth": "En mi ciudad hay dos museo y un iglesia.", "truth": "En mi ciudad hay dos museos y una iglesia.", "check": {"question": "What are the two mistakes in ‘dos museo y un iglesia’?", "options": ["both of these two separate words simply need to start with a capital letter", "‘dos’ should really be replaced with the whole phrase ‘dos veces’ instead of here", "‘museo’ needs the plural -s and ‘iglesia’ needs ‘una’, not ‘un’ (it’s feminine)", "nothing at all is actually wrong with this particular Spanish sentence at all"], "answer": 2, "explain": "‘dos museo’ should agree in number (museos); ‘iglesia’ is feminine, so it needs ‘una’, not ‘un’."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening for places and directions", "html": "Listen for ‘hay’ (something exists) versus ‘está’ (where a specific thing is), and for direction words like ‘a la derecha’ / ‘a la izquierda’ / ‘todo recto’ — they sound similar but point opposite ways, so don’t guess from the first syllable.", "check": {"question": "You hear ‘a la izquierda’. Which way is that?", "options": ["to the right", "to the left", "straight ahead", "next to the market"], "answer": 1, "explain": "a la izquierda = to the left; a la derecha = to the right — easy to confuse under exam pressure."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Watch ser vs estar carefully when translating: ‘es histórica’ (it is historic) is a description, ‘está en el norte’ (it is in the north) is a location — English uses ‘is’ for both, so don’t lose the distinction when you translate the other way.", "check": {"question": "‘Mi pueblo es tranquilo pero está lejos de la costa’ =", "options": ["My town is busy and it is close to the coast", "My town is modern but it is near the mountains", "My town is historic and it is next to the market", "My town is quiet but it is far from the coast"], "answer": 3, "explain": "es tranquilo = is quiet (description); está lejos de la costa = is far from the coast (location)."}}, {"title": "Paper 4 — Writing about my region", "html": "Build a strong paragraph: introduce with hay, describe with ser, locate with estar, add an opinion, and finish with a Higher-tier relative clause or se puede. Example: ‘En mi región hay un castillo que es muy antiguo; se puede visitar los fines de semana.’", "check": {"question": "Which answer reaches the top band?", "options": ["Hay un castillo. Es antiguo. Está en mi región. Es bonito. Es viejo", "Mi región tiene cosas", "En mi región hay un castillo que es muy antiguo y se puede visitar los fines de semana", "Hay un castillo, hay una catedral, hay un museo y también hay un parque muy grande y bonito"], "answer": 2, "explain": "It links hay, ser, a relative clause and se puede into one fluent sentence — range and accuracy, not just length or a repetitive list of ‘hay’."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) Where is Carlos’s village? (1)<br>(b) Name <strong>one</strong> place of interest mentioned besides the castle. (1)<br>(c) Where exactly is the castle? (1)<br>(d) What does Carlos like most about his region? (1)", "marks": 4, "hint": "Find the location after ‘en el norte…’, another building alongside ‘castillo’, the castle’s position after ‘está’, and his opinion after ‘lo que más me gusta’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> (in the) north of Spain, near the coast <em>(1)</em>.</li>\n                <li><strong>(b)</strong> cathedral / market (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> in the centre, next to the market <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (that) it is quiet but has a lot of history <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) My town is very quiet. <br>(b) There is a historic castle near the coast. <br>(c) You can visit the museum, which is in the centre.", "marks": 5, "hint": "‘My town is’ = ser for a description (Mi pueblo es…). ‘There is’ = hay. ‘You can visit’ = se puede visitar; ‘which is’ = que está.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Mi pueblo es muy tranquilo. <em>(1)</em></li>\n                <li><strong>(b)</strong> Hay un castillo histórico cerca de la costa. <em>(1)</em></li>\n                <li><strong>(c)</strong> Se puede visitar el museo <em>(1)</em>, que <em>(1)</em> está en el centro <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Mi pueblo es’ must use ‘es’, not ‘está’, for this description.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '8-1-technology-in-everyday-life', '8.1 Technology in Everyday Life', '{"learn": {"enabled": true, "items": [{"title": "What technology vocabulary do I need?", "html": "<p>Devices and gadgets — <strong>los aparatos</strong>. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el móvil\">el móvil</span></td><td>the mobile phone</td><td><span data-say=\"el teléfono\">el teléfono</span></td><td>the phone</td></tr>\n              <tr><td><span data-say=\"el ordenador\">el ordenador</span></td><td>the computer</td><td><span data-say=\"la tableta\">la tableta</span></td><td>the tablet</td></tr>\n              <tr><td><span data-say=\"el portátil\">el portátil</span></td><td>the laptop</td><td><span data-say=\"internet\">internet</span></td><td>the internet</td></tr>\n              <tr><td><span data-say=\"la aplicación\">la aplicación</span></td><td>the app</td><td><span data-say=\"la pantalla\">la pantalla</span></td><td>the screen</td></tr>\n            </table>\n            <p>Note the gender: <span data-say=\"el móvil\">el móvil</span> and <span data-say=\"el ordenador\">el ordenador</span> are both masculine, even though many tech words look like they could be feminine.</p>\n            <p>Model sentence: <span data-say=\"Tengo un móvil, una tableta y un portátil.\">Tengo un móvil, una tableta y un portátil.</span> — <em>I have a mobile phone, a tablet and a laptop.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"cargar\">cargar</span></td><td>to charge (a device)</td><td><span data-say=\"funcionar\">funcionar</span></td><td>to work / to function</td></tr>\n            </table>\n            <p>Extra: <span data-say=\"Cargo el móvil todos los días porque si no, no funciona.\">Cargo el móvil todos los días porque si no, no funciona.</span> — <em>I charge my phone every day because otherwise it doesn''t work.</em></p>", "check": {"question": "Which word means ‘the screen’?", "options": ["el ordenador", "la aplicación", "la pantalla", "el portátil"], "answer": 2, "explain": "la pantalla = the screen. The other three are all genuine device words, so read carefully."}}, {"title": "How do I say what I do online?", "html": "<p>Everyday internet actions, all in the present tense (yo form):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"navego por internet\">navegar por internet</span></td><td>to browse the internet</td><td><span data-say=\"mando mensajes\">mandar / enviar mensajes</span></td><td>to send messages</td></tr>\n              <tr><td><span data-say=\"descargo aplicaciones\">descargar</span></td><td>to download</td><td><span data-say=\"subo fotos\">subir fotos</span></td><td>to upload photos</td></tr>\n              <tr><td><span data-say=\"busco información\">buscar información</span></td><td>to search for information</td><td><span data-say=\"juego a videojuegos\">jugar a videojuegos</span></td><td>to play videogames</td></tr>\n              <tr><td><span data-say=\"veo vídeos\">ver vídeos</span></td><td>to watch videos</td><td><span data-say=\"hago los deberes\">hacer los deberes</span></td><td>to do homework</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Todos los días navego por internet, mando mensajes y veo vídeos.\">Todos los días navego por internet, mando mensajes y veo vídeos.</span></p>\n            <p>Extra: <span data-say=\"Guardo mis fotos favoritas y juego a un videojuego nuevo.\">Guardo mis fotos favoritas y juego a un videojuego nuevo.</span> — <em>I save my favourite photos and I play a new video game.</em> A veces hay <span data-say=\"un retraso\">un retraso</span> (a delay/lag) cuando intento <span data-say=\"conectar\">conectar</span> el móvil a internet.</p>", "check": {"question": "Which phrase means ‘to search for information’?", "options": ["subir fotos", "buscar información", "descargar aplicaciones", "mandar mensajes"], "answer": 1, "explain": "buscar información = to search for information. The others are real actions you do online, but different ones."}}, {"title": "How do I say what something is used FOR? (para + infinitive)", "html": "<p>To explain the purpose of a device, use <strong>para + infinitive</strong>. The verb after ‘para’ never changes — it always stays as the infinitive, whoever the subject is.</p>\n            <ul>\n              <li><span data-say=\"Uso el móvil para mandar mensajes.\">Uso el móvil para mandar mensajes.</span> — I use my phone to send messages.</li>\n              <li><span data-say=\"Uso la tableta para ver vídeos.\">Uso la tableta para ver vídeos.</span> — I use the tablet to watch videos.</li>\n              <li><span data-say=\"Usamos el ordenador para hacer los deberes.\">Usamos el ordenador para hacer los deberes.</span> — We use the computer to do homework.</li>\n            </ul>\n            <p>Common error: writing <em>“para mando mensajes”</em> — conjugating the second verb instead of leaving it as the infinitive.</p>", "check": {"question": "Which sentence correctly uses ‘para + infinitive’?", "options": ["Uso el móvil para mando mensajes", "Uso el móvil para mandando mensajes", "Uso el móvil para he mandado mensajes", "Uso el móvil para mandar mensajes"], "answer": 3, "explain": "After ‘para’ the verb must stay as the infinitive: mandar. The other three wrongly conjugate, use the gerund, or use the perfect tense."}}, {"title": "How do I give opinions about technology?", "html": "<p>Opinion adjectives for technology — tap 🔊:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"útil\">útil</span></td><td>useful</td><td><span data-say=\"práctico\">práctico</span></td><td>practical</td></tr>\n              <tr><td><span data-say=\"imprescindible\">imprescindible</span></td><td>essential</td><td><span data-say=\"rápido\">rápido</span></td><td>fast</td></tr>\n              <tr><td><span data-say=\"una pérdida de tiempo\">una pérdida de tiempo</span></td><td>a waste of time</td><td><span data-say=\"adicto\">adicto / adicta</span></td><td>addicted</td></tr>\n            </table>\n            <p>Use <strong>gustar</strong> / <strong>encantar</strong> — the verb agrees with what follows, not with you:</p>\n            <ul>\n              <li>ONE thing / an infinitive → <span data-say=\"me gusta\">me gusta</span>: <span data-say=\"Me gusta navegar por internet.\">Me gusta navegar por internet.</span></li>\n              <li>MORE THAN ONE thing → <span data-say=\"me encantan\">me encantan</span>: <span data-say=\"Me encantan los videojuegos.\">Me encantan los videojuegos.</span></li>\n            </ul>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"claro\">claro / clara</span></td><td>clear, light</td><td><span data-say=\"especial\">especial</span></td><td>special</td></tr>\n            </table>\n            <p>Extra: <span data-say=\"Esta foto es muy clara y el videojuego es especial e increíble.\">Esta foto es muy clara y el videojuego es especial e increíble.</span> — <em>This photo is very clear and the video game is special and incredible.</em></p>", "check": {"question": "Which sentence is grammatically correct?", "options": ["Me encanta los videojuegos", "Me encantan los videojuegos", "Me encantas los videojuegos", "Me encantamos los videojuegos"], "answer": 1, "explain": "‘los videojuegos’ is plural, so the verb agrees in the plural: encantan. Like gustar, encantar agrees with what follows, not with the speaker."}}, {"title": "How do I say how often I use technology?", "html": "<p>Frequency expressions — combine with a reason using <strong>porque</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"todos los días\">todos los días</span></td><td>every day</td></tr>\n              <tr><td><span data-say=\"siempre\">siempre</span></td><td>always</td></tr>\n              <tr><td><span data-say=\"a menudo\">a menudo</span></td><td>often</td></tr>\n              <tr><td><span data-say=\"nunca\">nunca</span></td><td>never</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Uso el móvil todos los días porque es muy práctico.\">Uso el móvil todos los días porque es muy práctico.</span> — <em>I use my phone every day because it is very practical.</em></p>\n            <p>Extra: <span data-say=\"Paso solo un minuto en la aplicación antes de pasar a la siguiente.\">Paso solo un minuto en la aplicación antes de pasar a la siguiente.</span> — <em>I spend only a minute on the app before moving on to the next one.</em> Mi <span data-say=\"último móvil\">último móvil</span> es mucho más rápido. — <em>My latest phone is much faster.</em></p>", "check": {"question": "Which phrase means ‘often’?", "options": ["siempre", "nunca", "todos los días", "a menudo"], "answer": 3, "explain": "a menudo = often. siempre = always, nunca = never, todos los días = every day — all real frequency words, but different meanings."}}, {"title": "Higher: advantages, disadvantages and the subjunctive", "html": "<p><span class=\"tier-h\">H</span> Structure an advantage or a disadvantage with <strong>es que</strong>:</p>\n            <ul>\n              <li><span data-say=\"Una ventaja de la tecnología es que es muy útil.\">Una ventaja de la tecnología es que es muy útil.</span> — An advantage of technology is that it is very useful.</li>\n              <li><span data-say=\"Una desventaja es que es fácil hacerse adicto.\">Una desventaja es que es fácil hacerse adicto.</span> — A disadvantage is that it is easy to become addicted.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> After <strong>es importante que</strong> the verb switches into the <strong>subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"Es importante que uses el móvil con cuidado.\">Es importante que uses el móvil con cuidado.</span> <span class=\"tier-h\">H</span> — It is important that you use your phone carefully.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"Un beneficio de la tecnología es la creación de aplicaciones nuevas cada día.\">Un beneficio de la tecnología es la creación de aplicaciones nuevas cada día.</span> — <em>A benefit of technology is the creation of new apps every day.</em></p>", "check": {"question": "Which sentence correctly uses the subjunctive after ‘es importante que’?", "options": ["Es importante que usas el móvil con cuidado", "Es importante que usa el móvil con cuidado", "Es importante que uses el móvil con cuidado", "Es importante que usar el móvil con cuidado"], "answer": 2, "explain": "es importante que triggers the subjunctive: uses. The other options wrongly use the indicative (usas/usa) or the infinitive (usar)."}}]}, "terms": {"enabled": true, "pairs": [{"term": "el móvil", "definition": "the mobile phone"}, {"term": "el ordenador", "definition": "the computer"}, {"term": "la tableta", "definition": "the tablet"}, {"term": "el portátil", "definition": "the laptop"}, {"term": "la aplicación (la app)", "definition": "the app"}, {"term": "la pantalla", "definition": "the screen"}, {"term": "navegar por internet", "definition": "to browse the internet"}, {"term": "mandar mensajes", "definition": "to send messages"}, {"term": "descargar", "definition": "to download"}, {"term": "subir fotos", "definition": "to upload photos"}, {"term": "buscar información", "definition": "to search for information"}, {"term": "jugar a videojuegos", "definition": "to play videogames"}, {"term": "hacer los deberes", "definition": "to do homework"}, {"term": "útil / práctico", "definition": "useful / practical"}, {"term": "una pérdida de tiempo", "definition": "a waste of time"}, {"term": "adicto / adicta (H)", "definition": "addicted"}, {"term": "todos los días / a menudo", "definition": "every day / often"}, {"term": "es importante que uses… (H)", "definition": "it is important that you use… (subjunctive)"}, {"term": "cargar", "definition": "to charge (a device)"}, {"term": "funcionar", "definition": "to work / to function"}, {"term": "guardar", "definition": "to save"}, {"term": "conectar", "definition": "to connect"}, {"term": "el retraso (H)", "definition": "the delay / lag"}, {"term": "el videojuego", "definition": "the video game"}, {"term": "claro / clara", "definition": "clear, light (colour/picture)"}, {"term": "último / última", "definition": "last / latest"}, {"term": "siguiente", "definition": "next / following"}, {"term": "especial", "definition": "special"}, {"term": "el minuto", "definition": "the minute"}, {"term": "la creación", "definition": "the creation"}, {"term": "el beneficio (H)", "definition": "the benefit"}, {"term": "increíble", "definition": "incredible"}, {"term": "vuestro / vuestra (H)", "definition": "your (plural, familiar)"}, {"term": "pesado / pesada (H)", "definition": "heavy / annoying, boring"}, {"term": "fatal (H)", "definition": "awful, terrible"}, {"term": "lo bueno", "definition": "the good thing"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Uso el móvil para mandar mensajes.\" data-listen></span><br>Listen. What is the phone used for?", "options": ["sending messages", "downloading photos", "doing homework", "playing videogames"], "answer": 0, "explain": "‘uso el móvil para mandar mensajes’ = I use my phone to send messages. The other three are real tech actions, but not this one."}, {"question": "<span data-say=\"Navego por internet todos los días.\" data-listen></span><br>Listen. What does the speaker do?", "options": ["I browsed the internet only once", "I browse the internet every day", "I never go on the internet at all", "I will browse the internet tomorrow"], "answer": 1, "explain": "‘navego … todos los días’ = present tense + every day. The traps swap in the preterite, a negative, and the future."}, {"question": "How do you say ‘I download apps’ in Spanish?", "options": ["Descargar aplicaciones", "Descargando aplicaciones", "Descargo aplicaciones", "Descargado aplicaciones"], "answer": 2, "explain": "‘I download’ needs the present tense (yo) form: descargo. The others are the infinitive, gerund and past participle."}, {"question": "Complete: ‘Uso la tableta para ___ vídeos.’", "options": ["veo", "viendo", "visto", "ver"], "answer": 3, "explain": "‘para’ is always followed by the infinitive: ver. veo/viendo/visto are all wrongly conjugated or non-infinitive forms."}, {"question": "Which is correct: ‘Me ___ los videojuegos.’", "options": ["gusta", "gustan", "gustas", "gustamos"], "answer": 1, "explain": "‘los videojuegos’ is plural, so gustar agrees in the plural: gustan."}, {"question": "‘una pérdida de tiempo’ means…", "options": ["a loss of signal", "a useful invention", "a waste of time", "a broken screen"], "answer": 2, "explain": "una pérdida de tiempo = a waste of time. The distractors are all plausible tech-related meanings, but wrong."}, {"question": "Which word means ‘practical’?", "options": ["rápido", "útil", "imprescindible", "práctico"], "answer": 3, "explain": "práctico = practical. rápido = fast, útil = useful, imprescindible = essential — all real opinion adjectives, easily confused."}, {"question": "Complete: ‘Es importante que ___ el móvil con cuidado.’", "options": ["uses", "usas", "usa", "usar"], "answer": 0, "explain": "‘es importante que’ triggers the subjunctive: uses. usas/usa are indicative, usar is the infinitive."}, {"question": "Which sentence gives a DISADVANTAGE of technology?", "options": ["Una ventaja es que es rápido y muy práctico", "Es rápido y práctico", "Una desventaja es que es adictiva", "Me encanta navegar por internet mucho"], "answer": 2, "explain": "‘una desventaja es que es adictiva’ names an actual disadvantage. Option A is an advantage, and length is not a clue — it is the longest option here and still wrong."}, {"question": "<span data-say=\"Subo fotos a la aplicación.\" data-listen></span><br>Listen. What does the person do?", "options": ["downloads photos from the app", "uploads photos to the app", "deletes photos from the phone", "sends photos to a friend"], "answer": 1, "explain": "‘subo fotos a la aplicación’ = I upload photos to the app. subir (to upload) is easily confused with descargar (to download) — that is exactly the trap in option A."}, {"question": "Which verb means ‘to charge’ (a device)?", "options": ["cargar", "guardar", "funcionar", "conectar"], "answer": 0, "explain": "cargar = to charge. guardar (to save), funcionar (to work) and conectar (to connect) are all real tech verbs, but different actions."}, {"question": "Complete: ‘Mi móvil no ___ bien hoy.’ (doesn’t work well today)", "options": ["funciona", "funcionando", "carga", "conecta"], "answer": 0, "explain": "The conjugated present-tense form is needed: funciona. funcionando wrongly uses the gerund; carga/conecta are the wrong verb entirely."}, {"question": "Which word means ‘to connect’?", "options": ["conectar", "cargar", "guardar", "funcionar"], "answer": 0, "explain": "conectar = to connect. The others are real tech verbs (to charge, to save, to work) but not this one."}, {"question": "<span data-say=\"Hay un retraso en la aplicación.\" data-listen></span><br>Listen. What is the problem?", "options": ["There is a delay in the app", "There is a new app available", "The app has been deleted", "The app is very fast today"], "answer": 0, "explain": "‘hay un retraso’ = there is a delay/lag. The traps invent an unrelated update, deletion or speed."}, {"question": "Which is the correct Spanish for ‘video game’?", "options": ["el videojuego", "la videojuega", "el video juego", "los videojuego"], "answer": 0, "explain": "el videojuego is one word, masculine, singular. The others wrongly change the gender ending, split it into two words, or use a plural article with a singular noun."}, {"question": "Which phrase means ‘to save photos’?", "options": ["guardar fotos", "subir fotos", "descargar fotos", "buscar fotos"], "answer": 0, "explain": "guardar fotos = to save photos. subir (upload), descargar (download) and buscar (search for) are all real, easily confused tech verbs."}, {"question": "Complete: ‘Uso la nube para ___ mis fotos.’ (to save)", "options": ["guardar", "guardando", "guardo", "guardado"], "answer": 0, "explain": "‘para’ is always followed by the infinitive: guardar. guardando/guardo/guardado are the gerund, conjugated and past-participle forms."}, {"question": "Which word means ‘incredible’?", "options": ["increíble", "especial", "último", "siguiente"], "answer": 0, "explain": "increíble = incredible. especial (special), último (last) and siguiente (next) are real opinion/sequence words, but different meanings."}, {"question": "Which phrase means ‘a benefit of technology’?", "options": ["un beneficio de la tecnología", "una ventaja de la tecnología", "una creación de la tecnología", "un impacto de la tecnología"], "answer": 0, "explain": "beneficio = benefit. ventaja (advantage), creación (creation) and impacto (impact) are all real, similar abstract nouns used about technology."}, {"question": "Which phrase means ‘a minute’?", "options": ["un minuto", "una hora", "un día", "una semana"], "answer": 0, "explain": "un minuto = a minute. hora (hour), día (day) and semana (week) are all real time units, but longer periods."}, {"question": "Which word means ‘clear’ or ‘light’ (describing a colour or a picture)?", "options": ["claro", "oscuro", "especial", "siguiente"], "answer": 0, "explain": "claro = clear/light. oscuro (dark) is its direct opposite; especial (special) and siguiente (next) are real adjectives, but different meanings."}, {"question": "Which word means ‘next’ or ‘following’?", "options": ["siguiente", "anterior", "último", "penúltimo"], "answer": 0, "explain": "siguiente = next/following. anterior (previous), último (last) and penúltimo (second-to-last) are all genuine sequence words that a student can easily mix up."}, {"question": "Which word means ‘last’ or ‘latest’?", "options": ["último", "siguiente", "especial", "increíble"], "answer": 0, "explain": "último = last/latest. siguiente (next), especial (special) and increíble (incredible) are real describing words, but different meanings."}, {"question": "Which word means ‘special’?", "options": ["especial", "claro", "siguiente", "increíble"], "answer": 0, "explain": "especial = special. claro (clear/of course), siguiente (next) and increíble (incredible) are all real adjectives easily confused with it."}, {"question": "Which word means ‘creation’?", "options": ["creación", "creador", "crear", "creativo"], "answer": 0, "explain": "creación (noun) = creation. creador (creator), crear (to create) and creativo (creative) are the same word family in a different form — a classic part-of-speech mix-up."}]}, "fib": {"enabled": true, "questions": [{"text": "Uso el [móvil] para navegar por internet. <span data-say=\"Uso el móvil para navegar por internet.\" data-listen></span>"}, {"text": "Mando [mensajes] a mis amigos todos los días. <span data-say=\"Mando mensajes a mis amigos todos los días.\" data-listen></span>"}, {"text": "Descargo [aplicaciones] en mi tableta. (apps)"}, {"text": "Uso el ordenador para [hacer] los deberes. (to do)"}, {"text": "Internet es muy [útil] para buscar información. (useful)"}, {"text": "Paso demasiado tiempo en el móvil — ¡soy [adicto]! (addicted)"}, {"text": "[Navegar] por internet es una pérdida de tiempo, en mi opinión. (browsing)"}, {"text": "Tengo que [cargar] el móvil porque la batería está baja. (to charge)"}, {"text": "Mi ordenador no [funciona] bien hoy. <span data-say=\"Mi ordenador no funciona bien hoy.\" data-listen></span>"}, {"text": "Quiero [conectar] mi portátil a internet. (to connect)"}, {"text": "Hay un [retraso] en la aplicación esta noche. <span data-say=\"Hay un retraso en la aplicación esta noche.\" data-listen></span>"}, {"text": "Solo tengo un [minuto] para revisar mis mensajes. (minute)"}, {"text": "Un [beneficio] de la tecnología es que puedes aprender cosas nuevas. (benefit)"}]}, "tf": {"enabled": true, "questions": [{"statement": "After ‘para’, the verb always stays as the infinitive.", "answer": true, "explain": "para mandar mensajes, para ver vídeos — never conjugated after para."}, {"statement": "‘El móvil’ is a feminine noun, so it should be ‘la móvil’.", "answer": false, "explain": "móvil is masculine: el móvil, even though many tech words end differently."}, {"statement": "‘Me gustan los videojuegos’ is correct because ‘videojuegos’ is plural.", "answer": true, "explain": "gustar (and encantar) agree with what follows, not with the speaker."}, {"statement": "‘Descargar’ means ‘to upload’.", "answer": false, "explain": "descargar = to download; subir = to upload — opposite actions."}, {"statement": "‘todos los días’ means ‘some days’.", "answer": false, "explain": "todos los días = every day, not ‘some days’."}, {"statement": "‘Es importante que uses el móvil con cuidado’ uses the subjunctive.", "answer": true, "explain": "es importante que triggers the subjunctive: uses (Higher tier)."}, {"statement": "‘una ventaja’ means ‘a disadvantage’.", "answer": false, "explain": "una ventaja = an advantage; una desventaja = a disadvantage."}, {"statement": "‘adicto/a’ agrees with gender like a normal adjective.", "answer": true, "explain": "soy adicto (masc.) / soy adicta (fem.)."}, {"statement": "‘guardar’ means ‘to look at’ a photo.", "answer": false, "explain": "guardar = to save, not to look at (mirar = to look at)."}, {"statement": "‘el retraso’ means ‘a delay’.", "answer": true, "explain": "el retraso = a delay/lag — useful when technology is slow to connect."}]}, "misc": {"enabled": true, "items": [{"myth": "Uso el móvil para mando mensajes.", "truth": "Uso el móvil para mandar mensajes.", "check": {"question": "What is the error in ‘para mando mensajes’?", "options": ["‘para’ should be replaced with ‘por’, since ‘por’ introduces the reason for an action", "‘para’ must be followed by the infinitive, not a conjugated verb", "‘mensajes’ needs the definite article ‘los’", "‘mando’ should be spelled ‘mandó’"], "answer": 1, "explain": "‘para’ is always followed by the infinitive: mandar, not the conjugated ‘mando’."}}, {"myth": "Me gusta los videojuegos.", "truth": "Me gustan los videojuegos.", "check": {"question": "Why must it be ‘gustan’, not ‘gusta’, here?", "options": ["‘gustar’ is always used in the plural form because it never changes for a singular subject", "‘los videojuegos’ is plural, so the verb agrees in the plural", "‘videojuegos’ is a feminine noun", "‘me’ should be changed to ‘te’"], "answer": 1, "explain": "gustar agrees with what follows: plural noun → gustan."}}, {"myth": "Descargar significa ‘subir’.", "truth": "Descargar significa ‘to download’; subir = ‘to upload’.", "check": {"question": "What is the real difference between ‘descargar’ and ‘subir’?", "options": ["‘descargar’ is only used for photos, ‘subir’ for apps, so the two words never overlap", "there is no difference — both are correct", "‘descargar’ = to download, ‘subir’ = to upload (opposite actions)", "they are two different ways to say the same action"], "answer": 2, "explain": "descargar and subir are opposite actions — download vs. upload — a very common mix-up."}}, {"myth": "La móvil es muy útil.", "truth": "El móvil es muy útil.", "check": {"question": "Why is ‘El móvil’ correct, not ‘La móvil’?", "options": ["adjectives always take the article ‘la’", "‘útil’ forces the article to be feminine because adjectives agree with a nearby word", "‘móvil’ is a feminine noun ending in -a", "‘móvil’ is a masculine noun, even though many tech words are feminine"], "answer": 3, "explain": "el móvil is masculine — gender must be learned per word, not guessed from meaning."}}, {"myth": "Es importante que usas el móvil con cuidado.", "truth": "Es importante que uses el móvil con cuidado.", "check": {"question": "Why does ‘es importante que’ need ‘uses’, not ‘usas’?", "options": ["‘usas’ is the correct form and ‘uses’ is wrong because the indicative always follows ‘que’", "‘es importante que’ triggers the subjunctive (uses), not the indicative", "‘uses’ is the plural form of ‘usar’", "‘que’ should be removed from the sentence"], "answer": 1, "explain": "es importante que is a subjunctive trigger — the following verb must be uses, not the indicative usas."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening & dictation", "html": "Listen for the device (el móvil, la tableta, el ordenador…) and the purpose after ‘para’, which is always an infinitive: para hacer los deberes, para mandar mensajes. Don’t confuse descargar (download) with subir (upload) — they sound different but are easy to mix up under pressure.", "check": {"question": "You hear ‘Uso el ordenador para hacer los deberes.’ What is the computer used for?", "options": ["sending messages", "browsing social media", "doing homework", "downloading apps"], "answer": 2, "explain": "para hacer los deberes = to do homework."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Translate para + infinitive naturally: ‘uso el móvil para navegar por internet’ = ‘I use my phone to browse the internet’, not a clumsy word-for-word version. Learn device words precisely — el portátil (laptop) is not the same word as el ordenador (computer).", "check": {"question": "‘Prefiero mi portátil porque es más rápido’ translates as…", "options": ["I prefer my laptop because it is faster", "I prefer my computer because it is slower", "I prefer my tablet because it is cheaper", "I prefer my phone because it is newer"], "answer": 0, "explain": "portátil = laptop; más rápido = faster."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine a device, a use, an opinion and a reason: ‘Uso el móvil todos los días para mandar mensajes, pero creo que una desventaja es que es fácil hacerse adicto.’ At Higher, add the subjunctive: ‘es importante que uses el móvil con cuidado’.", "check": {"question": "Which Spanish sentence reaches the top band for this topic?", "options": ["Uso el móvil todos los días para mando mensajes y veo vídeos, pero pienso que es muy útil, rápido y práctico para todo tipo de cosas", "Uso internet", "Es útil y rápido", "Uso el móvil todos los días para mandar mensajes, pero creo que una desventaja es que es fácil hacerse adicto"], "answer": 3, "explain": "Range + accuracy win: a device, a use, a linked disadvantage — all grammatically correct. Option A is longer but contains a ‘para mando’ error, proving length is not a reliable clue."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) Name <strong>one</strong> device Carlos has, other than his laptop. (1)<br>(b) Why does he prefer his laptop? (1)<br>(c) Name <strong>one</strong> thing he uses the internet for every day. (1)<br>(d) According to Carlos, what is a disadvantage of technology? (1)", "marks": 4, "hint": "Find the devices in the first sentence, the reason after ‘porque’, the daily uses after ‘uso internet para’, and the disadvantage after ‘una desventaja … es que’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> a mobile phone / a tablet (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> (because) it is faster <em>(1)</em>.</li>\n                <li><strong>(c)</strong> doing homework / searching for information (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(d)</strong> it is easy to become addicted <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) I use my mobile to send messages. <br>(b) Downloading apps is very practical. <br>(c) I think that the internet is very useful because it is fast.", "marks": 5, "hint": "‘I use my mobile to…’ = Uso mi móvil para + infinitive. ‘Downloading apps’ = Descargar aplicaciones. ‘I think that’ = Creo que…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Uso mi móvil para mandar mensajes. <em>(1)</em></li>\n                <li><strong>(b)</strong> Descargar aplicaciones es muy práctico. <em>(1)</em></li>\n                <li><strong>(c)</strong> Creo que <em>(1)</em> internet es muy útil <em>(1)</em> porque es rápido <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘para mandar’ must keep the infinitive, not a conjugated verb.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about social media?", "html": "<p>The key noun is <span data-say=\"la red social\">la red social</span> (the social network) / <span data-say=\"las redes sociales\">las redes sociales</span> (social media). Note: on its own, <strong>‘red’</strong> means <em>network</em>, not the colour red! Tap 🔊 to hear each word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el perfil\">el perfil</span></td><td>profile</td><td><span data-say=\"publicar\">publicar</span></td><td>to post</td></tr>\n              <tr><td><span data-say=\"compartir\">compartir</span></td><td>to share</td><td><span data-say=\"seguir a\">seguir a</span></td><td>to follow</td></tr>\n              <tr><td><span data-say=\"el seguidor\">el seguidor / la seguidora</span></td><td>follower</td><td><span data-say=\"el mensaje\">el mensaje</span></td><td>message</td></tr>\n              <tr><td><span data-say=\"chatear\">chatear</span></td><td>to chat</td><td><span data-say=\"en línea\">en línea</span></td><td>online</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Publico fotos en mi perfil y sigo a mis amigos.\">Publico fotos en mi perfil y sigo a mis amigos.</span> — <em>I post photos on my profile and I follow my friends.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el usuario\">el usuario / la usuaria</span></td><td>the user</td><td><span data-say=\"comentar\">comentar</span></td><td>to comment</td></tr>\n            </table>\n            <p>Extra: <span data-say=\"Como usuario, comento las fotos y actualizo mi estado con un emoticón.\">Como usuario, comento las fotos y actualizo mi estado con un emoticón.</span> — <em>As a user, I comment on photos and update my status with an emoji.</em></p>", "check": {"question": "What does ‘la red social’ mean?", "options": ["a social network", "the colour red used socially", "a social advertisement online", "an online newspaper article"], "answer": 0, "explain": "la red social = social network. ‘Red’ alone is a false friend here — it means network, not the colour red."}}, {"title": "What are the advantages of social media?", "html": "<p>Reasons people give for using social media:</p>\n            <ul>\n              <li><span data-say=\"estar en contacto con\">estar en contacto con</span> — to be/stay in contact with</li>\n              <li><span data-say=\"conocer gente\">conocer gente</span> — to meet people</li>\n              <li><span data-say=\"compartir fotos\">compartir fotos</span> — to share photos</li>\n              <li><span data-say=\"es divertido\">es divertido</span> — it is fun</li>\n            </ul>\n            <p>Model sentence: <span data-say=\"Me gusta usar las redes sociales porque puedo estar en contacto con mis amigos y es divertido.\">Me gusta usar las redes sociales porque puedo estar en contacto con mis amigos y es divertido.</span> — <em>I like using social media because I can stay in contact with my friends and it is fun.</em></p>\n            <p>Extra: <span data-say=\"Una sonrisa o un comentario positivo puede cambiar la actitud de una persona.\">Una sonrisa o un comentario positivo puede cambiar la actitud de una persona.</span> — <em>A smile or a positive comment can change someone''s attitude.</em></p>", "check": {"question": "What does ‘estar en contacto con’ mean?", "options": ["to stay in contact with", "to compete against someone", "to argue with a friend online", "to meet somebody only once"], "answer": 0, "explain": "estar en contacto con = to stay in contact with. The other options invent unrelated meanings."}}, {"title": "What are the dangers of the internet?", "html": "<p>Important safety vocabulary — the exam rewards recognising these:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el peligro\">el peligro</span></td><td>danger</td><td><span data-say=\"peligroso\">peligroso / peligrosa</span></td><td>dangerous</td></tr>\n              <tr><td><span data-say=\"el ciberacoso\">el ciberacoso</span></td><td>cyberbullying</td><td><span data-say=\"la privacidad\">la privacidad</span></td><td>privacy</td></tr>\n              <tr><td><span data-say=\"los datos personales\">los datos personales</span></td><td>personal data</td><td><span data-say=\"la contraseña\">la contraseña</span></td><td>password</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"El ciberacoso es un gran peligro en las redes sociales.\">El ciberacoso es un gran peligro en las redes sociales.</span> — <em>Cyberbullying is a big danger on social media.</em></p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"seguro\">seguro / segura</span></td><td>safe</td></tr>\n            </table>\n            <p>Extra: <span data-say=\"Si no tienes cuidado, la consecuencia puede ser un problema serio.\">Si no tienes cuidado, la consecuencia puede ser un problema serio.</span> — <em>If you are not careful, the consequence can be a serious problem.</em> Es importante sentirte <span data-say=\"seguro en línea\">seguro</span> en línea. — <em>It''s important to feel safe online.</em></p>", "check": {"question": "What does ‘el ciberacoso’ mean?", "options": ["cyberbullying", "a computer network fault", "an online friendship request", "a type of internet advertisement"], "answer": 0, "explain": "el ciberacoso = cyberbullying. The distractors invent unrelated tech meanings."}}, {"title": "How do I stay safe online?", "html": "<p>Safety verbs and phrases:</p>\n            <ul>\n              <li><span data-say=\"proteger\">proteger</span> — to protect: <span data-say=\"proteger la contraseña\">proteger la contraseña</span> (to protect your password)</li>\n              <li><span data-say=\"tener cuidado\">tener cuidado</span> — to be careful</li>\n              <li><span data-say=\"pasar demasiado tiempo\">pasar demasiado tiempo</span> — to spend too much time</li>\n              <li><span data-say=\"no compartir datos personales\">no compartir datos personales</span> — not to share personal data</li>\n            </ul>\n            <p>Model sentence: <span data-say=\"Hay que tener cuidado y no se debe compartir datos personales en línea.\">Hay que tener cuidado y no se debe compartir datos personales en línea.</span></p>", "check": {"question": "What does ‘tener cuidado’ mean?", "options": ["to be careful", "to have a lot of free time", "to take care of a pet", "to feel very tired online"], "answer": 0, "explain": "tener cuidado = to be careful, a key safety phrase for this topic."}}, {"title": "How do I give advice about online safety?", "html": "<p>Reuse the advice structures — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe proteger la contraseña\">se debe proteger la contraseña</span></td><td>one should protect your password</td></tr>\n              <tr><td><span data-say=\"no se debe compartir datos personales\">no se debe compartir datos personales</span></td><td>one must not share personal data</td></tr>\n              <tr><td><span data-say=\"hay que tener cuidado\">hay que tener cuidado</span></td><td>you have to be careful</td></tr>\n              <tr><td><span data-say=\"es importante proteger tu contraseña\">es importante proteger tu contraseña</span></td><td>it is important to protect your password</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Es importante proteger tu contraseña y no se debe compartir datos personales.\">Es importante proteger tu contraseña y no se debe compartir datos personales.</span></p>\n            <p>Extra: <span data-say=\"En alguna ocasión, el peor error es compartir tu contraseña.\">En alguna ocasión, el peor error es compartir tu contraseña.</span> — <em>On some occasions, the worst mistake is sharing your password.</em></p>", "check": {"question": "What follows ‘se debe’, ‘hay que’ and ‘es importante’?", "options": ["an infinitive (proteger, compartir…)", "a verb conjugated in the preterite past tense", "an adjective that must agree", "a noun used completely on its own"], "answer": 0, "explain": "All three advice structures take an infinitive."}}, {"title": "Higher: opinions and advice with the subjunctive", "html": "<p><span class=\"tier-h\">H</span> After <strong>es importante que</strong>, the verb changes to the <strong>subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"es importante que tengas cuidado\">es importante que tengas cuidado</span> <span class=\"tier-h\">H</span> — it is important that you are careful (tengas, not tienes)</li>\n              <li><span data-say=\"es importante que protejas tus datos personales\">es importante que protejas tus datos personales</span> <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Combine with the conditional for the top band:</p>\n            <ul>\n              <li><span data-say=\"Se debería tener más cuidado en línea.\">Se debería tener más cuidado en línea.</span> <span class=\"tier-h\">H</span> — One should be more careful online.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"La privacidad es una cuestión importante y da una buena impresión si tienes cuidado.\">La privacidad es una cuestión importante y da una buena impresión si tienes cuidado.</span> — <em>Privacy is an important issue and it gives a good impression if you are careful.</em></p>", "check": {"question": "Which sentence correctly uses the subjunctive after ‘es importante que’?", "options": ["Es importante que tengas cuidado", "Es importante que tienes cuidado", "Es importante que tener cuidado", "Es importante que teniendo cuidado"], "answer": 0, "explain": "es importante que triggers the subjunctive: tengas, not the indicative tienes."}}]}, "terms": {"enabled": true, "pairs": [{"term": "las redes sociales", "definition": "social media"}, {"term": "la red social", "definition": "social network"}, {"term": "el perfil", "definition": "profile"}, {"term": "publicar", "definition": "to post"}, {"term": "compartir", "definition": "to share"}, {"term": "seguir a · el seguidor", "definition": "to follow · follower"}, {"term": "el mensaje · chatear", "definition": "message · to chat"}, {"term": "en línea · la foto", "definition": "online · photo"}, {"term": "estar en contacto con", "definition": "to stay in contact with"}, {"term": "conocer gente", "definition": "to meet people"}, {"term": "el peligro · peligroso", "definition": "danger · dangerous"}, {"term": "el ciberacoso", "definition": "cyberbullying"}, {"term": "la privacidad", "definition": "privacy"}, {"term": "los datos personales", "definition": "personal data"}, {"term": "la contraseña · proteger", "definition": "password · to protect"}, {"term": "tener cuidado", "definition": "to be careful"}, {"term": "pasar demasiado tiempo", "definition": "to spend too much time"}, {"term": "es importante que tengas cuidado (H)", "definition": "it is important that you are careful (subjunctive)"}, {"term": "el usuario / la usuaria", "definition": "the user"}, {"term": "comentar", "definition": "to comment"}, {"term": "el emoticón", "definition": "the emoji / emoticon"}, {"term": "el estado", "definition": "the status (update)"}, {"term": "seguro / segura", "definition": "safe"}, {"term": "la cuestión (H)", "definition": "the issue / matter"}, {"term": "la ocasión (H)", "definition": "the occasion"}, {"term": "el peor / la peor (H)", "definition": "the worst"}, {"term": "la consecuencia (H)", "definition": "the consequence"}, {"term": "la actitud", "definition": "the attitude"}, {"term": "la sonrisa", "definition": "the smile"}, {"term": "la impresión (H)", "definition": "the impression"}, {"term": "la clave (H)", "definition": "the key / code"}, {"term": "la preocupación (H)", "definition": "the worry / concern"}, {"term": "el impacto (H)", "definition": "the impact"}, {"term": "de acuerdo", "definition": "agreed / OK"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"No se debe compartir datos personales.\" data-listen></span><br>Listen. What is the advice?", "options": ["You should not share personal data", "You should always share personal data", "You must always protect your friends", "You should share photos with everyone"], "answer": 0, "explain": "‘no se debe compartir datos personales’ = you should not share personal data. The traps reverse the negative or swap the object."}, {"question": "<span data-say=\"Sigo a muchos famosos en las redes sociales.\" data-listen></span><br>Listen. What is being said?", "options": ["I follow lots of celebrities on social media", "I never follow celebrities on social media", "I met lots of celebrities at a concert", "I posted photos of lots of celebrities online"], "answer": 0, "explain": "‘sigo a muchos famosos’ = I follow lots of celebrities. Trap B negates it; C and D invent different actions."}, {"question": "What does ‘el ciberacoso’ mean?", "options": ["cyberbullying", "a computer network fault that stops wifi working", "an online friendship request from a stranger", "a type of internet advertisement banner"], "answer": 0, "explain": "el ciberacoso = cyberbullying. The distractors invent longer, unrelated tech meanings."}, {"question": "Careful — ‘la red’ on its own (as in ‘la red social’) means…", "options": ["network", "the colour red", "a red warning sign", "a type of red fruit grown in Spain"], "answer": 0, "explain": "False friend! ‘red’ = network, not the colour red. The obvious guess is the trap."}, {"question": "Which sentence gives GOOD online safety advice?", "options": ["No se debe compartir datos personales", "Se debe compartir tu contraseña con todos tus amigos", "Se debe compartir datos personales sin cuidado", "No hay que proteger tu contraseña nunca"], "answer": 0, "explain": "‘no se debe compartir datos personales’ is sound advice; the rest recommend unsafe behaviour."}, {"question": "Complete: ‘Es importante ___ tu contraseña.’", "options": ["proteger", "protejo", "protegido", "protegiendo"], "answer": 0, "explain": "‘es importante’ takes an infinitive → proteger. The others are conjugated / non-finite forms."}, {"question": "What is ‘un seguidor’?", "options": ["a follower", "a private message", "a strong password", "a photo album shared online"], "answer": 0, "explain": "un seguidor = a follower, from the verb seguir (to follow)."}, {"question": "‘Paso demasiado tiempo en línea’ means…", "options": ["I spend too much time online", "I never go online at all", "I spend only a little time online", "I spend my time offline with friends"], "answer": 0, "explain": "‘paso demasiado tiempo en línea’ = I spend too much time online. Every distractor changes the amount or negates it."}, {"question": "Higher: ‘Es importante que tengas cuidado’ uses which verb form?", "options": ["the subjunctive (tengas)", "the ordinary present tense (tienes)", "the simple future tense (tendrás)", "a direct command form (ten)"], "answer": 0, "explain": "‘es importante que’ triggers the subjunctive: tengas, not tienes."}, {"question": "Which describes the safest online habit?", "options": ["proteger la contraseña y no compartir datos personales", "compartir la contraseña con cualquier desconocido que conoces en línea", "publicar todos los datos personales en el perfil", "aceptar como amigo a cualquier desconocido en línea"], "answer": 0, "explain": "Protecting your password and not sharing personal data is safe practice; the others describe risky behaviour."}, {"question": "Which word means ‘the user’?", "options": ["el usuario", "el ordenador", "la aplicación", "la tecnología"], "answer": 0, "explain": "el usuario = the user. The other three are real tech nouns, but they name a device or concept, not a person."}, {"question": "Which verb means ‘to comment’?", "options": ["comentar", "compartir", "publicar", "chatear"], "answer": 0, "explain": "comentar = to comment. compartir (to share), publicar (to post) and chatear (to chat) are all real social-media verbs, but different actions."}, {"question": "Which word means ‘emoji’ or ‘emoticon’?", "options": ["el emoticón", "el comentario", "el mensaje", "el perfil"], "answer": 0, "explain": "el emoticón = emoji/emoticon. comentario (comment), mensaje (message) and perfil (profile) are all real social-media nouns, but different things."}, {"question": "<span data-say=\"Actualizo mi estado con un emoticón divertido.\" data-listen></span><br>Listen. What does the person update?", "options": ["their status, with a fun emoji", "their password, with new letters", "their profile picture only", "their list of followers"], "answer": 0, "explain": "‘actualizo mi estado con un emoticón divertido’ = I update my status with a fun emoji. The traps swap in a password, a photo or a follower list."}, {"question": "Which sentence means ‘It’s important to feel safe online’?", "options": ["Es importante sentirte seguro en línea", "Es importante sentirte perdido en línea", "Es importante sentirte solo en línea", "Es importante sentirte triste en línea"], "answer": 0, "explain": "seguro = safe. perdido (lost), solo (alone) and triste (sad) are real feeling-words that fit the same sentence shape, but change the meaning."}, {"question": "Which word means ‘safe’?", "options": ["seguro", "peligroso", "divertido", "importante"], "answer": 0, "explain": "seguro = safe. peligroso (dangerous) is its direct opposite — a very common mix-up; divertido (fun) and importante (important) are unrelated."}, {"question": "Which word means ‘consequence’?", "options": ["la consecuencia", "la preocupación", "el peligro", "el impacto"], "answer": 0, "explain": "la consecuencia = consequence. preocupación (worry), peligro (danger) and impacto (impact) are all similar abstract nouns about risk, easily confused."}, {"question": "Which phrase describes ‘the worst mistake’?", "options": ["el peor error", "el mejor error", "el último error", "el mismo error"], "answer": 0, "explain": "el peor = the worst. el mejor (the best) is the opposite; el último (the last) and el mismo (the same) are other real describing words."}, {"question": "Which word means ‘occasion’, as in ‘on one occasion’?", "options": ["la ocasión", "la opción", "la ocupación", "la operación"], "answer": 0, "explain": "la ocasión = occasion. opción (option), ocupación (occupation) and operación (operation) look similar in writing but mean something different."}, {"question": "Which word means ‘attitude’?", "options": ["la actitud", "la aptitud", "la actividad", "la atención"], "answer": 0, "explain": "la actitud = attitude. la aptitud (aptitude) is the classic confusable pair; actividad (activity) and atención (attention) look similar too."}, {"question": "Which word means ‘a smile’?", "options": ["una sonrisa", "una sorpresa", "una sombra", "una sonata"], "answer": 0, "explain": "una sonrisa = a smile. sorpresa (surprise), sombra (shadow) and sonata (sonata) all start similarly, so read carefully."}, {"question": "Which word means ‘impression’?", "options": ["la impresión", "la expresión", "la impresora", "la depresión"], "answer": 0, "explain": "la impresión = impression. la impresora looks almost identical but is a false friend meaning ‘printer’; expresión (expression) and depresión (depression) are other look-alikes."}]}, "fib": {"enabled": true, "questions": [{"text": "Sigo a mis amigos en las redes [sociales]. <span data-say=\"Sigo a mis amigos en las redes sociales.\" data-listen>Sigo a mis amigos en las redes sociales.</span>"}, {"text": "Es importante proteger la [contraseña]. <span data-say=\"Es importante proteger la contraseña.\" data-listen>Es importante proteger la contraseña.</span>"}, {"text": "El ciberacoso es un gran [peligro] en línea. <span data-say=\"El ciberacoso es un gran peligro en línea.\" data-listen>El ciberacoso es un gran peligro en línea.</span>"}, {"text": "Hay que tener [cuidado] en las redes sociales. (be careful)"}, {"text": "Publico muchas fotos en mi [perfil]. (profile)"}, {"text": "No se debe [compartir] datos personales. <span data-say=\"no se debe compartir datos personales\" data-listen></span>"}, {"text": "Paso demasiado [tiempo] en línea. <span data-say=\"paso demasiado tiempo en línea\" data-listen></span>"}, {"text": "Soy un [usuario] nuevo en esta aplicación. (user)"}, {"text": "Me gusta [comentar] las fotos de mis amigos. (to comment on)"}, {"text": "Actualizo mi [estado] con una foto nueva. <span data-say=\"Actualizo mi estado con una foto nueva.\" data-listen></span>"}, {"text": "Envío un [emoticón] para expresar que estoy feliz. (emoji)"}, {"text": "Es importante sentirte [seguro] en línea. (safe)"}, {"text": "Compartir tu contraseña puede tener una [consecuencia] grave. (consequence)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘la red social’ means ‘social network’ — ‘red’ here is not the colour red.", "answer": true, "explain": "red = network in this context, a common false friend."}, {"statement": "‘compartir’ means ‘to share’.", "answer": true, "explain": "compartir = to share, e.g. compartir fotos."}, {"statement": "‘seguir a’ means ‘to stop following’ someone online.", "answer": false, "explain": "seguir a = to follow someone, not to stop following."}, {"statement": "‘el ciberacoso’ means ‘cyberbullying’.", "answer": true, "explain": "el ciberacoso = cyberbullying, an important safety term."}, {"statement": "It is good advice to share your password with new online friends.", "answer": false, "explain": "You should never share your password — proteger la contraseña."}, {"statement": "‘se debe’ and ‘hay que’ are both followed by an infinitive.", "answer": true, "explain": "se debe descansar / hay que tener cuidado — always an infinitive."}, {"statement": "‘tener cuidado’ means ‘to be careful’.", "answer": true, "explain": "tener cuidado = to be careful, key online-safety phrase."}, {"statement": "‘Es importante que tengas cuidado’ uses the subjunctive and is a Higher-tier structure.", "answer": true, "explain": "es importante que + subjunctive (tengas) is a Higher-tier feature."}, {"statement": "‘seguro’ means ‘dangerous’.", "answer": false, "explain": "seguro = safe; peligroso = dangerous — opposite meanings."}, {"statement": "‘la actitud’ means ‘attitude’, not ‘aptitude’ (that’s ‘la aptitud’).", "answer": true, "explain": "actitud and aptitud are easily confused look-alikes with different meanings."}]}, "misc": {"enabled": true, "items": [{"myth": "Se debe compartir tu contraseña con tus amigos.", "truth": "No se debe compartir tu contraseña con nadie.", "check": {"question": "Why is sharing your password bad advice?", "options": ["a password protects your personal data and should stay private", "passwords are not written in Spanish so it does not matter at all", "friends never misuse a shared password with each other", "‘contraseña’ actually means ‘friendship’ in Spanish"], "answer": 0, "explain": "A password should never be shared — it protects your personal data and account."}}, {"myth": "‘La red social’ means ‘a red social event’.", "truth": "‘La red social’ means ‘a social network’.", "check": {"question": "Why is translating ‘red’ as ‘the colour red’ wrong here?", "options": ["‘red’ is a false friend that means ‘network’ in this phrase", "‘red’ is always a colour in Spanish with absolutely no other meaning", "‘social’ changes ‘red’ into a completely different word", "the sentence is actually about traffic lights"], "answer": 0, "explain": "red = network; ‘red social’ = social network, not anything about colour."}}, {"myth": "Es importante proteges tu contraseña.", "truth": "Es importante proteger tu contraseña.", "check": {"question": "Why is ‘Es importante proteges tu contraseña’ wrong?", "options": ["‘es importante’ must be followed by an infinitive, not a conjugated verb", "‘proteges’ needs a written accent on its final letter to be considered correct", "‘contraseña’ should be written in the plural form in this particular sentence", "the sentence is missing the word ‘no’ before the verb"], "answer": 0, "explain": "es importante + infinitive → proteger, not the conjugated form proteges."}}, {"myth": "‘Sigo a mis amigos’ means ‘I stopped following my friends’.", "truth": "‘Sigo a mis amigos’ means ‘I follow my friends’.", "check": {"question": "What tense/meaning does ‘sigo’ actually express?", "options": ["present tense — I follow (now, ongoing)", "preterite tense — I followed once and stopped", "future tense — I will follow later", "a command telling someone else to follow"], "answer": 0, "explain": "sigo is present tense (from seguir) — I follow, not a past or stopped action."}}, {"myth": "Es importante que tienes cuidado.", "truth": "Es importante que tengas cuidado.", "check": {"question": "Why must ‘tienes’ change to ‘tengas’ here?", "options": ["‘es importante que’ triggers the subjunctive mood", "‘tienes’ is spelt incorrectly and should have an accent", "the sentence needs the imperfect tense instead", "‘que’ should be removed from the sentence"], "answer": 0, "explain": "es importante que is a subjunctive trigger, so tienes → tengas."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Safety-advice sentences reuse chunks you know: ‘no se debe…’, ‘hay que…’, ‘es importante…’. Listen carefully for the negative ‘no’ before ‘se debe’ — missing it reverses the whole meaning of the advice.", "check": {"question": "You hear ‘…no se debe…’ but write ‘se debe’. What has gone wrong?", "options": ["the advice has been reversed by missing the negative ‘no’", "nothing at all — ‘se debe’ and ‘no se debe’ mean exactly the same thing", "the tense has changed from present to past", "the subject of the sentence has changed"], "answer": 0, "explain": "Missing ‘no’ turns ‘you must not’ into ‘you must’ — the opposite meaning."}}, {"title": "Paper 3 — Reading and translation into English", "html": "Watch the false friend ‘red’ (network, not colour) and keep translations natural: ‘compartir datos personales’ = ‘to share personal data’, not a word-for-word oddity. Look out for ‘ciberacoso’, a topic-specific word worth learning by sight.", "check": {"question": "‘Nunca comparto mis datos personales en línea’ means…", "options": ["I never share my personal data online", "I always share my personal data online", "I sometimes share photos online", "I never go online at all"], "answer": 0, "explain": "nunca = never; comparto = I share; the sentence is a negative statement about sharing data."}}, {"title": "Paper 4 — Writing & translation into Spanish", "html": "Combine an opinion, advice and a reason: ‘Uso las redes sociales porque es divertido, pero es importante proteger tu contraseña.’ At Higher, add the subjunctive and conditional: ‘es importante que tengas cuidado’, ‘se debería tener más cuidado’.", "check": {"question": "Which answer reaches the top band?", "options": ["Uso las redes sociales porque es divertido, pero es importante que tengas cuidado", "Uso las redes sociales y es divertido y divertido y muy divertido y divertido siempre", "Las redes sociales son buenas", "Tengo un perfil"], "answer": 0, "explain": "It links an opinion, a reason and a Higher-tier subjunctive structure — range and accuracy, not just length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carla says. Answer <strong>in English</strong>.<br>(a) Give <strong>one</strong> reason Carla uses social media. (1)<br>(b) What does she never share? (1)<br>(c) What happened to her last year? (1)<br>(d) Who does she follow now? (1)", "marks": 4, "hint": "Find the reason after ‘porque’, what she never does after ‘nunca’, the past event after ‘el año pasado’, and who she follows after ‘ahora’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> to be in contact with friends / to share photos (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(b)</strong> her personal data <em>(1)</em>.</li>\n                <li><strong>(c)</strong> she suffered/experienced cyberbullying <em>(1)</em>.</li>\n                <li><strong>(d)</strong> only people she knows in person <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) You should protect your password. <br>(b) One must not share personal data. <br>(c) I am in contact with my friends because it is fun.", "marks": 5, "hint": "‘You should protect’ = Se debe proteger… ‘One must not share’ = No se debe compartir… ‘I am in contact with’ = Estoy en contacto con…", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Se debe proteger tu/la contraseña. <em>(1)</em></li>\n                <li><strong>(b)</strong> No se debe compartir datos personales. <em>(1)</em></li>\n                <li><strong>(c)</strong> Estoy en contacto con mis amigos <em>(1)</em> porque <em>(1)</em> es divertido <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘No se debe compartir datos personales’ must keep the negative ‘no’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', '{"learn": {"enabled": true, "items": [{"title": "How do I describe my home?", "html": "<p>Use <span data-say=\"vivir\">vivir</span> (to live) with <strong>en</strong> to say where you live. The two key words for ‘home’ are:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la casa\">la casa</span></td><td>house</td><td><span data-say=\"el piso\">el piso</span></td><td>flat / apartment</td></tr>\n              <tr><td><span data-say=\"la habitación\">la habitación</span></td><td>room</td><td><span data-say=\"cómodo\">cómodo / cómoda</span></td><td>comfortable</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Vivo en una casa cómoda en las afueras de la ciudad.\">Vivo en una casa cómoda en las afueras de la ciudad.</span> — <em>I live in a comfortable house on the outskirts of the city.</em></p>", "check": {"question": "What does ‘Vivo en un piso’ mean?", "options": ["I live in a flat", "I live in a big house with a garden", "I used to live in a flat", "I would like to live in a flat"], "answer": 0, "explain": "vivo = I live (present tense); el piso = flat/apartment. The distractors change the tense or add details that are not there."}}, {"title": "What rooms are there in my house?", "html": "<p>Use <span data-say=\"hay\">hay</span> (there is / there are) to list the rooms — <strong>hay never changes</strong>, whether you mean one thing or several.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el dormitorio\">el dormitorio</span></td><td>bedroom</td><td><span data-say=\"el salón\">el salón</span></td><td>living room</td></tr>\n              <tr><td><span data-say=\"la cocina\">la cocina</span></td><td>kitchen</td><td><span data-say=\"el cuarto de baño\">el cuarto de baño</span></td><td>bathroom</td></tr>\n              <tr><td><span data-say=\"el jardín\">el jardín</span></td><td>garden</td><td><span data-say=\"arriba\">arriba</span> / <span data-say=\"abajo\">abajo</span></td><td>upstairs / downstairs</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi casa hay cuatro dormitorios arriba y la cocina está abajo.\">En mi casa hay cuatro dormitorios arriba y la cocina está abajo.</span> — <em>In my house there are four bedrooms upstairs and the kitchen is downstairs.</em></p>", "check": {"question": "Where is ‘la cocina’ in the model sentence?", "options": ["downstairs", "upstairs, next to the bedrooms", "in the garden behind the house", "in the bathroom on the first floor"], "answer": 0, "explain": "la cocina está abajo = the kitchen is downstairs. Don’t confuse arriba (upstairs) with abajo (downstairs)."}}, {"title": "How do I describe my town or area?", "html": "<p>Key places in a <span data-say=\"el barrio\">barrio</span> (neighbourhood):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la ciudad\">la ciudad</span></td><td>city</td><td><span data-say=\"el pueblo\">el pueblo</span></td><td>town / village</td></tr>\n              <tr><td><span data-say=\"el centro\">el centro</span></td><td>town centre</td><td><span data-say=\"las tiendas\">las tiendas</span></td><td>shops</td></tr>\n              <tr><td><span data-say=\"el centro comercial\">el centro comercial</span></td><td>shopping centre</td><td><span data-say=\"el polideportivo\">el polideportivo</span></td><td>sports centre</td></tr>\n              <tr><td><span data-say=\"la estación\">la estación</span></td><td>station</td><td><span data-say=\"el ayuntamiento\">el ayuntamiento</span></td><td>town hall</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"En mi pueblo hay un polideportivo y un centro comercial cerca del ayuntamiento.\">En mi pueblo hay un polideportivo y un centro comercial cerca del ayuntamiento.</span> — <em>In my town there is a sports centre and a shopping centre near the town hall.</em></p>", "check": {"question": "What is ‘el ayuntamiento’?", "options": ["the town hall", "the shopping centre near the station", "the train station in the centre", "the sports centre building"], "answer": 0, "explain": "el ayuntamiento = town hall. Don’t confuse it with el centro comercial (shopping centre) or la estación (station)."}}, {"title": "How do I say what there is (or isn’t) and what you can do?", "html": "<p><span data-say=\"hay\">Hay</span> (there is/are) and <span data-say=\"no hay\">no hay</span> (there isn’t/aren’t) never change form. To say what is possible, use <span data-say=\"se puede\">se puede</span> + infinitive (you can / one can).</p>\n            <ul>\n              <li><span data-say=\"En mi barrio hay muchas tiendas.\">En mi barrio hay muchas tiendas.</span> — In my area there are many shops.</li>\n              <li><span data-say=\"No hay piscina en mi pueblo.\">No hay piscina en mi pueblo.</span> — There isn’t a swimming pool in my town.</li>\n              <li><span data-say=\"Se puede nadar en el polideportivo.\">Se puede nadar en el polideportivo.</span> — You can swim at the sports centre.</li>\n            </ul>", "check": {"question": "What does ‘no hay’ mean?", "options": ["there isn’t / there aren’t", "there is definitely one", "you are not allowed to go there", "there won’t be one next year"], "answer": 0, "explain": "no hay = there isn’t/aren’t, the negative of hay. It does not mean ‘forbidden’ or change the tense."}}, {"title": "How do I describe places and say where they are?", "html": "<p>Adjectives to describe a place (remember they must agree with the noun):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"grande\">grande</span></td><td>big</td><td><span data-say=\"pequeño\">pequeño / pequeña</span></td><td>small</td></tr>\n              <tr><td><span data-say=\"ruidoso\">ruidoso / ruidosa</span></td><td>noisy</td><td><span data-say=\"tranquilo\">tranquilo / tranquila</span></td><td>quiet</td></tr>\n              <tr><td><span data-say=\"limpio\">limpio / limpia</span></td><td>clean</td><td><span data-say=\"sucio\">sucio / sucia</span></td><td>dirty</td></tr>\n              <tr><td><span data-say=\"animado\">animado / animada</span></td><td>lively</td><td></td><td></td></tr>\n            </table>\n            <p>Use <strong>estar</strong> for location, with prepositions of place:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"al lado de\">al lado de</span></td><td>next to</td><td><span data-say=\"enfrente de\">enfrente de</span></td><td>opposite</td></tr>\n              <tr><td><span data-say=\"entre\">entre</span></td><td>between</td><td><span data-say=\"cerca de\">cerca de</span></td><td>near</td></tr>\n              <tr><td><span data-say=\"lejos de\">lejos de</span></td><td>far from</td><td><span data-say=\"en las afueras\">en las afueras</span></td><td>on the outskirts</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Mi barrio es animado pero un poco ruidoso; el parque está entre la estación y el centro comercial.\">Mi barrio es animado pero un poco ruidoso; el parque está entre la estación y el centro comercial.</span></p>", "check": {"question": "In the model sentence, where is ‘el parque’?", "options": ["between the station and the shopping centre", "next to the town hall in the centre", "far from the town centre and the train station", "opposite the sports centre and the shops"], "answer": 0, "explain": "está entre… y… = it is between… and… — the park is between the station and the shopping centre."}}, {"title": "Higher: comparing places and the imperfect tense", "html": "<p><span class=\"tier-h\">H</span> To compare two places, use <strong>más / menos + adjective + que</strong>:</p>\n            <ul>\n              <li><span data-say=\"Mi pueblo es más tranquilo que la ciudad.\">Mi pueblo es más tranquilo que la ciudad.</span> — My town is quieter than the city.</li>\n              <li><span data-say=\"La ciudad es menos tranquila que mi pueblo.\">La ciudad es menos tranquila que mi pueblo.</span> <span class=\"tier-h\">H</span> — The city is less quiet than my town.</li>\n            </ul>\n            <p><span class=\"tier-h\">H</span> To describe how things used to be, use the <strong>imperfect tense</strong> (vivía, había, era):</p>\n            <ul>\n              <li><span data-say=\"Antes vivía en un piso pequeño en la ciudad.\">Antes vivía en un piso pequeño en la ciudad.</span> — I used to live in a small flat in the city.</li>\n              <li><span data-say=\"De niño, no había centro comercial en mi barrio.\">De niño, no había centro comercial en mi barrio.</span> <span class=\"tier-h\">H</span> — As a child, there wasn’t a shopping centre in my area.</li>\n            </ul>", "check": {"question": "What does ‘Antes vivía en un piso pequeño’ mean?", "options": ["I used to live in a small flat", "I live in a small flat right now", "I am going to live in a small flat", "I would like to live in a small flat"], "answer": 0, "explain": "vivía is the imperfect tense = I used to live. It describes a past habitual state, not the present or future."}}, {"title": "How do I ask for and give directions?", "html": "<p>Use <span data-say=\"la dirección\">la dirección</span> (address/direction) to ask the way, <span data-say=\"cruzar\">cruzar</span> (to cross) and <span data-say=\"el punto\">el punto</span> (point) to describe a route, and <span data-say=\"fuera\">fuera</span> (outside) to say where something is.</p>\n            <p><span data-say=\"Perdón, ¿me puede dar la dirección al ayuntamiento?\">— Perdón, ¿me puede dar la dirección al ayuntamiento?</span><br>\n            <span data-say=\"Sí, claro. Tiene que cruzar la plaza; el punto de información turística está justo fuera de la estación.\">— Sí, claro. Tiene que cruzar la plaza; el punto de información turística está justo fuera de la estación.</span><br>\n            <span data-say=\"Muchas gracias.\">— Muchas gracias.</span></p>", "check": {"question": "According to the dialogue, where exactly is the tourist information point?", "options": ["just outside the station", "inside the town hall, near the plaza entrance", "opposite the train station main entrance", "next to the shopping centre car park entrance"], "answer": 0, "explain": "‘fuera de la estación’ = outside the station. The other options invent a different building or location that isn’t in the dialogue."}}, {"title": "How do I describe my neighbourhood in more detail?", "html": "<p>More vocabulary for describing where you live:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el lugar\">el lugar</span></td><td>place</td><td><span data-say=\"el sitio\">el sitio</span></td><td>site / place</td></tr>\n              <tr><td><span data-say=\"la comunidad\">la comunidad</span></td><td>community</td><td><span data-say=\"el vecino\">el vecino / la vecina</span></td><td>neighbour</td></tr>\n              <tr><td><span data-say=\"la entrada\">la entrada</span></td><td>entrance</td><td><span data-say=\"la pared\">la pared</span></td><td>wall</td></tr>\n              <tr><td><span data-say=\"la piedra\">la piedra</span></td><td>stone</td><td><span data-say=\"el metro\">el metro</span></td><td>metre / underground</td></tr>\n            </table>\n            <p>Model paragraph: <span data-say=\"Vivo en un lugar pequeño, casi como una isla tranquila, en un sitio cerca del río. Es una comunidad muy unida donde los vecinos se ayudan. La entrada de mi casa tiene una pared de piedra, y a diez metros hay una plaza de estilo colonial donde se venden productos locales. El espacio físico del pueblo no es grande — su tamaño es pequeño — y ahora mismo hay obras cerca de la iglesia, que lleva el nombre de un santo; por eso, algunas tiendas están abandonadas temporalmente.\">Vivo en un lugar pequeño, casi como una isla tranquila, en un sitio cerca del río. Es una comunidad muy unida donde los vecinos se ayudan. La entrada de mi casa tiene una pared de piedra, y a diez metros hay una plaza de estilo colonial donde se venden productos locales. El espacio físico del pueblo no es grande — su tamaño es pequeño — y ahora mismo hay obras cerca de la iglesia, que lleva el nombre de un santo; por eso, algunas tiendas están abandonadas temporalmente.</span> — <em>I live in a small place, almost like a quiet island, on a site near the river. It''s a very close-knit community where the neighbours help each other. My house''s entrance has a stone wall, and ten metres away there''s a colonial-style square where local products are sold. The physical space of the village isn''t big — its size is small — and right now there are roadworks near the church, which is named after a saint; because of this, some shops are temporarily abandoned.</em></p>", "check": {"question": "According to the paragraph, why are some shops temporarily closed?", "options": ["because of roadworks near the church", "because the whole community voted to close them down", "because the village is too small to need any shops", "because the neighbours all abandoned the square together"], "answer": 0, "explain": "‘hay obras cerca de la iglesia… algunas tiendas están abandonadas temporalmente’ = there are roadworks near the church, so some shops are temporarily closed/abandoned."}}]}, "terms": {"enabled": true, "pairs": [{"term": "la casa · el piso", "definition": "house · flat / apartment"}, {"term": "la habitación · cómodo", "definition": "room · comfortable"}, {"term": "el dormitorio · el salón", "definition": "bedroom · living room"}, {"term": "la cocina · el cuarto de baño", "definition": "kitchen · bathroom"}, {"term": "el jardín · arriba / abajo", "definition": "garden · upstairs / downstairs"}, {"term": "el barrio · el pueblo", "definition": "neighbourhood · town / village"}, {"term": "la ciudad · el centro", "definition": "city · town centre"}, {"term": "las tiendas · el centro comercial", "definition": "shops · shopping centre"}, {"term": "el polideportivo · la estación", "definition": "sports centre · station"}, {"term": "el ayuntamiento", "definition": "town hall"}, {"term": "hay · no hay", "definition": "there is/are · there isn’t/aren’t"}, {"term": "se puede + infinitive", "definition": "you can / one can"}, {"term": "grande · pequeño", "definition": "big · small"}, {"term": "ruidoso · tranquilo", "definition": "noisy · quiet"}, {"term": "limpio · sucio · animado", "definition": "clean · dirty · lively"}, {"term": "al lado de · enfrente de · entre", "definition": "next to · opposite · between"}, {"term": "cerca de · lejos de · en las afueras (H)", "definition": "near · far from · on the outskirts"}, {"term": "más … que · antes vivía (H)", "definition": "more … than · I used to live (imperfect)"}, {"term": "el lugar · el sitio", "definition": "the place · the site/place"}, {"term": "el punto", "definition": "the point"}, {"term": "las obras", "definition": "roadworks / building works"}, {"term": "gracias", "definition": "thank you"}, {"term": "fuera", "definition": "outside"}, {"term": "el producto", "definition": "the product"}, {"term": "el santo · la santa", "definition": "the saint"}, {"term": "el espacio", "definition": "the space"}, {"term": "la comunidad", "definition": "the community"}, {"term": "el estilo", "definition": "the style"}, {"term": "el tamaño", "definition": "the size"}, {"term": "la dirección", "definition": "the address / direction"}, {"term": "abandonar", "definition": "to abandon"}, {"term": "físico", "definition": "physical"}, {"term": "la entrada", "definition": "the entrance"}, {"term": "la piedra", "definition": "the stone"}, {"term": "la pared", "definition": "the wall"}, {"term": "el metro", "definition": "the metre / the underground"}, {"term": "el vecino · la vecina", "definition": "the neighbour"}, {"term": "la isla", "definition": "the island"}, {"term": "cruzar", "definition": "to cross"}, {"term": "el oro", "definition": "gold"}, {"term": "la distancia", "definition": "the distance"}, {"term": "la pintura", "definition": "the painting / paint"}, {"term": "la altura", "definition": "the height"}, {"term": "hermoso", "definition": "beautiful"}, {"term": "el ruido", "definition": "the noise"}, {"term": "la venta", "definition": "the sale"}, {"term": "cobrar", "definition": "to charge / to get paid"}, {"term": "la velocidad", "definition": "the speed"}, {"term": "el hogar", "definition": "the home"}, {"term": "robar", "definition": "to steal"}, {"term": "la señal", "definition": "the sign / signal"}, {"term": "cometer", "definition": "to commit (e.g. a crime)"}, {"term": "devolver", "definition": "to give back / return"}, {"term": "el kilómetro", "definition": "the kilometre"}, {"term": "la esquina", "definition": "the corner"}, {"term": "vacío", "definition": "empty"}, {"term": "la arquitectura", "definition": "the architecture"}, {"term": "el delito", "definition": "the crime"}, {"term": "el accidente", "definition": "the accident"}, {"term": "las compras", "definition": "the shopping / purchases"}, {"term": "la felicidad", "definition": "happiness"}, {"term": "el reloj", "definition": "the clock / watch"}, {"term": "infantil", "definition": "children''s (e.g. parque infantil)"}, {"term": "el costo", "definition": "the cost"}, {"term": "la carretera", "definition": "the road / highway"}, {"term": "efectivo", "definition": "cash"}, {"term": "la escalera", "definition": "the stairs"}, {"term": "los alrededores", "definition": "the surroundings / outskirts"}, {"term": "el rincón", "definition": "the corner / nook"}, {"term": "detrás", "definition": "behind"}, {"term": "la torre", "definition": "the tower"}, {"term": "caro", "definition": "expensive"}, {"term": "feo", "definition": "ugly"}, {"term": "ideal", "definition": "ideal"}, {"term": "el aeropuerto", "definition": "the airport"}, {"term": "situado", "definition": "situated / located"}, {"term": "el ascensor", "definition": "the lift / elevator"}, {"term": "la calefacción", "definition": "the heating"}, {"term": "el descuento", "definition": "the discount"}, {"term": "el supermercado", "definition": "the supermarket"}, {"term": "lo siento", "definition": "I''m sorry"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"en mi barrio hay muchas tiendas\" data-listen></span><br>Listen. What is being said?", "options": ["There are many shops in my area", "There is a big shopping centre near my house", "There aren’t any shops in my town", "There used to be many shops in my area"], "answer": 0, "explain": "‘en mi barrio hay muchas tiendas’ = there are many shops in my area. The traps add detail, reverse the meaning with a negative, or change the tense."}, {"question": "<span data-say=\"se puede nadar en el polideportivo\" data-listen></span><br>Listen. What can you do?", "options": ["You can swim at the sports centre", "You cannot swim at the sports centre", "You can swim in the sea near the town", "You used to be able to swim at the sports centre"], "answer": 0, "explain": "‘se puede nadar en el polideportivo’ = you can swim at the sports centre. Trap B negates it; C changes the place; D changes the tense."}, {"question": "How do you say ‘there isn’t a swimming pool in my town’?", "options": ["No hay piscina en mi pueblo", "Hay piscina en mi pueblo", "No hay piscinas en mi ciudad grande", "No había piscina en mi pueblo"], "answer": 0, "explain": "no hay + noun = there isn’t. B drops the negative (opposite meaning); C adds extra detail and changes place; D shifts to the imperfect (there wasn’t, used to be)."}, {"question": "Which sentence uses ‘estar’ correctly for location?", "options": ["El parque está al lado del ayuntamiento", "El parque es al lado del ayuntamiento", "El parque hay al lado del ayuntamiento", "El parque tiene al lado del ayuntamiento"], "answer": 0, "explain": "Location always uses estar. B wrongly uses ser; C wrongly uses hay; D wrongly uses tener."}, {"question": "What does ‘el cuarto de baño’ mean?", "options": ["the bathroom", "the bedroom, upstairs near the garden", "the kitchen, next to the living room", "the living room, which is usually downstairs"], "answer": 0, "explain": "el cuarto de baño = the bathroom. Don’t confuse it with el dormitorio (bedroom), la cocina (kitchen) or el salón (living room)."}, {"question": "Complete: ‘Mi pueblo es más tranquilo ___ la ciudad.’", "options": ["que", "como", "de", "muy"], "answer": 0, "explain": "Comparatives need más/menos + adjective + QUE. ‘como’ means ‘as/like’, ‘de’ means ‘of/from’, and ‘muy’ (very) does not fit here."}, {"question": "‘Antes vivía en un piso pequeño’ is in which tense?", "options": ["the imperfect tense (used to)", "the ordinary present tense (right now)", "the near future (going to)", "a direct command"], "answer": 0, "explain": "vivía is imperfect, matching ‘antes’ (before/in the past). It is not present, future or a command."}, {"question": "Which word means ‘noisy’?", "options": ["ruidoso", "tranquilo", "limpio", "animado"], "answer": 0, "explain": "ruidoso = noisy. tranquilo means quiet (the opposite), limpio means clean and animado means lively."}, {"question": "What does ‘en las afueras’ mean?", "options": ["on the outskirts", "in the town centre, near the shops", "next to the station, by the park", "between two shops, near the market"], "answer": 0, "explain": "en las afueras = on the outskirts. El centro is the town centre — the opposite idea."}, {"question": "‘No hay’ + a noun means…", "options": ["there isn’t / there aren’t — a negative", "there is definitely one nearby", "you are not allowed to go there at all today", "there won’t be one there next year"], "answer": 0, "explain": "no hay = there isn’t/aren’t, simply the negative of hay. It does not mean ‘forbidden’, ‘certain’ or change the tense."}, {"question": "Which word means ''distance''?", "options": ["la distancia", "la velocidad", "la altura", "el ruido"], "answer": 0, "explain": "la distancia = distance. la velocidad = speed, la altura = height, el ruido = noise — related measurements, but each is different."}, {"question": "Which word means ''to steal''?", "options": ["robar", "cobrar", "devolver", "cometer"], "answer": 0, "explain": "robar = to steal. cobrar = to charge/get paid, devolver = to give back, cometer = to commit (e.g. cometer un delito)."}, {"question": "Which word means ''a crime''?", "options": ["un delito", "un accidente", "una señal", "una venta"], "answer": 0, "explain": "un delito = a crime. un accidente = an accident, una señal = a sign/signal, una venta = a sale — all things a local news story might mention."}, {"question": "Which word means ''empty''?", "options": ["vacío", "hermoso", "grande", "pequeño"], "answer": 0, "explain": "vacío = empty. hermoso = beautiful, grande = big, pequeño = small — all common adjectives for describing a house or place."}, {"question": "Which word means ''height''?", "options": ["la altura", "el tamaño", "la distancia", "la velocidad"], "answer": 0, "explain": "la altura = height. el tamaño = size, la distancia = distance, la velocidad = speed — all measurements, but each means something different."}, {"question": "Which word means ''a sign'' or ''a signal''?", "options": ["una señal", "un delito", "un accidente", "una venta"], "answer": 0, "explain": "una señal = a sign/signal (e.g. a road sign). un delito = a crime, un accidente = an accident, una venta = a sale."}]}, "fib": {"enabled": true, "questions": [{"text": "En mi barrio [hay] muchas tiendas. <span data-say=\"en mi barrio hay muchas tiendas\" data-listen></span>"}, {"text": "Mi dormitorio está <span data-say=\"arriba\">arriba</span> y la cocina está [abajo]. (downstairs)"}, {"text": "En mi pueblo hay un polideportivo y un [centro comercial] cerca del ayuntamiento. (shopping centre)"}, {"text": "Se [puede] nadar en el polideportivo. (you can — se puede)"}, {"text": "Mi pueblo es más [tranquilo] que la ciudad. (quieter — comparative, H)"}, {"text": "De niño, [vivía] en un piso pequeño. (I used to live — imperfect, H)"}, {"text": "El parque [está] entre la estación y el centro comercial. (is — estar for location)"}, {"text": "El anillo de [oro] que compré en el mercado es precioso. (gold)"}, {"text": "La [arquitectura] de la catedral de mi ciudad es de estilo gótico. (architecture)"}, {"text": "Hay una [pintura] muy bonita en la pared del salón. (painting)"}, {"text": "El supermercado está a un [kilómetro] de mi casa. (kilometre)"}, {"text": "Dobla a la izquierda en la [esquina] y sigue todo recto. (corner)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘hay’ changes to ‘han’ when you talk about more than one thing.", "answer": false, "explain": "hay is invariable — it never changes, whether singular or plural."}, {"statement": "‘se puede’ is followed by an infinitive.", "answer": true, "explain": "se puede nadar / comprar / visitar — always an infinitive."}, {"statement": "Location (where something is) uses ‘estar’, not ‘ser’.", "answer": true, "explain": "El parque está cerca de mi casa — location always takes estar."}, {"statement": "‘el ayuntamiento’ means ‘the shopping centre’.", "answer": false, "explain": "el ayuntamiento = town hall; el centro comercial = shopping centre."}, {"statement": "Comparatives use ‘más / menos + adjective + que’.", "answer": true, "explain": "Mi pueblo es más tranquilo QUE la ciudad."}, {"statement": "‘antes vivía’ is in the present tense.", "answer": false, "explain": "vivía is the imperfect tense (used to live), not the present."}, {"statement": "‘tranquilo’ and ‘ruidoso’ are opposites.", "answer": true, "explain": "tranquilo = quiet, ruidoso = noisy."}, {"statement": "‘en las afueras’ means ‘in the town centre’.", "answer": false, "explain": "en las afueras = on the outskirts; el centro = the town centre."}, {"statement": "‘el vecino’ means ‘the neighbour’.", "answer": true, "explain": "el vecino / la vecina = neighbour."}, {"statement": "‘abandonado’ means ‘brand new’.", "answer": false, "explain": "abandonado means abandoned/deserted, not brand new (nuevo)."}, {"statement": "‘cruzar’ means ‘to cross’.", "answer": true, "explain": "cruzar la calle = to cross the street."}, {"statement": "‘la piedra’ means ‘brick’.", "answer": false, "explain": "la piedra means stone; a brick is un ladrillo."}]}, "misc": {"enabled": true, "items": [{"myth": "El parque es cerca de mi casa.", "truth": "El parque está cerca de mi casa.", "check": {"question": "Why is ‘es’ wrong here?", "options": ["location needs ‘estar’, not ‘ser’", "‘cerca’ must come before ‘el parque’", "‘casa’ needs the article ‘un’ instead", "the sentence needs the imperfect tense"], "answer": 0, "explain": "Location always uses estar: el parque está cerca de mi casa."}}, {"myth": "Hay piscinas en mi barrio, pero no han restaurantes.", "truth": "Hay piscinas en mi barrio, pero no hay restaurantes.", "check": {"question": "What is wrong with ‘no han restaurantes’?", "options": ["‘hay’ never changes form, even for plurals", "‘restaurantes’ should be written in the singular", "‘no’ should come straight after the verb", "‘piscinas’ needs the article ‘las’ in front"], "answer": 0, "explain": "hay is invariable — it never becomes ‘han’, whether singular or plural."}}, {"myth": "Se puede nadamos en el polideportivo.", "truth": "Se puede nadar en el polideportivo.", "check": {"question": "Why is ‘se puede nadamos’ incorrect?", "options": ["‘se puede’ must be followed by an infinitive", "‘nadamos’ needs a written accent on the last letter", "‘polideportivo’ should actually be feminine", "‘se puede’ only ever works with the verb ‘hay’"], "answer": 0, "explain": "se puede + infinitive: se puede nadar, not a conjugated form like nadamos."}}, {"myth": "Mi pueblo es más tranquilo la ciudad.", "truth": "Mi pueblo es más tranquilo que la ciudad.", "check": {"question": "What word is missing from the comparison?", "options": ["que (than)", "muy (very)", "con (with)", "de (of)"], "answer": 0, "explain": "Comparatives need más/menos + adjective + QUE: más tranquilo que la ciudad."}}, {"myth": "Vivo en un piso pequeño de niño.", "truth": "De niño, vivía en un piso pequeño.", "check": {"question": "Why must this be in the imperfect tense (vivía)?", "options": ["‘de niño’ signals a past, no-longer-true situation", "‘piso’ is secretly a feminine noun", "the sentence is actually written as a direct command", "‘pequeño’ must agree with the verb ‘vivo’"], "answer": 0, "explain": "‘de niño’ (as a child) signals a past habitual state → imperfect: vivía, not the present vivo."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Listening: hay vs no hay vs se puede", "html": "These three sound similar but mean different things: hay (there is), no hay (there isn’t), se puede (you can). Listen carefully for a ‘no’ before hay or puede, and for whether puede replaces hay entirely.", "check": {"question": "You hear ‘no se puede aparcar aquí’. What does it mean?", "options": ["you cannot park here", "there is a car park just here", "you must park here now", "there used to be no parking here"], "answer": 0, "explain": "no se puede + infinitive = you cannot… — listen for the negative before se puede."}}, {"title": "Paper 2 — Speaking: photo card on your local area", "html": "Describe what there is (hay), add an opinion adjective (tranquilo / animado / ruidoso) and a preposition of place (al lado de / cerca de). Examiners reward range, not just accuracy.", "check": {"question": "Which answer shows the most range for a photo of a town centre?", "options": ["Hay muchas tiendas y el ayuntamiento está al lado de la estación", "Hay tiendas en el centro", "Hay una tienda pequeña", "Hay tiendas, hay tiendas y hay muchas tiendas en el centro de mi pueblo"], "answer": 0, "explain": "It combines hay, a specific place noun and a preposition of place. Option D is longer but just repeats ‘hay tiendas’ — length without any real range."}}, {"title": "Paper 4 — Writing & translation with Higher structures", "html": "For the top band, combine a comparative (más… que) with the imperfect (antes vivía…) and a preposition of place: ‘Mi barrio es más animado que el pueblo donde vivía antes.’", "check": {"question": "Which sentence reaches the top band?", "options": ["Mi barrio es más animado que el pueblo donde vivía antes", "Mi barrio es animado", "Mi barrio es animado y animado y animado y muy animado también", "Mi barrio bueno"], "answer": 0, "explain": "It uses a comparative plus the imperfect (vivía) — range and complexity, not just a long string of repeated simple words."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) Where exactly does Carlos live? (1)<br>(b) Give <strong>one</strong> positive and <strong>one</strong> negative thing about his neighbourhood. (2)<br>(c) Why does he go to the sports centre? (1)<br>(d) What would he like next year? (1)", "marks": 5, "hint": "Find the home details after ‘Vivo en’, the opinion words ‘animado’/‘ruidoso’, the reason after ‘así que’, and the wish after ‘me gustaría’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> (a) small flat, in the city centre, near the station <em>(1)</em>.</li>\n                <li><strong>(b)</strong> positive: lively / lots of shops <em>(1)</em>; negative: quite noisy at night <em>(1)</em>.</li>\n                <li><strong>(c)</strong> (because) there is no swimming pool near his house <em>(1)</em>.</li>\n                <li><strong>(d)</strong> to live in a house with a garden <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) There is a big park near my house. <br>(b) My town is quieter than the city. <br>(c) I used to live in a flat, but now I live in a house.", "marks": 5, "hint": "‘There is’ = hay. ‘Quieter than’ = más tranquilo que (comparative). ‘I used to live’ = the imperfect vivía.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Hay un parque grande cerca de mi casa. <em>(1)</em></li>\n                <li><strong>(b)</strong> Mi pueblo es más tranquilo que la ciudad. <em>(1)</em></li>\n                <li><strong>(c)</strong> Vivía en un piso <em>(1)</em> pero <em>(1)</em> ahora vivo en una casa <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. ‘Vivía’ must be the imperfect, not the present ‘vivo’.</li>\n            </ul></div>"}]}}'::jsonb),
('spanish', '9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', '{"learn": {"enabled": true, "items": [{"title": "How do I talk about the environment?", "html": "<p>The key phrase is <span data-say=\"el medio ambiente\">el medio ambiente</span> (the environment). Here is the core vocabulary — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la contaminación\">la contaminación</span></td><td>pollution</td><td><span data-say=\"el reciclaje\">el reciclaje</span></td><td>recycling</td></tr>\n              <tr><td><span data-say=\"reciclar\">reciclar</span></td><td>to recycle</td><td><span data-say=\"la basura\">la basura</span></td><td>rubbish</td></tr>\n              <tr><td><span data-say=\"la naturaleza\">la naturaleza</span></td><td>nature</td><td><span data-say=\"los recursos naturales\">los recursos naturales</span></td><td>natural resources</td></tr>\n              <tr><td><span data-say=\"la energía\">la energía</span></td><td>energy</td><td><span data-say=\"proteger\">proteger</span></td><td>to protect</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Es importante proteger el medio ambiente y reciclar la basura.\">Es importante proteger el medio ambiente y reciclar la basura.</span> — <em>It is important to protect the environment and recycle rubbish.</em></p>", "check": {"question": "What does ‘el medio ambiente’ mean?", "options": ["the environment", "the average weather", "the middle of the city", "a natural resource"], "answer": 0, "explain": "el medio ambiente = the environment. On its own ‘ambiente’ can mean atmosphere, but this fixed phrase means environment."}}, {"title": "How do I describe environmental problems?", "html": "<p>Problems facing the planet — tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la contaminación del aire\">la contaminación del aire</span></td><td>air pollution</td><td><span data-say=\"el tráfico\">el tráfico</span></td><td>traffic</td></tr>\n              <tr><td><span data-say=\"la deforestación\">la deforestación</span></td><td>deforestation</td><td><span data-say=\"la sequía\">la sequía</span></td><td>drought</td></tr>\n              <tr><td><span data-say=\"el cambio climático\">el cambio climático</span></td><td>climate change</td><td><span data-say=\"el calentamiento global\">el calentamiento global</span></td><td>global warming</td></tr>\n            </table>\n            <p>Example: <span data-say=\"El tráfico causa mucha contaminación del aire en las ciudades.\">El tráfico causa mucha contaminación del aire en las ciudades.</span> — <em>Traffic causes a lot of air pollution in cities.</em></p>", "check": {"question": "What is ‘la sequía’?", "options": ["drought", "flooding", "a heatwave", "heavy rain"], "answer": 0, "explain": "la sequía = drought, a long period without rain. Do not confuse it with inundación (flood) or una ola de calor (heatwave)."}}, {"title": "How do I give environmental advice?", "html": "<p>Reuse the advice structures you already know — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe reciclar\">se debe reciclar</span></td><td>one should recycle</td></tr>\n              <tr><td><span data-say=\"no se debe malgastar agua\">no se debe malgastar agua</span></td><td>one must not waste water</td></tr>\n              <tr><td><span data-say=\"hay que ahorrar energía\">hay que ahorrar energía</span></td><td>you have to save energy</td></tr>\n              <tr><td><span data-say=\"hay que apagar las luces\">hay que apagar las luces</span></td><td>you have to turn off the lights</td></tr>\n              <tr><td><span data-say=\"se debería usar el transporte público\">se debería usar el transporte público</span> <span class=\"tier-h\">H</span></td><td>one should use public transport</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Para proteger el medio ambiente, se debe reciclar y no se debe malgastar el agua.\">Para proteger el medio ambiente, se debe reciclar y no se debe malgastar el agua.</span></p>", "check": {"question": "What follows ‘se debe’, ‘hay que’ and ‘se debería’?", "options": ["an infinitive (reciclar, ahorrar…)", "a verb in the preterite past tense", "an adjective that must agree", "a plural noun on its own"], "answer": 0, "explain": "All three advice structures are followed by an infinitive, never a conjugated verb."}}, {"title": "How do I talk about global issues?", "html": "<p><span class=\"tier-h\">H</span> At Higher tier you also need wider world problems, not just local ones:</p>\n            <ul>\n              <li><span data-say=\"los problemas globales\">los problemas globales</span> — global problems</li>\n              <li><span data-say=\"la pobreza\">la pobreza</span> — poverty</li>\n              <li><span data-say=\"el hambre\">el hambre</span> — hunger</li>\n              <li><span data-say=\"los países en desarrollo\">los países en desarrollo</span> — developing countries</li>\n            </ul>\n            <p>Example: <span data-say=\"La pobreza y el hambre son problemas globales muy graves.\">La pobreza y el hambre son problemas globales muy graves.</span> — <em>Poverty and hunger are very serious global problems.</em></p>", "check": {"question": "What does ‘el hambre’ mean?", "options": ["hunger", "poverty", "a natural disaster", "a global war"], "answer": 0, "explain": "el hambre = hunger. It uses ‘el’ even though the noun is feminine, because ‘hambre’ starts with a stressed ‘a’ sound."}}, {"title": "Higher: predicting the future of the planet", "html": "<p><span class=\"tier-h\">H</span> Use the simple future (will) to make predictions — take the infinitive and add the future endings:</p>\n            <ul>\n              <li><span data-say=\"el planeta estará en peligro\">el planeta estará en peligro</span> — the planet will be in danger</li>\n              <li><span data-say=\"la situación empeorará\">la situación empeorará</span> — the situation will get worse</li>\n              <li><span data-say=\"habrá menos agua en el futuro\">habrá menos agua en el futuro</span> — there will be less water in the future</li>\n            </ul>\n            <p>Example: <span data-say=\"Si no reciclamos, el planeta estará en peligro.\">Si no reciclamos, el planeta estará en peligro.</span></p>", "check": {"question": "‘El planeta estará en peligro’ is which tense?", "options": ["the future (will be)", "the present tense", "a command form", "the preterite past tense"], "answer": 0, "explain": "‘estará’ is the future tense of estar — ‘will be’."}}, {"title": "Higher: the subjunctive after ‘es importante que’", "html": "<p><span class=\"tier-h\">H</span> After certain impersonal expressions of opinion or necessity, Spanish uses the <strong>present subjunctive</strong>:</p>\n            <ul>\n              <li><span data-say=\"es importante que reciclemos\">es importante que reciclemos</span> — it is important that we recycle</li>\n              <li><span data-say=\"es necesario que protejamos la naturaleza\">es necesario que protejamos la naturaleza</span> — it is necessary that we protect nature</li>\n            </ul>\n            <p>Compare: <span data-say=\"Reciclamos el papel.\">Reciclamos el papel.</span> (we recycle — a simple statement) with <span data-say=\"Es importante que reciclemos el papel.\">Es importante que reciclemos el papel.</span> (it is important that we recycle — subjunctive after ‘que’).</p>", "check": {"question": "Why is it ‘reciclemos’, not ‘reciclamos’, after ‘es importante que’?", "options": ["‘es importante que’ triggers the subjunctive", "‘reciclemos’ is simply the ‘we’ form of the present tense", "the subject has changed from ‘we’ to ‘they’", "it describes a completed action in the past"], "answer": 0, "explain": "Impersonal expressions like ‘es importante que’ trigger the present subjunctive: reciclemos, not reciclamos."}}, {"title": "Bigger environmental ideas: cause and effect", "html": "<p><span class=\"tier-h\">H</span> Wider vocabulary for talking about environmental causes and effects:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"existir\">existir</span></td><td>to exist</td><td><span data-say=\"la tierra\">la tierra</span></td><td>earth / land</td></tr>\n              <tr><td><span data-say=\"el efecto\">el efecto</span></td><td>effect</td><td><span data-say=\"económico\">económico</span></td><td>economic</td></tr>\n              <tr><td><span data-say=\"el dato\">el dato</span></td><td>piece of data</td><td><span data-say=\"la cantidad\">la cantidad</span></td><td>quantity</td></tr>\n              <tr><td><span data-say=\"aumentar\">aumentar</span></td><td>to increase</td><td><span data-say=\"crecer\">crecer</span></td><td>to grow</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En la Tierra existen muchos problemas medioambientales. El efecto invernadero es una causa importante del cambio climático, y tiene consecuencias económicas graves para muchos países. Según los datos científicos, la cantidad de gases en la atmósfera aumenta y el problema crece cada año — por eso el cielo de las grandes ciudades ya no está tan limpio.\">En la Tierra existen muchos problemas medioambientales. El efecto invernadero es una causa importante del cambio climático, y tiene consecuencias económicas graves para muchos países. Según los datos científicos, la cantidad de gases en la atmósfera aumenta y el problema crece cada año — por eso el cielo de las grandes ciudades ya no está tan limpio.</span> — <em>On Earth, many environmental problems exist. The greenhouse effect is an important cause of climate change, and it has serious economic consequences for many countries. According to the scientific data, the amount of gases in the atmosphere is increasing and the problem grows every year — that''s why the sky of big cities is no longer as clean.</em></p>", "check": {"question": "According to the text, what does the writer say is increasing every year?", "options": ["the amount of harmful gases in the air", "the number of totally pollution-free countries in the world", "the price families pay for renewable energy every year", "the size of the world''s remaining rainforests and parks"], "answer": 0, "explain": "‘la cantidad de gases en la atmósfera aumenta … cada año’ = the amount of gases in the atmosphere increases every year. The other options invent facts not in the text."}}, {"title": "Global problems: poverty, population and solutions", "html": "<p><span class=\"tier-h\">H</span> Vocabulary for discussing world problems and who is trying to solve them:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la población\">la población</span></td><td>population</td><td><span data-say=\"pobre\">pobre</span></td><td>poor</td></tr>\n              <tr><td><span data-say=\"sufrir\">sufrir</span></td><td>to suffer</td><td><span data-say=\"la diferencia\">la diferencia</span></td><td>difference</td></tr>\n              <tr><td><span data-say=\"la organización\">la organización</span></td><td>organisation</td><td><span data-say=\"la paz\">la paz</span></td><td>peace</td></tr>\n              <tr><td><span data-say=\"la fuente\">la fuente</span></td><td>source</td><td><span data-say=\"desaparecer\">desaparecer</span></td><td>to disappear</td></tr>\n            </table>\n            <p>Example: <span data-say=\"La población mundial sigue creciendo, y muchas personas pobres sufren de hambre y falta de agua potable. Hay una gran diferencia entre los países ricos y los países en desarrollo. Organizaciones como la ONU trabajan por la paz y buscan fuentes de energía limpia para que los bosques no desaparezcan. El peor problema es que muchos gobiernos no actúan lo suficiente.\">La población mundial sigue creciendo, y muchas personas pobres sufren de hambre y falta de agua potable. Hay una gran diferencia entre los países ricos y los países en desarrollo. Organizaciones como la ONU trabajan por la paz y buscan fuentes de energía limpia para que los bosques no desaparezcan. El peor problema es que muchos gobiernos no actúan lo suficiente.</span> — <em>The world population keeps growing, and many poor people suffer from hunger and a lack of drinking water. There is a big difference between rich countries and developing countries. Organisations like the UN work for peace and look for sources of clean energy so that forests don''t disappear. The worst problem is that many governments don''t act enough.</em></p>", "check": {"question": "According to the text, what do organisations like the UN look for?", "options": ["clean sources of energy", "new countries to develop and industrialise", "cheaper food for poor families everywhere", "bigger cities to house a growing population"], "answer": 0, "explain": "‘buscan fuentes de energía limpia’ = they look for clean sources of energy. The other options are not stated in the text."}}, {"title": "Nature under threat: trees, forests and deforestation", "html": "<p><span class=\"tier-h\">H</span> More vocabulary for talking about nature and deforestation:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el árbol\">el árbol</span></td><td>tree</td><td><span data-say=\"cortar\">cortar</span></td><td>to cut</td></tr>\n              <tr><td><span data-say=\"utilizar\">utilizar</span></td><td>to use</td><td><span data-say=\"el estado\">el estado</span></td><td>state / condition</td></tr>\n              <tr><td><span data-say=\"la época\">la época</span></td><td>era / time period</td><td><span data-say=\"la duda\">la duda</span></td><td>doubt</td></tr>\n              <tr><td><span data-say=\"apenas\">apenas</span></td><td>hardly / barely</td><td><span data-say=\"igual\">igual</span></td><td>equal / the same</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cada año se cortan miles de árboles para utilizar la madera o crear más tierras de cultivo. En esta época de cambio climático, no hay duda de que el estado de los bosques del mundo está empeorando: en algunas zonas apenas quedan árboles, y esto no es igual en todos los países — algunos protegen sus bosques mucho mejor que otros.\">Cada año se cortan miles de árboles para utilizar la madera o crear más tierras de cultivo. En esta época de cambio climático, no hay duda de que el estado de los bosques del mundo está empeorando: en algunas zonas apenas quedan árboles, y esto no es igual en todos los países — algunos protegen sus bosques mucho mejor que otros.</span> — <em>Every year thousands of trees are cut down to use the wood or create more farmland. In this era of climate change, there is no doubt that the state of the world''s forests is getting worse: in some areas hardly any trees are left, and this isn''t the same in every country — some protect their forests much better than others.</em></p>", "check": {"question": "According to the text, what has happened in some areas because of deforestation?", "options": ["hardly any trees are left", "every country now protects its forests equally well", "the climate has completely stopped changing", "more farmland has been turned back into forest"], "answer": 0, "explain": "‘apenas quedan árboles’ = hardly any trees are left. The other options invent facts not in the text."}}]}, "terms": {"enabled": true, "pairs": [{"term": "el medio ambiente", "definition": "the environment"}, {"term": "la contaminación", "definition": "pollution"}, {"term": "reciclar", "definition": "to recycle"}, {"term": "la basura", "definition": "rubbish"}, {"term": "la naturaleza", "definition": "nature"}, {"term": "los recursos naturales", "definition": "natural resources"}, {"term": "la energía", "definition": "energy"}, {"term": "la contaminación del aire", "definition": "air pollution"}, {"term": "el tráfico", "definition": "traffic"}, {"term": "la deforestación", "definition": "deforestation"}, {"term": "la sequía", "definition": "drought"}, {"term": "el cambio climático", "definition": "climate change"}, {"term": "el calentamiento global", "definition": "global warming"}, {"term": "hay que ahorrar energía", "definition": "you have to save energy"}, {"term": "apagar las luces", "definition": "to turn off the lights"}, {"term": "la pobreza · el hambre (H)", "definition": "poverty · hunger"}, {"term": "se debería (H)", "definition": "one should (conditional)"}, {"term": "es importante que reciclemos (H)", "definition": "it’s important that we recycle (subjunctive)"}, {"term": "existir", "definition": "to exist"}, {"term": "la tierra", "definition": "the earth / land"}, {"term": "igual", "definition": "equal / the same"}, {"term": "utilizar", "definition": "to use"}, {"term": "el estado", "definition": "the state / condition"}, {"term": "el efecto", "definition": "the effect"}, {"term": "económico", "definition": "economic"}, {"term": "la época", "definition": "the era / time period"}, {"term": "la población", "definition": "the population"}, {"term": "la cantidad", "definition": "the quantity / amount"}, {"term": "apenas", "definition": "hardly / barely"}, {"term": "pobre", "definition": "poor"}, {"term": "sufrir", "definition": "to suffer"}, {"term": "la organización", "definition": "the organisation"}, {"term": "la diferencia", "definition": "the difference"}, {"term": "la duda", "definition": "the doubt"}, {"term": "el dato", "definition": "the piece of data / fact"}, {"term": "la paz", "definition": "peace"}, {"term": "crecer", "definition": "to grow"}, {"term": "el cielo", "definition": "the sky"}, {"term": "la fuente", "definition": "the source / fountain"}, {"term": "aumentar", "definition": "to increase"}, {"term": "desaparecer", "definition": "to disappear"}, {"term": "el peor, la peor, los peores, las peores", "definition": "the worst"}, {"term": "el árbol", "definition": "the tree"}, {"term": "cortar", "definition": "to cut"}, {"term": "profundo", "definition": "deep"}, {"term": "salvar", "definition": "to save / rescue"}, {"term": "la planta", "definition": "the plant"}, {"term": "negar; negarse a", "definition": "to deny; to refuse to"}, {"term": "el motivo", "definition": "the reason / motive"}, {"term": "recoger", "definition": "to collect / pick up"}, {"term": "la solución", "definition": "the solution"}, {"term": "el ciudadano · la ciudadana", "definition": "the citizen"}, {"term": "puro", "definition": "pure"}, {"term": "el grado", "definition": "the degree"}, {"term": "la madera", "definition": "wood"}, {"term": "advertir", "definition": "to warn"}, {"term": "conservar", "definition": "to conserve"}, {"term": "el factor", "definition": "the factor"}, {"term": "luchar", "definition": "to fight / struggle"}, {"term": "el olor", "definition": "the smell"}, {"term": "la violencia", "definition": "violence"}, {"term": "la intención", "definition": "the intention"}, {"term": "seco", "definition": "dry"}, {"term": "destruir", "definition": "to destroy"}, {"term": "reciente", "definition": "recent"}, {"term": "contribuir", "definition": "to contribute"}, {"term": "la temperatura", "definition": "the temperature"}, {"term": "el daño", "definition": "the damage / harm"}, {"term": "la clave", "definition": "the key / crucial point"}, {"term": "eléctrico", "definition": "electric"}, {"term": "el aumento", "definition": "the increase"}, {"term": "la protección", "definition": "protection"}, {"term": "encender", "definition": "to turn on / light"}, {"term": "el bosque", "definition": "the forest"}, {"term": "fresco", "definition": "fresh / cool"}, {"term": "la nube", "definition": "the cloud"}, {"term": "la frontera", "definition": "the border"}, {"term": "el gas", "definition": "gas"}, {"term": "la preocupación", "definition": "the worry / concern"}, {"term": "la cifra", "definition": "the figure / number"}, {"term": "emitir", "definition": "to emit"}, {"term": "la arena", "definition": "sand"}, {"term": "el paisaje", "definition": "the landscape"}, {"term": "gris", "definition": "grey"}, {"term": "el humo", "definition": "smoke"}, {"term": "justo", "definition": "fair / just"}, {"term": "consciente", "definition": "aware / conscious"}, {"term": "el entorno", "definition": "the environment / surroundings"}, {"term": "preferible", "definition": "preferable"}, {"term": "sobrevivir", "definition": "to survive"}, {"term": "huele (a)", "definition": "it smells (of)"}, {"term": "el monte", "definition": "the mountain"}, {"term": "el cultivo", "definition": "the crop / cultivation"}, {"term": "el lago", "definition": "the lake"}, {"term": "el desastre", "definition": "the disaster"}, {"term": "el incendio", "definition": "the fire"}, {"term": "la primavera", "definition": "spring"}, {"term": "el otoño", "definition": "autumn"}, {"term": "decepcionante", "definition": "disappointing"}]}, "mcq": {"enabled": true, "questions": [{"question": "<span data-say=\"Hay que ahorrar energía en casa.\" data-listen></span><br>Listen. What must you do?", "options": ["Save energy at home", "Waste energy at home", "Sell energy to your neighbours", "Buy more electrical appliances"], "answer": 0, "explain": "‘hay que ahorrar energía en casa’ = you have to save energy at home. The traps reverse the meaning or invent unrelated actions."}, {"question": "<span data-say=\"Se debe reciclar el vidrio y el plástico.\" data-listen></span><br>Listen. What should be recycled?", "options": ["Glass and plastic", "Paper and cardboard", "Glass only, never plastic", "Plastic and metal cans"], "answer": 0, "explain": "‘se debe reciclar el vidrio y el plástico’ = glass and plastic should be recycled. Every distractor swaps in a different, plausible pair of materials."}, {"question": "How do you say ‘air pollution’ in Spanish?", "options": ["la contaminación del aire", "la contaminación del agua", "el aire contaminado del tráfico", "la basura del aire y del mar"], "answer": 0, "explain": "la contaminación del aire = air pollution (aire = air). Option B swaps in agua (water), a genuine near-miss."}, {"question": "Which sentence gives correct, positive environmental advice?", "options": ["Se debe reciclar el papel y el vidrio", "No se debe reciclar nunca el papel", "Se debe malgastar el agua y la energía", "Hay que tirar la basura al río"], "answer": 0, "explain": "‘se debe reciclar el papel y el vidrio’ = one should recycle paper and glass. The others reverse the advice or recommend something harmful."}, {"question": "Which word means ‘drought’?", "options": ["la sequía", "la contaminación", "la deforestación", "el calentamiento"], "answer": 0, "explain": "la sequía = drought. contaminación = pollution, deforestación = deforestation, calentamiento = warming."}, {"question": "Which sentence correctly uses ‘hay que’ + infinitive?", "options": ["Hay que ahorrar agua en casa", "Hay que ahorramos agua en casa", "Hay que ahorrando agua en casa", "Hay que ahorrado agua en casa"], "answer": 0, "explain": "‘hay que’ must be followed by an infinitive (ahorrar), never a conjugated verb, a gerund or a past participle."}, {"question": "Complete: ‘Para proteger el medio ambiente, hay que ___ menos electricidad.’", "options": ["usar", "uso", "usando", "usado"], "answer": 0, "explain": "‘hay que’ takes an infinitive → usar. The others are the noun, the gerund and the past participle."}, {"question": "What does ‘los recursos naturales’ mean?", "options": ["natural resources", "natural disasters", "national parks", "national resources"], "answer": 0, "explain": "recursos = resources, naturales = natural. Distractors swap in ‘disasters’, ‘parks’ or the false friend ‘national’."}, {"question": "Which is the odd one out — NOT a cause of pollution?", "options": ["reciclar", "el tráfico", "la contaminación del aire", "la deforestación"], "answer": 0, "explain": "reciclar (to recycle) is a solution, not a cause. Traffic, air pollution and deforestation are all problems."}, {"question": "Which sentence correctly uses the subjunctive after ‘es importante que’?", "options": ["Es importante que reciclemos más", "Es importante que reciclamos más", "Es importante que reciclar más", "Es importante que reciclado más"], "answer": 0, "explain": "‘es importante que’ triggers the present subjunctive: reciclemos, not the present tense, the infinitive or the past participle."}, {"question": "Which word means ''to save'' (rescue)?", "options": ["salvar", "destruir", "contribuir", "advertir"], "answer": 0, "explain": "salvar = to save/rescue. destruir = to destroy (the opposite!), contribuir = to contribute, advertir = to warn."}, {"question": "Which word means ''a solution''?", "options": ["una solución", "una intención", "un motivo", "una clave"], "answer": 0, "explain": "una solución = a solution. una intención = an intention, un motivo = a reason/motive, una clave = a key/crucial point — all abstract nouns you might meet discussing a problem."}, {"question": "Which word means ''a citizen''?", "options": ["un ciudadano", "un vecino", "una población", "un país"], "answer": 0, "explain": "un ciudadano = a citizen. un vecino = a neighbour, una población = a population, un país = a country — all people/place words that are easy to muddle."}, {"question": "Which word means ''pure''?", "options": ["puro", "profundo", "seco", "eléctrico"], "answer": 0, "explain": "puro = pure (e.g. aire puro). profundo = deep, seco = dry, eléctrico = electric — other adjectives used to describe nature and energy."}, {"question": "Which word means ''a degree'' (of temperature)?", "options": ["un grado", "una temperatura", "un factor", "un dato"], "answer": 0, "explain": "un grado = a degree. una temperatura = a temperature (a close relative, but not the same word), un factor = a factor, un dato = a piece of data."}, {"question": "Which word means ''wood'' (the material)?", "options": ["la madera", "la piedra", "el bosque", "el cultivo"], "answer": 0, "explain": "la madera = wood, the material. la piedra = stone, el bosque = the forest (where wood comes from, but not the material itself), el cultivo = the crop/cultivation."}, {"question": "Which word means ''to warn''?", "options": ["advertir", "conservar", "contribuir", "destruir"], "answer": 0, "explain": "advertir = to warn (e.g. scientists warn us). conservar = to conserve, contribuir = to contribute, destruir = to destroy."}]}, "fib": {"enabled": true, "questions": [{"text": "Se debe [reciclar] el papel y el vidrio. <span data-say=\"Se debe reciclar el papel y el vidrio.\" data-listen>Se debe reciclar el papel y el vidrio.</span>"}, {"text": "Hay que [ahorrar] energía en casa. <span data-say=\"Hay que ahorrar energía en casa.\" data-listen>Hay que ahorrar energía en casa.</span>"}, {"text": "El [cambio] climático es un problema muy grave. <span data-say=\"El cambio climático es un problema muy grave.\" data-listen>El cambio climático es un problema muy grave.</span>"}, {"text": "La [contaminación] del aire es peor en las ciudades grandes. (pollution)"}, {"text": "Hay que apagar las [luces] cuando sales de una habitación. (lights)"}, {"text": "No se debe [malgastar] el agua; es un recurso muy valioso. (waste)"}, {"text": "Es importante que [reciclemos] más para proteger la naturaleza. (we recycle — subjunctive)"}, {"text": "Mi abuela cultiva una [planta] de tomates en el jardín. (plant)"}, {"text": "No se puede [negar] que el planeta está en peligro. (deny)"}, {"text": "Los voluntarios van a [recoger] botellas de plástico de la playa este sábado. (collect)"}, {"text": "Es importante [luchar] contra la pobreza en todo el mundo. (to fight)"}, {"text": "La contaminación puede causar mucho [daño] a los animales marinos. (damage)"}, {"text": "Según un estudio [reciente], las temperaturas van a subir dos grados. (recent)"}, {"text": "La energía solar es la [clave] para reducir la contaminación. (key)"}]}, "tf": {"enabled": true, "questions": [{"statement": "‘reciclar’ means ‘to recycle’.", "answer": true, "explain": "reciclar = to recycle, from ‘el reciclaje’ (recycling)."}, {"statement": "‘la sequía’ means ‘flooding’.", "answer": false, "explain": "la sequía means drought — the opposite of flooding (inundación)."}, {"statement": "‘hay que’ is followed by an infinitive.", "answer": true, "explain": "hay que reciclar / ahorrar / proteger — always an infinitive."}, {"statement": "‘se debe’ and ‘no se debe’ mean the same thing.", "answer": false, "explain": "‘se debe’ = one should; ‘no se debe’ = one must not — opposite meanings."}, {"statement": "‘el calentamiento global’ means ‘global warming’.", "answer": true, "explain": "calentamiento = warming, global = global."}, {"statement": "‘la pobreza’ means ‘wealth’.", "answer": false, "explain": "la pobreza means poverty, not wealth (la riqueza)."}, {"statement": "Higher: ‘el planeta estará en peligro’ uses the future tense.", "answer": true, "explain": "‘estará’ is the future of estar — the planet WILL BE in danger."}, {"statement": "Higher: after ‘es importante que’, Spanish uses the subjunctive (e.g. reciclemos).", "answer": true, "explain": "Impersonal expressions of opinion/necessity trigger the present subjunctive."}, {"statement": "‘el árbol’ means ‘the tree’.", "answer": true, "explain": "el árbol = the tree."}, {"statement": "‘pobre’ means ‘rich’.", "answer": false, "explain": "pobre means poor; rich is rico."}, {"statement": "‘la paz’ means ‘war’.", "answer": false, "explain": "la paz means peace; war is la guerra."}, {"statement": "‘la pobreza’ and ‘pobre’ are related words meaning ‘poverty’ and ‘poor’.", "answer": true, "explain": "la pobreza (poverty) comes from the same root as pobre (poor)."}]}, "misc": {"enabled": true, "items": [{"myth": "<span data-say=\"Se debe malgastar el agua.\">Se debe malgastar el agua.</span>", "truth": "<span data-say=\"No se debe malgastar el agua.\">No se debe malgastar el agua.</span>", "check": {"question": "What does ‘malgastar’ mean?", "options": ["to waste", "to save", "to recycle", "to protect"], "answer": 0, "explain": "malgastar = to waste. It is often confused with ‘ahorrar’ (to save) because both appear beside environment vocabulary."}}, {"myth": "<span data-say=\"la sequía\">la sequía</span> significa “flooding”.", "truth": "<span data-say=\"la sequía\">la sequía</span> significa “drought”.", "check": {"question": "Why is ‘la sequía’ NOT ‘flooding’?", "options": ["it means the opposite — a lack of rain (drought)", "it is simply another word that means exactly the same as ‘inundación’", "it only ever refers to snow falling in winter", "it means ‘a rainy season’ that lasts several months"], "answer": 0, "explain": "la sequía = drought, a long dry period with no rain — the opposite of a flood."}}, {"myth": "<span data-say=\"la contaminación del aire\">la contaminación del aire</span> = water pollution", "truth": "<span data-say=\"la contaminación del aire\">la contaminación del aire</span> = air pollution", "check": {"question": "‘la contaminación del aire’ is pollution of…", "options": ["the air", "the water", "the soil", "the ocean only"], "answer": 0, "explain": "aire = air. Students often mishear or confuse it with agua (water)."}}, {"myth": "<span data-say=\"hay que reciclando\">Hay que reciclando.</span>", "truth": "<span data-say=\"hay que reciclar\">Hay que reciclar.</span>", "check": {"question": "Why is ‘Hay que reciclando’ wrong?", "options": ["‘hay que’ is a fixed structure that must be followed by an infinitive, not a gerund", "‘reciclando’ is not actually a real word anywhere at all in the whole Spanish language", "‘hay que’ can only be used in negative sentences", "the verb needs to agree with a subject pronoun first"], "answer": 0, "explain": "hay que + infinitive: hay que reciclar, never the -ando gerund form."}}, {"myth": "<span data-say=\"es importante que reciclamos\">Es importante que reciclamos.</span>", "truth": "<span data-say=\"es importante que reciclemos\">Es importante que reciclemos.</span>", "check": {"question": "Why does ‘es importante que’ need ‘reciclemos’, not ‘reciclamos’?", "options": ["it triggers the present subjunctive", "‘reciclamos’ is simply a spelling mistake", "the subject silently changes to ‘ellos’", "it describes a finished past action"], "answer": 0, "explain": "es importante que + subjunctive: reciclemos, not the ordinary present tense reciclamos."}}]}, "tips": {"enabled": true, "items": [{"title": "Paper 1 — Dictation (listening)", "html": "Environment sentences reuse chunks you know: ‘se debe…’, ‘hay que…’, ‘es importante que…’. Listen carefully for the difference between ‘el aire’ (air) and ‘el agua’ (water) — they sound similar but completely change the meaning of a pollution sentence.", "check": {"question": "You hear ‘la contaminación del agua’. What is being polluted?", "options": ["the water", "the air outside", "the soil nearby", "the food supply"], "answer": 0, "explain": "agua = water; do not confuse it with aire (air), which sounds similar."}}, {"title": "Paper 3 — Reading & translation into English", "html": "Watch for near-miss vocabulary: ‘la sequía’ (drought) is not ‘la lluvia’ (rain), and ‘los recursos’ (resources) is not ‘los recuerdos’ (memories) — a classic false-friend trap. Keep translations natural: ‘hay que ahorrar energía’ = ‘you have to save energy’.", "check": {"question": "‘Hay que proteger los recursos naturales’ means…", "options": ["You have to protect natural resources", "You have to remember lots of natural things", "There is a natural protector nearby", "You must forget about the resources"], "answer": 0, "explain": "recursos = resources, not recuerdos (memories) — a classic false-friend pair."}}, {"title": "Paper 4 — Writing & translation into Spanish (Higher)", "html": "Combine a problem, advice and a prediction: ‘La contaminación es un problema grave, así que se debe reciclar más.’ At Higher, add the future and the subjunctive: ‘Si no actuamos, el planeta estará en peligro’ and ‘es importante que reciclemos’.", "check": {"question": "Which answer reaches the top band?", "options": ["La contaminación es grave; hay que reciclar y es importante que protejamos la naturaleza", "La contaminación es mala. La contaminación es mala otra vez y otra vez sin parar", "Hay mucha contaminación, mucha basura, mucho tráfico y muchísimos problemas graves cada día", "Reciclamos el papel y usamos el transporte público y siempre apagamos las luces en casa"], "answer": 0, "explain": "It links a problem, advice and the subjunctive — range and accuracy score higher than length alone; simple repeated statements or a plain list of present-tense facts score lower even at similar length."}}]}, "exam": {"enabled": true, "questions": [{"question": "Read what Carlos says. Answer <strong>in English</strong>.<br>(a) What causes air pollution in his city? (1)<br>(b) Name <strong>one</strong> thing his family recycles at home. (1)<br>(c) Why do they turn off the lights? (1)<br>(d) What are they going to do next month, and why? (1)", "marks": 4, "hint": "Find the cause after ‘a causa de’, the recycled items after ‘reciclamos’, the reason after ‘para’, and the plan and reason after ‘vamos a’ / ‘porque’.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO3 Reading)</h5><ul>\n                <li><strong>(a)</strong> traffic <em>(1)</em>.</li>\n                <li><strong>(b)</strong> paper / glass (ANY ONE) <em>(1)</em>.</li>\n                <li><strong>(c)</strong> to save energy <em>(1)</em>.</li>\n                <li><strong>(d)</strong> (they are going to) plant trees, because it is important to protect nature <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Answers in English; do not penalise spelling if the meaning is clear.</li>\n            </ul></div>"}, {"question": "Translate these sentences <strong>into Spanish</strong>.<br>(a) We must recycle paper and glass. <br>(b) One should not waste water. <br>(c) It is important that we protect the environment because the planet will be in danger.", "marks": 5, "hint": "‘We must’ = se debe / hay que + infinitive. ‘One should not’ = no se debe. ‘It is important that’ triggers the subjunctive: es importante que + subjunctive verb.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 5 marks (AO4 Writing: translation)</h5><ul>\n                <li><strong>(a)</strong> Se debe reciclar el papel y el vidrio. <em>(1)</em></li>\n                <li><strong>(b)</strong> No se debe malgastar el agua. <em>(1)</em></li>\n                <li><strong>(c)</strong> Es importante que protejamos el medio ambiente <em>(1)</em> porque <em>(1)</em> el planeta estará en peligro <em>(1)</em>.</li>\n            </ul></div>\n            <div class=\"marks-section\"><h5>How the marks are given</h5><ul>\n                <li>Accept minor accent errors. Part (c) needs the subjunctive ‘protejamos’ and the future ‘estará’.</li>\n            </ul></div>"}]}}'::jsonb)
